-- Update exercise_library with Italian translations

UPDATE public.exercise_library 
SET name_it = '3/4 Sit-Up', description_it = 'Sdraiati a terra e blocca i piedi. Le ginocchia devono essere piegate. Posiziona le mani dietro la nuca o ai lati della testa. Parti con la schiena a terra; questa è la tua posizione iniziale. Fletti i fianchi e la colonna vertebrale per sollevare il busto verso le ginocchia. Al culmine della contrazione, il busto deve essere perpendicolare al suolo. Inverti il movimento tornando solo per ¾ del percorso. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = '3/4 Sit-Up';

UPDATE public.exercise_library 
SET name_it = '90/90 Hamstring', description_it = 'Sdraiati sulla schiena con una gamba distesa. Con l''altra gamba, fletti l''anca e il ginocchio a 90 gradi. Puoi sostenere la gamba con le mani se necessario. Questa è la tua posizione iniziale. Distendi la gamba verso l''alto, facendo una breve pausa in cima. Ritorna alla posizione iniziale. Ripeti per 10-20 ripetizioni, poi cambia gamba.' 
WHERE name = '90/90 Hamstring';

UPDATE public.exercise_library 
SET name_it = 'Ab Crunch Machine', description_it = 'Seleziona una resistenza leggera e siediti sulla macchina posizionando i piedi sotto gli appositi rulli e afferrando le maniglie superiori. Le braccia devono essere piegate a 90 gradi con i tricipiti appoggiati ai cuscinetti. Questa è la tua posizione iniziale. Contemporaneamente, solleva le gambe ed esegui un crunch con il busto, espirando durante il movimento. Consiglio: esegui il movimento in modo lento e controllato. Concentrati sull''utilizzo degli addominali per spostare il carico, rilassando gambe e piedi. Dopo un secondo di pausa, ritorna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Ab Crunch Machine';

UPDATE public.exercise_library 
SET name_it = 'Ab Roller', description_it = 'Impugna l''Ab Roller con entrambe le mani e inginocchiati a terra. Posiziona l''attrezzo davanti a te in modo da essere in quadrupedia (come in una posizione di piegamento in ginocchio). Questa è la tua posizione iniziale. Spingi lentamente l''Ab Roller in avanti, distendendo il corpo fino ad arrivare in posizione orizzontale. Consiglio: scendi il più possibile senza toccare il pavimento con il corpo. Inspira durante questa fase del movimento. Dopo una pausa nella posizione di massima estensione, tirati indietro verso la posizione iniziale espirando. Consiglio: procedi lentamente e mantieni gli addominali sempre contratti.' 
WHERE name = 'Ab Roller';

UPDATE public.exercise_library 
SET name_it = 'Adductor', description_it = 'Sdraiati a pancia in giù con una gamba sopra un foam roller. Ruota la gamba in modo che il foam roller sia a contatto con l''interno coscia. Scarica sul rullo tutto il peso che riesci a tollerare. Cercando di rilassare i muscoli dell''interno coscia, scorri con il rullo tra l''anca e il ginocchio, mantenendo la pressione sui punti di tensione per 10-30 secondi. Ripeti con l''altra gamba.' 
WHERE name = 'Adductor';

UPDATE public.exercise_library 
SET name_it = 'Adductor/Groin', description_it = 'Sdraiati sulla schiena con le gambe sollevate verso il soffitto. Fatti tenere i piedi o le caviglie da un partner. Divarica le gambe il più possibile. Questa è la tua posizione iniziale. Cerca di chiudere le gambe stringendole per 10 o più secondi, mentre il partner oppone resistenza impedendoti di farlo. Ora, rilassa i muscoli delle gambe mentre il partner spinge i tuoi piedi verso l''esterno, allungandoli fin dove risulta confortevole. Comunica sempre al partner quando lo stretching è sufficiente per evitare sovra-allungamenti o infortuni.' 
WHERE name = 'Adductor/Groin';

UPDATE public.exercise_library 
SET name_it = 'Advanced Kettlebell Windmill', description_it = 'Esegui un Clean e un press per portare il kettlebell sopra la testa con un braccio. Mantenendo il kettlebell bloccato in alto per tutto il tempo, spingi il bacino nella direzione del braccio teso. Tieni il braccio che non lavora dietro la schiena e ruota i piedi a quarantacinque gradi rispetto al braccio che regge il kettlebell. Scendi il più possibile. Fai una pausa di un secondo e inverti il movimento per tornare alla posizione iniziale.' 
WHERE name = 'Advanced Kettlebell Windmill';

UPDATE public.exercise_library 
SET name_it = 'Air Bike', description_it = 'Sdraiati a terra con la parte bassa della schiena ben aderente al suolo. Metti le mani ai lati della testa, facendo attenzione a non sforzare il collo durante l''esecuzione. Solleva le spalle nella posizione di crunch. Porta le ginocchia a 90 gradi rispetto al pavimento, con la parte inferiore delle gambe parallela al suolo. Questa è la tua posizione iniziale. Ora, simultaneamente, esegui un movimento di pedalata spingendo in avanti la gamba destra e portando il ginocchio sinistro verso il petto. Avvicina il gomito destro al ginocchio sinistro ruotando il busto ed espirando. Torna alla posizione iniziale inspirando. Esegui il crunch sul lato opposto mentre pedali, portando il gomito sinistro verso il ginocchio destro ed espirando. Alterna in questo modo fino al completamento delle ripetizioni raccomandate per ciascun lato.' 
WHERE name = 'Air Bike';

UPDATE public.exercise_library 
SET name_it = 'All Fours Quad Stretch', description_it = 'Inizia in posizione di quadrupedia, poi solleva una gamba dal pavimento e afferra il piede con la mano. Usa la mano per tenere il piede o la caviglia, mantenendo il ginocchio completamente flesso per allungare quadricipiti e flessori dell''anca. Concentrati sull''estensione delle anche, spingendole verso il pavimento. Mantieni la posizione per 10-20 secondi e poi cambia lato.' 
WHERE name = 'All Fours Quad Stretch';

UPDATE public.exercise_library 
SET name_it = 'Alternate Hammer Curl', description_it = 'In piedi con il busto eretto, impugna un manubrio in ogni mano lungo i fianchi. I gomiti devono essere vicini al busto e i palmi delle mani rivolti verso il corpo. Questa è la tua posizione iniziale. Tenendo fermo il braccio superiore, fletti il braccio destro verso l''alto contraendo il bicipite ed espirando. Continua il movimento finché il bicipite non è completamente contratto e il manubrio è all''altezza della spalla. Mantieni la contrazione per un secondo strizzando il bicipite. Consiglio: solo gli avambracci devono muoversi. Torna lentamente alla posizione iniziale inspirando. Ripeti con la mano sinistra. Questa è una ripetizione. Continua ad alternare per il numero di ripetizioni consigliato.' 
WHERE name = 'Alternate Hammer Curl';

UPDATE public.exercise_library 
SET name_it = 'Alternate Heel Touchers', description_it = 'Sdraiati a terra con le ginocchia flesse e i piedi appoggiati al suolo a una distanza di circa 45-60 cm. Tieni le braccia distese lungo i fianchi. Questa è la posizione di partenza. Esegui un crunch sollevando il busto di circa 7-10 cm verso destra e tocca il tallone destro, mantenendo la contrazione per un secondo. Espira durante l''esecuzione del movimento. Torna lentamente alla posizione di partenza inspirando. Esegui quindi un crunch sollevando il busto di 7-10 cm verso sinistra e tocca il tallone sinistro, mantenendo la contrazione per un secondo. Espira durante il movimento e torna alla posizione iniziale inspirando. Il tocco di entrambi i talloni equivale a 1 ripetizione. Continua ad alternare i lati fino al completamento delle ripetizioni previste.' 
WHERE name = 'Alternate Heel Touchers';

UPDATE public.exercise_library 
SET name_it = 'Alternate Incline Dumbbell Curl', description_it = 'Siediti su una panca inclinata con un manubrio in ciascuna mano, braccia distese. Suggerimento: tieni i gomiti vicini al busto. Questa è la posizione di partenza. Mantenendo la parte superiore del braccio ferma, fletti il braccio destro in avanti contraendo i bicipiti ed espirando. Durante il movimento, ruota la mano in modo che il palmo sia rivolto verso l''alto. Continua finché il bicipite non è completamente contratto e il manubrio è all''altezza della spalla. Mantieni la posizione di contrazione per un secondo strizzando il bicipite. Suggerimento: dovrebbero muoversi solo gli avambracci. Torna lentamente alla posizione iniziale inspirando. Ripeti il movimento con la mano sinistra. Questo equivale a una ripetizione. Continua ad alternare le braccia per il numero di ripetizioni raccomandato.' 
WHERE name = 'Alternate Incline Dumbbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Alternate Leg Diagonal Bound', description_it = 'Assumi una posizione comoda con un piede leggermente più avanti dell''altro. Inizia spingendo con la gamba anteriore, portando il ginocchio opposto in avanti e il più in alto possibile prima dell''atterraggio. Cerca di coprire la massima distanza possibile lateralmente a ogni balzo. Può essere utile utilizzare una linea tracciata a terra come riferimento per la distanza laterale. Ripeti la sequenza con l''altra gamba.' 
WHERE name = 'Alternate Leg Diagonal Bound';

UPDATE public.exercise_library 
SET name_it = 'Alternating Cable Shoulder Press', description_it = 'Posiziona i cavi nella parte inferiore della torre e seleziona un peso adeguato. Afferra i cavi e tienili all''altezza delle spalle, con i palmi rivolti in avanti. Questa è la posizione di partenza. Mantenendo testa e petto alti, distendi il braccio spingendo un lato direttamente sopra la testa. Dopo una breve pausa in alto, torna alla posizione di partenza e ripeti sul lato opposto.' 
WHERE name = 'Alternating Cable Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Alternating Deltoid Raise', description_it = 'In posizione eretta, tieni una coppia di manubri lungo i fianchi. Mantenendo i gomiti leggermente flessi, solleva i pesi direttamente davanti a te fino all''altezza delle spalle, evitando slanci o compensazioni. Riporta i pesi lungo i fianchi. Nella ripetizione successiva, solleva i pesi lateralmente, portandoli verso l''esterno fino all''altezza delle spalle. Riporta i pesi alla posizione di partenza e continua alternando i movimenti frontali e laterali.' 
WHERE name = 'Alternating Deltoid Raise';

UPDATE public.exercise_library 
SET name_it = 'Alternating Floor Press', description_it = 'Sdraiati a terra con due kettlebell accanto alle spalle. Posiziona il primo sul petto e poi il secondo, afferrando le maniglie con i palmi rivolti in avanti. Distendi entrambe le braccia in modo che i kettlebell siano sollevati sopra il petto. Abbassa un kettlebell portandolo al petto e ruota il polso nella direzione del braccio teso. Solleva il kettlebell e ripeti sul lato opposto.' 
WHERE name = 'Alternating Floor Press';

UPDATE public.exercise_library 
SET name_it = 'Alternating Hang Clean', description_it = 'Posiziona due kettlebell tra i piedi. Per assumere la posizione di partenza, spingi il bacino all''indietro e guarda dritto davanti a te. Esegui un Clean con un kettlebell portandolo alla spalla, mentre l''altro rimane in posizione di sospensione (hang). Solleva il kettlebell alla spalla estendendo gambe e anche mentre lo tiri verso l''alto; ruota il polso durante il movimento. Abbassa il kettlebell in posizione di sospensione ed esegui il Clean con l''altro. Ripeti.' 
WHERE name = 'Alternating Hang Clean';

UPDATE public.exercise_library 
SET name_it = 'Alternating Kettlebell Press', description_it = 'Esegui un Clean con due kettlebell portandoli alle spalle, estendendo gambe e anche mentre li tiri verso l''alto e ruoti i polsi. Spingi un kettlebell direttamente sopra la testa distendendo il gomito, ruotandolo in modo che il palmo sia rivolto in avanti, mentre mantieni l''altro kettlebell fermo alla spalla. Abbassa il kettlebell sollevato alla posizione di partenza e spingi immediatamente con l''altro braccio.' 
WHERE name = 'Alternating Kettlebell Press';

UPDATE public.exercise_library 
SET name_it = 'Alternating Kettlebell Row', description_it = 'Posiziona due kettlebell davanti ai piedi. Fletti leggermente le ginocchia e spingi il bacino il più possibile all''indietro. Piegati in avanti per assumere la posizione di partenza e afferra entrambi i kettlebell per le maniglie. Solleva un kettlebell da terra mantenendo l''altro fermo. Retrai la scapola del lato attivo flettendo il gomito e tirando il kettlebell verso lo stomaco o la cassa toracica. Abbassa il kettlebell e ripeti con l''altro braccio.' 
WHERE name = 'Alternating Kettlebell Row';

UPDATE public.exercise_library 
SET name_it = 'Alternating Renegade Row', description_it = 'Posiziona due kettlebell a terra alla larghezza delle spalle. Mettiti in posizione di push-up (flessioni) sulle punte dei piedi e sulle mani, con il corpo dritto e teso. Usa le maniglie dei kettlebell come supporto per la parte superiore del corpo; potresti dover tenere i piedi larghi per maggiore stabilità. Spingi un kettlebell contro il pavimento ed esegui il rematore con l''altro, retraendo la scapola del lato attivo mentre fletti il gomito e tiri il peso verso il fianco. Riporta il kettlebell a terra e ripeti con il braccio opposto. Ripeti per diverse ripetizioni.' 
WHERE name = 'Alternating Renegade Row';

UPDATE public.exercise_library 
SET name_it = 'Circonduzioni delle caviglie', description_it = 'Utilizza un supporto stabile, come un rack, per mantenerti in equilibrio. Solleva la gamba destra da terra (circa 5 cm) ed esegui un movimento circolare con l''alluce, come se stessi disegnando un grande cerchio. Consiglio: un giro completo equivale a una ripetizione. Respira normalmente durante l''esecuzione. Una volta completata la serie con il piede destro, ripeti con la gamba sinistra.' 
WHERE name = 'Ankle Circles';

UPDATE public.exercise_library 
SET name_it = 'Caviglia sul ginocchio', description_it = 'Partendo da una posizione distesa, piega le ginocchia mantenendo i piedi appoggiati a terra. Appoggia la caviglia di un piede sul ginocchio opposto. Afferra la coscia o il ginocchio della gamba a terra e tira entrambe le gambe verso il petto. Rilassa collo e spalle. Mantieni la posizione per 10-20 secondi, poi cambia lato.' 
WHERE name = 'Ankle On The Knee';

UPDATE public.exercise_library 
SET name_it = 'SMR Tibiale Anteriore', description_it = 'Siediti a terra con le gambe flesse e i piedi appoggiati al pavimento. Utilizzando un rullo muscolare (Muscle Roller) o un matterello, applica pressione sui muscoli della parte esterna dello stinco. Lavora dall''area appena sotto il ginocchio fino a sopra la caviglia, fermandoti sui punti di tensione per 10-30 secondi. Ripeti sull''altra gamba.' 
WHERE name = 'Anterior Tibialis-SMR';

UPDATE public.exercise_library 
SET name_it = 'Anti-Gravity Press', description_it = 'Posiziona un bilanciere a terra dietro la parte superiore di una panca inclinata. Sdraiati sulla panca a pancia in giù. Con una presa prona, solleva il bilanciere da terra. Fletti i gomiti eseguendo un curl inverso per portare il bilanciere vicino al petto: questa è la posizione di partenza. Spingi il bilanciere davanti alla testa estendendo i gomiti, mantenendo le braccia parallele al terreno durante tutto il movimento. Torna alla posizione iniziale e ripeti per completare la serie.' 
WHERE name = 'Anti-Gravity Press';

UPDATE public.exercise_library 
SET name_it = 'Circonduzioni delle braccia', description_it = 'In piedi, estendi le braccia lateralmente. Le braccia devono essere parallele al pavimento e perpendicolari al busto (angolo di 90 gradi): questa è la posizione di partenza. Inizia lentamente a disegnare cerchi di circa 30 cm di diametro con entrambe le braccia tese. Respira normalmente. Continua il movimento circolare per circa dieci secondi, quindi inverte il senso di rotazione.' 
WHERE name = 'Arm Circles';

UPDATE public.exercise_library 
SET name_it = 'Arnold Dumbbell Press', description_it = 'Siediti su una panca con schienale e tieni due manubri davanti a te all''altezza della parte alta del petto, con i palmi rivolti verso il corpo e i gomiti piegati. Consiglio: le braccia devono essere vicine al busto. La posizione iniziale deve assomigliare alla fase di contrazione di un curl con manubri. Solleva i manubri ruotando i palmi delle mani finché non sono rivolti in avanti. Continua a sollevare i manubri finché le braccia non sono completamente estese sopra la testa. Espira durante questa fase. Dopo una breve pausa in alto, abbassa i manubri nella posizione originale ruotando i palmi verso di te. Consiglio: il braccio sinistro ruota in senso antiorario, il destro in senso orario. Inspira durante questa fase. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Arnold Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Around The Worlds', description_it = 'Sdraiati su una panca piana tenendo un manubrio in ciascuna mano con i palmi rivolti verso il soffitto. Consiglio: le braccia devono essere parallele al pavimento e vicino alle cosce. Per evitare infortuni, mantieni i gomiti leggermente piegati. Questa è la posizione di partenza. Muovi i manubri disegnando un semicerchio dalla posizione iniziale fin sopra la testa. Durante tutto il movimento, le braccia devono rimanere parallele al pavimento. Inspira durante questa fase. Inverte il movimento per riportare il peso alla posizione iniziale mentre espiri.' 
WHERE name = 'Around The Worlds';

UPDATE public.exercise_library 
SET name_it = 'Atlas Stone Trainer', description_it = 'Questo attrezzo è efficace per sviluppare la forza specifica per le Atlas Stones quando non si dispone di pietre vere; è solitamente realizzato con estremità di bilancieri o tubi pesanti. Carica il peso desiderato sulla barra. Mettiti a cavalcioni dell''attrezzo, avvolgilo con le braccia e fletti le anche. Inizia sollevando il peso oltre le ginocchia, estendendo le anche. Una volta superate le ginocchia, posiziona il peso sulle cosce sedendoti leggermente indietro e stringendolo forte al petto. Completa il movimento estendendo anche e ginocchia per sollevare il peso il più in alto possibile. Il peso può essere riportato sulle cosce o a terra per le ripetizioni successive.' 
WHERE name = 'Atlas Stone Trainer';

UPDATE public.exercise_library 
SET name_it = 'Atlas Stones', description_it = 'Posiziona l''Atlas Stone tra i piedi. Fletti le anche per avvolgere verticalmente la pietra con le braccia, cercando di infilare le dita sotto di essa. Molte pietre hanno una piccola parte piatta sul fondo che ne facilita la presa. Tirando la pietra verso il busto, spingi con la parte posteriore dei piedi per sollevare la pietra da terra. Quando la pietra supera le ginocchia, appoggiala sulle cosce sedendoti all''indietro. Siediti in basso, porta la pietra in alto sul petto mentre cambi la presa per abbracciarla meglio. Alzati in piedi spingendo con le anche. Avvicinati alla piattaforma di carico e inclinati all''indietro, estendendo le anche per posizionare la pietra il più in alto possibile.' 
WHERE name = 'Atlas Stones';

UPDATE public.exercise_library 
SET name_it = 'Axle Deadlift', description_it = 'Avvicinati al bilanciere (axle) in modo che sia centrato sopra i piedi. I piedi devono essere alla larghezza delle anche. Fletti le anche per afferrare la barra alla larghezza delle spalle, consentendo alle scapole di protarsi. Solitamente si utilizza una presa mista (over/under). Con piedi e presa posizionati, fai un respiro profondo, abbassa le anche e fletti le ginocchia finché gli stinchi non toccano la barra. Guarda avanti, mantieni il petto alto e la schiena inarcata, quindi spingi attraverso i talloni per sollevare il carico. Dopo che la barra ha superato le ginocchia, tirala energicamente verso di te, stringendo le scapole mentre spingi le anche in avanti contro la barra. Abbassa la barra flettendo le anche e guidandola verso il pavimento.' 
WHERE name = 'Axle Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Back Flyes con elastici', description_it = 'Fissa un elastico attorno a un supporto stabile, come un rack. Afferra l''elastico dalle maniglie e allontanati per creare tensione. Estendi e solleva le braccia dritte davanti a te. Consiglio: le braccia devono essere tese e parallele al pavimento, perpendicolari al busto. I piedi devono essere ben piantati a terra alla larghezza delle spalle: questa è la posizione di partenza. Espirando, muovi le braccia lateralmente e verso dietro. Mantieni le braccia estese e parallele al pavimento. Continua il movimento finché le braccia non sono completamente aperte ai lati. Dopo una pausa, torna alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Back Flyes - With Bands';

UPDATE public.exercise_library 
SET name_it = 'Backward Drag (Trascinamento all''indietro)', description_it = 'Carica una slitta con il peso desiderato, fissando una corda o delle cinghie a cui poterti aggrappare. Inizia l''esercizio muovendoti all''indietro per una distanza prestabilita. Inclinati all''indietro, spingi con le gambe facendo piccoli passi per muoverti il più velocemente possibile.' 
WHERE name = 'Backward Drag';

UPDATE public.exercise_library 
SET name_it = 'Lancio all''indietro della Medicine Ball', description_it = 'Questo esercizio è ideale con un partner. Se non ne hai uno, la palla può essere recuperata dopo il lancio o lanciata contro un muro. Inizia in piedi a pochi metri davanti al partner, entrambi rivolti nella stessa direzione. Tieni la palla tra le gambe. Esegui uno squat e poi inverte la direzione con forza, estendendoti completamente mentre lanci la palla sopra la testa verso il partner. Il partner può poi farti rotolare la palla indietro. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Backward Medicine Ball Throw';

UPDATE public.exercise_library 
SET name_it = 'Balance Board', description_it = 'Posiziona una balance board davanti a te. Salici sopra e cerca di mantenere l''equilibrio. Mantieni la posizione per il tempo desiderato.' 
WHERE name = 'Balance Board';

UPDATE public.exercise_library 
SET name_it = 'Ball Leg Curl', description_it = 'Inizia sdraiato a terra sulla schiena con i piedi sopra la fitball. Posiziona la palla in modo che, a gambe estese, le caviglie siano sopra di essa. Questa è la posizione di partenza. Solleva i fianchi da terra, mantenendo il peso sulle scapole e sui piedi. Fletti le ginocchia, tirando la palla il più vicino possibile a te, contraendo i muscoli ischiocrurali. Dopo una breve pausa, torna alla posizione iniziale.' 
WHERE name = 'Ball Leg Curl';

UPDATE public.exercise_library 
SET name_it = 'Trazioni assistite con elastico', description_it = 'Fissa l''elastico attorno al centro della sbarra per trazioni. Puoi usare elastici diversi per variare il livello di assistenza. Tira l''estremità dell''elastico verso il basso e posiziona un ginocchio piegato nell''anello, assicurandoti che non scivoli via. Afferra la sbarra con una presa da media ad ampia. Questa è la posizione di partenza. Sollevati contraendo i dorsali e flettendo i gomiti. Il gomito deve essere guidato verso il fianco. Tira verso l''avanti, cercando di portare il mento sopra la sbarra. Evita movimenti oscillanti o a scatto. Dopo una breve pausa, torna alla posizione iniziale.' 
WHERE name = 'Band Assisted Pull-Up';

UPDATE public.exercise_library 
SET name_it = 'Good Morning con elastico', description_it = 'Usando un elastico da 41 pollici (104 cm), calpestalo con un''estremità e divarica leggermente i piedi. Piega i fianchi per far passare l''altra estremità dell''elastico dietro il collo. Questa è la posizione di partenza. Mantenendo le gambe tese, estendi i fianchi per tornare a una posizione quasi verticale. Assicurati di non incurvare la schiena mentre torni verso la posizione di partenza.' 
WHERE name = 'Band Good Morning';

UPDATE public.exercise_library 
SET name_it = 'Good Morning con elastico (Pull Through)', description_it = 'Aggancia l''elastico a un supporto. Standoti a poca distanza, fai passare l''altra estremità attorno al collo. Le mani possono aiutare a mantenere l''elastico in posizione. Inizia flettendo i fianchi, portando i glutei il più indietro possibile. Mantieni la schiena piatta e piegati in avanti fino a circa 90 gradi. Le ginocchia devono essere solo leggermente flesse. Torna alla posizione iniziale spingendo con i fianchi fino a tornare in piedi.' 
WHERE name = 'Band Good Morning (Pull Through)';

UPDATE public.exercise_library 
SET name_it = 'Adduzioni dell''anca con elastico', description_it = 'Ancora l''elastico a un supporto solido o a un oggetto fisso. Mettiti con il fianco sinistro rispetto al supporto e inserisci il piede destro nell''elastico, posizionandolo attorno alla caviglia. Rimani in piedi dritto e, se necessario, reggiti al supporto. Questa è la posizione di partenza. Mantenendo il ginocchio teso, solleva la gamba destra lateralmente il più possibile. Torna alla posizione iniziale e ripeti per il numero di ripetizioni desiderato. Cambia lato.' 
WHERE name = 'Band Hip Adductions';

UPDATE public.exercise_library 
SET name_it = 'Band Pull Apart', description_it = 'Inizia con le braccia tese davanti a te, tenendo l''elastico con entrambe le mani. Avvia il movimento eseguendo un''apertura (reverse fly), portando le mani lateralmente verso l''esterno. Mantieni i gomiti estesi durante il movimento, portando l''elastico verso il petto. Assicurati di mantenere le spalle indietro durante l''esercizio. Fai una pausa al completamento del movimento e torna alla posizione iniziale controllando la tensione.' 
WHERE name = 'Band Pull Apart';

UPDATE public.exercise_library 
SET name_it = 'Band Skull Crusher', description_it = 'Fissa una banda elastica alla base di un rack o di una panca. Sdraiati sulla panca in modo che la banda sia allineata con la testa. Afferra la banda sollevando i gomiti, in modo che la parte superiore del braccio sia perpendicolare al pavimento. Con il gomito flesso, la banda dovrebbe trovarsi sopra la tua testa. Questa è la posizione di partenza. Estendi il gomito per raddrizzare il braccio, mantenendo ferma la parte superiore del braccio. Fai una pausa al culmine del movimento e torna alla posizione di partenza.' 
WHERE name = 'Band Skull Crusher';

UPDATE public.exercise_library 
SET name_it = 'Barbell Ab Rollout', description_it = 'Per questo esercizio devi metterti in posizione di push-up, ma invece di avere le mani a terra, afferrerai un bilanciere olimpionico (caricato con 2,5-4,5 kg per lato). Questa è la posizione di partenza. Mantenendo una leggera curvatura della schiena, solleva i fianchi e fai rotolare il bilanciere verso i piedi espirando. Consiglio: durante il movimento, i glutei dovrebbero salire, gli addominali devono rimanere contratti e la postura della schiena deve essere mantenuta costante. Inoltre, le braccia devono rimanere perpendicolari al pavimento durante tutto il movimento; in caso contrario, lavoreresti più con le spalle e la schiena che con gli addominali. Dopo un secondo di contrazione nel punto più alto, inizia a far rotolare lentamente il bilanciere in avanti verso la posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Ab Rollout';

UPDATE public.exercise_library 
SET name_it = 'Barbell Ab Rollout sulle ginocchia', description_it = 'Afferra un bilanciere olimpionico caricato con 2,5-4,5 kg per lato e inginocchiati sul pavimento. Posiziona il bilanciere a terra davanti a te in modo da trovarti in appoggio sulle mani e sulle ginocchia (come in una posizione di push-up sulle ginocchia). Questa è la posizione di partenza. Fai rotolare lentamente il bilanciere in avanti, distendendo il corpo fino a una posizione dritta. Consiglio: scendi il più possibile senza toccare il pavimento con il corpo. Inspira durante questa fase del movimento. Dopo un secondo di pausa nella posizione di massima estensione, inizia a tornare lentamente alla posizione di partenza espirando. Consiglio: muoviti lentamente e mantieni gli addominali sempre contratti.' 
WHERE name = 'Barbell Ab Rollout - On Knees';

UPDATE public.exercise_library 
SET name_it = 'Barbell Bench Press - Presa media', description_it = 'Sdraiati su una panca piana. Utilizzando una presa di larghezza media (che crei un angolo di 90 gradi tra avambracci e braccia a metà movimento), solleva il bilanciere dal rack e tienilo dritto sopra di te con le braccia distese. Questa è la posizione di partenza. Inspirando, inizia a scendere lentamente finché il bilanciere non tocca la parte centrale del petto. Dopo una breve pausa, spingi il bilanciere verso la posizione iniziale espirando. Concentrati sulla spinta utilizzando i pettorali. Distendi le braccia e contrai i pettorali nel punto di massima contrazione, mantieni per un secondo e poi inizia a scendere lentamente. Consiglio: idealmente, la fase di discesa del peso dovrebbe durare il doppio rispetto a quella di risalita. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi il bilanciere nel rack.' 
WHERE name = 'Barbell Bench Press - Medium Grip';

UPDATE public.exercise_library 
SET name_it = 'Barbell Curl', description_it = 'In piedi, busto eretto, impugna un bilanciere con una presa pari alla larghezza delle spalle. I palmi delle mani devono essere rivolti in avanti e i gomiti vicini al busto. Questa è la posizione di partenza. Mantenendo ferme le braccia, fletti il bilanciere verso l''alto contraendo i bicipiti ed espirando. Consiglio: solo gli avambracci dovrebbero muoversi. Continua il movimento finché i bicipiti non sono completamente contratti e il bilanciere si trova all''altezza delle spalle. Mantieni la contrazione per un secondo strizzando bene i bicipiti. Torna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Barbell Curls su panca inclinata', description_it = 'Sdraiati contro una panca inclinata, con le braccia che tengono un bilanciere distese verso il basso in linea orizzontale. Questa è la posizione di partenza. Mantenendo ferme le braccia, fletti il peso verso l''alto il più possibile contraendo i bicipiti. Espira durante questa fase del movimento. Consiglio: solo gli avambracci devono muoversi. Non dondolare con le braccia. Dopo un secondo di contrazione, torna lentamente alla posizione di partenza inspirando. Consiglio: assicurati di scendere completamente. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Curls Lying Against An Incline';

UPDATE public.exercise_library 
SET name_it = 'Barbell Deadlift (Stacco da terra)', description_it = 'Posizionati di fronte a un bilanciere carico. Mantenendo la schiena il più dritta possibile, piega le ginocchia, chinati in avanti e afferra il bilanciere con una presa prona di larghezza media (pari alla larghezza delle spalle). Questa sarà la posizione di partenza. Consiglio: se è difficile mantenere la presa, alterna le mani o usa le cinghie da polso. Tenendo il bilanciere, inizia il sollevamento spingendo con le gambe e portando contemporaneamente il busto in posizione eretta mentre espiri. In posizione eretta, spingi il petto in fuori e contrai la schiena portando le scapole indietro. Immagina la postura dei soldati sull''attenti. Torna alla posizione di partenza flettendo le ginocchia e piegando contemporaneamente il busto in avanti, mantenendo la schiena dritta. Quando il peso tocca terra, sei tornato alla posizione iniziale, pronto per la ripetizione successiva. Esegui il numero di ripetizioni prescritto dal programma.' 
WHERE name = 'Barbell Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Barbell Full Squat (Squat completo)', description_it = 'Per sicurezza, questo esercizio va eseguito all''interno di un rack. Imposta il bilanciere sul rack appena sopra l''altezza delle spalle. Una volta scelto l''altezza corretta e caricato il bilanciere, posizionati sotto la sbarra appoggiandola sulla parte posteriore delle spalle (appena sotto il collo). Impugna il bilanciere da entrambi i lati e sollevalo dal rack spingendo con le gambe e raddrizzando il busto. Allontanati dal rack e posiziona le gambe a una larghezza media, pari a quella delle spalle, con le punte dei piedi leggermente rivolte verso l''esterno. Mantieni sempre la testa alta e la schiena dritta. Questa è la posizione di partenza. Inizia a scendere lentamente flettendo le ginocchia e spingendo i fianchi all''indietro, mantenendo la postura dritta e la testa alta. Scendi finché i femorali non toccano i polpacci. Inspira durante questa fase. Inizia a risalire espirando, spingendo sul pavimento con il tallone o con la parte centrale del piede, raddrizzando le gambe ed estendendo i fianchi per tornare alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Full Squat';

UPDATE public.exercise_library 
SET name_it = 'Barbell Glute Bridge', description_it = 'Inizia seduto a terra con un bilanciere carico sulle gambe. L''utilizzo di un bilanciere spesso o di un cuscinetto protettivo può ridurre notevolmente il fastidio. Fai rotolare il bilanciere finché non si trova direttamente sopra i fianchi, quindi sdraiati sulla schiena. Inizia il movimento spingendo attraverso i talloni ed estendendo i fianchi verticalmente, sollevando il bilanciere. Il peso deve essere sostenuto dalla parte alta della schiena e dai talloni. Estendi il più possibile, quindi inverti il movimento per tornare alla posizione di partenza.' 
WHERE name = 'Barbell Glute Bridge';

UPDATE public.exercise_library 
SET name_it = 'Barbell Guillotine Bench Press', description_it = 'Utilizzando una presa di larghezza media (che crei un angolo di 90 gradi tra avambracci e braccia a metà movimento), solleva il bilanciere dal rack e tienilo dritto sopra il collo con le braccia distese. Questa è la posizione di partenza. Inspirando, porta il bilanciere lentamente verso il basso fino a circa 2-3 cm dal collo. Dopo un secondo di pausa, riporta il bilanciere alla posizione di partenza espirando e spingendo con i muscoli pettorali. Distendi le braccia e contrai i pettorali nella posizione di massima chiusura, mantieni per un secondo e poi inizia a scendere di nuovo lentamente. La fase di discesa dovrebbe richiedere almeno il doppio del tempo rispetto alla fase di risalita. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi il bilanciere nel rack.' 
WHERE name = 'Barbell Guillotine Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Barbell Hack Squat', description_it = 'Stai in piedi con la schiena dritta tenendo un bilanciere dietro di te a braccia tese e i piedi alla larghezza delle spalle. Suggerimento: una presa larga quanto le spalle è l''ideale, con i palmi rivolti all''indietro. Puoi usare dei ganci o fasce per i polsi per una presa migliore. Questa è la tua posizione di partenza. Mantenendo la testa alta, lo sguardo in avanti e la schiena dritta, scendi in squat finché le cosce non sono parallele al pavimento. Inspira mentre scendi lentamente. Spingendo principalmente sui talloni e contraendo le cosce, torna verso l''alto espirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Hack Squat';

UPDATE public.exercise_library 
SET name_it = 'Barbell Hip Thrust', description_it = 'Siediti a terra con una panca posizionata direttamente dietro di te. Posiziona un bilanciere carico sopra le gambe. L''utilizzo di un bilanciere olimpionico spesso o di un cuscinetto protettivo può ridurre notevolmente il fastidio causato dall''esercizio. Fai rotolare il bilanciere finché non è posizionato sopra le anche e appoggiati con la schiena alla panca, in modo che le scapole siano vicino al bordo superiore. Inizia il movimento spingendo attraverso i piedi ed estendendo le anche verticalmente, sollevando il bilanciere. Il peso deve essere sostenuto dalle scapole e dai piedi. Estendi il più possibile, quindi inverte il movimento per tornare alla posizione di partenza.' 
WHERE name = 'Barbell Hip Thrust';

UPDATE public.exercise_library 
SET name_it = 'Barbell Incline Bench Press - Presa Media', description_it = 'Sdraiati su una panca inclinata. Utilizzando una presa di larghezza media (tale da creare un angolo di 90 gradi tra avambracci e braccia a metà movimento), stacca il bilanciere dal rack e tienilo sopra di te con le braccia tese. Questa è la tua posizione di partenza. Inspirando, scendi lentamente finché il bilanciere non sfiora la parte alta del petto. Dopo una pausa di un secondo, riporta il bilanciere nella posizione iniziale espirando e spingendo con i muscoli pettorali. Blocca le braccia nella posizione contratta, contrai il petto, mantieni per un secondo e ricomincia a scendere lentamente. Suggerimento: la fase di discesa dovrebbe durare almeno il doppio di quella di salita. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi il bilanciere nel rack.' 
WHERE name = 'Barbell Incline Bench Press - Medium Grip';

UPDATE public.exercise_library 
SET name_it = 'Barbell Incline Shoulder Raise', description_it = 'Sdraiati su una panca inclinata. Con una presa media (leggermente più larga delle spalle), solleva il bilanciere dal rack e tienilo dritto sopra di te con le braccia tese. Questa è la tua posizione di partenza. Mantenendo le braccia tese, solleva il bilanciere protraendo le scapole e staccando le spalle dalla panca mentre espiri. Torna alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Incline Shoulder Raise';

UPDATE public.exercise_library 
SET name_it = 'Affondi con Bilanciere', description_it = 'Per sicurezza, esegui questo esercizio all''interno di un rack. Posiziona il bilanciere sul rack appena sotto l''altezza delle spalle. Una volta caricato il bilanciere, posizionati sotto di esso e appoggia la parte posteriore delle spalle (appena sotto il collo) sulla barra. Afferra il bilanciere con entrambe le mani ai lati e sollevalo dal rack spingendo con le gambe e raddrizzando il busto. Allontanati dal rack, fai un passo in avanti con la gamba destra e scendi in affondo mantenendo il busto eretto e in equilibrio. Inspira mentre scendi. Nota: non permettere al ginocchio di superare la punta del piede per evitare stress eccessivo all''articolazione. Spingendo principalmente sul tallone, torna alla posizione iniziale espirando. Ripeti per il numero di ripetizioni raccomandato e poi cambia gamba.' 
WHERE name = 'Barbell Lunge';

UPDATE public.exercise_library 
SET name_it = 'Barbell Rear Delt Row', description_it = 'In piedi, tieni un bilanciere con una presa larga (più delle spalle) e prona (palmi rivolti verso il corpo). Piega leggermente le ginocchia e inclinati in avanti mantenendo la curvatura naturale della schiena. Lascia che le braccia pendano davanti a te tenendo il bilanciere. Quando il busto è parallelo al pavimento, divarica i gomiti verso l''esterno. Suggerimento: il tuo busto e le braccia dovrebbero formare una lettera "T". Ora sei pronto a iniziare. Mantenendo la parte superiore delle braccia perpendicolare al busto, tira il bilanciere verso la parte alta del petto contraendo i deltoidi posteriori ed espirando. Suggerimento: se eseguito correttamente, questo esercizio dovrebbe somigliare a una panca piana al contrario. Evita di usare i bicipiti; le braccia devono agire solo come ganci. Torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Rear Delt Row';

UPDATE public.exercise_library 
SET name_it = 'Barbell Rollout dalla Panca', description_it = 'Posiziona un bilanciere carico a terra vicino all''estremità di una panca. Inginocchiati sulla panca e afferra il bilanciere con una presa da media a stretta. Questa è la tua posizione di partenza. Inizia estendendo le anche per far rotolare lentamente il bilanciere in avanti. Mentre ti allunghi, fletti le spalle per portare il bilanciere sopra la testa. Assicurati che le braccia rimangano tese durante tutto il movimento. Quando il bilanciere è arrivato il più lontano possibile, torna alla posizione di partenza.' 
WHERE name = 'Barbell Rollout from Bench';

UPDATE public.exercise_library 
SET name_it = 'Calf Raise Seduto con Bilanciere', description_it = 'Posiziona un blocco o uno step a circa 30 cm davanti a una panca piana. Siediti sulla panca e appoggia l''avampiede sul blocco. Chiedi a qualcuno di posizionare un bilanciere sopra le cosce, circa 7-8 cm sopra le ginocchia. Questa è la tua posizione di partenza. Sollevati sulle punte dei piedi il più in alto possibile contraendo i polpacci ed espirando. Dopo un secondo di contrazione, torna lentamente alla posizione iniziale. Suggerimento: per il massimo beneficio, stendi i polpacci il più possibile. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Seated Calf Raise';

UPDATE public.exercise_library 
SET name_it = 'Military Press (Shoulder Press) con Bilanciere', description_it = 'Siediti su una panca con schienale all''interno di un rack. Posiziona il bilanciere a un''altezza appena sopra la testa. Afferra il bilanciere con una presa prona (palmi rivolti in avanti). Una volta sollevato il bilanciere, portalo sopra la testa bloccando le braccia. Mantieni la posizione all''altezza delle spalle, leggermente davanti al capo. Questa è la tua posizione di partenza. Abbassa il bilanciere fino alle spalle lentamente mentre inspiri. Riporta il bilanciere alla posizione di partenza espirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Shrug con Bilanciere', description_it = 'In piedi, piedi alla larghezza delle spalle, tieni un bilanciere davanti a te con una presa prona (palmi rivolti verso le cosce). Suggerimento: le mani dovrebbero essere leggermente più larghe delle spalle. Puoi usare ganci o fasce per una presa migliore. Questa è la tua posizione di partenza. Solleva le spalle il più in alto possibile espirando e mantieni la contrazione per un secondo. Suggerimento: non cercare di sollevare il bilanciere usando i bicipiti. Torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Barbell Shrug';

UPDATE public.exercise_library 
SET name_it = 'Scrollate con bilanciere dietro la schiena', description_it = 'Stai in piedi con i piedi alla larghezza delle spalle e impugna un bilanciere dietro la schiena con una presa prona (palmi rivolti all''indietro). Consiglio: tieni le mani leggermente più larghe rispetto alla larghezza delle spalle. Puoi usare le fasce per i polsi per una presa migliore. Questa è la posizione di partenza. Solleva le spalle il più in alto possibile espirando e mantieni la contrazione per un secondo. Consiglio: evita di sollevare il bilanciere usando i bicipiti. Le braccia devono rimanere sempre tese. Torna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Barbell Shrug Behind The Back';

UPDATE public.exercise_library 
SET name_it = 'Flessioni laterali con bilanciere', description_it = 'Stai in piedi con un bilanciere posizionato sulla parte alta della schiena (leggermente sotto il collo). I piedi devono essere alla larghezza delle spalle. Questa è la posizione di partenza. Mantenendo la schiena dritta e la testa alta, fletti il busto lateralmente solo verso destra il più possibile. Inspira mentre ti fletti. Mantieni la posizione per un secondo e torna alla posizione eretta espirando. Consiglio: mantieni il resto del corpo immobile. Ripeti il movimento flettendoti verso sinistra. Mantieni per un secondo e torna alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Barbell Side Bend';

UPDATE public.exercise_library 
SET name_it = 'Side Split Squat con bilanciere', description_it = 'Stai in piedi con un bilanciere posizionato sulla parte alta della schiena (leggermente sotto il collo). Posiziona i piedi ben distanti tra loro, con il piede della gamba guida rivolto verso l''esterno. Questa è la posizione di partenza. Abbassa il corpo verso il lato del piede angolato flettendo il ginocchio e l''anca della gamba guida, mantenendo l''altra gamba solo leggermente piegata. Inspira durante la discesa. Torna alla posizione di partenza estendendo l''anca e il ginocchio della gamba guida. Espira durante questo movimento. Dopo aver eseguito il numero di ripetizioni consigliato, ripeti con l''altra gamba.' 
WHERE name = 'Barbell Side Split Squat';

UPDATE public.exercise_library 
SET name_it = 'Squat con bilanciere', description_it = 'Per motivi di sicurezza, questo esercizio va eseguito all''interno di un rack. Imposta il bilanciere sul rack appena sotto l''altezza delle spalle. Posizionati sotto la sbarra e appoggiala sulla parte alta della schiena (leggermente sotto il collo). Impugna il bilanciere con entrambe le mani e sollevalo dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto. Allontanati dal rack e posiziona i piedi alla larghezza delle spalle con le punte leggermente rivolte verso l''esterno. Mantieni la testa alta e la schiena dritta. Questa è la posizione di partenza. Inizia ad abbassare lentamente il bilanciere flettendo ginocchia e anche, mantenendo la postura eretta. Scendi finché l''angolo tra cosce e polpacci è leggermente inferiore a 90 gradi. Inspira durante la discesa. Consiglio: se eseguito correttamente, le ginocchia non devono superare la punta dei piedi per evitare stress articolare. Risali espirando, spingendo con i talloni e tornando alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Barbell Squat';

UPDATE public.exercise_library 
SET name_it = 'Squat con bilanciere su panca', description_it = 'Esercizio da eseguire all''interno di un rack. Posiziona una panca piana dietro di te per imparare a spingere le anche indietro e raggiungere la profondità corretta. Imposta il bilanciere all''altezza delle spalle, posizionati sotto la sbarra e appoggiala sulla parte alta della schiena. Solleva il bilanciere dal rack, allontanati e posiziona i piedi alla larghezza delle spalle. Mantieni la testa alta e la schiena dritta. Inizia a scendere flettendo ginocchia e portando le anche indietro, finché i glutei non toccano leggermente la panca. Inspira durante la discesa. Consiglio: le ginocchia non devono superare la linea immaginaria perpendicolare alla punta dei piedi. Risali espirando, spingendo sui talloni e distendendo le anche fino alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Barbell Squat To A Bench';

UPDATE public.exercise_library 
SET name_it = 'Step-up con bilanciere', description_it = 'Stai in piedi con un bilanciere posizionato sulla parte alta della schiena e posizionati davanti a una piattaforma rialzata. Questa è la posizione di partenza. Appoggia il piede destro sulla piattaforma. Sali sulla piattaforma estendendo l''anca e il ginocchio della gamba destra. Usa principalmente il tallone per sollevare il corpo e appoggia anche il piede sinistro sulla piattaforma. Espira durante lo sforzo. Scendi con il piede sinistro flettendo anca e ginocchio della gamba destra mentre inspiri. Torna nella posizione di partenza iniziale. Ripeti con la gamba destra per le ripetizioni consigliate, poi passa alla sinistra.' 
WHERE name = 'Barbell Step Ups';

UPDATE public.exercise_library 
SET name_it = 'Affondi in camminata con bilanciere', description_it = 'Inizia in piedi con i piedi alla larghezza delle spalle e un bilanciere sulla parte alta della schiena. Fai un passo avanti con una gamba, flettendo le ginocchia per abbassare il bacino. Scendi finché il ginocchio posteriore tocca quasi terra. Mantieni il busto eretto e il ginocchio anteriore allineato sopra il piede corrispondente. Spingi attraverso il tallone del piede avanzato ed estendi entrambe le ginocchia per risalire. Fai un passo in avanti con la gamba posteriore, ripetendo l''affondo con l''altra gamba.' 
WHERE name = 'Barbell Walking Lunge';

UPDATE public.exercise_library 
SET name_it = 'Battling Ropes', description_it = 'Per questo esercizio avrai bisogno di una corda pesante ancorata al centro a circa 4-6 metri di distanza. In piedi davanti alla corda, afferra un''estremità in ogni mano con le braccia distese lungo i fianchi. Questa è la posizione di partenza. Inizia il movimento sollevando rapidamente un braccio fino all''altezza della spalla. Mentre lasci scendere quel braccio, solleva l''altro. Continua ad alternare braccio destro e sinistro, facendo ondeggiare le corde più velocemente possibile.' 
WHERE name = 'Battling Ropes';

UPDATE public.exercise_library 
SET name_it = 'Bear Crawl con traino della slitta', description_it = 'Indossando un''imbracatura o una cintura da sovraccarico, collega la catena al retro in modo da essere rivolto lontano dalla slitta. Piegati in avanti con le mani a terra. La schiena deve essere piatta e le ginocchia flesse. Questa è la posizione di partenza. Inizia a spingere con le gambe, alternando sinistra e destra. Usa le mani per mantenere l''equilibrio e aiutarti nella trazione. Cerca di mantenere la schiena piatta mentre percorri la distanza stabilita.' 
WHERE name = 'Bear Crawl Sled Drags';

UPDATE public.exercise_library 
SET name_it = 'Stretching pettorali dietro la nuca', description_it = 'Siediti dritto a terra con un partner dietro di te. Posiziona le mani dietro la nuca e spingi i gomiti indietro il più possibile. Il partner dovrà bloccare i tuoi gomiti. Questa è la posizione di partenza. Prova delicatamente a tirare i gomiti in avanti mantenendo le mani dietro la nuca per almeno 10 secondi, mentre il partner impedisce il movimento. Successivamente, rilassa i muscoli e lascia che il partner tiri delicatamente i gomiti all''indietro fin dove è confortevole per te. Comunica al partner quando lo stretching è sufficiente per evitare infortuni o eccessiva tensione.' 
WHERE name = 'Behind Head Chest Stretch';

UPDATE public.exercise_library 
SET name_it = 'Alzate posteriori con manubri a busto flesso con testa su panca', description_it = 'In piedi, tieni un manubrio in ogni mano con una panca inclinata davanti a te. Mantenendo la schiena dritta e la sua curvatura naturale, piegati in avanti finché la fronte non tocca la panca. Lascia le braccia a penzoloni, perpendicolari al suolo, con i palmi rivolti l''uno verso l''altro e il busto parallelo al pavimento. Questa è la posizione di partenza. Mantenendo il busto fermo e le braccia tese con un leggero gomito flesso, solleva i manubri lateralmente finché le braccia non sono parallele al pavimento. Espira durante il sollevamento. Attenzione: evita di oscillare il busto o di portare le braccia all''indietro invece che lateralmente. Dopo un secondo di contrazione in alto, abbassa lentamente i manubri fino alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Bent Over Dumbbell Rear Delt Raise With Head On Bench';

UPDATE public.exercise_library 
SET name_it = 'Alzate laterali a busto flesso ai cavi bassi', description_it = 'Seleziona un carico e afferra la maniglia della carrucola bassa con la mano destra. Piegati in vita finché il busto non è quasi parallelo al pavimento. Le gambe devono essere leggermente flesse e la mano sinistra appoggiata sulla coscia sinistra. Il braccio destro deve pendere dalla spalla davanti a te con un leggero gomito flesso. Questa è la posizione di partenza. Solleva il braccio destro, mantenendo il gomito leggermente flesso, lateralmente finché non è parallelo al pavimento e in linea con l''orecchio destro. Espira durante il movimento. Abbassa lentamente il peso alla posizione iniziale mentre inspiri. Ripeti per il numero di ripetizioni raccomandato, poi cambia braccio.' 
WHERE name = 'Bent Over Low-Pulley Side Lateral';

UPDATE public.exercise_library 
SET name_it = 'Rematore con bilanciere a un braccio (Landmine Row)', description_it = 'Carica un''estremità di un bilanciere olimpico. Assicurati che l''altra estremità sia bloccata in un angolo o contro un oggetto pesante affinché non scivoli. Piegati in avanti mantenendo il busto il più possibile parallelo al pavimento e le ginocchia leggermente flesse. Afferra il bilanciere con un braccio subito dietro i dischi e appoggia l''altra mano sul ginocchio. Questa è la posizione di partenza. Tira il bilanciere verso l''alto tenendo il gomito vicino al corpo (per massimizzare lo stimolo dorsale) finché i dischi non toccano la parte bassa del petto. Contrai i muscoli della schiena e tieni la posizione per un secondo in alto. Espira durante il sollevamento. Consiglio: non oscillare il busto; solo il braccio deve muoversi. Abbassa lentamente il bilanciere senza far toccare i dischi a terra. Per un miglior range di movimento, usa dischi piccoli (da 10-15 kg). Ripeti per le ripetizioni previste e cambia braccio.' 
WHERE name = 'Bent Over One-Arm Long Bar Row';

UPDATE public.exercise_library 
SET name_it = 'Rematore con bilanciere a due braccia (Landmine Row)', description_it = 'Carica un''estremità di un bilanciere olimpico fissato a terra. Piegati in avanti tenendo il busto parallelo al pavimento e le ginocchia leggermente flesse. Afferra il bilanciere con entrambe le mani subito dietro i dischi. Questa è la posizione di partenza. Tira il bilanciere verso l''alto tenendo i gomiti vicini al corpo finché i dischi non toccano la parte bassa del petto. Contrai i muscoli della schiena e tieni per un secondo in alto. Espira durante il sollevamento. Consiglio: usa una maniglia a V o un accessorio a doppia presa agganciato sotto l''estremità del bilanciere. Abbassa lentamente il bilanciere senza far toccare i dischi a terra. Usa dischi piccoli per un range di movimento ottimale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Bent Over Two-Arm Long Bar Row';

UPDATE public.exercise_library 
SET name_it = 'Rematore con manubri a busto flesso', description_it = 'Con un manubrio per mano (palmi rivolti verso il busto), fletti leggermente le ginocchia e piegati in vita mantenendo la schiena dritta fino a portarla quasi parallela al pavimento. Consiglio: tieni la testa alta. I pesi devono pendere direttamente sotto le tue spalle. Questa è la posizione di partenza. Mantenendo il busto fermo, solleva i manubri lateralmente (espirando), tenendo i gomiti vicini al corpo (non usare la forza degli avambracci). In alto, contrai i dorsali per un secondo. Abbassa lentamente il peso alla posizione iniziale mentre inspiri. Ripeti per le ripetizioni previste.' 
WHERE name = 'Bent Over Two-Dumbbell Row';

UPDATE public.exercise_library 
SET name_it = 'Rematore con manubri a presa neutra', description_it = 'Con un manubrio per mano (palmi rivolti l''uno verso l''altro), piega leggermente le ginocchia e fletti il busto in avanti mantenendo la schiena dritta, quasi parallela al pavimento. Consiglio: tieni la testa alta. I pesi devono pendere perpendicolari al pavimento. Questa è la posizione di partenza. Mantenendo il busto fermo, solleva i manubri lateralmente espirando e avvicinando le scapole. Nel punto di massima contrazione, contrai i muscoli della schiena e tieni per un secondo. Abbassa lentamente il peso alla posizione iniziale mentre inspiri. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Bent Over Two-Dumbbell Row With Palms In';

UPDATE public.exercise_library 
SET name_it = 'Bent Press', description_it = 'Porta il kettlebell alla spalla (Clean) estendendo gambe e anche, ruotando il polso durante il movimento. Questa è la posizione di partenza. Inizia a piegarti lateralmente sul lato opposto al kettlebell, continuando finché non riesci a toccare terra con la mano libera, tenendo gli occhi fissi sul kettlebell. Contemporaneamente, spingi il peso verticalmente estendendo il gomito e mantenendo il braccio perpendicolare al suolo. Torna in posizione eretta con il kettlebell sopra la testa. Riporta il kettlebell alla spalla e ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Bent Press';

UPDATE public.exercise_library 
SET name_it = 'Ciclismo', description_it = 'Per iniziare, siediti sulla bicicletta e regola il sellino in base alla tua altezza.' 
WHERE name = 'Bicycling';

UPDATE public.exercise_library 
SET name_it = 'Cylette (Bici stazionaria)', description_it = 'Per iniziare, siediti sulla bici e regola il sellino in base alla tua altezza. Seleziona l''opzione desiderata dal menu. Potrebbe essere necessario iniziare a pedalare per accendere il display. Puoi usare l''impostazione manuale o selezionare un programma. Solitamente, inserendo età e peso, la bici stima le calorie bruciate. Il livello di resistenza può essere variato durante l''allenamento. Le maniglie possono essere usate per monitorare la frequenza cardiaca per mantenere l''intensità adeguata.' 
WHERE name = 'Bicycling, Stationary';

UPDATE public.exercise_library 
SET name_it = 'Board Press', description_it = 'Sdraiati su una panca piana, posizionando la testa oltre il bilanciere se possibile. Si possono usare da uno a cinque blocchi di legno (sovrapposti), tenuti in posizione da un compagno, fasce elastiche o infilati sotto la maglietta. Tieni i piedi ben puntati e inarca la schiena. Solleva le spalle dalla panca contraendo le scapole e usa i piedi per spingere i trapezi contro la panca. Mantieni questa posizione compatta per tutto il movimento. Puoi usare una presa standard o una presa larghezza spalle per concentrarti sui tricipiti. Estrai il bilanciere dal rack senza protrarre le spalle. Bilanciere, polsi e gomiti devono rimanere sempre allineati. Concentrati sulla contrazione del bilanciere. Abbassa il bilanciere fino a toccare le tavolette, poi spingilo verso l''alto con la massima forza possibile. I gomiti devono rimanere vicini al corpo fino alla completa estensione.' 
WHERE name = 'Board Press';

UPDATE public.exercise_library 
SET name_it = 'Body-Up', description_it = 'Assumi una posizione di plank a terra. Sostieni il peso del corpo sulle punte dei piedi e sugli avambracci, mantenendo il busto dritto. Gli avambracci devono essere distanziati alla larghezza delle spalle. Questa è la posizione di partenza. Premendo saldamente i palmi delle mani a terra, distendi i gomiti per sollevare il corpo da terra. Mantieni il busto rigido durante l''esecuzione del movimento. Abbassa lentamente gli avambracci verso il pavimento flettendo i gomiti. Ripeti.' 
WHERE name = 'Body-Up';

UPDATE public.exercise_library 
SET name_it = 'Body Tricep Press', description_it = 'Posiziona un bilanciere su un rack all''altezza del petto. In posizione eretta, impugna il bilanciere alla larghezza delle spalle e fai un passo o due all''indietro, con i piedi uniti e le braccia distese, in modo da appoggiarti al bilanciere. Questa è la posizione di partenza. Inizia flettendo i gomiti, abbassandoti verso il bilanciere. Fai una pausa, quindi inverti il movimento estendendo i gomiti. Puoi aumentare la difficoltà aggiungendo delle catene sulle spalle.' 
WHERE name = 'Body Tricep Press';

UPDATE public.exercise_library 
SET name_it = 'Bodyweight Flyes', description_it = 'Posiziona due bilancieri EZ caricati in modo uguale a terra, uno accanto all''altro, assicurandoti che possano rotolare. Assumi una posizione di piegamento (push-up) sopra i bilancieri, sostenendo il peso sulle punte dei piedi e sulle mani, con braccia tese e corpo dritto. Appoggia le mani sui bilancieri. Questa è la posizione di partenza. Con un movimento lento e controllato, allontana le mani dalla linea mediana del corpo, facendo rotolare i bilancieri verso l''esterno. Inspira durante questa fase. Dopo aver allontanato i bilancieri il più possibile, torna alla posizione iniziale avvicinandoli nuovamente. Espira durante questo movimento.' 
WHERE name = 'Bodyweight Flyes';

UPDATE public.exercise_library 
SET name_it = 'Bodyweight Mid Row', description_it = 'Inizia con un''impugnatura da media a larga su una sbarra per trazioni, con i palmi rivolti lontano da te. Dalla posizione appesa, porta le ginocchia al petto, inclinati all''indietro e fai passare le gambe oltre la sbarra. Questa è la posizione di partenza. Partendo con le braccia tese, fletti i gomiti e contrai le scapole per sollevare il corpo finché le gambe non toccano la sbarra. Dopo una breve pausa, torna alla posizione iniziale.' 
WHERE name = 'Bodyweight Mid Row';

UPDATE public.exercise_library 
SET name_it = 'Bodyweight Squat', description_it = 'In piedi, con i piedi alla larghezza delle spalle. Puoi posizionare le mani dietro la testa. Questa è la posizione di partenza. Inizia il movimento flettendo ginocchia e anche, spingendo il bacino all''indietro. Continua a scendere fino alla massima profondità possibile e inverti rapidamente il movimento fino a tornare alla posizione iniziale. Mentre esegui lo squat, tieni la testa e il petto alti e spingi le ginocchia verso l''esterno.' 
WHERE name = 'Bodyweight Squat';

UPDATE public.exercise_library 
SET name_it = 'Bodyweight Walking Lunge', description_it = 'Parti in piedi con i piedi alla larghezza delle spalle e le mani sui fianchi. Fai un passo in avanti con una gamba, flettendo le ginocchia per abbassare il bacino. Scendi finché il ginocchio posteriore quasi tocca terra. La postura deve rimanere eretta e il ginocchio anteriore deve rimanere allineato sopra il piede. Spingi attraverso il tallone del piede anteriore ed estendi entrambe le ginocchia per risalire. Fai un passo in avanti con il piede posteriore e ripeti l''affondo con l''altra gamba.' 
WHERE name = 'Bodyweight Walking Lunge';

UPDATE public.exercise_library 
SET name_it = 'Bosu Ball Cable Crunch With Side Bends', description_it = 'Collega una maniglia standard a ciascun cavo della macchina, posizionandoli nel punto più basso. Posiziona una Bosu Ball davanti al centro della macchina. Sdraiati sulla Bosu Ball con la parte bassa della schiena arcuata sulla sfera. I glutei devono essere vicini al pavimento senza toccarlo. Con entrambe le mani, afferra le maniglie dei cavi. Con i piedi in una posizione ampia, stendi le braccia dritte davanti a te, tra le ginocchia. Le mani devono essere all''altezza delle ginocchia. Mantieni le braccia tese e allineate con l''angolo del cavo. Solleva il busto con un movimento di crunch senza piegare le braccia. Mantieni le braccia rigide. Scendi lentamente alla posizione iniziale con la schiena arcuata sulla Bosu Ball e gli addominali allungati. Ripeti fino al cedimento. Al cedimento, tieni gli addominali contratti e solleva il busto in posizione di plank, staccando la schiena dalla Bosu Ball. Abbassa le braccia lungo i fianchi, tenendole tese. Inizia a eseguire delle flessioni laterali alternate; cerca di toccare i talloni! Questo movimento finale si concentrerà sugli obliqui.' 
WHERE name = 'Bosu Ball Cable Crunch With Side Bends';

UPDATE public.exercise_library 
SET name_it = 'Bottoms-Up Clean From The Hang Position', description_it = 'Inizia l''esercizio in posizione eretta con una kettlebell in una mano. Fai oscillare la kettlebell all''indietro con forza e poi inverti il movimento con decisione. Stringi il manico della kettlebell il più forte possibile e porta la kettlebell alla spalla mantenendola capovolta.' 
WHERE name = 'Bottoms-Up Clean From The Hang Position';

UPDATE public.exercise_library 
SET name_it = 'Bottoms Up', description_it = 'Sdraiati a terra sulla schiena. Le gambe devono essere tese e le braccia lungo i fianchi. Questa è la posizione di partenza. Per eseguire il movimento, porta le ginocchia verso il petto flettendo anche e ginocchia. Successivamente, stendi le gambe direttamente sopra di te in modo che siano perpendicolari al suolo. Ruota ed eleva il bacino per sollevare i glutei da terra. Dopo una breve pausa, torna alla posizione iniziale.' 
WHERE name = 'Bottoms Up';

UPDATE public.exercise_library 
SET name_it = 'Box Jump (Multiple Response)', description_it = 'Assumi una posizione rilassata di fronte a una scatola o una piattaforma, a circa un braccio di distanza. Le braccia devono essere lungo i fianchi e le gambe leggermente flesse. Usando le braccia per favorire la spinta iniziale, salta verso l''alto e in avanti, atterrando con entrambi i piedi contemporaneamente sopra la scatola o la piattaforma. Scendi o salta immediatamente all''indietro tornando al punto di partenza originale; quindi ripeti la sequenza.' 
WHERE name = 'Box Jump (Multiple Response)';

UPDATE public.exercise_library 
SET name_it = 'Box Skip', description_it = 'Avrai bisogno di diversi box allineati a circa 2,5 metri di distanza l''uno dall''altro. Inizia di fronte al primo box con una gamba leggermente dietro l''altra. Spingi con la gamba posteriore, cercando di ottenere la massima altezza possibile con i fianchi. Non appena atterri sul box, spingi l''altra gamba in avanti e verso l''alto per guadagnare altezza e distanza, saltando via dal box. Atterra tra i primi due box con la stessa gamba che è atterrata sul primo box. Successivamente, spostati al box successivo e ripeti.' 
WHERE name = 'Box Skip';

UPDATE public.exercise_library 
SET name_it = 'Box Squat', description_it = 'Il box squat permette di eseguire lo squat alla profondità desiderata e di sviluppare forza esplosiva nel movimento. Inizia in un power rack con un box dell''altezza appropriata dietro di te. In genere, l''obiettivo è un''altezza che porti a uno squat parallelo, ma è possibile allenarsi più in alto o più in basso se desiderato. Posizionati sotto il bilanciere e appoggialo sulla parte alta della schiena. Avvicina le scapole e ruota i gomiti in avanti, cercando di flettere il bilanciere sulle spalle. Stacca il bilanciere, crea un leggero arco lombare e fai un passo indietro per posizionarti. Posiziona i piedi più larghi per enfatizzare schiena, glutei, adduttori e femorali, o più stretti per uno sviluppo maggiore dei quadricipiti. Mantieni la testa rivolta in avanti. Con schiena, spalle e core contratti, spingi ginocchia e sedere verso l''esterno e inizia la discesa. Siediti all''indietro con i fianchi finché non sei seduto sul box. Idealmente, le tibie dovrebbero essere perpendicolari al suolo. Fai una pausa sul box e rilassa i flessori dell''anca. Non rimbalzare mai sul box. Mantenendo il peso sui talloni e spingendo piedi e ginocchia verso l''esterno, spingi verso l''alto partendo dal box, guidando il movimento con la testa. Continua la risalita mantenendo tutto il corpo in tensione.' 
WHERE name = 'Box Squat';

UPDATE public.exercise_library 
SET name_it = 'Box Squat con elastici (Bands)', description_it = 'Inizia in un power rack con un box di altezza appropriata dietro di te. Monta gli elastici sulle estremità del bilanciere, fissandoli a pioli, al rack o a manubri in modo che vi sia la tensione adeguata. Se utilizzi dei manubri, assicurati che siano fissati saldamente e che siano abbastanza pesanti da gestire la tensione degli elastici; in caso, usa dei dischi aggiuntivi per tenerli fermi. Se serve più tensione, puoi allargare la base a terra o avvolgere ulteriormente gli elastici. Segui le indicazioni tecniche del Box Squat tradizionale per la posizione e l''esecuzione. Fai attenzione nel riporre il bilanciere sul rack.' 
WHERE name = 'Box Squat with Bands';

UPDATE public.exercise_library 
SET name_it = 'Box Squat con catene (Chains)', description_it = 'Inizia in un power rack con un box di altezza appropriata dietro di te. Per preparare le catene, fai passare la catena guida sulle estremità del bilanciere. La catena pesante deve essere agganciata con un moschettone. Regola la lunghezza della catena guida in modo che alcune maglie tocchino ancora il suolo nella parte superiore del movimento. Segui le indicazioni tecniche del Box Squat tradizionale per la posizione e l''esecuzione, beneficiando della resistenza variabile fornita dalle catene.' 
WHERE name = 'Box Squat with Chains';

UPDATE public.exercise_library 
SET name_it = 'Brachialis-SMR', description_it = 'Sdraiati su un fianco con la parte superiore del braccio contro il foam roller. Il braccio dovrebbe essere più o meno allineato con il corpo, con la parte esterna del bicipite premuta contro il rullo. Solleva i fianchi da terra, sostenendo il peso sul braccio e sui piedi. Mantieni la posizione per 10-30 secondi, poi cambia lato.' 
WHERE name = 'Brachialis-SMR';

UPDATE public.exercise_library 
SET name_it = 'Bradford/Rocky Press', description_it = 'Siediti su una panca per Military Press con il bilanciere all''altezza delle spalle e una presa prona (palmi rivolti in avanti). Consiglio: la presa dovrebbe essere più larga delle spalle e formare un angolo di 90 gradi tra avambraccio e braccio mentre il bilanciere scende. Questa è la posizione iniziale. Solleva il bilanciere sopra la testa bloccando le braccia. Abbassa lentamente il bilanciere dietro la nuca espirando. Solleva nuovamente il bilanciere nella posizione iniziale espirando, quindi abbassalo davanti fino alla posizione di partenza inspirando. Questa è una ripetizione. Alterna in questo modo fino al completamento delle ripetizioni raccomandate.' 
WHERE name = 'Bradford/Rocky Presses';

UPDATE public.exercise_library 
SET name_it = 'Butt-Ups', description_it = 'Inizia in posizione di push-up ma con i gomiti a terra e appoggiato sugli avambracci. Le braccia devono essere piegate a 90 gradi. Inarca leggermente la schiena anziché mantenerla completamente dritta. Solleva i glutei verso il soffitto, contraendo intensamente gli addominali per ridurre la distanza tra cassa toracica e fianchi. Il risultato finale sarà una posizione a ponte alto. Espira durante questa fase del movimento. Torna lentamente alla posizione iniziale inspirando. Consiglio: non lasciare che la schiena si inarchi verso il basso. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Butt-Ups';

UPDATE public.exercise_library 
SET name_it = 'Butt Lift (Ponte)', description_it = 'Sdraiati sulla schiena con le mani lungo i fianchi e le ginocchia piegate. I piedi devono essere posizionati a circa la larghezza delle spalle. Questa è la posizione iniziale. Spingendo principalmente sui talloni, solleva i fianchi da terra mantenendo la schiena dritta. Espira durante questa fase e mantieni la contrazione in alto per un secondo. Torna lentamente alla posizione iniziale inspirando.' 
WHERE name = 'Butt Lift (Bridge)';

UPDATE public.exercise_library 
SET name_it = 'Butterfly', description_it = 'Siediti sulla macchina con la schiena ben aderente allo schienale. Afferra le maniglie. Consiglio: le braccia dovrebbero essere parallele al pavimento; regola la macchina di conseguenza. Questa è la posizione iniziale. Spingi le maniglie l''una verso l''altra lentamente mentre contrai i pettorali al centro. Espira durante questa fase e mantieni la contrazione per un secondo. Torna lentamente alla posizione iniziale inspirando, finché i muscoli pettorali non sono completamente allungati. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Butterfly';

UPDATE public.exercise_library 
SET name_it = 'Cable Chest Press', description_it = 'Regola il peso a un livello appropriato, siediti e afferra le maniglie. Le braccia dovrebbero formare un angolo di circa 45 gradi rispetto al corpo, con testa e petto alti. I gomiti dovrebbero essere piegati a circa 90 gradi. Questa è la posizione iniziale. Estendi i gomiti spingendo le maniglie in avanti. Mantieni le scapole retratte durante l''esecuzione. Dopo una breve pausa in estensione completa, torna alla posizione iniziale mantenendo la tensione sui cavi. Puoi eseguire questo movimento anche con la schiena staccata dallo schienale, su panca inclinata o declinata, o alternando le braccia.' 
WHERE name = 'Cable Chest Press';

UPDATE public.exercise_library 
SET name_it = 'Cable Crossover', description_it = 'Per la posizione di partenza, posiziona le carrucole in alto (sopra la testa), seleziona la resistenza desiderata e impugna le maniglie. Fai un passo in avanti rispetto alla linea immaginaria tra le due carrucole, portando le braccia davanti a te. Il busto deve essere leggermente inclinato in avanti partendo dai fianchi. Con i gomiti leggermente flessi per evitare stress al tendine del bicipite, estendi le braccia lateralmente seguendo un arco ampio finché non senti un allungamento nel petto. Inspira durante questa fase. Suggerimento: mantieni braccia e busto fermi durante il movimento; l''azione deve avvenire solo a livello dell''articolazione della spalla. Torna alla posizione iniziale espirando, seguendo lo stesso arco di movimento. Mantieni la posizione per un secondo e ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Cable Crossover';

UPDATE public.exercise_library 
SET name_it = 'Cable Crunch', description_it = 'Inginocchiati sotto una carrucola alta dotata di corda. Impugna la corda e abbassala finché le mani non si trovano vicino al viso. Fletti leggermente i fianchi e lascia che il peso iper-estenda la parte bassa della schiena: questa è la posizione di partenza. Mantenendo i fianchi fermi, fletti il busto contraendo gli addominali in modo che i gomiti si muovano verso la metà delle cosce. Espira durante questa fase e mantieni la contrazione per un secondo. Torna lentamente alla posizione iniziale inspirando. Suggerimento: mantieni una tensione costante sugli addominali. Non scegliere un peso eccessivo che costringa la parte bassa della schiena a compiere lo sforzo principale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Cable Crunch';

UPDATE public.exercise_library 
SET name_it = 'Cable Deadlifts', description_it = 'Posiziona i cavi nella parte inferiore delle torri e seleziona un peso adeguato. Posizionati esattamente tra le torri. Per iniziare, esegui uno squat flettendo fianchi e ginocchia finché non riesci ad afferrare le maniglie. Dopo averle afferrate, inizia la risalita. Spingendo sui talloni, estendi fianchi e ginocchia mantenendo le mani lungo i fianchi. Tieni la testa alta e il petto in fuori durante tutto il movimento. Dopo aver raggiunto la posizione eretta, torna alla posizione iniziale e ripeti.' 
WHERE name = 'Cable Deadlifts';

UPDATE public.exercise_library 
SET name_it = 'Cable Hammer Curls - con corda', description_it = 'Aggancia una corda a una carrucola bassa e posizionati di fronte alla macchina a circa 30 cm di distanza. Impugna la corda con una presa neutra (palmi rivolti verso l''interno) e mantieni la schiena con la sua naturale curvatura e il busto fermo. Tieni i gomiti aderenti ai fianchi per tutta la durata del movimento. Suggerimento: solo gli avambracci devono muoversi, non la parte superiore delle braccia. Questa è la posizione di partenza. Usando i bicipiti, tira le braccia verso l''alto espirando finché i bicipiti non toccano gli avambracci. Dopo una contrazione di 1 secondo, torna lentamente alla posizione originale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Cable Hammer Curls - Rope Attachment';

UPDATE public.exercise_library 
SET name_it = 'Cable Hip Adduction', description_it = 'Posizionati di fronte a una carrucola bassa con una gamba vicina alla torre e l''altra lontana. Aggancia la cavigliera al cavo e alla caviglia della gamba vicina alla torre. Allontanati dalla torre assumendo una posizione ampia e afferra la barra del sistema a carrucola. Poggia il peso sul piede che non ha la cavigliera (il piede lontano) e lascia che la gamba con la cavigliera venga tirata verso la carrucola: questa è la posizione di partenza. Esegui il movimento portando la gamba con la cavigliera davanti alla gamba d''appoggio, usando l''interno coscia per addurre l''anca. Espira durante questa fase. Torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato, poi cambia gamba.' 
WHERE name = 'Cable Hip Adduction';

UPDATE public.exercise_library 
SET name_it = 'Cable Incline Pushdown', description_it = 'Sdraiati su una panca inclinata rivolto in direzione opposta rispetto a una carrucola alta dotata di barra dritta. Afferra la barra sopra la testa con una presa prona (palmi verso il basso) alla larghezza delle spalle ed estendi le braccia davanti a te. La barra dovrebbe trovarsi a circa 5 cm dalle cosce: questa è la posizione di partenza. Mantenendo la parte superiore delle braccia ferma, solleva le braccia descrivendo un semicerchio finché la barra non è direttamente sopra la testa. Inspira durante questa fase. Torna lentamente alla posizione iniziale usando i dorsali e mantieni la contrazione una volta raggiunta la posizione di partenza. Espira durante l''esecuzione. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Cable Incline Pushdown';

UPDATE public.exercise_library 
SET name_it = 'Cable Incline Triceps Extension', description_it = 'Sdraiati su una panca inclinata rivolto in direzione opposta rispetto a una carrucola alta dotata di barra dritta. Afferra la barra sopra la testa con una presa prona stretta (meno della larghezza delle spalle) e tieni i gomiti vicini ai fianchi. La parte superiore delle braccia dovrebbe formare un angolo di circa 25 gradi rispetto al pavimento. Mantenendo la parte superiore delle braccia ferma, estendi gli avambracci contraendo i tricipiti. Espira durante questa fase e mantieni la contrazione per un secondo. Torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Cable Incline Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Cable Internal Rotation', description_it = 'Siediti di lato rispetto a una carrucola bassa (con le gambe distese o incrociate) e afferra la maniglia singola con il braccio più vicino al cavo. Suggerimento: se puoi regolare l''altezza della carrucola, puoi sederti su una panca. Posiziona il gomito contro il fianco, piegato a 90°, con l''avambraccio rivolto verso la carrucola. Questa è la posizione di partenza. Tira la maniglia verso il corpo ruotando internamente la spalla finché l''avambraccio non è davanti all''addome, creando un semicerchio immaginario. Suggerimento: l''avambraccio deve rimanere perpendicolare al busto. Torna lentamente alla posizione iniziale e ripeti per il numero di ripetizioni consigliato, poi cambia braccio.' 
WHERE name = 'Cable Internal Rotation';

UPDATE public.exercise_library 
SET name_it = 'Cable Iron Cross', description_it = 'Porta le carrucole in posizione alta, seleziona il peso e impugna le maniglie. Stai in piedi esattamente tra le due torri con le braccia estese lateralmente. Testa alta, petto in fuori e braccia a formare una "T". Questa è la posizione di partenza. Mantenendo i gomiti estesi, tira le braccia dritte verso i fianchi. Torna alla posizione iniziale dopo una pausa nel picco di contrazione. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Cable Iron Cross';

UPDATE public.exercise_library 
SET name_it = 'Cable Judo Flip', description_it = 'Collega una corda a una torre e posiziona la carrucola nella posizione più bassa. Stai di lato rispetto alla torre con una posizione dei piedi ampia e afferra la corda con entrambe le mani. Ruota il corpo lontano dalla carrucola portando la corda sopra la spalla come se stessi eseguendo un judo flip. Sposta il peso tra i piedi mentre ruoti e fletti il busto in avanti, tirando il cavo verso il basso. Torna alla posizione di partenza e ripeti fino a esaurimento. Successivamente, cambia lato e ripeti la sequenza.' 
WHERE name = 'Cable Judo Flip';

UPDATE public.exercise_library 
SET name_it = 'Cable Lying Triceps Extension', description_it = 'Sdraiati su una panca piana e afferra l''accessorio a barra dritta collegato a una carrucola bassa con una presa prona stretta. Suggerimento: il modo più semplice è farsi passare la barra da qualcuno mentre ci si sdraia. Con le braccia tese, posiziona la barra sopra il torace. Le braccia e il torace dovrebbero formare un angolo di 90 gradi. Questa sarà la posizione di partenza. Abbassa la barra flettendo i gomiti, mantenendo la parte superiore delle braccia ferma e i gomiti chiusi. Scendi fino a quando la barra tocca leggermente la fronte. Inspira durante questa fase del movimento. Contrai i tricipiti mentre riporti la barra nella posizione iniziale. Espira durante questa fase del movimento. Mantieni la contrazione per un secondo nella posizione finale e ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Cable Lying Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Cable One Arm Tricep Extension', description_it = 'Con la mano destra, afferra una maniglia singola collegata alla carrucola alta utilizzando una presa supina (palmi rivolti verso l''alto). Posizionati direttamente di fronte al pacco pesi. Tira la maniglia verso il basso in modo che la parte superiore del braccio e il gomito siano bloccati lungo il fianco. Il braccio e l''avambraccio devono formare un angolo acuto (meno di 90 gradi). Puoi tenere l''altro braccio lungo il fianco e posizionare una gamba avanti e l''altra indietro per un migliore equilibrio. Questa sarà la posizione di partenza. Mentre contrai il tricipite, porta la maniglia verso il basso finché il braccio non è teso. Espira durante il movimento. Suggerimento: solo gli avambracci devono muoversi; la parte superiore delle braccia deve rimanere ferma in ogni momento. Contrai il tricipite e mantieni per un secondo la posizione. Torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato e poi esegui lo stesso movimento con l''altro braccio.' 
WHERE name = 'Cable One Arm Tricep Extension';

UPDATE public.exercise_library 
SET name_it = 'Cable Preacher Curl', description_it = 'Posiziona una panca Scott (preacher bench) a circa 60 cm da una macchina a carrucole. Collega una barra dritta alla carrucola bassa. Siediti sulla panca con i gomiti e la parte superiore delle braccia ben poggiati sul cuscinetto e fatti passare la barra dalla carrucola bassa. Afferra la barra e distendi completamente le braccia sul cuscinetto della panca. Questa sarà la posizione di partenza. Inizia a sollevare il peso verso le spalle e contrai intensamente i bicipiti nella parte superiore del movimento. Espira durante l''esecuzione e mantieni la contrazione per un secondo. Torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Cable Preacher Curl';

UPDATE public.exercise_library 
SET name_it = 'Cable Rear Delt Fly', description_it = 'Regola le carrucole all''altezza appropriata, sopra la testa, e seleziona il peso. Afferra la carrucola sinistra con la mano destra e quella destra con la mano sinistra, incrociandole davanti a te. Questa sarà la posizione di partenza. Inizia il movimento portando le braccia verso l''esterno e all''indietro, mantenendole tese durante l''esecuzione. Fermati alla fine del movimento prima di riportare le maniglie alla posizione di partenza.' 
WHERE name = 'Cable Rear Delt Fly';

UPDATE public.exercise_library 
SET name_it = 'Cable Reverse Crunch', description_it = 'Collega un cinturino per caviglia a una carrucola bassa e posiziona un tappetino sul pavimento di fronte ad essa. Siediti con i piedi verso la carrucola e fissa il cavo alle caviglie. Sdraiati, solleva le gambe e piega le ginocchia a 90 gradi. Le gambe e il cavo devono essere allineati; in caso contrario, regola l''altezza della carrucola. Con le mani dietro la testa, porta le ginocchia verso il torace e solleva i fianchi dal pavimento. Fermati un istante, quindi in modo lento e controllato abbassa i fianchi e riporta le gambe nella posizione iniziale a 90 gradi. Mantieni sempre in tensione gli addominali. Ripeti fino al cedimento muscolare.' 
WHERE name = 'Cable Reverse Crunch';

UPDATE public.exercise_library 
SET name_it = 'Cable Rope Overhead Triceps Extension', description_it = 'Collega una corda alla carrucola bassa. Afferrando la corda con entrambe le mani, estendi le braccia sopra la testa con una presa neutra (palmi rivolti l''uno verso l''altro). I gomiti devono essere vicini alla testa e le braccia perpendicolari al pavimento, con le nocche rivolte verso il soffitto. Questa sarà la posizione di partenza. Abbassa lentamente la corda dietro la testa mantenendo ferme le braccia. Inspira durante il movimento e fermati quando i tricipiti sono completamente allungati. Torna alla posizione di partenza flettendo i tricipiti ed espirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Cable Rope Overhead Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Cable Rope Rear-Delt Rows', description_it = 'Siediti in posizione di rematore basso, come faresti per un normale row ai cavi. Collega una corda alla carrucola e afferrala con una presa prona. Le braccia devono essere tese e parallele al pavimento con i gomiti rivolti verso l''esterno. Mantieni la parte bassa della schiena dritta e sposta i fianchi all''indietro con le ginocchia leggermente flesse. Questa sarà la posizione di partenza. Tira la corda verso la parte superiore del petto, appena sotto il collo, mantenendo i gomiti alti e verso l''esterno. Continua il movimento espirando finché i gomiti non superano leggermente la schiena. Suggerimento: mantieni le braccia orizzontali, perpendicolari al busto e parallele al pavimento per tutto il movimento. Torna alla posizione iniziale in cui le braccia sono tese e le spalle allungate in avanti. Inspira durante questa fase. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Cable Rope Rear-Delt Rows';

UPDATE public.exercise_library 
SET name_it = 'Cable Russian Twists', description_it = 'Collega una maniglia standard e posiziona la carrucola a un''altezza media. Sdraiati su una fitball perpendicolarmente al cavo e afferra la maniglia con una mano. Dovresti essere a circa una lunghezza di braccio dalla carrucola, con il peso del cavo in tensione. Afferra la maniglia con entrambe le mani e distendi completamente le braccia sopra il petto. Le mani devono essere in linea con la carrucola; in caso contrario, regola l''altezza. Mantieni i fianchi sollevati e gli addominali contratti. Ruota il busto allontanandoti dalla carrucola per una rotazione completa di un quarto. Il corpo deve formare una linea retta dalla testa alle ginocchia. Fermati un istante e torna lentamente alla posizione iniziale in modo controllato. Mantieni la tensione sul cavo anche nella posizione di riposo. Ripeti fino al cedimento, poi cambia lato e ripeti la serie.' 
WHERE name = 'Cable Russian Twists';

UPDATE public.exercise_library 
SET name_it = 'Cable Seated Crunch', description_it = 'Siediti su una panca piana con la schiena rivolta a una carrucola alta. Afferra la corda con entrambe le mani (palmi rivolti l''uno verso l''altro) e posiziona le mani saldamente sopra le spalle. Suggerimento: permetti al peso di iperestendere leggermente la parte bassa della schiena. Questa sarà la posizione di partenza. Con i fianchi fermi, fletti la vita in modo che i gomiti si muovano verso i fianchi. Espira durante questa fase. Mentre inspiri, torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Cable Seated Crunch';

UPDATE public.exercise_library 
SET name_it = 'Cable Seated Lateral Raise', description_it = 'Mettiti tra due carrucole basse opposte e posiziona una panca piana dietro di te (perpendicolare alla tua posizione; il lato stretto della panca deve essere dietro di te). Seleziona il peso. Siediti sul bordo della panca con i piedi ben piantati davanti alle ginocchia. Piegati in avanti mantenendo la schiena piatta e appoggia il busto sulle cosce. Fatti passare le maniglie collegate alle carrucole: afferra la carrucola sinistra con la mano destra e quella destra con la mano sinistra. I cavi passeranno sotto le ginocchia; le braccia saranno tese con i palmi rivolti l''uno verso l''altro e un leggero piegamento dei gomiti. Questa sarà la posizione di partenza. Mantenendo le braccia ferme, solleva le braccia verso i lati finché non sono parallele al pavimento e all''altezza delle spalle. Espira durante l''esecuzione e mantieni la contrazione per un secondo. Abbassa lentamente le braccia nella posizione iniziale mentre inspiri. Ripeti per il numero di ripetizioni raccomandato. Suggerimento: mantieni la parte superiore delle braccia perpendicolare al busto e i gomiti a un angolo fisso (10-30 gradi) durante tutto l''esercizio.' 
WHERE name = 'Cable Seated Lateral Raise';

UPDATE public.exercise_library 
SET name_it = 'Cable Shoulder Press', description_it = 'Posiziona i cavi nella parte bassa delle torri e seleziona un peso adeguato. Mettiti in piedi esattamente tra i montanti. Afferra i cavi e tienili all''altezza delle spalle, con i palmi rivolti in avanti. Questa sarà la tua posizione di partenza. Mantenendo la testa e il petto alti, distendi i gomiti per spingere le maniglie direttamente sopra la testa. Dopo una breve pausa in alto, ritorna alla posizione di partenza e ripeti.' 
WHERE name = 'Cable Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Cable Shrugs', description_it = 'Afferra una barra collegata a una puleggia bassa con una presa prona (palmi rivolti verso il basso) di larghezza pari o leggermente superiore a quella delle spalle. Stai in piedi in posizione eretta vicino alla puleggia con le braccia distese davanti a te che tengono la barra. Questa sarà la tua posizione di partenza. Solleva la barra elevando le spalle il più possibile mentre espiri. Mantieni la contrazione nella parte alta per un secondo. Consiglio: le braccia devono rimanere sempre tese. Evita di usare i bicipiti per aiutare il sollevamento; solo le spalle devono muoversi verso l''alto e verso il basso. Abbassa la barra fino alla posizione originale e ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Cable Shrugs';

UPDATE public.exercise_library 
SET name_it = 'Cable Wrist Curl', description_it = 'Posiziona una panca piana davanti a una puleggia bassa dotata di un''asta dritta. Afferra l''asta con una presa supina (palmi rivolti verso l''alto) di larghezza pari o inferiore a quella delle spalle e appoggia gli avambracci sopra le cosce. I polsi dovrebbero sporgere oltre le ginocchia. Inizia flettendo i polsi verso l''alto ed espirando. Mantieni la contrazione per un secondo. Abbassa lentamente i polsi alla posizione di partenza mentre inspiri. Gli avambracci devono rimanere fermi; il movimento deve coinvolgere esclusivamente i polsi. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Cable Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Calf-Machine Shoulder Shrug', description_it = 'Posizionati sulla macchina per polpacci in modo che i cuscinetti per le spalle siano sopra di esse. Il busto deve essere dritto con le braccia distese lungo i fianchi. Questa sarà la tua posizione di partenza. Solleva le spalle verso le orecchie mentre espiri e mantieni la contrazione per un secondo pieno. Ritorna lentamente alla posizione di partenza mentre inspiri. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Calf-Machine Shoulder Shrug';

UPDATE public.exercise_library 
SET name_it = 'Calf Press', description_it = 'Regola il sedile in modo che le gambe siano solo leggermente flesse nella posizione iniziale. L''avampiede deve essere saldamente sulla piattaforma. Seleziona un peso appropriato e afferra le maniglie. Questa sarà la tua posizione di partenza. Distendi le gambe estendendo le ginocchia, sollevando appena il peso dal pacco. Le caviglie devono essere completamente flesse, con le dita dei piedi rivolte verso l''alto. Esegui il movimento spingendo verso il basso con l''avampiede il più lontano possibile. Dopo una breve pausa, inverte il movimento e ripeti.' 
WHERE name = 'Calf Press';

UPDATE public.exercise_library 
SET name_it = 'Calf Press su Leg Press', description_it = 'Seduto sulla leg press, posiziona i piedi sulla piattaforma davanti a te con una larghezza pari a quella delle spalle. Abbassa le barre di sicurezza e spingi la piattaforma fino a distendere le gambe senza bloccare le ginocchia (nota: se la macchina lo consente, mantenere le barre di sicurezza è preferibile). Il busto e le gambe devono formare un angolo di 90 gradi. Posiziona accuratamente l''avampiede sulla parte inferiore della piattaforma, lasciando i talloni nel vuoto. Questa sarà la tua posizione di partenza. Spingi sulla piattaforma sollevando i talloni mentre espiri, estendendo le caviglie il più possibile e contraendo i polpacci. Assicurati che le ginocchia restino ferme e non flesse. Mantieni la contrazione per un secondo, quindi torna lentamente alla posizione iniziale mentre inspiri, abbassando i talloni finché i polpacci non sono allungati. Ripeti.' 
WHERE name = 'Calf Press On The Leg Press Machine';

UPDATE public.exercise_library 
SET name_it = 'Calf Raise su Manubrio', description_it = 'Aggrappati a un oggetto stabile per l''equilibrio e posizionati sopra il manico di un manubrio (preferibilmente con dischi tondi per renderlo instabile e aumentare l''efficacia). Fai rotolare il piede leggermente in avanti per allungare il polpaccio. Questa è la posizione di partenza. Solleva il tallone facendo rotolare il piede sopra il manico per ottenere una completa estensione. Espira durante il movimento, contrai intensamente il polpaccio in alto e mantieni per un secondo. Consiglio: durante la risalita, fai rotolare leggermente il manubrio all''indietro. Inspira mentre fai rotolare il manubrio in avanti durante la discesa per un migliore allungamento. Ripeti.' 
WHERE name = 'Calf Raise On A Dumbbell';

UPDATE public.exercise_library 
SET name_it = 'Calf Raises con Bande Elastiche', description_it = 'Mettiti in piedi sopra una banda elastica con la punta dei piedi, assicurandoti che la lunghezza della banda sia uguale su entrambi i lati. Afferra le maniglie della banda e solleva le braccia ai lati della testa come se dovessi eseguire un lento avanti. I palmi devono essere rivolti in avanti, con i gomiti piegati verso l''esterno. Questo movimento creerà tensione sulla banda. Questa è la posizione di partenza. Mantenendo le mani all''altezza delle spalle, sollevati sulle punte dei piedi mentre espiri, contraendo i polpacci intensamente. Dopo un secondo di contrazione, torna lentamente alla posizione iniziale. Ripeti.' 
WHERE name = 'Calf Raises - With Bands';

UPDATE public.exercise_library 
SET name_it = 'Stretching Polpacci con Gomiti al Muro', description_it = 'Mettiti di fronte a una parete a circa 60 cm di distanza. Appoggiati al muro scaricando il peso sugli avambracci. Cerca di mantenere i talloni a terra. Mantieni la posizione per 10-20 secondi. Puoi regolare la difficoltà avvicinandoti o allontanandoti dalla parete.' 
WHERE name = 'Calf Stretch Elbows Against Wall';

UPDATE public.exercise_library 
SET name_it = 'Stretching Polpacci con Mani al Muro', description_it = 'Mettiti di fronte a una parete a una certa distanza. Assumi una posizione sfalsata con un piede in avanti. Inclinati in avanti appoggiando le mani al muro, mantenendo tallone, anca e testa allineati. Cerca di mantenere il tallone a terra. Mantieni per 10-20 secondi e poi cambia gamba.' 
WHERE name = 'Calf Stretch Hands Against Wall';

UPDATE public.exercise_library 
SET name_it = 'SMR Polpacci', description_it = 'Inizia seduto sul pavimento. Posiziona un foam roller sotto la parte inferiore della gamba. L''altra gamba può essere incrociata sopra quella opposta o appoggiata a terra per sostenere parte del peso. Questa sarà la posizione di partenza. Posiziona le mani ai fianchi o appena dietro di te, quindi fai pressione per sollevare i fianchi da terra, scaricando gran parte del peso sul muscolo del polpaccio. Rotola dalla zona sotto il ginocchio fino a sopra la caviglia, fermandoti sui punti di tensione per 10-30 secondi. Ripeti con l''altra gamba.' 
WHERE name = 'Calves-SMR';

UPDATE public.exercise_library 
SET name_it = 'Car Deadlift', description_it = 'Questo attrezzo dispone solitamente di maniglie con presa neutra, sebbene alcuni modelli presentino una barra dritta utilizzabile come un normale stacco da terra. L''attrezzo può essere caricato con un veicolo o altri oggetti pesanti come pneumatici da trattore o barili. Centrati tra le maniglie se preferisci uno squat potente, o arretra di alcuni centimetri se hai una tecnica di stacco più efficace. I piedi dovrebbero essere larghi quanto le anche. Piegati a livello delle anche per afferrare le maniglie. Con piedi e presa posizionati, fai un respiro profondo, abbassa i fianchi e fletti le ginocchia. Guarda avanti, tieni il petto alto e la schiena inarcata, e inizia a spingere attraverso i talloni per sollevare il peso. Mentre il peso sale, stringi le scapole tra loro spingendo i fianchi in avanti. Abbassa il peso flettendo le anche e guidandolo verso il pavimento.' 
WHERE name = 'Car Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Car Drivers', description_it = 'In posizione eretta, impugna un disco da bilanciere con entrambe le mani nelle posizioni delle ore 3 e 9. I palmi devono essere rivolti l''uno verso l''altro e le braccia tese in avanti. Questa sarà la posizione di partenza. Inizia il movimento ruotando il disco il più possibile verso un lato, utilizzando lo stesso movimento che useresti per girare il volante di un''auto. Inverti il movimento, ruotando il disco fino al lato opposto. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Car Drivers';

UPDATE public.exercise_library 
SET name_it = 'Carioca Quick Step', description_it = 'Inizia con i piedi a pochi centimetri di distanza e il braccio sinistro sollevato in una posizione atletica rilassata. Con il piede destro, esegui un passo veloce dietro e tira il ginocchio verso l''alto. Riporta le braccia verso l''alto quando sollevi il ginocchio destro, assicurandoti che il movimento del ginocchio sia verticale. Evita di ruotare i piedi mentre ti muovi e continua a guardare avanti durante lo spostamento laterale.' 
WHERE name = 'Carioca Quick Step';

UPDATE public.exercise_library 
SET name_it = 'Cat Stretch (Posizione del gatto)', description_it = 'Mettiti a terra carponi, appoggiandoti su mani e ginocchia. Risucchia l''addome verso l''interno e incurva la colonna vertebrale, la parte bassa della schiena, le spalle e il collo, lasciando cadere la testa. Mantieni la posizione per 15 secondi.' 
WHERE name = 'Cat Stretch';

UPDATE public.exercise_library 
SET name_it = 'Catch and Overhead Throw', description_it = 'Inizia in piedi di fronte a una parete o a un partner. Usando entrambe le mani, posiziona la palla dietro la testa, allungandoti il più possibile, e lancia la palla in avanti con forza. Assicurati di seguire il movimento del lancio, preparandoti a ricevere il rimbalzo. Se ti stai allenando contro una parete, assicurati di stare abbastanza vicino per ricevere il rimbalzo e mira leggermente più in alto rispetto a quanto faresti con un partner.' 
WHERE name = 'Catch and Overhead Throw';

UPDATE public.exercise_library 
SET name_it = 'Chain Handle Extension', description_it = 'Per questo esercizio sono necessari due attacchi a maniglia per cavi, una panca piana e delle catene. Aggancia il centro delle catene alle maniglie e posizionati sulla panca piana. I gomiti dovrebbero essere rivolti verso l''alto. Inizia estendendo i gomiti, mantenendo le braccia ferme e i polsi in pronazione. Fermati al punto di blocco e inverti il movimento per tornare alla posizione di partenza.' 
WHERE name = 'Chain Handle Extension';

UPDATE public.exercise_library 
SET name_it = 'Chain Press', description_it = 'Inizia collegando le catene agli attacchi a maniglia dei cavi. Posizionati sulla panca piana nella stessa posizione prevista per le distensioni con manubri. I polsi devono essere in pronazione e le braccia perpendicolari al pavimento. Questa sarà la posizione di partenza. Abbassa le catene flettendo i gomiti, scaricando parte del peso delle catene sul pavimento. Continua finché il gomito non forma un angolo di 90 gradi, quindi inverti il movimento estendendo il braccio fino al blocco.' 
WHERE name = 'Chain Press';

UPDATE public.exercise_library 
SET name_it = 'Chair Leg Extended Stretch', description_it = 'Siediti dritto su una sedia e afferra i lati della seduta. Solleva una gamba, estendendo il ginocchio e flettendo la caviglia durante il movimento. Sposta lentamente la gamba verso l''esterno il più possibile, poi riportala al centro e abbassala. Ripeti con l''altra gamba.' 
WHERE name = 'Chair Leg Extended Stretch';

UPDATE public.exercise_library 
SET name_it = 'Chair Lower Back Stretch', description_it = 'Siediti dritto su una sedia. Piegati su un lato portando il braccio sopra la testa. Puoi tenerti alla sedia con la mano libera. Mantieni la posizione per 10 secondi e ripeti sull''altro lato.' 
WHERE name = 'Chair Lower Back Stretch';

UPDATE public.exercise_library 
SET name_it = 'Chair Squat', description_it = 'Per iniziare, regola il bilanciere a un''altezza adeguata. Posizionati sotto il bilanciere e appoggialo sulla parte alta della schiena. Afferralo con le mani rivolte in avanti, sgancialo dal rack ed estendi le gambe per sollevarlo. Porta i piedi circa 45 cm avanti rispetto al bilanciere. Posiziona le gambe a una larghezza pari a quella delle spalle con le punte dei piedi leggermente verso l''esterno. Guarda sempre in avanti e mantieni la colonna vertebrale neutra o leggermente arcuata: questa è la posizione di partenza. Abbassa lentamente il bilanciere piegando le ginocchia e mantenendo la postura eretta e la testa alta. Scendi finché l''angolo tra coscia e polpaccio supera i 90 gradi. Inizia la risalita espirando, spingendo sui talloni, estendendo le ginocchia e tornando alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Chair Squat';

UPDATE public.exercise_library 
SET name_it = 'Stretching parte superiore del corpo su sedia', description_it = 'Siediti sul bordo di una sedia, afferrandone lo schienale. Distendi le braccia, mantieni la schiena dritta e tira il busto in avanti finché non avverti l''allungamento. Mantieni la posizione per 20-30 secondi.' 
WHERE name = 'Chair Upper Body Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching pettorali e parte anteriore delle spalle', description_it = 'Inizia in posizione eretta con le gambe unite, tenendo un bastone ginnico o il manico di una scopa. Afferra il bastone con una presa leggermente più larga delle spalle e tienilo davanti a te con i palmi rivolti verso il basso. Solleva con cautela il bastone sopra la testa e portalo dietro la schiena.' 
WHERE name = 'Chest And Front Of Shoulder Stretch';

UPDATE public.exercise_library 
SET name_it = 'Chest Push (3 punti di appoggio)', description_it = 'Inizia in posizione a tre punti di appoggio: accovacciato, schiena piatta e una mano a terra. Posiziona la palla medica direttamente davanti a te. Per iniziare, fai il primo passo mentre porti la palla al petto, posizionando entrambe le mani in preparazione al lancio. Durante il secondo passo, rilascia la palla in avanti con la massima esplosività possibile.' 
WHERE name = 'Chest Push from 3 point stance';

UPDATE public.exercise_library 
SET name_it = 'Chest Push (risposta multipla)', description_it = 'Inizia in posizione inginocchiata di fronte a una parete o a un partner. Tieni la palla stretta al petto con entrambe le mani. Esegui il passaggio esplodendo in avanti e verso l''esterno con le anche mentre spingi la palla con la massima forza. Accompagna il movimento cadendo in avanti e attutendo il colpo con le mani. Torna immediatamente in posizione eretta. Ripeti per il numero di volte desiderato.' 
WHERE name = 'Chest Push (multiple response)';

UPDATE public.exercise_library 
SET name_it = 'Chest Push (risposta singola)', description_it = 'Inizia in posizione inginocchiata tenendo la palla medica ben stretta al petto con entrambe le mani. Esegui il passaggio esplodendo in avanti e verso l''esterno con le anche mentre spingi la palla il più lontano possibile. Accompagna il movimento cadendo in avanti e attutendo il colpo con le mani.' 
WHERE name = 'Chest Push (single response)';

UPDATE public.exercise_library 
SET name_it = 'Chest Push con rilascio in corsa', description_it = 'Inizia in posizione atletica con le ginocchia flesse, anche indietro e schiena piatta. Tieni la palla medica vicino alle gambe: questa è la posizione di partenza. Durante il primo passo, porta la palla medica al petto. Al secondo passo, spingi la palla in avanti in modo esplosivo e scatta immediatamente per 10 metri dopo il rilascio. Se sei abbastanza veloce, puoi persino recuperare il tuo lancio!' 
WHERE name = 'Chest Push with Run Release';

UPDATE public.exercise_library 
SET name_it = 'Stretching pettorali su Stability Ball', description_it = 'Mettiti in ginocchio a terra accanto a una fitball. Appoggia i gomiti sulla parte superiore della palla, tenendo le braccia di lato. Questa è la posizione di partenza. Abbassa il busto verso il pavimento mantenendo i gomiti sulla palla. Mantieni lo stretching per 20-30 secondi, quindi ripeti con l''altro braccio.' 
WHERE name = 'Chest Stretch on Stability Ball';

UPDATE public.exercise_library 
SET name_it = 'Child''s Pose (posizione del bambino)', description_it = 'Mettiti in ginocchio e allunga le mani davanti a te sul pavimento. Abbassa i glutei fino a sederti sui talloni. Lascia scivolare le braccia sul pavimento mentre ti siedi per allungare l''intera colonna vertebrale. Una volta seduto sui talloni, porta le mani accanto ai piedi e rilassati. "Respira" nella schiena. Appoggia la fronte a terra. Evita questa posizione in caso di problemi alle ginocchia.' 
WHERE name = 'Child''s Pose';

UPDATE public.exercise_library 
SET name_it = 'Chin-Up', description_it = 'Afferra la sbarra per trazioni con i palmi rivolti verso il torso e una presa più stretta della larghezza delle spalle. Con le braccia distese e la sbarra in mano, tieni il busto il più dritto possibile, inarcando leggermente la parte bassa della schiena e spingendo il petto in fuori. Questa è la posizione di partenza. Consiglio: mantenere il busto dritto massimizza il lavoro sui bicipiti minimizzando il coinvolgimento della schiena. Espirando, solleva il busto finché la testa non supera il livello della sbarra. Concentrati sull''uso dei bicipiti per eseguire il movimento. Tieni i gomiti vicini al corpo. Consiglio: il busto deve rimanere fermo nello spazio e solo le braccia devono muoversi. Gli avambracci devono solo mantenere la presa. Dopo un secondo di contrazione massima dei bicipiti, abbassa lentamente il busto fino alla posizione iniziale, tornando a braccia completamente distese. Inspira durante questa fase. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Chin-Up';

UPDATE public.exercise_library 
SET name_it = 'Stretching mento al petto', description_it = 'Siediti a terra. Posiziona entrambe le mani dietro la nuca con le dita intrecciate, i pollici rivolti verso il basso e i gomiti che puntano dritto in avanti. Porta lentamente la testa verso il petto. Mantieni la posizione per 20-30 secondi.' 
WHERE name = 'Chin To Chest Stretch';

UPDATE public.exercise_library 
SET name_it = 'Circus Bell', description_it = 'La circus bell è un manubrio sovradimensionato con un''impugnatura spessa. Inizia con il manubrio tra i piedi e afferra l''impugnatura con entrambe le mani. Esegui il ''clean'' del manubrio estendendo fianchi e ginocchia per portare l''attrezzo alla spalla desiderata, lasciando la presa con la mano libera. Assicurati che una delle teste del manubrio sia posizionata dietro la spalla per evitare di perdere l''equilibrio. Per sollevarlo sopra la testa, fletti le ginocchia (dip) e spingi verso l''alto estendendoti, inclinandoti leggermente lontano dal manubrio durante l''esecuzione. Riporta il manubrio a terra con cura, mantenendolo il più possibile sotto controllo. È consigliabile eseguire questo esercizio su un tappeto di gomma spesso per evitare danni al pavimento.' 
WHERE name = 'Circus Bell';

UPDATE public.exercise_library 
SET name_it = 'Clean (Girata)', description_it = 'Con un bilanciere a terra vicino agli stinchi, utilizza una presa prona (o hook grip) appena all''esterno delle gambe. Abbassa i fianchi caricando il peso sui talloni, schiena dritta, testa rivolta in avanti, petto in fuori e spalle leggermente davanti al bilanciere. Questa è la posizione di partenza. Inizia la prima trazione spingendo sui talloni ed estendendo le ginocchia. L''angolo della schiena deve rimanere costante e le braccia distese. Muovi il peso con controllo finché non supera le ginocchia. Segue la seconda trazione, la principale fonte di accelerazione: quando il bilanciere raggiunge la metà coscia, inizia l''estensione dei fianchi. Con un movimento simile a un salto, accelera estendendo fianchi, ginocchia e caviglie. Non è necessario tirare attivamente con le braccia; al termine della seconda trazione, il corpo deve essere completamente esteso, inclinato leggermente all''indietro, con le braccia ancora distese. Raggiunta la massima estensione, passa alla terza trazione scrollando energicamente le spalle e flettendo le braccia con i gomiti verso l''alto e l''esterno. Al culmine, scendi rapidamente sotto il bilanciere ruotando i gomiti. Ricevi il bilanciere in posizione di front squat; il bilanciere deve poggiare sulle spalle protratte, sfiorando la gola con le mani rilassate. Scendi fino in fondo allo squat per favorire il recupero. Risali immediatamente spingendo sui talloni, mantenendo il busto eretto e i gomiti alti, fino alla posizione eretta.' 
WHERE name = 'Clean';

UPDATE public.exercise_library 
SET name_it = 'Clean Deadlift', description_it = 'Inizia in piedi con un bilanciere vicino agli stinchi. I piedi devono essere sotto i fianchi e leggermente ruotati verso l''esterno. Afferra il bilanciere con una presa doppia prona o hook grip, alla larghezza delle spalle. Scendi in squat fino al bilanciere. La colonna vertebrale deve essere in estensione completa, con un angolo della schiena che posizioni le spalle davanti al bilanciere e la schiena il più verticale possibile. Inizia spingendo con la parte anteriore dei talloni. Mentre il bilanciere sale, mantieni costante l''angolo della schiena. Sposta le ginocchia verso l''esterno per evitare che ostacolino il percorso del bilanciere. Dopo che il bilanciere ha superato le ginocchia, completa l''alzata spingendo i fianchi verso il bilanciere fino alla completa estensione di fianchi e ginocchia.' 
WHERE name = 'Clean Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Clean Pull', description_it = 'Con un bilanciere a terra vicino agli stinchi, impugna il bilanciere appena fuori dalle gambe (presa prona o hook grip). Abbassa i fianchi, peso sui talloni, schiena dritta, petto in fuori e spalle leggermente davanti al bilanciere. Inizia la prima trazione spingendo sui talloni ed estendendo le ginocchia. Mantieni l''angolo della schiena costante e le braccia distese con i gomiti verso l''esterno. Superate le ginocchia, passa alla seconda trazione: quando il bilanciere arriva a metà coscia, estendi i fianchi con un movimento esplosivo simile a un salto, estendendo fianchi, ginocchia e caviglie per accelerare il bilanciere. Le braccia non devono tirare attivamente; alla fine della seconda trazione il corpo deve essere completamente esteso, leggermente inclinato all''indietro, con le braccia ancora tese. L''estensione finale deve essere violenta e rapida, evitando di prolungarla oltre il necessario.' 
WHERE name = 'Clean Pull';

UPDATE public.exercise_library 
SET name_it = 'Clean Shrug', description_it = 'Inizia con una presa doppia prona o hook grip alla larghezza delle spalle, bilanciere sospeso a metà coscia. Schiena dritta e leggermente inclinata in avanti. Esegui una scrollata delle spalle verso le orecchie. Anche se questo esercizio solitamente permette carichi superiori a un clean, evita sovraccarichi eccessivi che rallenterebbero l''esecuzione.' 
WHERE name = 'Clean Shrug';

UPDATE public.exercise_library 
SET name_it = 'Clean and Jerk (Slancio)', description_it = 'Esegui la fase di Clean come descritto nell''esercizio ''Clean''. La seconda fase è il Jerk, per sollevare il peso sopra la testa. Con il peso sulle spalle, esegui il ''dip'': con i piedi sotto i fianchi, fletti le ginocchia senza portare i fianchi all''indietro. Scendi leggermente e inverti il movimento con la massima potenza. Spingi sui talloni per generare velocità e forza, assicurandoti di spostare la testa quando il bilanciere lascia le spalle. Nel momento in cui i piedi si staccano da terra, posizionali rapidamente nella posizione di ricezione (split jerk), con un piede avanti e uno indietro. Ricevi il bilanciere con le braccia completamente bloccate sopra la testa, quindi torna in posizione eretta.' 
WHERE name = 'Clean and Jerk';

UPDATE public.exercise_library 
SET name_it = 'Clean and Press', description_it = 'Assumi una posizione con piedi alla larghezza delle spalle e ginocchia all''interno delle braccia. Con la schiena piatta, fletti ginocchia e fianchi per afferrare il bilanciere (presa prona leggermente più larga delle spalle). Gomiti rivolti verso l''esterno, bilanciere vicino agli stinchi, spalle sopra o leggermente davanti al bilanciere. Inizia a tirare estendendo le ginocchia; muovi i fianchi in avanti e solleva le spalle mantenendo l''angolo della schiena costante. Superate le ginocchia, estendi con forza caviglie, ginocchia e fianchi (movimento simile a un salto). Guida il bilanciere verso l''alto scrollando le spalle. Al culmine dell''elevazione, i piedi dovrebbero staccarsi da terra mentre ti posizioni sotto il bilanciere in uno squat. Ruota i gomiti attorno al bilanciere e ricevilo sulle spalle anteriori. In piedi, spingi il bilanciere sopra la testa espirando. Abbassa il bilanciere sotto controllo.' 
WHERE name = 'Clean and Press';

UPDATE public.exercise_library 
SET name_it = 'Clean from Blocks', description_it = 'Con il bilanciere posizionato su blocchi o supporti all''altezza desiderata, esegui una presa prona o hook grip appena fuori dalle gambe. Abbassa i fianchi, peso sui talloni, schiena dritta e spalle davanti al bilanciere. Inizia la trazione spingendo sui talloni ed estendendo le ginocchia, mantenendo l''angolo della schiena costante e le braccia distese. Al raggiungimento della massima estensione, passa rapidamente alla ricezione: scrolla le spalle, fletti le braccia portando i gomiti in alto e all''esterno, e scendi sotto il bilanciere ruotando i gomiti. Ricevi il bilanciere in posizione di front squat e scendi fino in fondo per facilitare il recupero. Risali fino alla posizione eretta e riponi il bilanciere sui blocchi.' 
WHERE name = 'Clean from Blocks';

UPDATE public.exercise_library 
SET name_it = 'Clock Push-Up', description_it = 'Posizionati in plank a terra, supportando il peso su mani e punte dei piedi. Braccia distese alla larghezza delle spalle, corpo in linea. Fletti i gomiti per scendere verso terra. Alla base, spingi il più rapidamente possibile per sollevarti da terra in un piccolo ''salto'' laterale di 30-45 cm. Durante la spinta, sposta il piede esterno nella direzione del movimento. Una volta a terra, ruota il corpo di circa 30 gradi per la ripetizione successiva. Ripeti il ciclo completo finché non torni alla posizione di partenza.' 
WHERE name = 'Clock Push-Up';

UPDATE public.exercise_library 
SET name_it = 'Panca piana a presa stretta con bilanciere', description_it = 'Sdraiati su una panca piana. Con una presa stretta (circa la larghezza delle spalle), solleva il bilanciere dal rack e tienilo teso sopra di te con le braccia distese. Questa sarà la tua posizione di partenza. Inspirando, scendi lentamente finché non senti il bilanciere toccare il centro del petto. Suggerimento: a differenza della panca piana classica, mantieni i gomiti vicini al busto per massimizzare il coinvolgimento dei tricipiti. Dopo una pausa di un secondo, riporta il bilanciere nella posizione di partenza espirando e spingendo con i tricipiti. Distendi le braccia nella posizione contratta, mantieni per un secondo e ricomincia a scendere lentamente. Suggerimento: la fase di discesa dovrebbe durare almeno il doppio di quella di salita. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi il bilanciere nel rack.' 
WHERE name = 'Close-Grip Barbell Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Press con manubrio a presa stretta', description_it = 'Posiziona un manubrio in verticale su una panca piana. Assicurandoti che il manubrio sia ben saldo all''estremità della panca, sdraiati perpendicolarmente ad essa con le sole spalle appoggiate alla superficie. I fianchi devono trovarsi sotto la panca e le gambe piegate con i piedi ben saldi a terra. Afferra il manubrio con entrambe le mani e tienilo dritto sopra il petto a braccia tese. Entrambi i palmi devono premere contro la parte inferiore dei dischi del manubrio. Questa è la posizione di partenza. Inizia il movimento abbassando il manubrio verso il petto. Ritorna alla posizione di partenza estendendo i gomiti.' 
WHERE name = 'Close-Grip Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Curl con bilanciere EZ e banda elastica (presa stretta)', description_it = 'Fissa una banda elastica a ciascuna estremità del bilanciere. Afferra il bilanciere posizionando un piede al centro della banda. Stai in piedi con una presa stretta e suinata sul bilanciere EZ. I gomiti devono essere vicini al busto. Questa è la posizione di partenza. Mantenendo la parte superiore delle braccia ferma, fletti i gomiti per eseguire il curl. Espira mentre sollevi il peso. Continua il movimento finché i bicipiti non sono completamente contratti e il bilanciere è all''altezza delle spalle. Mantieni la posizione contratta per un secondo contraendo intensamente i bicipiti. Inizia a riportare lentamente il bilanciere alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Close-Grip EZ-Bar Curl with Band';

UPDATE public.exercise_library 
SET name_it = 'Press con bilanciere EZ a presa stretta', description_it = 'Sdraiati su una panca piana con un bilanciere EZ caricato con un peso appropriato. Usando una presa stretta, solleva il bilanciere e tienilo dritto sopra il busto con i gomiti chiusi. Le braccia devono essere perpendicolari al pavimento. Questa è la posizione di partenza. Ora abbassa il bilanciere verso la parte bassa del petto inspirando. Mantieni i gomiti stretti durante l''esecuzione. Utilizzando i tricipiti, spingi il bilanciere verso l''alto tornando alla posizione di partenza ed espirando mentre distendi i gomiti. Ripeti.' 
WHERE name = 'Close-Grip EZ-Bar Press';

UPDATE public.exercise_library 
SET name_it = 'Curl con bilanciere EZ a presa stretta', description_it = 'Stai in piedi con il busto eretto mentre impugni un bilanciere EZ sull''impugnatura interna più stretta. I palmi delle mani devono essere rivolti in avanti e leggermente inclinati verso l''interno a causa della forma del bilanciere. I gomiti devono rimanere vicini al busto. Questa è la posizione di partenza. Mantenendo la parte superiore delle braccia ferma, solleva il bilanciere flettendo i gomiti e contraendo i bicipiti mentre espiri. Suggerimento: solo gli avambracci devono muoversi. Continua il movimento finché i bicipiti non sono completamente contratti e il bilanciere è all''altezza delle spalle. Mantieni la posizione contratta per un secondo contraendo intensamente i bicipiti. Inizia a riportare lentamente il bilanciere alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Close-Grip EZ Bar Curl';

UPDATE public.exercise_library 
SET name_it = 'Lat machine avanti a presa stretta', description_it = 'Siediti su una lat machine con una barra lunga agganciata alla carrucola superiore. Regola il blocco per le ginocchia in base alla tua altezza per evitare che il corpo si sollevi a causa della resistenza. Afferra la barra con i palmi rivolti in avanti usando la presa prescritta. Nota sulle prese: per una presa larga le mani devono essere più larghe delle spalle; per una presa media la distanza è pari alla larghezza delle spalle; per una presa stretta la distanza è inferiore alla larghezza delle spalle. Con le braccia estese davanti a te, porta il busto indietro di circa 30 gradi inarcando leggermente la parte bassa della schiena e spingendo il petto in fuori. Questa è la posizione di partenza. Espirando, porta la barra verso il petto alto tirando le spalle e i gomiti verso il basso e indietro. Suggerimento: concentrati sulla contrazione dei muscoli della schiena una volta raggiunta la posizione di massima contrazione. Il busto deve rimanere fermo (solo le braccia si muovono). Gli avambracci devono solo reggere la barra; non cercare di tirare usando le braccia. Dopo un secondo di contrazione, stringendo le scapole, risali lentamente verso la posizione di partenza finché le braccia non sono completamente distese e i dorsali allungati. Inspira durante questa fase. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Close-Grip Front Lat Pulldown';

UPDATE public.exercise_library 
SET name_it = 'Piegamenti a presa stretta su manubrio', description_it = 'Sdraiati a terra e posiziona le mani su un manubrio posto verticalmente. Sostenendo il peso sulle punte dei piedi e sulle mani, mantieni il busto rigido, i gomiti stretti e le braccia distese. Questa è la posizione di partenza. Abbassa il corpo flettendo i gomiti mentre inspiri. Mantieni il corpo dritto, senza far scendere o salire i fianchi. Spingiti verso l''alto tornando alla posizione di partenza estendendo i gomiti. Espira durante questa fase. Dopo una pausa nella posizione contratta, ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Close-Grip Push-Up off of a Dumbbell';

UPDATE public.exercise_library 
SET name_it = 'Curl in piedi con bilanciere a presa stretta', description_it = 'Afferra un bilanciere con entrambe le mani, palmi rivolti verso l''alto e a pochi centimetri di distanza. Stai in piedi con il busto dritto e la testa alta. I piedi devono essere alla larghezza delle spalle e i gomiti vicini al busto. Questa è la posizione di partenza. Suggerimento: mantieni la parte superiore delle braccia e i gomiti fermi per tutto il movimento. Solleva il bilanciere con un movimento semicircolare finché gli avambracci non toccano i bicipiti. Espira durante questa fase e contrai i bicipiti con forza per un secondo in cima. Suggerimento: evita di inarcare la schiena o di oscillare per sollevare il peso. Solo gli avambracci devono muoversi. Torna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Close-Grip Standing Barbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Cocoons (Addominali a bozzolo)', description_it = 'Inizia sdraiato sulla schiena a terra. Le gambe devono essere distese e le braccia tese dietro la testa. Questa è la posizione di partenza. Per eseguire il movimento, porta le ginocchia verso il petto, ruotando il bacino per sollevare i glutei da terra. Contemporaneamente, fletti la colonna vertebrale portando le braccia sopra la testa in un movimento di crunch simultaneo. Dopo una breve pausa, ritorna alla posizione di partenza.' 
WHERE name = 'Cocoons';

UPDATE public.exercise_library 
SET name_it = 'Conan''s Wheel', description_it = 'Con il peso caricato, esegui una presa tipo ''Zurcher'' sull''estremità dell''attrezzo. Posiziona la barra nell''incavo del gomito e afferra i tuoi polsi. Cerca di non far gravare il peso sugli avambracci. Inizia sollevando il peso da terra. Mantieni una postura eretta e contratta mentre inizi a camminare, facendo passi brevi e veloci. Guarda avanti e leggermente verso l''alto mentre ruoti in cerchio. Non trattenere il respiro durante l''esercizio. Continua a camminare finché non completi uno o più giri.' 
WHERE name = 'Conan''s Wheel';

UPDATE public.exercise_library 
SET name_it = 'Concentration Curls', description_it = 'Siediti su una panca piana con un manubrio davanti a te, tra le gambe. Le gambe devono essere divaricate, le ginocchia flesse e i piedi ben appoggiati a terra. Afferra il manubrio con il braccio destro. Posiziona la parte posteriore del braccio destro contro la parte superiore dell''interno coscia destro. Ruota il palmo della mano verso l''esterno. Suggerimento: il braccio deve essere esteso e il manubrio sospeso da terra; questa è la posizione di partenza. Mantenendo la parte superiore del braccio ferma, fletti l''avambraccio verso l''alto contraendo il bicipite ed espirando. Solo l''avambraccio deve muoversi. Continua il movimento finché il bicipite non è completamente contratto e il manubrio si trova all''altezza della spalla. Suggerimento: nella parte alta del movimento, assicurati che il mignolo sia più in alto del pollice per una contrazione ottimale. Mantieni la contrazione per un secondo stringendo il bicipite. Inspira e torna lentamente alla posizione di partenza. Attenzione: evita movimenti oscillatori. Ripeti per il numero di ripetizioni consigliato, poi passa al braccio sinistro.' 
WHERE name = 'Concentration Curls';

UPDATE public.exercise_library 
SET name_it = 'Cross-Body Crunch', description_it = 'Sdraiati sulla schiena e piega le ginocchia a circa 60 gradi. Tieni i piedi piatti a terra e posiziona le mani leggermente dietro la testa; questa è la posizione di partenza. Esegui un crunch portando il gomito e la spalla destra verso l''interno, mentre contemporaneamente porti il ginocchio sinistro verso la spalla sinistra. Cerca di toccare il ginocchio con il gomito ed espira durante il movimento. Suggerimento: cerca di sollevare la spalla verso il ginocchio piuttosto che muovere solo il gomito, concentrandoti sulla contrazione degli addominali. Inspira mentre torni alla posizione di partenza e ripeti con il gomito sinistro e il ginocchio destro. Alterna fino al completamento delle ripetizioni previste.' 
WHERE name = 'Cross-Body Crunch';

UPDATE public.exercise_library 
SET name_it = 'Cross Body Hammer Curl', description_it = 'In piedi, con la schiena dritta e un manubrio in ogni mano, tieni le braccia lungo i fianchi con i palmi rivolti verso l''interno. Mantenendo i palmi rivolti verso l''interno e senza ruotare il braccio, fletti il manubrio destro verso la spalla sinistra ed espira. Tocca la spalla con il manubrio e mantieni la contrazione per un secondo. Inspira e abbassa lentamente il manubrio lungo lo stesso percorso. Ripeti con il braccio sinistro. Alterna i movimenti fino a completare il numero di ripetizioni consigliato per ogni braccio.' 
WHERE name = 'Cross Body Hammer Curl';

UPDATE public.exercise_library 
SET name_it = 'Cross Over - Con Elastici', description_it = 'Fissa un elastico da fitness a un supporto stabile. Dai le spalle al supporto, afferra le maniglie alle estremità dell''elastico e fai un passo in avanti per creare tensione. Solleva le braccia lateralmente, parallelamente al pavimento e perpendicolari al busto (le braccia e il busto devono formare una "T"), con i palmi rivolti in avanti. Le braccia devono essere tese con una leggera flessione dei gomiti; questa è la posizione di partenza. Mantenendo le braccia tese, portale davanti al petto con un movimento semicircolare ed espira, contraendo i pettorali. Mantieni la contrazione per un secondo. Inspira e torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Cross Over - With Bands';

UPDATE public.exercise_library 
SET name_it = 'Crossover Reverse Lunge', description_it = 'In piedi, con i piedi alla larghezza delle spalle; questa è la posizione di partenza. Esegui un affondo all''indietro facendo un passo indietro con un piede e flettendo le anche e il ginocchio della gamba anteriore. Contemporaneamente, ruota il busto sopra la gamba anteriore. Dopo una breve pausa, torna alla posizione di partenza e ripeti dall''altro lato, alternando.' 
WHERE name = 'Crossover Reverse Lunge';

UPDATE public.exercise_library 
SET name_it = 'Crucifix', description_it = 'Il crucifix consiste nel mantenere pesi lateralmente in posizione statica per un tempo prolungato. Sebbene si possa praticare con manubri, è preferibile usare attrezzi specifici come asce o martelli per una sensazione diversa. In piedi, solleva le braccia lateralmente tenendo gli attrezzi. Le braccia devono essere parallele al suolo. In gara, giudici o sensori segnalano quando il braccio scende sotto la linea parallela. Mantieni la posizione il più a lungo possibile. Solitamente, il carico dovrebbe essere tale da causare il cedimento entro 30-60 secondi.' 
WHERE name = 'Crucifix';

UPDATE public.exercise_library 
SET name_it = 'Crunch - Mani Oltre il Capo', description_it = 'Sdraiati a terra con la schiena piatta e le ginocchia flesse a un angolo di circa 60 gradi tra femorali e polpacci. Tieni i piedi piatti a terra e distendi le braccia oltre la testa con i palmi incrociati; questa è la posizione di partenza. Solleva la parte superiore del corpo in avanti portando le scapole appena fuori dal pavimento. Mantieni le braccia sempre allineate con testa, collo e spalle, senza spingerle in avanti. Espira durante questa fase del movimento e mantieni la contrazione per un secondo. Inspira e torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Crunch - Hands Overhead';

UPDATE public.exercise_library 
SET name_it = 'Crunch - Gambe su Fitball', description_it = 'Sdraiati sulla schiena con i piedi appoggiati su una fitball e le ginocchia flesse a 90 gradi. Tieni i piedi distanti 7-10 cm e punta le dita verso l''interno finché si toccano. Posiziona le mani leggermente ai lati della testa tenendo i gomiti chiusi. Suggerimento: non intrecciare le dita dietro la nuca. Spingi la parte bassa della schiena contro il pavimento per isolare meglio gli addominali; questa è la posizione di partenza. Solleva le spalle da terra e continua a spingere con la parte bassa della schiena. Le spalle dovrebbero staccarsi solo di circa 10 cm, mentre la parte bassa della schiena deve rimanere a terra. Espira durante il movimento. Contrai intensamente gli addominali nella parte alta e mantieni per un secondo. Suggerimento: concentrati su un movimento lento e controllato, evitando l''uso di slancio. Inspira e torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Crunch - Legs On Exercise Ball';

UPDATE public.exercise_library 
SET name_it = 'Crunches', description_it = 'Sdraiati sulla schiena con i piedi piatti a terra o appoggiati su una panca con le ginocchia flesse a 90 gradi. Se usi una panca, tieni i piedi distanti 7-10 cm con le punte rivolte verso l''interno. Posiziona le mani leggermente ai lati della testa, gomiti chiusi. Suggerimento: non intrecciare le dita dietro la nuca. Spingendo la parte bassa della schiena contro il pavimento per isolare gli addominali, inizia a sollevare le spalle. Continua a spingere con la parte bassa della schiena mentre contrai gli addominali ed espiri. Le spalle devono staccarsi da terra solo di circa 10 cm, mantenendo la zona lombare a contatto col suolo. Nella parte alta, contrai intensamente gli addominali per un secondo. Suggerimento: concentrati su un movimento lento e controllato, evitando di barare con lo slancio. Dopo la contrazione, torna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Crunches';

UPDATE public.exercise_library 
SET name_it = 'Cuban Press', description_it = 'In piedi, afferra un manubrio per mano con una presa prona. Solleva la parte superiore delle braccia finché sono parallele al pavimento, lasciando gli avambracci penzolare nella posizione "spaventapasseri"; questa è la posizione di partenza. Per iniziare il movimento, ruota esternamente le spalle per muovere la parte superiore del braccio di 180 gradi. Mantieni le braccia in posizione, ruotandole finché i polsi si trovano direttamente sopra i gomiti e gli avambracci sono perpendicolari al suolo. Ora distendi i gomiti spingendo i manubri verso l''alto, raddrizzando le braccia. Inspira e torna alla posizione di partenza invertendo i passaggi. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Cuban Press';

UPDATE public.exercise_library 
SET name_it = 'Dancer''s Stretch', description_it = 'Siediti a terra. Incrocia la gamba destra sopra la sinistra, mantenendo il ginocchio piegato. La gamba sinistra deve essere tesa e appoggiata a terra. Posiziona il braccio sinistro sulla gamba destra e la mano destra a terra. Ruota la parte superiore del corpo verso destra e mantieni la posizione per 10-20 secondi. Cambia lato.' 
WHERE name = 'Dancer''s Stretch';

UPDATE public.exercise_library 
SET name_it = 'Dead Bug', description_it = 'Sdraiati sulla schiena con le braccia distese verso il soffitto. Porta piedi, ginocchia e anche a 90 gradi. Espira con forza per abbassare la gabbia toracica e appiattire la schiena contro il pavimento, ruotando il bacino verso l''alto e contraendo i glutei. Mantieni questa posizione durante tutto il movimento: questa è la posizione di partenza. Inizia l''esercizio estendendo una gamba, distendendo ginocchio e anca fino a portare la gamba appena sopra il pavimento. Mantieni la posizione di zona lombare e bacino durante il movimento, evitando che la schiena si inarchi. Rimani in tensione e riporta la gamba nella posizione iniziale. Ripeti con il lato opposto, alternando fino al completamento della serie.' 
WHERE name = 'Dead Bug';

UPDATE public.exercise_library 
SET name_it = 'Deadlift con bande elastiche', description_it = 'Per lo stacco con bande corte, falle semplicemente passare attorno al bilanciere prima di iniziare e posizionaci i piedi all''interno. Per le bande lunghe, è necessario ancorarle a una base sicura, come manubri pesanti o un rack. Con i piedi e la presa ben saldi, fai un respiro profondo, abbassa le anche e piega le ginocchia finché gli stinchi non toccano il bilanciere. Guarda avanti, tieni il petto in fuori, la schiena inarcata e spingi sui talloni per sollevare il carico. Dopo che il bilanciere ha superato le ginocchia, tira energicamente indietro il bilanciere, stringendo le scapole mentre spingi le anche in avanti contro la sbarra. Abbassa il bilanciere piegandoti dalle anche e guidandolo verso il pavimento.' 
WHERE name = 'Deadlift with Bands';

UPDATE public.exercise_library 
SET name_it = 'Deadlift con catene', description_it = 'Puoi agganciare le catene alle estremità del bilanciere o semplicemente farle passare sopra la barra, in modo che il peso aumenti man mano che sollevi. Avvicinati al bilanciere in modo che sia centrato rispetto ai piedi. I piedi dovrebbero essere larghi quanto le anche. Piegati dalle anche per afferrare il bilanciere alla larghezza delle spalle, permettendo alle scapole di protarsi. Solitamente si utilizza una presa prona o una presa mista per le serie più pesanti. Con i piedi e la presa ben saldi, fai un respiro profondo, abbassa le anche e piega le ginocchia finché gli stinchi non toccano il bilanciere. Guarda avanti, tieni il petto in fuori, la schiena inarcata e spingi sui talloni per sollevare il carico. Dopo che il bilanciere ha superato le ginocchia, tira energicamente indietro, stringendo le scapole mentre spingi le anche in avanti contro la sbarra. Abbassa il bilanciere piegandoti dalle anche e guidandolo verso il pavimento.' 
WHERE name = 'Deadlift with Chains';

UPDATE public.exercise_library 
SET name_it = 'Distensioni su panca declinata con bilanciere', description_it = 'Fissa le gambe all''estremità della panca declinata e sdraiati lentamente. Utilizzando una presa di larghezza media (che crei un angolo di 90 gradi tra avambracci e braccia nel punto centrale del movimento), solleva il bilanciere dal rack e tienilo dritto sopra di te con le braccia tese, perpendicolari al pavimento. Questa è la posizione di partenza. Suggerimento: per proteggere la cuffia dei rotatori, fatti aiutare da uno spotter per staccare il bilanciere. Inspira e scendi lentamente fino a sentire il bilanciere sul petto basso. Dopo una pausa di un secondo, riporta il bilanciere alla posizione iniziale espirando e spingendo con i muscoli pettorali. Distendi le braccia, contrai il petto, mantieni la posizione per un secondo e riparti lentamente. Suggerimento: la fase di discesa dovrebbe durare almeno il doppio di quella di salita. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi il bilanciere sul rack.' 
WHERE name = 'Decline Barbell Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Decline Close-Grip Bench to Skull Crusher', description_it = 'Fissa le gambe all''estremità della panca declinata e sdraiati lentamente. Utilizzando una presa stretta (leggermente inferiore alla larghezza delle spalle), solleva il bilanciere dal rack e tienilo dritto sopra di te con le braccia tese e i gomiti chiusi, perpendicolari al pavimento. Questa è la posizione di partenza. Suggerimento: fatti aiutare da uno spotter. Inspira e abbassa il bilanciere verso il petto basso, tenendo i gomiti stretti. Espira e spingi il bilanciere verso l''alto usando i tricipiti, tornando alla posizione iniziale. Mantenendo la parte superiore delle braccia ferma, inspira e abbassa lentamente il bilanciere muovendo solo gli avambracci in un arco semicircolare finché la sbarra non tocca leggermente la fronte. Espira e contrai i tricipiti per riportare il bilanciere alla posizione iniziale. Ripeti i passaggi 3-6 per le ripetizioni raccomandate.' 
WHERE name = 'Decline Close-Grip Bench To Skull Crusher';

UPDATE public.exercise_library 
SET name_it = 'Crunch su panca declinata', description_it = 'Fissa le gambe all''estremità della panca declinata e sdraiati. Posiziona le mani leggermente ai lati della testa tenendo i gomiti chiusi. Suggerimento: non incrociare le dita dietro la nuca. Spingendo la zona lombare contro la panca per isolare meglio gli addominali, inizia a sollevare le spalle. Continua a spingere forte con la bassa schiena mentre contrai gli addominali ed espiri. Le spalle dovrebbero sollevarsi dalla panca solo di circa 10 centimetri, mantenendo la zona lombare aderente alla panca. In cima al movimento, contrai intensamente gli addominali per un secondo. Suggerimento: concentrati su un movimento lento e controllato, evita di usare lo slancio. Dopo la contrazione, inspira e torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Decline Crunch';

UPDATE public.exercise_library 
SET name_it = 'Distensioni su panca declinata con manubri', description_it = 'Fissa le gambe all''estremità della panca declinata e sdraiati con un manubrio in ogni mano appoggiato sulle cosce. I palmi sono rivolti l''uno verso l''altro. Una volta sdraiato, porta i manubri davanti a te alla larghezza delle spalle. Ruota i polsi in avanti in modo che i palmi siano rivolti lontano da te. Questa è la posizione di partenza. Espira e abbassa lentamente i pesi ai lati, mantenendo il pieno controllo. Suggerimento: gli avambracci devono essere sempre perpendicolari al pavimento. Espira e spingi i manubri verso l''alto usando i muscoli pettorali. Distendi le braccia, contrai il petto, mantieni la posizione per un secondo e riparti lentamente. Suggerimento: la fase di discesa dovrebbe durare almeno il doppio di quella di salita. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Decline Dumbbell Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Croci su panca declinata con manubri', description_it = 'Fissa le gambe all''estremità della panca declinata e sdraiati con un manubrio in ogni mano appoggiato sulle cosce. Una volta sdraiato, porta i manubri davanti a te alla larghezza delle spalle, con i palmi rivolti l''uno verso l''altro, braccia tese e perpendicolari al pavimento. Questa è la posizione di partenza. Con i gomiti leggermente piegati per evitare stress al tendine del bicipite, abbassa le braccia lateralmente con un ampio arco finché non senti lo stretching sul petto. Inspira durante questa fase. Suggerimento: le braccia devono rimanere ferme, il movimento deve avvenire solo nell''articolazione della spalla. Espira e torna alla posizione iniziale contraendo i pettorali. Suggerimento: segui lo stesso arco di movimento utilizzato per scendere. Mantieni la contrazione per un secondo in cima e ripeti per le ripetizioni prescritte.' 
WHERE name = 'Decline Dumbbell Flyes';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti su panca declinata con manubri', description_it = 'Fissa le gambe all''estremità della panca declinata e sdraiati con i manubri sulle cosce. Porta i manubri davanti a te alla larghezza delle spalle, con palmi rivolti l''uno verso l''altro, braccia tese e perpendicolari al pavimento. Questa è la posizione di partenza. Mantenendo la parte superiore delle braccia ferma e i gomiti stretti, inspira e abbassa lentamente i manubri muovendo gli avambracci in un arco semicircolare finché i pollici non sono vicini alle orecchie. Espira e contrai i tricipiti per sollevare i manubri e tornare alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Decline Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti con EZ bar su panca declinata', description_it = 'Assicurati le gambe all''estremità della panca declinata e sdraiati lentamente. Utilizzando una presa stretta (leggermente inferiore alla larghezza delle spalle), solleva il bilanciere EZ dal rack e tienilo dritto sopra di te con le braccia tese e i gomiti chiusi. Le braccia devono essere perpendicolari al pavimento. Questa sarà la posizione di partenza. Suggerimento: per proteggere la cuffia dei rotatori, è preferibile farsi assistere da uno spotter per staccare il bilanciere dal rack. Inspirando e mantenendo le braccia ferme, abbassa lentamente il bilanciere con un movimento semicircolare verso di te finché non sfiora la fronte. Espirando, torna alla posizione di partenza contraendo i tricipiti. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Decline EZ Bar Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Crunch obliqui su panca declinata', description_it = 'Assicurati le gambe all''estremità della panca declinata e sdraiati lentamente. Solleva la parte superiore del corpo finché il busto non forma un angolo di circa 35-45 gradi rispetto al pavimento. Posiziona una mano accanto alla testa e l''altra sulla coscia. Questa è la posizione di partenza. Solleva lentamente il busto ruotandolo verso sinistra. Continua a contrarre l''addome espirando finché il gomito destro non tocca il ginocchio sinistro. Mantieni la contrazione per un secondo. Suggerimento: concentrati sul tenere gli addominali tesi e sul controllare il movimento. Scendi lentamente inspirando. Dopo aver completato la serie su un lato, passa all''altro.' 
WHERE name = 'Decline Oblique Crunch';

UPDATE public.exercise_library 
SET name_it = 'Piegamenti declinati', description_it = 'Sdraiati a terra a pancia in giù e posiziona le mani a circa 90 cm di distanza, mantenendo il busto sollevato con le braccia tese. Appoggia i piedi su un rialzo o una panca. Questa è la posizione di partenza. Scendi verso il basso inspirando finché il petto non sfiora quasi il pavimento. Espira e spingi il corpo verso l''alto tornando alla posizione iniziale, contraendo i pettorali. Dopo una breve pausa nella posizione di massima contrazione, ripeti l''esercizio.' 
WHERE name = 'Decline Push-Up';

UPDATE public.exercise_library 
SET name_it = 'Crunch inversi su panca declinata', description_it = 'Sdraiati supino su una panca declinata e afferra la parte alta della panca con entrambe le mani. Mantieni le gambe parallele al pavimento usando gli addominali, tenendo ginocchia e piedi uniti. Suggerimento: le gambe devono essere completamente estese con una leggera flessione delle ginocchia. Questa è la posizione di partenza. Espirando, porta le gambe verso il busto ruotando il bacino all''indietro e sollevando i fianchi dalla panca. Alla fine del movimento le ginocchia toccheranno il petto. Mantieni la contrazione per un secondo e torna lentamente alla posizione iniziale inspirando.' 
WHERE name = 'Decline Reverse Crunch';

UPDATE public.exercise_library 
SET name_it = 'Panca declinata Smith machine', description_it = 'Posiziona una panca declinata sotto la Smith machine. Regola l''altezza del bilanciere in modo da poterlo raggiungere quando sei sdraiato con le braccia quasi completamente estese. Utilizzando una presa prona più ampia delle spalle, sblocca il bilanciere e tienilo sopra di te con le braccia tese. Questa è la posizione di partenza. Inspirando, abbassa il bilanciere in modo controllato piegando i gomiti finché non sfiorano il busto. Dopo una breve pausa, torna alla posizione di partenza estendendo i gomiti ed espirando. Al termine della serie, blocca il bilanciere sul rack.' 
WHERE name = 'Decline Smith Press';

UPDATE public.exercise_library 
SET name_it = 'Deficit Deadlift', description_it = 'Posiziona una piattaforma o dei dischi su cui stare in piedi (altezza 2,5-7,5 cm). Avvicinati al bilanciere in modo che sia centrato sopra i piedi, posizionati alla larghezza delle anche. Fletti le anche per afferrare il bilanciere alla larghezza delle spalle. Usa una presa prona o alternata per carichi pesanti. Con i piedi e la presa ben saldi, fai un respiro profondo, abbassa i fianchi e piega le ginocchia finché le tibie non toccano il bilanciere. Guarda avanti, tieni il petto alto e la schiena inarcata, e spingi attraverso i talloni per sollevare il peso. Dopo che il bilanciere ha superato le ginocchia, tira energicamente indietro, contraendo le scapole e spingendo i fianchi in avanti. Abbassa il bilanciere controllando il movimento fino al pavimento.' 
WHERE name = 'Deficit Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Depth Jump Leap', description_it = 'Per questo esercizio sono necessari due box, uno alto 30-40 cm e l''altro 55-65 cm. Stai sul box più basso con i piedi uniti leggermente oltre il bordo. Posiziona il secondo box a circa 60-90 cm di distanza di fronte a te. Scendi dal primo box e, appena tocchi terra, sfrutta il rimbalzo per saltare immediatamente. Spingi verso l''alto e in avanti con la massima intensità, usando le braccia e l''estensione completa del corpo per saltare sul box più alto. Assorbi l''impatto con le gambe all''atterraggio.' 
WHERE name = 'Depth Jump Leap';

UPDATE public.exercise_library 
SET name_it = 'Dip Machine', description_it = 'Siediti sulla dip machine, seleziona il carico e afferra saldamente le impugnature. Tieni i gomiti stretti lungo i fianchi per enfatizzare il lavoro dei tricipiti. I gomiti devono essere piegati a 90 gradi. Contraendo i tricipiti, estendi le braccia verso il basso espirando. Suggerimento: nella parte inferiore del movimento, mantieni una leggera flessione delle braccia per preservare la tensione muscolare. Torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dip Machine';

UPDATE public.exercise_library 
SET name_it = 'Dips - Versione per pettorali', description_it = 'Utilizza le parallele. Per la posizione di partenza, mantieni il corpo sospeso con le braccia tese. Inspirando, scendi lentamente inclinando il busto in avanti di circa 30 gradi e tenendo i gomiti leggermente aperti finché non senti una leggera tensione al petto. Una volta percepito l''allungamento, usa i pettorali per riportare il corpo nella posizione di partenza espirando. Suggerimento: contrai i pettorali per un secondo nella parte alta del movimento. Ripeti per le ripetizioni prescritte.' 
WHERE name = 'Dips - Chest Version';

UPDATE public.exercise_library 
SET name_it = 'Dips - Versione per tricipiti', description_it = 'Per la posizione di partenza, mantieni il corpo sospeso con le braccia quasi tese sopra le parallele. Inspira e scendi lentamente verso il basso. Il busto deve rimanere verticale e i gomiti vicini al corpo per concentrare lo sforzo sui tricipiti. Scendi finché non si forma un angolo di 90 gradi tra braccio e avambraccio. Espira e spingi il corpo verso l''alto usando la forza dei tricipiti per tornare alla posizione iniziale. Ripeti per le ripetizioni prescritte.' 
WHERE name = 'Dips - Triceps Version';

UPDATE public.exercise_library 
SET name_it = 'Donkey Calf Raises', description_it = 'Per questo esercizio è necessaria una macchina per Donkey Calf Raise. Posiziona la parte bassa della schiena e i fianchi sotto la leva imbottita fornita. L''area dell''osso sacro dovrebbe essere quella a contatto con l''imbottitura. Poggia entrambe le braccia sulle maniglie laterali e posiziona l''avampiede sul blocco per polpacci, lasciando i talloni sospesi. Allinea le punte dei piedi in avanti, verso l''interno o verso l''esterno, a seconda della zona che desideri colpire, e distendi le ginocchia senza bloccarle. Questa è la posizione di partenza. Solleva i talloni espirando, estendendo le caviglie il più in alto possibile e contraendo il polpaccio. Assicurati che le ginocchia rimangano immobili per tutto il movimento. Non deve esserci alcuna flessione. Mantieni la posizione di contrazione per un secondo prima di tornare verso il basso. Torna lentamente alla posizione iniziale inspirando, abbassando i talloni e flettendo le caviglie fino a sentire i polpacci allungati. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Donkey Calf Raises';

UPDATE public.exercise_library 
SET name_it = 'Double Kettlebell Alternating Hang Clean', description_it = 'Posiziona due kettlebell tra i piedi. Per assumere la posizione di partenza, spingi il bacino all''indietro e guarda dritto davanti a te. Esegui un Clean con un kettlebell portandolo alla spalla, mantenendo la presa sull''altro kettlebell. Con un movimento fluido, abbassa il kettlebell superiore mentre spingi verso l''alto quello inferiore.' 
WHERE name = 'Double Kettlebell Alternating Hang Clean';

UPDATE public.exercise_library 
SET name_it = 'Double Kettlebell Jerk', description_it = 'Impugna un kettlebell per il manico in ogni mano. Esegui un Clean portando i kettlebell alle spalle estendendo gambe e anche mentre li tiri verso l''alto. Ruota i polsi durante il movimento in modo che i palmi siano rivolti in avanti. Questa è la tua posizione di partenza. Esegui un leggero squat piegando le ginocchia e mantenendo il busto eretto. Inverti immediatamente la direzione, spingendo sui talloni, come se saltassi, per creare slancio. Contemporaneamente, spingi i kettlebell sopra la testa fino a bloccare i gomiti, usando lo slancio del corpo per sollevare i pesi. Riporta i piedi a terra in posizione affondata (split), con un piede avanti e uno indietro. Mantenendo i pesi sopra la testa, torna in posizione eretta unendo i piedi. Abbassa i pesi per eseguire la ripetizione successiva.' 
WHERE name = 'Double Kettlebell Jerk';

UPDATE public.exercise_library 
SET name_it = 'Double Kettlebell Push Press', description_it = 'Esegui un Clean con due kettlebell portandoli alle spalle. Esegui un breve squat e inverte il movimento rapidamente. Sfrutta lo slancio delle gambe per spingere i kettlebell sopra la testa. Una volta che le braccia sono completamente distese, abbassa i kettlebell alle spalle e ripeti.' 
WHERE name = 'Double Kettlebell Push Press';

UPDATE public.exercise_library 
SET name_it = 'Double Kettlebell Snatch', description_it = 'Posiziona due kettlebell dietro i piedi. Piega le ginocchia e spingi il bacino indietro per afferrarli. Fai oscillare i kettlebell tra le gambe con forza e inverte la direzione. Spingi con le anche e porta i kettlebell sopra la testa bloccandoli in un unico movimento ininterrotto.' 
WHERE name = 'Double Kettlebell Snatch';

UPDATE public.exercise_library 
SET name_it = 'Double Kettlebell Windmill', description_it = 'Posiziona un kettlebell davanti al piede anteriore, quindi esegui un Clean e Press con il braccio opposto per portare l''altro kettlebell sopra la testa. Ruota il polso durante il movimento in modo che il palmo sia rivolto in avanti. Mantenendo il kettlebell bloccato sopra la testa, spingi il bacino verso il lato del kettlebell sollevato. Ruota i piedi di 45 gradi rispetto al braccio che sostiene il peso. Piegandoti lateralmente all''altezza dell''anca e spingendo il bacino in fuori, scendi lentamente finché non riesci a raccogliere il kettlebell da terra. Tieni sempre gli occhi fissi sul kettlebell sopra la testa. Fermati per un secondo dopo aver raccolto il peso e inverte il movimento per tornare alla posizione iniziale.' 
WHERE name = 'Double Kettlebell Windmill';

UPDATE public.exercise_library 
SET name_it = 'Double Leg Butt Kick', description_it = 'Parti in piedi con le ginocchia leggermente flesse. Esegui un rapido e breve squat, flettendo anche e ginocchia, ed estendi immediatamente le gambe per saltare raggiungendo la massima altezza verticale. Durante la salita, porta i talloni verso i glutei flettendo le ginocchia. Termina il movimento atterrando con le ginocchia leggermente flesse, usando le gambe per assorbire l''impatto.' 
WHERE name = 'Double Leg Butt Kick';

UPDATE public.exercise_library 
SET name_it = 'Downward Facing Balance', description_it = 'Sdraiati a pancia in giù sopra una palla da fitness (Swiss ball). Mentre sei appoggiato con lo stomaco sulla palla, cammina con le mani in avanti sul pavimento e solleva le gambe, distendendo gomiti e ginocchia.' 
WHERE name = 'Downward Facing Balance';

UPDATE public.exercise_library 
SET name_it = 'Drag Curl', description_it = 'Afferra un bilanciere con una presa supinata (palmi rivolti in avanti) e tieni i gomiti vicini al busto e rivolti all''indietro. Questa è la posizione di partenza. Espirando, solleva il bilanciere mantenendo i gomiti verso l''indietro e trascinando la sbarra a contatto con il torso. Consiglio: non tenere i gomiti bloccati ai fianchi, ma portali leggermente indietro. Inoltre, non sollevare le spalle. Torna lentamente alla posizione di partenza mantenendo sempre il bilanciere a contatto con il torso. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Drag Curl';

UPDATE public.exercise_library 
SET name_it = 'Drop Push', description_it = 'Posiziona dei box bassi o altre piattaforme a una distanza di 60-90 cm l''una dall''altra. Mettiti in posizione di push-up tra di essi, sostenendoti con le mani sui box. Mantenendo una buona postura, lasciati scendere dalle piattaforme spingendo verso l''alto e spostando le mani alla larghezza delle spalle, ammortizzando l''atterraggio attraverso le braccia.' 
WHERE name = 'Drop Push';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Alternate Bicep Curl', description_it = 'In piedi (busto eretto) con un manubrio in ogni mano lungo i fianchi. I gomiti devono essere vicini al busto e i palmi delle mani rivolti verso le cosce. Mantenendo la parte superiore del braccio ferma, solleva il manubrio destro ruotando il palmo finché non è rivolto in avanti. Continua a contrarre il bicipite espirando finché non è completamente contratto e il manubrio è all''altezza della spalla. Mantieni la posizione di contrazione per un secondo strizzando il bicipite. Consiglio: solo gli avambracci devono muoversi. Torna lentamente alla posizione iniziale inspirando, ricordandoti di ruotare i palmi verso le cosce durante la discesa. Ripeti con la mano sinistra per completare una ripetizione. Alterna in questo modo per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dumbbell Alternate Bicep Curl';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Bench Press', description_it = 'Sdraiati su una panca piana con un manubrio in ogni mano poggiato sulle cosce. I palmi sono rivolti l''uno verso l''altro. Usando le cosce come spinta, solleva i manubri uno alla volta fino a tenerli davanti a te alla larghezza delle spalle. Ruota i polsi in avanti in modo che i palmi siano rivolti in avanti. I manubri devono trovarsi ai lati del petto, con braccio e avambraccio a formare un angolo di 90 gradi. Questa è la posizione di partenza. Espirando, spingi i manubri verso l''alto usando i pettorali. Blocca le braccia in alto, contrai il petto, mantieni per un secondo e scendi lentamente. Consiglio: la discesa dovrebbe durare circa il doppio della salita. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Dumbbell Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Bench Press con Presa Neutra', description_it = 'Afferra un manubrio per mano e sdraiati su una panca piana. Piedi ben piantati a terra e scapole addotte. Mantenendo una presa neutra (palmi rivolti l''uno verso l''altro), inizia con le braccia distese sopra di te, perpendicolari al pavimento. Questa è la posizione di partenza. Inizia il movimento flettendo i gomiti e abbassando le braccia lateralmente. Scendi finché i manubri sono all''altezza del busto. Fai una pausa, quindi estendi i gomiti tornando alla posizione di partenza.' 
WHERE name = 'Dumbbell Bench Press with Neutral Grip';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Bicep Curl', description_it = 'In piedi, schiena dritta, con un manubrio in ogni mano lungo i fianchi. Tieni i gomiti vicini al busto e ruota i palmi in avanti. Questa è la posizione di partenza. Mantenendo ferma la parte superiore del braccio, espira e solleva i pesi contraendo i bicipiti. Continua a sollevare finché i bicipiti sono completamente contratti e i manubri sono all''altezza delle spalle. Mantieni la contrazione per una breve pausa strizzando i muscoli. Quindi, inspira e torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dumbbell Bicep Curl';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Clean', description_it = 'In piedi, con un manubrio in ogni mano e piedi alla larghezza delle spalle. Abbassa i pesi verso il pavimento flettendo anche e ginocchia, spingendo il bacino all''indietro. Questa è la posizione di partenza. Per iniziare il movimento, dai una spinta esplosiva verso l''alto estendendo anche, ginocchia e caviglie per accelerare i pesi. Mantieni una presa neutra e le braccia tese finché non raggiungi la massima estensione. Dopo l''estensione, fletti nuovamente anche e ginocchia per ricevere il peso in posizione di squat. Permetti alle braccia di flettersi, guidando i manubri verso le spalle. Dalla posizione di squat, estendi anche e ginocchia per finire in piedi con i pesi sulle spalle.' 
WHERE name = 'Dumbbell Clean';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Floor Press', description_it = 'Sdraiati a terra tenendo i manubri in mano. Le ginocchia possono essere piegate. Inizia con i pesi completamente estesi sopra di te. Abbassa i pesi finché la parte superiore del braccio tocca il pavimento. Puoi tenere i gomiti stretti per enfatizzare tricipiti e forza, oppure angolare le braccia verso l''esterno per focalizzarti sul petto. Fai una pausa sul fondo, quindi riporta i pesi verso l''alto estendendo i gomiti.' 
WHERE name = 'Dumbbell Floor Press';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Flyes', description_it = 'Sdraiati su una panca piana con un manubrio per mano sulle cosce. Solleva i manubri uno alla volta fino a tenerli davanti a te alla larghezza delle spalle, con i palmi rivolti l''uno verso l''altro. Solleva i manubri come se stessi facendo una distensione, ma fermati poco prima del blocco articolare; questa è la posizione di partenza. Con una leggera flessione dei gomiti per proteggere il tendine del bicipite, abbassa le braccia lateralmente descrivendo un arco ampio finché non senti allungare il petto. Inspira durante la discesa. Consiglio: le braccia devono restare ferme, il movimento deve avvenire solo dall''articolazione della spalla. Torna alla posizione iniziale contraendo i pettorali ed espirando. Mantieni la contrazione per un secondo e ripeti.' 
WHERE name = 'Dumbbell Flyes';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Incline Row', description_it = 'Con una presa neutra, appoggiati a una panca inclinata. Prendi un manubrio in ogni mano con presa neutra, iniziando con le braccia distese. Questa è la posizione di partenza. Retrai le scapole e fletti i gomiti per remare portando i manubri ai lati del busto. Fai una pausa in cima al movimento e torna alla posizione di partenza.' 
WHERE name = 'Dumbbell Incline Row';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Incline Shoulder Raise', description_it = 'Siediti su una panca inclinata tenendo un manubrio per mano sulle cosce. Solleva le gambe per portare i pesi alle spalle e sdraiati all''indietro. Posiziona i manubri sopra le spalle con le braccia tese, perpendicolari al pavimento, palmi rivolti in avanti e nocche verso il soffitto. Questa è la posizione di partenza. Mantenendo le braccia tese e bloccate, solleva i manubri alzando le spalle dalla panca mentre espiri. Torna alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dumbbell Incline Shoulder Raise';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Lunges', description_it = 'In piedi, busto eretto, con due manubri in mano lungo i fianchi. Questa è la posizione di partenza. Fai un passo in avanti con la gamba destra (circa 60 cm) e abbassa il busto mantenendo l''equilibrio e il torso dritto. Inspira durante la discesa. Nota: non permettere al ginocchio di superare la punta del piede per non sovraccaricare l''articolazione. La tibia anteriore deve rimanere perpendicolare al suolo. Spingendo principalmente sul tallone, torna alla posizione iniziale espirando. Ripeti per le ripetizioni consigliate e poi esegui con la gamba sinistra.' 
WHERE name = 'Dumbbell Lunges';

UPDATE public.exercise_library 
SET name_it = 'Alzate laterali posteriori su panca a un braccio', description_it = 'Impugnando un manubrio in una mano, sdraiati prono su una panca regolabile leggermente inclinata (circa 15 gradi rispetto al pavimento). L''altra mano può essere utilizzata per fare presa sulla gamba della panca per maggiore stabilità. Posiziona il palmo della mano che impugna il manubrio in posizione neutra (palmi rivolti verso il busto) mantenendo il braccio esteso con il gomito leggermente piegato. Questa sarà la posizione di partenza. Espirando, solleva il braccio con il manubrio lateralmente finché il gomito non è all''altezza della spalla e il braccio risulta approssimativamente parallelo al pavimento. Consiglio: mantieni il braccio perpendicolare al busto e ben esteso durante tutto il movimento. Mantieni la contrazione per un secondo nel punto di massima elevazione. Inspira e abbassa lentamente il manubrio verso la posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dumbbell Lying One-Arm Rear Lateral Raise';

UPDATE public.exercise_library 
SET name_it = 'Pronazione con manubrio su panca', description_it = 'Sdraiati prono su una panca piana, con un braccio che impugna un manubrio e l''altra mano piegata sulla panca per appoggiarvi la testa. Piega il gomito del braccio che sostiene il manubrio in modo da creare un angolo di 90 gradi tra braccio e avambraccio. Ora solleva la parte superiore del braccio in modo che l''avambraccio sia perpendicolare al pavimento e la parte superiore del braccio sia perpendicolare al busto. Consiglio: la parte superiore del braccio deve essere parallela al pavimento e formare un angolo di 90 gradi con il busto. Questa è la posizione di partenza. Espirando, ruota esternamente l''avambraccio sollevando il manubrio in avanti, mantenendo l''angolo di 90 gradi tra braccio e avambraccio. Continua la rotazione esterna finché l''avambraccio non è parallelo al pavimento. Mantieni la contrazione per un secondo. Inspira e torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dumbbell Lying Pronation';

UPDATE public.exercise_library 
SET name_it = 'Alzate laterali posteriori su panca', description_it = 'Impugnando un manubrio per mano, sdraiati prono su una panca regolabile leggermente inclinata (circa 15 gradi rispetto al suolo). Posiziona i palmi delle mani in modo neutro (palmi rivolti verso il busto) e mantieni le braccia estese con i gomiti leggermente piegati. Questa è la posizione di partenza. Espirando, solleva le braccia lateralmente finché i gomiti non sono all''altezza delle spalle e le braccia sono approssimativamente parallele al pavimento. Consiglio: mantieni le braccia perpendicolari al busto ed estese durante tutto il movimento. Mantieni la contrazione per un secondo nel punto di massima elevazione. Inspira e abbassa lentamente i manubri alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato, quindi passa all''altro braccio.' 
WHERE name = 'Dumbbell Lying Rear Lateral Raise';

UPDATE public.exercise_library 
SET name_it = 'Supinazione con manubrio su panca', description_it = 'Sdraiati su un fianco su una panca piana, con un braccio che impugna un manubrio e l''altra mano piegata sulla panca per appoggiarvi la testa. Piega il gomito del braccio che sostiene il manubrio per creare un angolo di 90 gradi tra braccio e avambraccio. Ora solleva la parte superiore del braccio in modo che l''avambraccio sia parallelo al pavimento e perpendicolare al busto (Consiglio: l''avambraccio deve trovarsi direttamente davanti a te). La parte superiore del braccio rimane ferma lungo il busto e deve essere parallela al pavimento. Questa è la posizione di partenza. Espirando, ruota esternamente l''avambraccio sollevando il manubrio con un movimento semicircolare, mantenendo l''angolo di 90 gradi. Continua la rotazione esterna finché l''avambraccio non è perpendicolare al pavimento e il busto è rivolto verso il soffitto. Mantieni la contrazione per un secondo. Inspira e torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato e poi cambia braccio.' 
WHERE name = 'Dumbbell Lying Supination';

UPDATE public.exercise_library 
SET name_it = 'Military press con manubrio a un braccio', description_it = 'Afferra un manubrio e siediti su una panca con schienale, oppure resta in piedi con la schiena dritta. Porta il manubrio all''altezza della spalla (Clean). L''altro braccio può essere tenuto esteso lateralmente, lungo il fianco o facendo presa su una superficie fissa. Ruota il polso in modo che il palmo sia rivolto in avanti. Questa è la posizione di partenza. Espirando, spingi il manubrio verso l''alto finché il braccio non è completamente esteso. Dopo una pausa di un secondo, inspira e torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato e cambia braccio.' 
WHERE name = 'Dumbbell One-Arm Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti sopra la testa a un braccio', description_it = 'Afferra un manubrio da seduto o in piedi. Porta il manubrio all''altezza della spalla e distendi il braccio sopra la testa in modo che sia perpendicolare al pavimento e vicino alla testa. L''altra mano può sostenere il braccio che lavora, essere tenuta lungo il fianco o fare presa su un supporto. Ruota il polso in modo che il palmo sia rivolto in avanti e il mignolo verso il soffitto. Questa è la posizione di partenza. Inspira e abbassa lentamente il manubrio dietro la testa mantenendo fermo il braccio. Fermati quando i tricipiti sono completamente distesi. Espirando, torna alla posizione iniziale contraendo i tricipiti. Consiglio: solo l''avambraccio deve muoversi; la parte superiore del braccio deve restare immobile accanto alla testa. Ripeti per le ripetizioni previste e cambia braccio.' 
WHERE name = 'Dumbbell One-Arm Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Tirate al mento a un braccio con manubrio', description_it = 'In piedi, schiena dritta, impugna un manubrio con il braccio esteso davanti a te, gomito leggermente flesso. Il manubrio deve poggiare sulla coscia con il palmo rivolto verso di essa. Questa è la posizione di partenza. L''altra mano può essere tenuta lungo il fianco o su un supporto. Espirando, utilizza la spalla laterale per sollevare il manubrio, mantenendolo vicino al corpo, finché non è quasi allineato con il mento. Consiglio: il movimento deve essere guidato dal gomito, che deve rimanere sempre più in alto dell''avambraccio. Tieni il busto fermo e fai una pausa di un secondo nel punto più alto. Inspira e abbassa lentamente il manubrio alla posizione iniziale. Ripeti per le ripetizioni previste e cambia braccio.' 
WHERE name = 'Dumbbell One-Arm Upright Row';

UPDATE public.exercise_library 
SET name_it = 'Curl su panca inclinata (prono)', description_it = 'Afferra un manubrio per mano e sdraiati prono su una panca inclinata con le spalle vicino alla parte superiore. Le ginocchia possono poggiare sulla seduta o le gambe possono stare divaricate ai lati. Lascia che le braccia pendano naturalmente verso il basso, perpendicolari al pavimento. Mantieni i gomiti stretti lungo i fianchi e rivolgi i palmi in avanti. Questa è la posizione di partenza. Solleva i manubri contraendo i bicipiti finché le braccia non sono completamente flesse. Espira durante il movimento e assicurati che si muovano solo gli avambracci; la parte superiore delle braccia deve rimanere ferma. Abbassa i manubri fino alla completa estensione. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dumbbell Prone Incline Curl';

UPDATE public.exercise_library 
SET name_it = 'Alzate laterali con manubri', description_it = 'In piedi, schiena dritta, impugna un manubrio per mano con le braccia distese lungo i fianchi e i gomiti leggermente piegati. Il manubrio deve trovarsi vicino alle cosce con i palmi rivolti all''indietro. Questa è la posizione di partenza. Espirando, utilizza le spalle laterali per sollevare i manubri lateralmente finché non sono quasi allineati con il mento. Consiglio: il movimento deve essere guidato dai gomiti, che devono rimanere sempre più in alto degli avambracci. Mantieni il busto fermo e fai una pausa di un secondo nel punto più alto. Inspira e abbassa lentamente i manubri alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Dumbbell Raise';

UPDATE public.exercise_library 
SET name_it = 'Affondi posteriori con manubri', description_it = 'In piedi, busto eretto, impugna due manubri lungo i fianchi. Questa è la posizione di partenza. Fai un passo indietro con la gamba destra per circa 60 cm e abbassa il corpo, mantenendo il busto verticale ed equilibrato. Inspira durante la discesa. Consiglio: non superare la punta del piede con il ginocchio anteriore per evitare stress articolare. Mantieni la tibia anteriore perpendicolare al suolo. Un affondo lungo enfatizza il grande gluteo, un affondo breve i quadricipiti. Espirando, spingi e torna alla posizione iniziale. Consiglio: spingi sull''avampiede per enfatizzare i quadricipiti, usa i talloni per focalizzarti sui glutei. Ripeti con la gamba opposta.' 
WHERE name = 'Dumbbell Rear Lunge';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Scaption', description_it = 'Questo esercizio correttivo rinforza i muscoli stabilizzatori della scapola. Impugna un peso leggero in ogni mano, lasciando le braccia distese lungo i fianchi con i pollici rivolti verso l''alto. Inizia il movimento sollevando le braccia frontalmente, inclinate di circa 30 gradi rispetto al centro. Mantieni le braccia completamente distese durante l''esecuzione. Continua fino a quando le braccia sono parallele al suolo, quindi torna alla posizione iniziale.' 
WHERE name = 'Dumbbell Scaption';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Seated Box Jump', description_it = 'Posiziona un box a poca distanza da una panca. Impugna un manubrio al petto con entrambe le mani e siediti sulla panca rivolto verso il box; questa è la posizione di partenza. Appoggia saldamente i piedi a terra, inclinati in avanti ed estendi anche e ginocchia per saltare verso l''alto e in avanti. Atterra sul box con entrambi i piedi, ammortizzando l''impatto flettendo anche e ginocchia. Scendi e torna nella posizione iniziale.' 
WHERE name = 'Dumbbell Seated Box Jump';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Seated One-Leg Calf Raise', description_it = 'Posiziona un blocco o rialzo a circa 30 cm da una panca piana. Siediti sulla panca e posiziona un manubrio sulla parte superiore della coscia sinistra, circa 7-8 cm sopra il ginocchio. Appoggia l''avampiede sinistro sul blocco: questa è la posizione di partenza. Espirando, solleva il tallone il più in alto possibile contraendo il polpaccio. Mantieni la contrazione per un secondo. Torna lentamente alla posizione iniziale, allungando il muscolo il più possibile. Ripeti per il numero di ripetizioni prescritte, quindi cambia gamba.' 
WHERE name = 'Dumbbell Seated One-Leg Calf Raise';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Shoulder Press', description_it = 'Seduto su una panca con schienale (o panca per military press) e un manubrio in ogni mano, appoggia i manubri sulle cosce. Portali all''altezza delle spalle uno alla volta, usando la spinta delle cosce per facilitare il movimento. Ruota i polsi in modo che i palmi siano rivolti in avanti: questa è la posizione di partenza. Espira e spingi i manubri verso l''alto fino a farli toccare. Dopo una breve pausa in contrazione, scendi lentamente espirando fino alla posizione iniziale. Ripeti per le ripetizioni consigliate.' 
WHERE name = 'Dumbbell Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Shrug', description_it = 'In piedi, con la schiena dritta e un manubrio per mano (palmi rivolti verso il busto), braccia distese lungo i fianchi. Espirando, solleva i manubri elevando le spalle il più in alto possibile. Mantieni la contrazione per un secondo. Nota: le braccia devono rimanere sempre tese; evita di usare i bicipiti per sollevare il peso. Solo le spalle devono muoversi verticalmente. Abbassa i manubri nella posizione originale e ripeti.' 
WHERE name = 'Dumbbell Shrug';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Side Bend', description_it = 'In piedi, con i piedi alla larghezza delle spalle, tieni un manubrio nella mano sinistra (palmo rivolto verso il busto) e la mano destra appoggiata sul fianco. Questa è la posizione di partenza. Mantenendo la schiena dritta e lo sguardo in avanti, fletti il busto verso destra il più possibile, inspirando durante il movimento. Mantieni la posizione per un secondo e torna su espirando. Nota: mantieni il resto del corpo immobile. Ripeti il movimento piegandoti a sinistra. Esegui il numero di ripetizioni consigliato e poi cambia mano.' 
WHERE name = 'Dumbbell Side Bend';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Squat', description_it = 'In piedi, con un manubrio in ogni mano (palmi rivolti verso le gambe). Posiziona i piedi alla larghezza delle spalle con le punte leggermente extra-ruotate. Mantieni la testa alta e la schiena dritta. Inizia a scendere lentamente flettendo le ginocchia, mantenendo il busto eretto. Scendi finché le cosce sono parallele al suolo. Nota: le ginocchia non devono superare la linea immaginaria perpendicolare alle punte dei piedi per evitare stress articolare. Risali espirando, spingendo principalmente sui talloni, fino alla posizione iniziale.' 
WHERE name = 'Dumbbell Squat';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Squat To A Bench', description_it = 'In piedi davanti a una panca, impugnando un manubrio per mano lungo i fianchi. Posiziona i piedi alla larghezza delle spalle con le punte leggermente extra-ruotate. Mantieni la testa alta e la schiena dritta. Scendi lentamente flettendo le ginocchia, mantenendo la postura eretta, finché non tocchi leggermente la panca dietro di te; inspira durante la discesa. Nota: le ginocchia non devono superare la linea delle punte dei piedi. Risali espirando, spingendo sui talloni, fino alla posizione iniziale.' 
WHERE name = 'Dumbbell Squat To A Bench';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Step Ups', description_it = 'In piedi, impugnando un manubrio per mano lungo i fianchi. Appoggia il piede destro sulla piattaforma rialzata. Sali sulla piattaforma estendendo anca e ginocchio della gamba destra, usando la forza del tallone per sollevare il corpo e portare anche il piede sinistro sulla piattaforma. Espira durante lo sforzo. Scendi con il piede sinistro flettendo anca e ginocchio destro mentre inspiri. Torna nella posizione di partenza con entrambi i piedi a terra. Ripeti con la gamba destra per le ripetizioni consigliate, poi esegui con la sinistra.' 
WHERE name = 'Dumbbell Step Ups';

UPDATE public.exercise_library 
SET name_it = 'Dumbbell Tricep Extension - Pronated Grip', description_it = 'Sdraiato su una panca piana, tieni due manubri direttamente sopra le spalle. Le braccia devono essere completamente distese e formare un angolo di 90 gradi rispetto al busto e al pavimento. I palmi devono essere rivolti in avanti e i gomiti chiusi verso l''interno; questa è la posizione di partenza. Inspira e abbassa lentamente i manubri finché non sono vicini alle orecchie, mantenendo le braccia ferme e i gomiti stretti. Espira e usa i tricipiti per riportare i pesi nella posizione iniziale.' 
WHERE name = 'Dumbbell Tricep Extension -Pronated Grip';

UPDATE public.exercise_library 
SET name_it = 'Stretching dinamico per la schiena', description_it = 'In piedi, con i piedi alla larghezza delle spalle. Questa è la posizione di partenza. Tenendo le braccia tese, falle oscillare verso l''alto davanti a te per 5-10 volte, aumentando ogni volta l''ampiezza del movimento finché le braccia non arrivano sopra la testa.' 
WHERE name = 'Dynamic Back Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching dinamico per il petto', description_it = 'In piedi, con le mani unite e le braccia distese direttamente davanti a te. Questa è la posizione di partenza. Tenendo le braccia tese, muovile rapidamente all''indietro il più possibile e riportale nella posizione iniziale, come in un movimento di battito di mani esagerato. Ripeti 5-10 volte, aumentando la velocità durante l''esecuzione.' 
WHERE name = 'Dynamic Chest Stretch';

UPDATE public.exercise_library 
SET name_it = 'Curl con bilanciere EZ', description_it = 'In piedi, impugna un bilanciere EZ sulla parte esterna più larga. I palmi delle mani devono essere rivolti in avanti e leggermente inclinati verso l''interno a causa della forma del bilanciere. Tieni i gomiti vicini al busto. Questa è la posizione di partenza. Ora, mantenendo le braccia ferme, espira e solleva il bilanciere flettendo i bicipiti. Concentrati sul muovere solo gli avambracci. Continua a sollevare il peso finché i bicipiti non sono completamente contratti e il bilanciere è all''altezza delle spalle. Mantieni la posizione di massima contrazione per un istante, strizzando i bicipiti. Quindi inspira e abbassa lentamente il bilanciere fino alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'EZ-Bar Curl';

UPDATE public.exercise_library 
SET name_it = 'Skullcrusher con bilanciere EZ', description_it = 'Utilizzando un''impugnatura stretta, solleva il bilanciere EZ e tienilo con i gomiti stretti mentre sei sdraiato su una panca. Le braccia devono essere perpendicolari al pavimento. Questa è la posizione di partenza. Mantenendo la parte superiore delle braccia ferma, abbassa il bilanciere flettendo i gomiti. Inspira durante questa fase del movimento. Fermati quando il bilanciere è direttamente sopra la fronte. Solleva nuovamente il bilanciere nella posizione di partenza estendendo il gomito ed espirando. Ripeti.' 
WHERE name = 'EZ-Bar Skullcrusher';

UPDATE public.exercise_library 
SET name_it = 'Circonduzioni dei gomiti', description_it = 'Seduto o in piedi con i piedi leggermente separati. Posiziona le mani sulle spalle con i gomiti all''altezza delle spalle e rivolti verso l''esterno. Disegna lentamente un cerchio con i gomiti. Espira all''inizio del cerchio e inspira mentre lo completi.' 
WHERE name = 'Elbow Circles';

UPDATE public.exercise_library 
SET name_it = 'Gomito al ginocchio', description_it = 'Sdraiato sul pavimento, incrocia la gamba destra sopra il ginocchio sinistro piegato. Incrocia le mani dietro la nuca, partendo con le scapole a contatto con il suolo. Questa è la posizione di partenza. Esegui il movimento flettendo la colonna vertebrale e ruotando il busto per portare il gomito sinistro verso il ginocchio destro. Torna alla posizione di partenza e ripeti il movimento per il numero di ripetizioni desiderato prima di cambiare lato.' 
WHERE name = 'Elbow to Knee';

UPDATE public.exercise_library 
SET name_it = 'Gomiti all''indietro', description_it = 'In piedi, in posizione eretta. Metti entrambe le mani sulla parte bassa della schiena, con le dita rivolte verso il basso e i gomiti verso l''esterno. Quindi, tira delicatamente i gomiti all''indietro cercando di farli toccare tra loro.' 
WHERE name = 'Elbows Back';

UPDATE public.exercise_library 
SET name_it = 'Affondo posteriore rialzato', description_it = 'Posiziona un bilanciere su un rack all''altezza delle spalle caricato con un peso adeguato. Posiziona una pedana bassa e rialzata dietro di te. Carica il bilanciere sulla parte alta della schiena, mantenendo la schiena arcuata e contratta. Sali sulla pedana con entrambi i piedi. Questa è la posizione di partenza. Inizia facendo un passo indietro con una gamba. Scendi flettendo fianchi e ginocchia finché il ginocchio non tocca il pavimento. Fermati, quindi estendi fianchi e ginocchia per risalire, tornando completamente alla posizione di partenza prima di alternare le gambe.' 
WHERE name = 'Elevated Back Lunge';

UPDATE public.exercise_library 
SET name_it = 'Rematore al cavo rialzato', description_it = 'Procurati una pedana (può essere uno step per aerobica o un rialzo per polpacci) alta circa 10-15 cm. Posizionala sul sedile della macchina per il rematore (cable row). Siediti sulla macchina e appoggia i piedi sulla pedana anteriore o sulla barra di supporto, assicurandoti che le ginocchia siano leggermente flesse e non bloccate. Inclinati in avanti mantenendo l''allineamento naturale della schiena e afferra la maniglia a V. Con le braccia tese, tira indietro finché il busto non forma un angolo di 90 gradi con le gambe. La schiena dovrebbe essere leggermente arcuata e il petto in fuori. Dovresti sentire un buon allungamento dei dorsali mentre tieni la barra davanti a te. Questa è la posizione di partenza. Mantenendo il busto fermo, tira le maniglie verso il busto tenendo le braccia vicine al corpo finché non tocchi gli addominali. Espira durante il movimento. In quel punto dovresti contrarre intensamente i muscoli della schiena. Mantieni la contrazione per un secondo e torna lentamente alla posizione originale espirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Elevated Cable Rows';

UPDATE public.exercise_library 
SET name_it = 'Ellittica', description_it = 'Per iniziare, sali sull''ellittica e seleziona l''opzione desiderata dal menu. La maggior parte delle ellittiche ha un''impostazione manuale, oppure è possibile selezionare un programma preimpostato. In genere, è possibile inserire età e peso per stimare le calorie bruciate durante l''esercizio. L''elevazione può essere regolata per modificare l''intensità dell''allenamento. Le maniglie possono essere utilizzate per monitorare la frequenza cardiaca e aiutarti a mantenere l''intensità corretta.' 
WHERE name = 'Elliptical Trainer';

UPDATE public.exercise_library 
SET name_it = 'Crunch su palla fitness', description_it = 'Sdraiati su una palla fitness appoggiando la zona lombare alla superficie sferica. I piedi devono essere ben saldi a terra con le ginocchia flesse. La parte superiore del busto deve sporgere oltre la sommità della palla. Tieni le braccia lungo i fianchi o incrociate sul petto per evitare tensioni al collo (evita di mettere le mani dietro la nuca). Abbassa il busto in posizione di allungamento, mantenendo il collo fermo: questa è la posizione di partenza. Con le anche ferme, fletti la vita contraendo gli addominali e solleva spalle e busto finché non senti una contrazione efficace. Se le braccia sono lungo i fianchi, falle scivolare verso le gambe; se sono incrociate, tienile sul petto. La zona lombare deve rimanere sempre in contatto con la palla. Espira durante il movimento e mantieni la contrazione per un secondo. Inspira tornando nella posizione iniziale. Ripeti per il numero di volte raccomandato.' 
WHERE name = 'Exercise Ball Crunch';

UPDATE public.exercise_library 
SET name_it = 'Pull-In su palla fitness', description_it = 'Posiziona una palla fitness davanti a te e mettiti in posizione di piegamento (push-up) con le mani a terra alla larghezza delle spalle. Appoggia la parte inferiore degli stinchi sulla palla. Suggerimento: le gambe devono essere completamente distese e il corpo deve essere sostenuto dalle braccia tese in avanti. Questa è la posizione di partenza. Mantenendo la schiena dritta e il busto immobile, espira e porta le ginocchia verso il petto, lasciando che la palla rotoli in avanti sotto le caviglie. Contrai gli addominali e tieni la posizione per un secondo. Inspira e distendi lentamente le gambe, facendo rotolare la palla indietro verso la posizione iniziale. Ripeti per il numero di volte raccomandato.' 
WHERE name = 'Exercise Ball Pull-In';

UPDATE public.exercise_library 
SET name_it = 'Extended Range One-Arm Kettlebell Floor Press', description_it = 'Sdraiati a terra e posiziona una kettlebell in modo da poterla spingere con un braccio. Afferra la kettlebell per l''impugnatura. La gamba sullo stesso lato del braccio che lavora deve essere flessa, con il ginocchio incrociato oltre la linea mediana del corpo. Spingi la kettlebell estendendo il gomito e adducendo il braccio verso l''alto, sopra il corpo. Torna alla posizione di partenza.' 
WHERE name = 'Extended Range One-Arm Kettlebell Floor Press';

UPDATE public.exercise_library 
SET name_it = 'Rotazione esterna', description_it = 'Sdraiati di fianco su una panca piana, tenendo un manubrio in una mano; appoggia la testa sull''altra mano piegata sulla panca. Piega il gomito del braccio che regge il manubrio creando un angolo di 90 gradi tra braccio e avambraccio. Suggerimento: tieni il braccio parallelo al busto. Mantenendo il braccio fermo, l''avambraccio deve essere parallelo al pavimento e perpendicolare al busto (puntato davanti a te). Questa è la posizione di partenza. Espirando, ruota esternamente l''avambraccio sollevando il manubrio in un movimento semicircolare, mantenendo l''angolo di 90 gradi. Continua la rotazione fino a quando l''avambraccio è perpendicolare al pavimento e rivolto verso il soffitto. Mantieni la contrazione per un secondo. Inspira tornando lentamente alla posizione iniziale. Ripeti per le ripetizioni previste, poi cambia braccio.' 
WHERE name = 'External Rotation';

UPDATE public.exercise_library 
SET name_it = 'Rotazione esterna con elastico', description_it = 'Fissa l''elastico a un supporto all''altezza del gomito. Stai in piedi con il fianco sinistro rivolto verso il punto di ancoraggio, a breve distanza. Afferra l''estremità dell''elastico con la mano destra e tieni il gomito premuto saldamente contro il fianco. Consigliamo di tenere un cuscinetto o un rullo di gommapiuma tra il gomito e il fianco per mantenerlo in posizione. Con il braccio in posizione, piega il gomito a 90 gradi in modo che la mano passi davanti al busto. Questa è la posizione di partenza. Esegui il movimento ruotando il braccio verso l''esterno, mantenendo il gomito fermo. Continua finché possibile, fai una pausa e torna alla posizione iniziale.' 
WHERE name = 'External Rotation with Band';

UPDATE public.exercise_library 
SET name_it = 'Rotazione esterna ai cavi', description_it = 'Regola il cavo all''altezza del gomito. Stai in piedi con il fianco rivolto verso la macchina a breve distanza. Afferra la maniglia con la mano opposta e tieni il gomito premuto saldamente contro il fianco. Suggeriamo di utilizzare un cuscinetto o un rullo per mantenere il gomito in posizione. Con il braccio fermo, il gomito deve essere flesso a 90 gradi con la mano davanti al torso. Questa è la posizione di partenza. Esegui il movimento ruotando il braccio verso l''esterno, mantenendo il gomito fisso.' 
WHERE name = 'External Rotation with Cable';

UPDATE public.exercise_library 
SET name_it = 'Face Pull', description_it = 'Di fronte a una carrucola alta dotata di corda o doppia maniglia, tira il peso direttamente verso il viso, separando le mani durante il movimento. Mantieni le braccia parallele al suolo.' 
WHERE name = 'Face Pull';

UPDATE public.exercise_library 
SET name_it = 'Farmer''s Walk (Camminata del contadino)', description_it = 'Esistono vari attrezzi specifici per la Farmer''s Walk, ma in alternativa si possono usare manubri pesanti o bilancieri corti. Inizia posizionandoti tra gli attrezzi. Afferra le impugnature, sollevale facendo forza sui talloni, mantenendo la schiena dritta e la testa alta. Cammina facendo passi brevi e veloci, senza dimenticare di respirare. Percorri la distanza stabilita, tipicamente 15-30 metri, il più velocemente possibile.' 
WHERE name = 'Farmer''s Walk';

UPDATE public.exercise_library 
SET name_it = 'Skip veloce', description_it = 'Inizia in una posizione rilassata con una gamba leggermente avanzata. Esegui il movimento combinando un passo e un saltello alternando: destra-destra-passo, sinistra-sinistra-passo. Esegui lo skip mantenendo un contatto rapido con il terreno, riducendo il tempo di sospensione e muovendoti il più velocemente possibile.' 
WHERE name = 'Fast Skipping';

UPDATE public.exercise_library 
SET name_it = 'Finger Curls (Flessioni delle dita)', description_it = 'Afferra un bilanciere con entrambe le mani, palmi rivolti verso l''alto; le mani devono essere distanziate quanto la larghezza delle spalle. I piedi devono essere ben piantati a terra, leggermente più larghi delle spalle. Questa è la posizione di partenza. Abbassa il bilanciere il più possibile estendendo le dita. Lascia che la sbarra rotoli verso le punte delle dita, quindi bloccala con l''ultima falange. Ora fletti le dita verso l''alto il più possibile chiudendo le mani mentre espiri. Mantieni la contrazione nella parte alta.' 
WHERE name = 'Finger Curls';

UPDATE public.exercise_library 
SET name_it = 'Croci ai cavi su panca piana', description_it = 'Posiziona una panca piana tra due carrucole basse in modo che, sdraiandoti, il petto sia allineato con i cavi. Sdraiati sulla panca con i piedi ben piantati a terra. Fatti passare le maniglie, una per mano. Afferra ogni maniglia con il palmo rivolto verso l''alto. Estendi le braccia lateralmente con una leggera flessione dei gomiti. Consiglio: mantieni questa flessione costante per tutto il movimento. Le braccia devono essere parallele al pavimento: questa è la posizione di partenza. Inizia a sollevare le braccia con un movimento a semicerchio direttamente davanti a te, tirando i cavi fino a far incontrare le mani al centro. Contrai i pettorali durante il movimento ed espira. Mantieni la contrazione per un secondo nella posizione di massima chiusura. Consiglio: se eseguito correttamente, nella posizione finale le braccia devono essere perpendicolari al busto e al pavimento, convergendo sopra il petto. Torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Flat Bench Cable Flyes';

UPDATE public.exercise_library 
SET name_it = 'Leg pull-in su panca piana', description_it = 'Sdraiati su un tappetino o su una panca piana con le gambe oltre il bordo. Posiziona le mani sotto i glutei con i palmi rivolti verso il basso oppure ai lati della panca (o del tappetino) per fare presa. Estendi le gambe in avanti: questa è la posizione di partenza. Fletti le ginocchia e tira le cosce verso l''addome espirando. Continua il movimento finché le ginocchia non sono vicine al petto. Mantieni la posizione di contrazione per un secondo. Inspirando, torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Flat Bench Leg Pull-In';

UPDATE public.exercise_library 
SET name_it = 'Leg raise sdraiato su panca piana', description_it = 'Sdraiati su una panca piana con le gambe estese oltre il bordo. Posiziona le mani sotto i glutei con i palmi verso il basso oppure afferra i bordi della panca. Questa è la posizione di partenza. Mantieni le gambe tese, con le ginocchia leggermente flesse ma bloccate, e sollevale finché non formano un angolo di 90 gradi con il pavimento. Espira durante questa fase del movimento e mantieni la contrazione nel punto più alto per un secondo. Inspirando, abbassa lentamente le gambe fino a tornare alla posizione di partenza.' 
WHERE name = 'Flat Bench Lying Leg Raise';

UPDATE public.exercise_library 
SET name_it = 'Curl con manubri su panca inclinata', description_it = 'Impugna il manubrio verso l''estremità esterna per spostare il carico sulla parte più vicina al corpo (tecnica efficace per tutti i curl con manubri). Esegui un normale curl su panca inclinata, mantenendo i polsi il più possibile estesi all''indietro per neutralizzare lo stress articolare. Siediti su una panca inclinata a 45 gradi con un manubrio per mano. Lascia le braccia distese lungo i fianchi, con i gomiti stretti e i palmi rivolti in avanti, pollici verso l''esterno. Consiglio: mantieni questa posizione delle mani per tutta l''esecuzione, senza ruotare i polsi durante la salita. Questa è la posizione di partenza. Solleva entrambi i manubri simultaneamente fino alla massima contrazione dei bicipiti ed espira. Consiglio: non slanciare le braccia né usare lo slancio. Mantieni un movimento controllato in ogni fase. Trattieni la posizione di contrazione per un secondo in alto. Inspira mentre torni lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Flexor Incline Dumbbell Curls';

UPDATE public.exercise_library 
SET name_it = 'Floor Glute-Ham Raise', description_it = 'Puoi farti assistere da un partner o bloccare i piedi sotto un supporto stabile. Inizia in ginocchio con il busto eretto. Se ti assiste un partner, questi dovrà tenere saldamente i tuoi piedi. Questa è la posizione di partenza. Abbassati estendendo le ginocchia, facendo attenzione a NON flettere le anche mentre ti sposti in avanti. Poggia le mani a terra quando le raggiungi. Questo esercizio è molto impegnativo e potresti non riuscire a eseguirlo senza aiuto. Usa le braccia per spingere leggermente sul pavimento e facilitare il ritorno alla posizione iniziale.' 
WHERE name = 'Floor Glute-Ham Raise';

UPDATE public.exercise_library 
SET name_it = 'Floor Press', description_it = 'Regola i ganci del rack all''altezza corretta. Sdraiati sul pavimento con la testa vicino all''estremità di un power rack. Con le scapole addotte, stacca il bilanciere dai ganci. Abbassa il bilanciere verso la parte bassa del petto o la parte alta dell''addome, stringendo la sbarra come se volessi spezzarla. Assicurati di tenere i gomiti vicini al busto durante il movimento. Abbassa il bilanciere fino a quando le braccia toccano terra e fai una pausa, evitando di far rimbalzare o sbattere il peso. Spingi il bilanciere verso l''alto il più velocemente possibile, mantenendo allineati bilanciere, polsi e gomiti.' 
WHERE name = 'Floor Press';

UPDATE public.exercise_library 
SET name_it = 'Floor Press con catene', description_it = 'Regola i ganci del rack all''altezza corretta. Per questo esercizio, fai passare le catene direttamente sulle estremità del bilanciere, evitando che le estremità tocchino i dischi. Sdraiati sul pavimento con la testa vicino all''estremità di un power rack. Con le scapole addotte, stacca il bilanciere dai ganci. Abbassa il bilanciere verso la parte bassa del petto o la parte alta dell''addome, stringendo la sbarra come se volessi spezzarla. Assicurati di tenere i gomiti vicini al busto. Abbassa il bilanciere fino a quando le braccia toccano terra e fai una pausa, evitando di far rimbalzare il peso. Spingi il bilanciere verso l''alto il più velocemente possibile, mantenendo allineati bilanciere, polsi e gomiti.' 
WHERE name = 'Floor Press with Chains';

UPDATE public.exercise_library 
SET name_it = 'Flutter Kicks (su panca)', description_it = 'Sdraiati a pancia in giù su una panca piana con le anche sul bordo; le gambe devono essere dritte, sollevate dal pavimento, e le braccia devono afferrare il bordo anteriore della panca. Contrai glutei e femorali e allinea le gambe con il bacino: questa è la posizione di partenza. Inizia il movimento sollevando la gamba sinistra più in alto della destra. Quindi abbassa la sinistra e solleva la destra. Continua ad alternare (come nel movimento delle gambe nel nuoto) fino a completare le ripetizioni consigliate per gamba. Mantieni un movimento controllato. Consiglio: respira normalmente durante l''esecuzione.' 
WHERE name = 'Flutter Kicks';

UPDATE public.exercise_library 
SET name_it = 'Rilascio miofasciale (SMR) del piede', description_it = 'Questo esercizio distende la fascia plantare. Siediti e togliti le scarpe. Utilizzando un rullo per piedi o un oggetto simile, come un piccolo pezzo di tubo in PVC, posiziona la pianta del piede sopra il rullo, in corrispondenza dell''arco plantare. Questa è la posizione di partenza. Esercita una pressione decisa facendolo rotolare lungo l''arco del piede. Mantieni la posizione per 10-30 secondi, poi cambia piede.' 
WHERE name = 'Foot-SMR';

UPDATE public.exercise_library 
SET name_it = 'Forward Drag con distensione', description_it = 'Aggancia una catena a due maniglie o una fune alla slitta. Rivolgi le spalle alla slitta e impugna le maniglie. Inizia il movimento facendo un passo in avanti. Inclinandoti in avanti, spingi con gambe e anche per avanzare, facendo una pausa a ogni passo per estendere i gomiti, spingendo le mani in avanti. Continua a camminare in avanti fino a tornare alla posizione di partenza, pronto per una nuova distensione.' 
WHERE name = 'Forward Drag with Press';

UPDATE public.exercise_library 
SET name_it = 'Frankenstein Squat', description_it = 'Questo esercizio insegna il corretto posizionamento del bilanciere e del corpo durante il clean e il front squat. Posiziona il bilanciere sulla parte anteriore delle spalle, rilasciando la presa e distendendo le braccia davanti a te. Le spalle devono essere spinte in avanti per creare un appoggio e il bilanciere deve essere a contatto con la gola. Assicurati di muovere in avanti solo le scapole; non incurvare la colonna vertebrale toracica. Esegui lo squat flettendo ginocchia e anche, scendendo tra le gambe. Mantieni il busto eretto, le braccia sollevate e le spalle in avanti; il bilanciere dovrebbe rimanere in posizione. Scendi fino a quando la parte posteriore delle cosce tocca i polpacci. Torna alla posizione eretta spingendo attraverso la parte anteriore del tallone ed estendendo ginocchia e anche.' 
WHERE name = 'Frankenstein Squat';

UPDATE public.exercise_library 
SET name_it = 'Freehand Jump Squat', description_it = 'Incrocia le braccia sul petto. Con la testa alta e la schiena dritta, posiziona i piedi alla larghezza delle spalle. Mantenendo la schiena dritta e il petto in fuori, inspira ed esegui uno squat finché le cosce non sono parallele al pavimento o più in basso. Ora, spingendo principalmente con l''avampiede, salta verticalmente il più in alto possibile, usando le cosce come molle. Espira durante questa fase del movimento. Quando tocchi nuovamente il pavimento, esegui immediatamente un altro squat e salta di nuovo. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Freehand Jump Squat';

UPDATE public.exercise_library 
SET name_it = 'Frog Hops', description_it = 'In piedi con le mani dietro la testa, esegui uno squat mantenendo il busto eretto e la testa alta. Questa sarà la posizione di partenza. Salta in avanti per circa un metro, evitando di saltare inutilmente in alto. Quando i piedi toccano terra, assorbi l''impatto con le gambe e salta di nuovo. Ripeti questa azione per 5-10 volte.' 
WHERE name = 'Frog Hops';

UPDATE public.exercise_library 
SET name_it = 'Frog Sit-Ups', description_it = 'Sdraiati con la schiena piatta a terra (o sul tappetino) e le gambe distese davanti a te. Piega le ginocchia e appoggia l''esterno delle cosce a terra facendo toccare le piante dei piedi l''una con l''altra. Spingi entrambe le piante dei piedi avvicinandole il più possibile al bacino, mantenendo l''esterno delle cosce a terra (o quasi). Consiglio: in questa posizione le gambe dovrebbero formare un diamante. Incrocia le braccia davanti al petto toccando le spalle opposte. Questa è la posizione di partenza. Espirando, appiattisci la parte bassa della schiena contro il pavimento mentre sollevi il busto. Consiglio: questo equivale a eseguire il primo quarto di un normale sit-up. Mantieni la posizione di picco per un secondo. Inspira e torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Frog Sit-Ups';

UPDATE public.exercise_library 
SET name_it = 'Front Barbell Squat', description_it = 'Per sicurezza, questo esercizio va eseguito all''interno di un rack. Imposta il bilanciere su un rack all''altezza giusta. Una volta caricato il bilanciere, porta le braccia sotto la sbarra tenendo i gomiti alti e la parte superiore delle braccia leggermente sopra il parallelo al pavimento. Appoggia il bilanciere sopra i deltoidi e incrocia le braccia afferrando la sbarra per un controllo totale. Stacca il bilanciere dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto. Allontanati dal rack e posiziona i piedi alla larghezza delle spalle con le punte leggermente rivolte verso l''esterno. Tieni sempre la testa alta e la schiena dritta. Inizia a scendere lentamente piegando le ginocchia. Continua fino a quando l''angolo tra cosce e polpacci è leggermente inferiore a 90 gradi (cosce sotto il parallelo). Inspira durante la discesa. Consiglio: se eseguito correttamente, le ginocchia dovrebbero essere allineate con le punte dei piedi; se superano le punte, stai sovraccaricando le articolazioni. Risali espirando, spingendo principalmente con la parte centrale del piede, fino alla posizione iniziale.' 
WHERE name = 'Front Barbell Squat';

UPDATE public.exercise_library 
SET name_it = 'Front Barbell Squat To A Bench', description_it = 'Esercizio da eseguire in un rack. Posiziona una panca piana dietro di te e imposta il bilanciere alla giusta altezza. Porta le braccia sotto la sbarra, tenendo i gomiti alti. Appoggia il bilanciere sui deltoidi e incrocia le braccia per controllarlo. Stacca il bilanciere dal rack spingendo con le gambe e raddrizzando il busto. Allontanati dal rack con i piedi alla larghezza delle spalle e le punte leggermente verso l''esterno. Mantieni testa alta e schiena dritta. Scendi lentamente piegando le ginocchia finché i glutei non toccano la panca. Inspira durante la discesa. Consiglio: le ginocchia devono rimanere allineate con le punte dei piedi per evitare stress eccessivi. Risali espirando, spingendo principalmente con i talloni fino alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Front Barbell Squat To A Bench';

UPDATE public.exercise_library 
SET name_it = 'Front Box Jump', description_it = 'Posiziona una scatola (box) di altezza adeguata a 30-60 cm davanti a te. In piedi con i piedi alla larghezza delle spalle. Esegui un mezzo squat preparatorio oscillando le braccia all''indietro. Esegui il salto esplosivo estendendo anche, ginocchia e caviglie. Oscilla le braccia in avanti e verso l''alto. Atterra sulla scatola con le ginocchia leggermente flesse per assorbire l''impatto. Puoi saltare indietro per tornare a terra o, preferibilmente, scendere una gamba alla volta.' 
WHERE name = 'Front Box Jump';

UPDATE public.exercise_library 
SET name_it = 'Front Cable Raise', description_it = 'Seleziona il carico su un macchinario ai cavi bassi e afferra l''impugnatura singola con la mano sinistra. Datti di schiena rispetto alla puleggia con il braccio disteso davanti alle cosce, palmi verso l''interno. Mantieni il busto fermo e solleva il braccio sinistro in avanti con il gomito leggermente flesso e il palmo rivolto verso il basso. Continua finché il braccio non è leggermente sopra il parallelo al pavimento. Espira durante la salita e mantieni la posizione un secondo. Inspira e abbassa lentamente il braccio fino alla posizione iniziale. Ripeti per le ripetizioni previste, poi cambia braccio.' 
WHERE name = 'Front Cable Raise';

UPDATE public.exercise_library 
SET name_it = 'Front Cone Hops (o hurdle hops)', description_it = 'Disponi una fila di coni o piccoli ostacoli a breve distanza l''uno dall''altro. In piedi davanti al primo cono, piedi alla larghezza delle spalle. Inizia saltando con entrambi i piedi sopra il primo cono, oscillando le braccia. Assorbi l''impatto all''atterraggio flettendo le ginocchia e rimbalza immediatamente verso il salto successivo. Continua finché non hai superato tutti i coni.' 
WHERE name = 'Front Cone Hops (or hurdle hops)';

UPDATE public.exercise_library 
SET name_it = 'Front Dumbbell Raise', description_it = 'Afferra due manubri in piedi, busto dritto, braccia distese davanti alle cosce con i palmi rivolti verso di esse. Mantenendo il busto fermo, solleva il manubrio sinistro in avanti con il gomito leggermente flesso e il palmo rivolto verso il basso. Continua a salire finché il braccio non è leggermente sopra il parallelo al pavimento. Espira durante il sollevamento e fai una pausa di un secondo in cima. Inspira dopo la pausa. Abbassa lentamente il manubrio verso la posizione iniziale mentre sollevi contemporaneamente il destro. Alterna le braccia fino al completamento delle ripetizioni previste.' 
WHERE name = 'Front Dumbbell Raise';

UPDATE public.exercise_library 
SET name_it = 'Alzate frontali con manubri su panca inclinata', description_it = 'Siediti su una panca inclinata regolata tra i 30 e i 60 gradi, tenendo un manubrio in ciascuna mano. Consiglio: puoi modificare l''inclinazione per colpire il muscolo in modo leggermente diverso ogni volta. Estendi le braccia dritto davanti a te con i palmi rivolti verso il basso e i manubri sollevati di circa 2-3 cm sopra le cosce; questa è la posizione di partenza. Solleva lentamente i manubri finché non sono leggermente sopra le spalle, mantenendo i gomiti bloccati. Contrai i muscoli per un secondo nel punto di massima elevazione ed espira durante questa fase del movimento. Consiglio: tieni la testa appoggiata alla panca e i piedi ben saldi a terra per tutta la durata dell''esercizio. Riporta le braccia nella posizione iniziale mentre inspiri. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Front Incline Dumbbell Raise';

UPDATE public.exercise_library 
SET name_it = 'Slanci frontali della gamba', description_it = 'Stai in piedi accanto a una sedia o un supporto, tenendoti con una mano. Slancia la gamba in avanti mantenendola dritta. Prosegui con un movimento all''indietro, portando la gamba il più lontano possibile in base alla tua flessibilità. Ripeti 5-10 volte, quindi cambia gamba.' 
WHERE name = 'Front Leg Raises';

UPDATE public.exercise_library 
SET name_it = 'Alzate frontali con disco', description_it = 'In posizione eretta, impugna un disco con entrambe le mani nelle posizioni delle ore 3 e 9. I palmi devono essere rivolti l''uno verso l''altro, le braccia tese e bloccate con una leggera flessione dei gomiti; il disco deve trovarsi vicino alla vita. Consiglio: le braccia devono rimanere in questa posizione per tutto l''esercizio. Questa è la posizione di partenza. Espirando, solleva lentamente il disco finché non è leggermente sopra il livello delle spalle. Mantieni la contrazione per un secondo. Consiglio: evita di dondolare con il peso o di piegare i gomiti; il busto deve rimanere immobile per tutto il movimento. Inspira mentre riporti lentamente il disco alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Front Plate Raise';

UPDATE public.exercise_library 
SET name_it = 'Alzate frontali e pullover', description_it = 'Sdraiati su una panca piana tenendo un bilanciere con una presa prona (palmi verso il basso) a una larghezza di circa 40 cm. Appoggia il bilanciere sulle cosce, estendi le braccia bloccandole ma mantenendo una leggera flessione ai gomiti; questa è la posizione di partenza. Solleva il peso con un movimento semicircolare mantenendo le braccia tese mentre inspiri. Continua il movimento finché il bilanciere non si trova oltre la testa. (Consiglio: il bilanciere percorrerà circa 180 gradi). A questo punto, le braccia dovrebbero essere parallele al pavimento con i palmi rivolti verso il soffitto. Torna alla posizione di partenza invertendo il movimento ed espirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Front Raise And Pullover';

UPDATE public.exercise_library 
SET name_it = 'Front Squat (Clean Grip)', description_it = 'Posiziona il bilanciere su un rack leggermente sotto l''altezza delle spalle. Appoggia il bilanciere sopra i deltoidi, spingendo contro le clavicole e sfiorando la gola. Le mani devono essere in presa ''clean'', toccando il bilanciere solo con le dita per mantenerlo in posizione. Solleva il bilanciere dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto. Allontanati dal rack e posiziona le gambe con una larghezza media pari a quella delle spalle e le punte dei piedi leggermente verso l''esterno. Mantieni la testa e i gomiti alti in ogni momento. Questa è la posizione di partenza. Piega le ginocchia scendendo tra le gambe finché i bicipiti femorali non toccano i polpacci. Mantieni le ginocchia allineate con i piedi usando gli abduttori per spingere le ginocchia verso l''esterno durante lo squat. Espirando, risali spingendo il pavimento principalmente con il tallone o la parte centrale del piede, raddrizzando le gambe e tornando alla posizione iniziale.' 
WHERE name = 'Front Squat (Clean Grip)';

UPDATE public.exercise_library 
SET name_it = 'Front Squat con due Kettlebell', description_it = 'Esegui un ''clean'' con due kettlebell portandole alle spalle, estendendo gambe e anche mentre le tiri verso l''alto e ruoti i polsi. Guardando sempre dritto in avanti, scendi in squat il più in basso possibile e fai una pausa nel punto inferiore. Durante la discesa, spingi le ginocchia verso l''esterno. Scendi tra le gambe mantenendo il busto eretto, la testa e il petto alti. Risali spingendo sui talloni e ripeti.' 
WHERE name = 'Front Squats With Two Kettlebells';

UPDATE public.exercise_library 
SET name_it = 'Alzate frontali con due manubri', description_it = 'Prendi due manubri e mettiti in piedi con il busto dritto; tieni i pesi davanti alle cosce, braccia tese e palmi rivolti verso le cosce. Questa è la posizione di partenza. Mantenendo il busto immobile (senza oscillare), solleva i manubri frontalmente con una leggera flessione dei gomiti e i palmi sempre rivolti verso il basso. Continua a salire finché le braccia non sono leggermente sopra il parallelo rispetto al pavimento. Espira durante questa fase e fai una pausa di un secondo nel punto più alto. Inspira mentre abbassi lentamente i manubri alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Front Two-Dumbbell Raise';

UPDATE public.exercise_library 
SET name_it = 'Lat Pulldown a range di movimento completo', description_it = 'In piedi o seduto su una panca alta, impugna due maniglie collegate alle carrucole alte. Usa le mani opposte in modo che le braccia siano incrociate davanti a te e i palmi rivolti in avanti. Mantieni il petto alto e una leggera curvatura nella zona lombare, quindi tira le maniglie verso il basso come in un classico pulldown; il movimento seguirà un arco. Durante l''esecuzione, ruota le mani in modo che nella posizione finale i palmi siano rivolti l''uno verso l''altro anziché in avanti. Torna lentamente alla posizione iniziale e ripeti.' 
WHERE name = 'Full Range-Of-Motion Lat Pulldown';

UPDATE public.exercise_library 
SET name_it = 'Gironda Sternum Chins', description_it = 'Afferra la sbarra per le trazioni con una presa supina (palmi verso il viso) alla larghezza delle spalle. Rimani appeso con le braccia completamente estese, spingi il petto in fuori e inclinati all''indietro. Consiglio: dovrai mantenere questa inclinazione per tutto il movimento. Questa è la posizione di partenza. Inizia a tirarti verso la sbarra mantenendo la colonna vertebrale inarcata e la testa inclinata all''indietro il più lontano possibile dalla sbarra. Espira durante questa fase. Consiglio: nella parte alta del movimento, i fianchi e le gambe formeranno un angolo di circa 45 gradi rispetto al pavimento. Continua a tirare finché la clavicola non supera la sbarra e la parte bassa del petto (sterno) la tocca. Mantieni la contrazione per un secondo. Consiglio: al completamento di questa fase, la testa sarà parallela al pavimento. Inspira mentre torni lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Gironda Sternum Chins';

UPDATE public.exercise_library 
SET name_it = 'Glute Ham Raise', description_it = 'Regola l''attrezzo in base alla tua corporatura. Posiziona i piedi contro la pedana tra i rulli mentre sei sdraiato a faccia in giù; le ginocchia devono trovarsi appena dietro il cuscinetto. Inizia dalla parte inferiore del movimento. Mantieni la schiena inarcata e inizia flettendo le ginocchia. Spingi le punte dei piedi contro la pedana durante il movimento. Mantieni la parte superiore del corpo dritta e continua finché il busto non è in posizione verticale. Ritorna alla posizione iniziale, mantenendo il controllo durante la discesa.' 
WHERE name = 'Glute Ham Raise';

UPDATE public.exercise_library 
SET name_it = 'Glute Kickback', description_it = 'Inginocchiati sul pavimento o su un tappetino da fitness e piegati in avanti con le braccia distese (perpendicolari al busto), assumendo una posizione simile a quella di un piegamento, ma con le mani alla larghezza delle spalle. Lo sguardo deve essere rivolto in avanti e le ginocchia devono formare un angolo di 90 gradi tra cosce e polpacci. Questa è la posizione di partenza. Espirando, solleva la gamba destra fino a quando la coscia è allineata con la schiena, mantenendo l''angolo di 90 gradi. Contrai i glutei durante tutto il movimento e mantieni la contrazione per un secondo nella fase alta. Consiglio: al termine del movimento, la coscia deve essere parallela al pavimento mentre il polpaccio deve essere perpendicolare. Inspira tornando alla posizione iniziale e ripeti con la gamba sinistra. Continua ad alternare le gambe fino al completamento delle ripetizioni previste.' 
WHERE name = 'Glute Kickback';

UPDATE public.exercise_library 
SET name_it = 'Goblet Squat', description_it = 'In piedi, tieni un kettlebell leggero per le corna vicino al petto. Questa è la posizione di partenza. Esegui uno squat scendendo tra le gambe finché i bicipiti femorali non toccano i polpacci. Mantieni petto e testa alti e la schiena dritta. Nella posizione bassa, fai una pausa e usa i gomiti per spingere le ginocchia verso l''esterno. Torna alla posizione di partenza e ripeti per 10-20 ripetizioni.' 
WHERE name = 'Goblet Squat';

UPDATE public.exercise_library 
SET name_it = 'Good Morning', description_it = 'Inizia con un bilanciere su un rack all''altezza delle spalle. Posiziona il bilanciere sulla parte alta della schiena (non sopra il collo), come in uno squat. Mantieni la schiena contratta, le scapole addotte e le ginocchia leggermente flesse. Fai un passo indietro rispetto al rack. Inizia il movimento flettendo le anche e spingendole all''indietro mentre ti pieghi in avanti fino a raggiungere quasi il parallelo. Mantieni la schiena inarcata (neutra) e la colonna cervicale correttamente allineata. Inverti il movimento estendendo le anche usando glutei e bicipiti femorali. Continua fino a tornare alla posizione eretta iniziale.' 
WHERE name = 'Good Morning';

UPDATE public.exercise_library 
SET name_it = 'Good Morning off Pins', description_it = 'Posiziona il bilanciere sui supporti di un rack all''altezza dello stomaco. Infilati sotto il bilanciere e posizionalo sulla parte posteriore delle spalle, come per uno squat. All''altezza corretta, dovresti essere quasi parallelo al pavimento quando sei piegato. Mantieni la schiena contratta, le scapole unite e le ginocchia leggermente flesse. Mantieni la schiena inarcata e il collo correttamente allineato. Inizia il movimento estendendo le anche con glutei e bicipiti femorali, sollevando il carico. Abbassa lentamente il peso fino a riappoggiarlo sui supporti, tornando alla posizione iniziale.' 
WHERE name = 'Good Morning off Pins';

UPDATE public.exercise_library 
SET name_it = 'Gorilla Chin/Crunch', description_it = 'Appenditi a una sbarra per trazioni con una presa supina (palmi rivolti verso di te) leggermente più larga delle spalle. Piega le ginocchia a 90 gradi in modo che i polpacci siano paralleli al pavimento e le cosce perpendicolari. Questa è la posizione di partenza. Espirando, esegui una trazione verso l''alto mentre contrai l''addome portando le ginocchia verso il petto. Fermati quando il naso raggiunge il livello della sbarra. Consiglio: in questo punto dovresti completare simultaneamente la trazione e la contrazione addominale. Inspira lentamente tornando alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Gorilla Chin/Crunch';

UPDATE public.exercise_library 
SET name_it = 'Groin and Back Stretch', description_it = 'Siediti a terra con le ginocchia flesse e le piante dei piedi a contatto. Intreccia le dita dietro la nuca. Questa è la posizione di partenza. Esegui una flessione del busto in avanti, portando i gomiti all''interno delle cosce. Dopo una breve pausa, torna alla posizione iniziale con la testa alta e la schiena dritta. Ripeti per 10-20 ripetizioni.' 
WHERE name = 'Groin and Back Stretch';

UPDATE public.exercise_library 
SET name_it = 'Groiners', description_it = 'Inizia in posizione di piegamento sulle braccia (pushup). Questa è la posizione di partenza. Con un salto, porta i piedi in avanti posizionandoli accanto alle mani. Tieni la testa alta durante il movimento. Torna alla posizione iniziale con un salto e ripeti immediatamente, continuando per 10-20 ripetizioni.' 
WHERE name = 'Groiners';

UPDATE public.exercise_library 
SET name_it = 'Hack Squat', description_it = 'Appoggia il busto contro lo schienale della macchina e posiziona le spalle sotto gli appositi cuscinetti. Posiziona i piedi sulla pedana alla larghezza delle spalle con le punte leggermente rivolte verso l''esterno. Consiglio: tieni la testa alta e la schiena sempre aderente allo schienale. Impugna le maniglie laterali e sblocca le sicure. Distendi le gambe senza bloccare le ginocchia: questa è la posizione di partenza. Inizia ad abbassare lentamente il carrello flettendo le ginocchia, mantenendo una postura dritta. Scendi finché l''angolo tra cosce e polpacci è leggermente inferiore a 90 gradi (cosce sotto il parallelo). Inspira durante questa fase. Consiglio: se eseguito correttamente, le ginocchia non dovrebbero superare la linea immaginaria perpendicolare alle punte dei piedi per evitare stress articolare. Espirando, spingi con i talloni per tornare alla posizione di partenza. Ripeti per le ripetizioni previste.' 
WHERE name = 'Hack Squat';

UPDATE public.exercise_library 
SET name_it = 'Hammer Curls', description_it = 'In piedi, busto eretto, con un manubrio in ogni mano a braccia distese lungo i fianchi. I palmi devono essere rivolti verso il busto. Questa è la posizione di partenza. Mantenendo la parte superiore del braccio ferma, espira e fletti l''avambraccio verso l''alto contraendo i bicipiti. Solleva il peso finché il bicipite è completamente contratto e il manubrio è all''altezza della spalla. Mantieni la contrazione per un breve istante strizzando il muscolo. Consiglio: concentrati sul tenere il gomito fisso, muovendo solo l''avambraccio. Dopo la pausa, inspira e scendi lentamente verso la posizione iniziale. Ripeti per le ripetizioni previste.' 
WHERE name = 'Hammer Curls';

UPDATE public.exercise_library 
SET name_it = 'Hammer Grip Incline DB Bench Press', description_it = 'Sdraiati su una panca inclinata con un manubrio in ogni mano appoggiato sulle cosce. I palmi sono rivolti l''uno verso l''altro. Usa la spinta delle cosce per portare i manubri all''altezza delle spalle, una alla volta. Mantieni i palmi in posizione neutra (uno di fronte all''altro). Tieni i gomiti leggermente aperti, con le braccia in linea con le spalle (perpendicolari al busto) e piegate a 90 gradi. Questa è la posizione di partenza. Inspira e abbassa lentamente i pesi ai lati, mantenendo il pieno controllo. Espira e spingi i manubri verso l''alto usando i pettorali. Blocca le braccia in posizione di massima contrazione, mantieni per un secondo e torna lentamente verso il basso. Consiglio: la fase di discesa dovrebbe durare almeno il doppio della fase di spinta. Ripeti per le ripetizioni prescritte. Al termine, riporta i manubri sulle cosce e poi a terra.' 
WHERE name = 'Hammer Grip Incline DB Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Hamstring SMR (Auto-rilascio miofasciale)', description_it = 'In posizione seduta, estendi le gambe sopra un foam roller posizionato sotto la parte posteriore delle cosce. Appoggia le mani ai lati o dietro di te per sostenere il peso. Questa sarà la posizione di partenza. Usando le mani, solleva i fianchi dal pavimento e sposta il peso del corpo su una gamba. Rilassa i muscoli ischiocrurali della gamba che stai trattando. Fai scorrere il foam roller dalla parte inferiore del bacino fino a sopra la parte posteriore del ginocchio, soffermandoti sui punti di tensione per 10-30 secondi. Ripeti per l''altra gamba.' 
WHERE name = 'Hamstring-SMR';

UPDATE public.exercise_library 
SET name_it = 'Stretching per i muscoli ischiocrurali', description_it = 'Sdraiati sulla schiena con una gamba estesa verso l''alto, mantenendo l''anca a novanta gradi. Tieni l''altra gamba distesa a terra. Fai passare una cintura, una fascia o una corda attorno alla pianta del piede. Questa sarà la posizione di partenza. Tira la cinghia per creare tensione nei polpacci e negli ischiocrurali. Mantieni l''allungamento per 10-30 secondi, quindi ripeti con l''altra gamba.' 
WHERE name = 'Hamstring Stretch';

UPDATE public.exercise_library 
SET name_it = 'Handstand Push-Ups (Piegamenti in verticale)', description_it = 'Con la schiena rivolta verso la parete, piegati in avanti e appoggia le mani a terra alla larghezza delle spalle. Slanciati verso l''alto portandoti contro la parete con le braccia distese. Il corpo deve essere capovolto con braccia e gambe completamente estese. Mantieni il corpo il più dritto possibile. Consiglio: se è la prima volta, fatti assistere da uno spotter. Assicurati di mantenere lo sguardo rivolto verso la parete e non verso il basso. Espirando, scendi lentamente verso il suolo finché la testa non sfiora quasi il pavimento. Consiglio: è fondamentale scendere lentamente per evitare traumi alla testa. Spingiti verso l''alto espirando finché i gomiti non sono quasi bloccati. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Handstand Push-Ups';

UPDATE public.exercise_library 
SET name_it = 'Hang Clean', description_it = 'Inizia con una presa larga quanto le spalle, utilizzando una presa prona doppia o hook grip, con il bilanciere sospeso all''altezza di metà coscia. La schiena deve essere dritta e leggermente inclinata in avanti. Inizia estendendo energicamente anche, ginocchia e caviglie, spingendo il peso verso l''alto. Contemporaneamente, effettua una scrollata di spalle verso le orecchie. Recupera immediatamente facendo forza sui talloni, mantenendo il busto eretto e i gomiti alti. Continua finché non sei in posizione eretta.' 
WHERE name = 'Hang Clean';

UPDATE public.exercise_library 
SET name_it = 'Hang Clean - Sotto le ginocchia', description_it = 'Inizia con una presa larga quanto le spalle, utilizzando una presa prona doppia o hook grip, con il bilanciere sospeso appena sotto le ginocchia. La schiena deve essere dritta e leggermente inclinata in avanti. Inizia estendendo energicamente anche, ginocchia e caviglie, spingendo il peso verso l''alto. Contemporaneamente, effettua una scrollata di spalle verso le orecchie. Una volta raggiunta la massima estensione, passa alla terza fase della tirata scrollando vigorosamente le spalle e flettendo le braccia con i gomiti verso l''alto e l''esterno. Al culmine dell''estensione, tirati energicamente sotto il bilanciere ruotando i gomiti. Ricevi il bilanciere in posizione di front squat; la profondità dipende dall''altezza raggiunta dal bilanciere. Il bilanciere deve poggiare sulle spalle, toccando leggermente la gola con le mani rilassate. Scendi fino alla posizione di squat completa per facilitare il recupero. Risali immediatamente facendo forza sui talloni, mantenendo il busto eretto e i gomiti alti.' 
WHERE name = 'Hang Clean - Below the Knees';

UPDATE public.exercise_library 
SET name_it = 'Hang Snatch', description_it = 'Inizia con una presa larga sul bilanciere, utilizzando una presa prona o hook grip. I piedi devono essere sotto le anche, leggermente ruotati verso l''esterno. Le ginocchia devono essere leggermente flesse e il busto inclinato in avanti. La colonna vertebrale deve essere ben estesa e lo sguardo rivolto in avanti. Il bilanciere deve trovarsi all''altezza delle anche. Questa è la posizione di partenza. Estendi energicamente gambe e anche. Al culmine, scrolla le spalle e permetti ai gomiti di flettersi lateralmente. Mentre porti i piedi in posizione di ricezione, tirati con forza sotto il bilanciere mentre lo sollevi sopra la testa. Ricevi il bilanciere con il corpo il più basso possibile e le braccia completamente estese sopra la testa. Torna in posizione eretta mantenendo il peso sopra la testa. Riporta il peso a terra controllando il movimento.' 
WHERE name = 'Hang Snatch';

UPDATE public.exercise_library 
SET name_it = 'Hang Snatch - Sotto le ginocchia', description_it = 'Inizia con una presa larga sul bilanciere, utilizzando una presa prona o hook grip. I piedi devono essere sotto le anche, leggermente ruotati verso l''esterno. Le ginocchia devono essere leggermente flesse e il busto inclinato in avanti. Il bilanciere deve trovarsi appena sotto le ginocchia. Questa è la posizione di partenza. Estendi energicamente gambe e anche. Al culmine, scrolla le spalle e fletti i gomiti lateralmente. Mentre porti i piedi in posizione di ricezione, tirati con forza sotto il bilanciere elevandolo sopra la testa. Ricevi il bilanciere con il corpo il più basso possibile e le braccia completamente estese sopra la testa. Torna in posizione eretta mantenendo il peso sopra la testa, quindi riponi il bilanciere a terra controllando il movimento.' 
WHERE name = 'Hang Snatch - Below Knees';

UPDATE public.exercise_library 
SET name_it = 'Hanging Bar Good Morning', description_it = 'Inizia con un bilanciere su un rack posizionato all''altezza dello stomaco. Sospendi il bilanciere usando catene o cinghie. Infilati sotto la barra e posizionala sulla parte posteriore delle spalle, non sopra i trapezi, come in un power squat. Alla giusta altezza, dovresti essere quasi parallelo al pavimento quando sei piegato. Mantieni la schiena contratta, le scapole addotte e le ginocchia leggermente flesse. Mantieni la curvatura naturale della schiena e la colonna cervicale in linea. Inizia il movimento estendendo le anche usando glutei e ischiocrurali, sollevando il peso fino alla posizione eretta. Riabbassa lentamente il peso nella posizione di partenza, dove è sostenuto dalle catene.' 
WHERE name = 'Hanging Bar Good Morning';

UPDATE public.exercise_library 
SET name_it = 'Hanging Leg Raise (Sollevamento gambe alla sbarra)', description_it = 'Appenditi a una sbarra per trazioni con le braccia distese, usando una presa larga o media. Le gambe devono essere tese verso il basso con il bacino leggermente ruotato all''indietro. Questa sarà la posizione di partenza. Solleva le gambe finché il busto non forma un angolo di 90 gradi con le stesse. Espira durante il movimento e mantieni la contrazione per un secondo circa. Torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Hanging Leg Raise';

UPDATE public.exercise_library 
SET name_it = 'Hanging Pike', description_it = 'Appenditi a una sbarra per trazioni con gambe e piedi uniti, usando una presa prona (palmi rivolti lontano da te) leggermente più larga delle spalle. Consiglio: puoi usare delle fasce per i polsi per migliorare la presa. Piega le ginocchia a 90 gradi e porta la parte superiore delle gambe in avanti, in modo che i polpacci siano perpendicolari al pavimento e le cosce parallele ad esso. Questa sarà la posizione di partenza. Espirando, tira le gambe verso l''alto finché gli stinchi non toccano quasi la sbarra sopra di te. Consiglio: cerca di stendere le gambe il più possibile nella fase finale. Abbassa le gambe il più lentamente possibile fino alla posizione di partenza. Consiglio: evita di oscillare o di usare lo slancio. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Hanging Pike';

UPDATE public.exercise_library 
SET name_it = 'Heaving Snatch Balance', description_it = 'Questo esercizio aiuta ad apprendere lo snatch. Inizia tenendo un peso leggero appoggiato sulle spalle. I piedi devono essere leggermente più larghi della larghezza delle anche e ruotati verso l''esterno, nella stessa posizione in cui eseguiresti uno squat. Inizia con un leggero affondo delle ginocchia e spingi verso l''alto per scaricare brevemente il bilanciere. Posizionati rapidamente sotto il bilanciere, portandolo sopra la testa mentre scendi in uno squat completo. Ritorna in posizione eretta.' 
WHERE name = 'Heaving Snatch Balance';

UPDATE public.exercise_library 
SET name_it = 'Heavy Bag Thrust', description_it = 'Utilizza un sacco pesante per questo esercizio. Assumi una posizione eretta accanto al sacco, con i piedi sfalsati e abbastanza distanziati. Appoggia la mano sul sacco all''altezza del petto: questa sarà la tua posizione di partenza. Inizia ruotando il busto e spingendo il sacco in avanti con quanta più forza possibile. Esegui il movimento rapidamente, allontanando il sacco dal corpo. Accogli il sacco mentre oscilla all''indietro invertendo i passaggi.' 
WHERE name = 'Heavy Bag Thrust';

UPDATE public.exercise_library 
SET name_it = 'High Cable Curls', description_it = 'Posizionati tra due carrucole alte e afferra una maniglia con ciascuna mano. Posiziona le braccia in modo che siano parallele al pavimento con i palmi rivolti verso di te. Questa sarà la tua posizione di partenza. Fletti le maniglie verso di te fino a portarle vicino alle orecchie. Assicurati di contrarre i bicipiti ed espirare durante l''esecuzione. La parte superiore delle braccia deve rimanere ferma, muovendo solo gli avambracci. Mantieni la contrazione per un secondo strizzando i bicipiti, quindi riporta lentamente le braccia nella posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'High Cable Curls';

UPDATE public.exercise_library 
SET name_it = 'Hip Circles (prone)', description_it = 'Mettiti a terra in quadrupedia (a quattro zampe). Mantenendo una postura corretta, solleva un ginocchio piegato da terra. Questa sarà la posizione di partenza. Mantenendo il ginocchio piegato, ruota il femore tracciando un arco, cercando di disegnare un ampio cerchio con il ginocchio. Esegui il movimento lentamente per un numero prestabilito di ripetizioni, quindi ripeti con l''altra gamba.' 
WHERE name = 'Hip Circles (prone)';

UPDATE public.exercise_library 
SET name_it = 'Hip Extension with Bands', description_it = 'Fissa un''estremità della banda elastica alla parte inferiore di un supporto e l''altra a una caviglia. Rivolto verso il punto di ancoraggio, appoggiati alla colonna per stabilizzarti. Mantenendo testa e petto alti, spingi la gamba con la resistenza il più indietro possibile, tenendo il ginocchio teso. Ritorna con la gamba nella posizione di partenza.' 
WHERE name = 'Hip Extension with Bands';

UPDATE public.exercise_library 
SET name_it = 'Hip_Flexion_with_Band', description_it = 'Fissa un''estremità della banda elastica alla parte inferiore di un supporto e l''altra a una caviglia. Rivolgi le spalle al punto di ancoraggio della banda. Mantenendo testa e petto alti, solleva il ginocchio fino a 90 gradi e fai una pausa. Ritorna con la gamba nella posizione di partenza.' 
WHERE name = 'Hip Flexion with Band';

UPDATE public.exercise_library 
SET name_it = 'Hip Lift with Band', description_it = 'Dopo aver scelto una banda adatta, sdraiati al centro del rack dopo averla fissata su entrambi i lati. Se il rack non ha pioli, la banda può essere fissata con manubri pesanti o oggetti simili, assicurandoti che non si muovano. Regola la posizione in modo che la banda si trovi direttamente sopra i fianchi. Piega le ginocchia e appoggia i piedi a terra. Le mani possono restare a terra o tenere la banda in posizione. Mantenendo le spalle a terra, spingi sui talloni per sollevare i fianchi, opponendoti alla resistenza della banda il più in alto possibile. Fai una pausa nel punto massimo, quindi torna alla posizione iniziale.' 
WHERE name = 'Hip Lift with Band';

UPDATE public.exercise_library 
SET name_it = 'Hug A Ball', description_it = 'Siediti sul pavimento. Posiziona una palla da ginnastica tra le gambe e abbassa i fianchi verso il pavimento. Abbraccia la palla con le braccia per sostenere il corpo. Regola le gambe in modo che i piedi siano ben appoggiati a terra e le ginocchia siano allineate sopra le caviglie. Mantieni una presa salda sulla palla in modo che non rotoli via facendoti cadere all''indietro sui glutei.' 
WHERE name = 'Hug A Ball';

UPDATE public.exercise_library 
SET name_it = 'Hug Knees To Chest', description_it = 'Sdraiati sulla schiena e porta entrambe le ginocchia al petto. Tieni le braccia sotto le ginocchia, non sopra (ciò eserciterebbe troppa pressione sulle articolazioni del ginocchio). Tira lentamente le ginocchia verso le spalle. Questo esercizio allunga anche i muscoli dei glutei.' 
WHERE name = 'Hug Knees To Chest';

UPDATE public.exercise_library 
SET name_it = 'Hurdle Hops', description_it = 'Posiziona una fila di ostacoli o altre piccole barriere a poca distanza l''una dall''altra. Stai di fronte al primo ostacolo con i piedi alla larghezza delle spalle. Questa è la posizione di partenza. Inizia saltando con entrambi i piedi oltre il primo ostacolo, facendo oscillare le braccia durante il salto. Assorbi l''impatto dell''atterraggio piegando le ginocchia e sfrutta la spinta per saltare immediatamente oltre l''ostacolo successivo. Continua finché non avrai superato tutti gli ostacoli.' 
WHERE name = 'Hurdle Hops';

UPDATE public.exercise_library 
SET name_it = 'Hyperextensions (Estensioni della schiena)', description_it = 'Sdraiati a pancia in giù su una panca per hyperextension, infilando le caviglie saldamente sotto i rulli. Regola il supporto superiore, se possibile, in modo che le cosce poggino piatte sull''imbottitura, lasciando spazio sufficiente per flettere il busto senza restrizioni. Con il corpo dritto, incrocia le braccia davanti al petto (scelta consigliata) o dietro la nuca. Questa è la posizione di partenza. Suggerimento: puoi tenere un disco in mano davanti al petto per una maggiore resistenza. Inizia a fletterti lentamente in avanti partendo dalla vita, fin dove riesci mantenendo la schiena dritta. Inspira durante il movimento. Prosegui fino a sentire una buona tensione sui bicipiti femorali e finché non riesci più a scendere senza curvare la schiena. Suggerimento: non curvare mai la schiena. La chiave è arrivare fin dove il corpo lo permette senza compromettere la postura. Risali lentamente verso la posizione iniziale espirando. Suggerimento: evita di inarcare eccessivamente la schiena oltre la linea retta e non slanciare il busto per evitare infortuni. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Hyperextensions (Back Extensions)';

UPDATE public.exercise_library 
SET name_it = 'Hyperextensions senza panca specifica', description_it = 'Fatti bloccare le gambe da qualcuno e scivola verso l''estremità di una panca piana finché le anche non sporgono dal bordo. Suggerimento: tutto il busto deve pendere verso il pavimento. Sarai nella stessa posizione di una panca per hyperextension, ma il range di movimento sarà ridotto a causa dell''altezza della panca piana. Con il corpo dritto, incrocia le braccia davanti al petto o dietro la nuca. Questa è la posizione di partenza. Inizia a fletterti in avanti lentamente, mantenendo la schiena dritta e inspirando. Scendi finché non tocchi quasi il pavimento o senti una buona tensione sui bicipiti femorali. Suggerimento: non curvare mai la schiena. Risali lentamente espirando. Suggerimento: evita di inarcare la schiena oltre la linea retta e non usare slanci. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Hyperextensions With No Hyperextension Bench';

UPDATE public.exercise_library 
SET name_it = 'Stretching della banda ileotibiale e dei glutei', description_it = 'Fai passare una cinghia, una corda o una banda elastica attorno a un piede e porta la gamba tesa lateralmente oltre il corpo, mantenendola estesa mentre sei disteso a terra. Questa è la posizione di partenza. Mantenendo il piede sollevato da terra, tira la cinghia usando la tensione per sollevare le punte dei piedi. Mantieni la posizione per 10-20 secondi e ripeti sull''altro lato.' 
WHERE name = 'IT Band and Glute Stretch';

UPDATE public.exercise_library 
SET name_it = 'Rilascio miofasciale (SMR) della fascia ileotibiale', description_it = 'Sdraiati su un fianco con la gamba inferiore posizionata sopra un foam roller, tra l''anca e il ginocchio. L''altra gamba può essere incrociata davanti a te. Scarica sul foam roller quanto più peso possibile; non è necessario che la gamba inferiore tocchi terra. Assicurati di rilassare i muscoli della gamba che stai trattando. Fai rotolare la gamba sul foam roller dall''anca al ginocchio, soffermandoti per 10-30 secondi sui punti di maggiore tensione. Ripeti con la gamba opposta.' 
WHERE name = 'Iliotibial Tract-SMR';

UPDATE public.exercise_library 
SET name_it = 'Inchworm', description_it = 'In piedi con i piedi vicini. Mantenendo le gambe tese, piegati in avanti e appoggia le mani sul pavimento davanti a te. Questa è la posizione di partenza. Inizia a camminare in avanti con le mani, alternando sinistra e destra. Durante il movimento, fletti solo le anche mantenendo le gambe tese. Continua finché il corpo non è parallelo al suolo in posizione di pushup. Ora, mantenendo le mani ferme, fai piccoli passi con i piedi, muovendoti di pochi centimetri alla volta. Continua a camminare finché i piedi non sono vicini alle mani, mantenendo le gambe sempre tese.' 
WHERE name = 'Inchworm';

UPDATE public.exercise_library 
SET name_it = 'Incline Barbell Triceps Extension', description_it = 'Afferra un bilanciere con una presa prona (palmi verso il basso) leggermente più stretta della larghezza delle spalle. Sdraiati su una panca inclinata tra i 45 e i 75 gradi. Porta il bilanciere sopra la testa con le braccia tese e i gomiti chiusi. Le braccia devono essere in linea con il busto sopra la testa. Questa è la posizione di partenza. Abbassa il bilanciere con un movimento semicircolare dietro la testa finché gli avambracci non toccano i bicipiti. Inspira durante il movimento. Suggerimento: mantieni la parte superiore delle braccia immobile e vicina alla testa; devono muoversi solo gli avambracci. Torna alla posizione iniziale espirando e contraendo i tricipiti. Mantieni la contrazione per un secondo. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Incline Barbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Incline Bench Pull', description_it = 'Impugna un manubrio per mano e sdraiati a pancia in giù su una panca inclinata a circa 30 gradi. Lascia le braccia tese verso il pavimento. Ruota i polsi in modo che le mani siano in posizione prona (palmi verso il basso). Apri i gomiti verso l''esterno. Questa è la posizione di partenza. Espirando, solleva i manubri come se eseguissi una panca piana al contrario, flettendo i gomiti e portando la parte superiore delle braccia verso l''alto mentre gli avambracci pendono. Continua finché la parte superiore delle braccia è allineata con la schiena. Suggerimento: i gomiti si aprono lateralmente, formando una "T" con il busto. Mantieni la contrazione per un secondo. Torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Incline Bench Pull';

UPDATE public.exercise_library 
SET name_it = 'Incline Cable Chest Press', description_it = 'Regola il carico e siediti afferrando le maniglie. La parte superiore delle braccia deve formare un angolo di circa 45 gradi rispetto al busto, con testa e petto alti. I gomiti devono essere flessi a circa 90 gradi. Questa è la posizione di partenza. Inizia estendendo i gomiti, spingendo le maniglie in avanti. Mantieni le scapole retratte durante l''esecuzione. Dopo una breve pausa a braccia tese, torna alla posizione iniziale mantenendo i cavi in tensione.' 
WHERE name = 'Incline Cable Chest Press';

UPDATE public.exercise_library 
SET name_it = 'Incline Cable Flye', description_it = 'Posiziona le carrucole al livello più basso possibile. Posiziona una panca inclinata (45 gradi) tra le carrucole, seleziona il carico e afferra le maniglie. Sdraiati sulla panca e unisci le mani a braccia tese davanti al viso. Questa è la posizione di partenza. Con i gomiti leggermente flessi (per non stressare il tendine del bicipite), apri le braccia lateralmente seguendo un arco ampio finché non senti allungare i pettorali. Inspira durante questa fase. Suggerimento: le braccia devono rimanere immobili, il movimento avviene solo nell''articolazione della spalla. Torna alla posizione di partenza espirando e contraendo i pettorali. Mantieni la contrazione per un secondo. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Incline Cable Flye';

UPDATE public.exercise_library 
SET name_it = 'Panca inclinata con manubri (palmi rivolti all''interno)', description_it = 'Sdraiati su una panca inclinata con un manubrio per mano appoggiato sulle cosce. I palmi sono rivolti l''uno verso l''altro. Usa le cosce per aiutare a portare i manubri in posizione, uno alla volta, tenendoli all''altezza delle spalle. Con una presa neutra (palmi che si guardano), tieni i gomiti larghi con la parte superiore delle braccia perpendicolare al busto e i gomiti flessi a 90 gradi. Questa è la posizione di partenza. Abbassa lentamente i pesi ai lati inspirando. Mantieni sempre il controllo dei manubri. Espirando, spingi i manubri verso l''alto usando i muscoli pettorali. Blocca le braccia nella posizione contratta, mantieni per un secondo e poi scendi lentamente. Suggerimento: la fase di discesa dovrebbe durare il doppio della fase di risalita. Ripeti per il numero di ripetizioni prescritto. Al termine, appoggia i manubri sulle cosce e poi a terra.' 
WHERE name = 'Incline Dumbbell Bench With Palms Facing In';

UPDATE public.exercise_library 
SET name_it = 'Curl su panca inclinata con manubri', description_it = 'Siediti su una panca inclinata tenendo un manubrio in ciascuna mano a braccia distese. Mantieni i gomiti vicini al busto e ruota i palmi delle mani finché non sono rivolti in avanti. Questa sarà la tua posizione di partenza. Mantenendo la parte superiore del braccio ferma, solleva i pesi flettendo i bicipiti ed espirando. Solo gli avambracci devono muoversi. Continua il movimento finché i bicipiti non sono completamente contratti e i manubri sono all''altezza delle spalle. Mantieni la contrazione per un secondo. Inizia lentamente a riportare i manubri nella posizione di partenza mentre inspiri. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Incline Dumbbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Croci su panca inclinata con manubri', description_it = 'Impugna un manubrio in ogni mano e sdraiati su una panca inclinata con un angolo non superiore a 30 gradi. Estendi le braccia sopra di te con una leggera flessione dei gomiti. Ora ruota i polsi in modo che i palmi delle mani siano rivolti verso di te. Suggerimento: i mignoli dovrebbero essere vicini tra loro. Questa sarà la posizione di partenza. Mentre inspiri, inizia ad abbassare lentamente le braccia lateralmente, mantenendole estese e ruotando i polsi finché i palmi delle mani non si guardano. Suggerimento: alla fine del movimento le braccia saranno ai tuoi lati con i palmi rivolti verso il soffitto. Mentre espiri, inizia a riportare i manubri nella posizione di partenza invertendo il movimento e ruotando le mani in modo che i mignoli siano di nuovo vicini. Suggerimento: ricorda che il movimento avviene solo a livello dell''articolazione della spalla e del polso. Non deve esserci alcun movimento nell''articolazione del gomito. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Incline Dumbbell Flyes';

UPDATE public.exercise_library 
SET name_it = 'Croci su panca inclinata con manubri - Con rotazione', description_it = 'Impugna un manubrio in ogni mano e sdraiati su una panca inclinata con un angolo non superiore a 30 gradi. Estendi le braccia sopra di te con una leggera flessione dei gomiti. Ora ruota i polsi in modo che i palmi delle mani siano rivolti verso di te. Suggerimento: i mignoli dovrebbero essere vicini tra loro. Questa sarà la posizione di partenza. Mentre inspiri, inizia ad abbassare lentamente le braccia lateralmente, mantenendole estese e ruotando i polsi finché i palmi delle mani non si guardano. Suggerimento: alla fine del movimento le braccia saranno ai tuoi lati con i palmi rivolti verso il soffitto. Mentre espiri, inizia a riportare i manubri nella posizione di partenza invertendo il movimento e ruotando le mani in modo che i mignoli siano di nuovo vicini. Suggerimento: ricorda che il movimento avviene solo a livello dell''articolazione della spalla e del polso. Non deve esserci alcun movimento nell''articolazione del gomito. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Incline Dumbbell Flyes - With A Twist';

UPDATE public.exercise_library 
SET name_it = 'Distensioni su panca inclinata con manubri', description_it = 'Sdraiati su una panca inclinata con un manubrio in ogni mano appoggiato sulle cosce. I palmi delle mani devono essere rivolti l''uno verso l''altro. Utilizzando le cosce per aiutarti a spingere i manubri, sollevali uno alla volta finché non riesci a tenerli all''altezza delle spalle. Una volta sollevati, ruota i polsi in avanti in modo che i palmi siano rivolti lontano da te. Questa sarà la posizione di partenza. Mantieni sempre il pieno controllo dei manubri. Espira e spingi i manubri verso l''alto usando i pettorali. Distendi completamente le braccia in alto, tieni per un secondo e inizia ad abbassare lentamente il peso. Suggerimento: idealmente, la discesa del peso dovrebbe richiedere circa il doppio del tempo rispetto alla salita. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi i manubri sulle cosce e poi a terra. Questo è il modo più sicuro per posare i pesi.' 
WHERE name = 'Incline Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Hammer curl su panca inclinata', description_it = 'Siediti su una panca inclinata con un manubrio in ogni mano. Schiena ben appoggiata allo schienale e piedi uniti. Lascia che i manubri pendano lungo i fianchi con una presa neutra. Questa sarà la tua posizione di partenza. Inizia il movimento flettendo il gomito e cercando di mantenere ferma la parte superiore del braccio. Continua fino alla fine del movimento, fai una pausa e torna lentamente alla posizione iniziale.' 
WHERE name = 'Incline Hammer Curls';

UPDATE public.exercise_library 
SET name_it = 'Curl bicipiti interno su panca inclinata', description_it = 'Impugna un manubrio in ogni mano e sdraiati su una panca inclinata. I manubri devono pendere lungo i fianchi a braccia distese e i palmi devono essere rivolti verso l''esterno. Questa sarà la posizione di partenza. Espirando, solleva i pesi verso l''esterno e verso l''alto, mantenendo gli avambracci in linea con i deltoidi laterali. Continua il curl finché i manubri non sono all''altezza delle spalle, ai lati dei deltoidi. Suggerimento: la posizione finale dovrebbe assomigliare a una posa di doppio bicipite. Dopo una contrazione di un secondo nella parte alta, inspira e abbassa lentamente i pesi nella posizione iniziale seguendo lo stesso percorso. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Incline Inner Biceps Curl';

UPDATE public.exercise_library 
SET name_it = 'Push-up inclinati', description_it = 'Mettiti di fronte a una panca o a una piattaforma elevata e robusta. Appoggia le mani sul bordo della panca, a una larghezza leggermente superiore a quella delle spalle. Posiziona la punta dei piedi indietro rispetto alla panca, mantenendo braccia e corpo dritti. Le braccia devono essere perpendicolari al corpo. Mantenendo il corpo dritto, abbassa il petto verso il bordo della panca flettendo le braccia. Spingi il corpo verso l''alto finché le braccia non sono distese. Ripeti.' 
WHERE name = 'Incline Push-Up';

UPDATE public.exercise_library 
SET name_it = 'Push-up inclinati a presa stretta', description_it = 'Mettiti di fronte a una sbarra (come quella di una Smith machine) o a una piattaforma elevata di altezza adeguata. Posiziona le mani vicine l''una all''altra sulla sbarra. Posiziona i piedi indietro rispetto alla sbarra, tenendo braccia e corpo dritti. Questa sarà la tua posizione di partenza. Mantenendo il corpo dritto, abbassa il petto verso la sbarra flettendo le braccia. Torna alla posizione di partenza estendendo i gomiti e spingendo il corpo verso l''alto.' 
WHERE name = 'Incline Push-Up Close-Grip';

UPDATE public.exercise_library 
SET name_it = 'Push-up inclinati con salto (Depth Jump)', description_it = 'Per questo esercizio avrai bisogno di un box alto circa 30 cm e due tappetini spessi o step aerobici. Posiziona gli step appena fuori dalla larghezza delle spalle e metti i piedi sopra il box in posizione di push-up inclinato, con le mani appena all''interno degli step. Questa sarà la tua posizione di partenza. Inizia flettendo i gomiti per abbassare il corpo, invertendo rapidamente il movimento per spingere il corpo via dal terreno. Mentre ti stacchi da terra, sposta le mani sugli step, flettendo i gomiti per assorbire l''impatto. Ripeti il movimento per tornare alla posizione di partenza.' 
WHERE name = 'Incline Push-Up Depth Jump';

UPDATE public.exercise_library 
SET name_it = 'Push-up inclinati a presa media', description_it = 'Mettiti di fronte a una sbarra (come quella di una Smith machine) o a una piattaforma elevata di altezza adeguata. Appoggia le mani sulla sbarra, a una larghezza pari a quella delle spalle. Posiziona i piedi indietro rispetto alla sbarra, tenendo braccia e corpo dritti. Questa sarà la tua posizione di partenza. Mantenendo il corpo dritto, abbassa il petto verso la sbarra flettendo le braccia. Torna alla posizione di partenza estendendo i gomiti e spingendo il corpo verso l''alto.' 
WHERE name = 'Incline Push-Up Medium';

UPDATE public.exercise_library 
SET name_it = 'Incline Push-Up con presa inversa', description_it = 'Posizionati di fronte a una Smith machine o a una piattaforma sollevata robusta all''altezza adeguata. Appoggia le mani sulla barra con i palmi rivolti verso l''alto, a una larghezza pari a quella delle spalle. Distanzia i piedi dalla barra mantenendo braccia e corpo dritti; questa sarà la posizione di partenza. Mantenendo il corpo dritto, abbassa il petto verso la barra flettendo le braccia. Torna alla posizione iniziale estendendo i gomiti e spingendo verso l''alto.' 
WHERE name = 'Incline Push-Up Reverse Grip';

UPDATE public.exercise_library 
SET name_it = 'Incline Push-Up a presa larga', description_it = 'Posizionati di fronte a una Smith machine o a una piattaforma sollevata robusta all''altezza adeguata. Appoggia le mani sulla barra a una larghezza superiore a quella delle spalle. Distanzia i piedi dalla barra mantenendo braccia e corpo dritti, con le braccia perpendicolari al busto; questa sarà la posizione di partenza. Mantenendo il corpo dritto, abbassa il petto verso la barra flettendo le braccia. Torna alla posizione iniziale estendendo i gomiti e spingendo verso l''alto.' 
WHERE name = 'Incline Push-Up Wide';

UPDATE public.exercise_library 
SET name_it = 'Stretching per l''inguine (intermedio)', description_it = 'Sdraiati sulla schiena con le gambe distese. Fai passare una cinghia, una corda o una fascia attorno a un piede e sposta quella gamba lateralmente il più lontano possibile; questa sarà la posizione di partenza. Tira delicatamente la cinghia per creare tensione nell''inguine e nei muscoli femorali. Mantieni per 10-20 secondi e ripeti sull''altro lato.' 
WHERE name = 'Intermediate Groin Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching per flessori dell''anca e quadricipiti (intermedio)', description_it = 'Sdraiati a pancia in giù sul pavimento con una corda, una cinghia o una fascia attorno a un piede. Fletti il ginocchio ed estendi l''anca della gamba da allungare, usando entrambe le mani per tirare la cinghia. Il ginocchio e l''anca dovrebbero sollevarsi dal pavimento, creando tensione nei flessori dell''anca e nei quadricipiti. Mantieni lo stretching per 10-20 secondi e ripeti sull''altra gamba.' 
WHERE name = 'Intermediate Hip Flexor and Quad Stretch';

UPDATE public.exercise_library 
SET name_it = 'Rotazione interna con elastico', description_it = 'Fissa l''elastico attorno a un palo all''altezza del gomito. Posizionati con il fianco destro rivolto verso l''elastico a circa mezzo metro di distanza. Afferra l''estremità dell''elastico con la mano destra e tieni il gomito premuto saldamente contro il fianco (consigliamo di tenere un cuscinetto o un foam roller tra il gomito e il fianco per mantenerlo in posizione). Con il braccio in posizione, il gomito dovrebbe essere flesso a 90 gradi con la mano rivolta verso l''esterno rispetto al busto; questa è la posizione di partenza. Esegui il movimento ruotando il braccio verso l''interno, mantenendo il gomito fermo. Continua finché possibile, fai una pausa e torna alla posizione iniziale.' 
WHERE name = 'Internal Rotation with Band';

UPDATE public.exercise_library 
SET name_it = 'Inverted Row', description_it = 'Posiziona una barra su un rack all''altezza della vita (puoi usare anche una Smith machine). Afferra la barra con una presa più ampia rispetto alle spalle e posizionati sospeso sotto di essa. Il corpo deve essere dritto, i talloni a terra e le braccia completamente estese; questa sarà la posizione di partenza. Inizia flettendo i gomiti per tirare il petto verso la barra, contraendo le scapole durante il movimento. Fai una pausa nella parte alta e torna alla posizione iniziale. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Inverted Row';

UPDATE public.exercise_library 
SET name_it = 'Inverted Row con cinghie', description_it = 'Appendi una corda o delle cinghie in sospensione a un rack o a un oggetto stabile. Afferra le estremità e posizionati in posizione supina, sospeso dalle cinghie. Il corpo deve essere dritto, i talloni a terra e le braccia completamente estese; questa sarà la posizione di partenza. Inizia flettendo i gomiti per tirare il petto verso le mani, contraendo le scapole durante il movimento. Fai una pausa nella parte alta e torna alla posizione iniziale. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Inverted Row with Straps';

UPDATE public.exercise_library 
SET name_it = 'Iron Cross', description_it = 'Esercizio non specificato.' 
WHERE name = 'Iron Cross';

UPDATE public.exercise_library 
SET name_it = 'Iron Crosses (stretching)', description_it = 'Sdraiati a pancia in giù sul pavimento con le braccia distese lateralmente e i palmi premuti contro il suolo; questa sarà la posizione di partenza. Per iniziare, fletti un ginocchio e porta quella gamba dietro il corpo, cercando di toccare il suolo vicino alla mano opposta. Torna rapidamente alla posizione iniziale e ripeti velocemente con l''altra gamba. Continua ad alternare per 10-20 ripetizioni.' 
WHERE name = 'Iron Crosses (stretch)';

UPDATE public.exercise_library 
SET name_it = 'Isometric Chest Squeezes', description_it = 'Da seduto o in piedi, fletti le braccia a 90 gradi e unisci i palmi delle mani davanti al petto. Consiglio: le mani devono essere aperte con i palmi uniti e le dita rivolte in avanti (perpendicolari al busto). Spingi le mani l''una contro l''altra mentre contrai i pettorali. Inizia con una tensione leggera e aumenta gradualmente. Continua a respirare normalmente durante la contrazione. Mantieni per il tempo raccomandato, quindi rilascia lentamente la tensione. Riposa per il tempo indicato e ripeti.' 
WHERE name = 'Isometric Chest Squeezes';

UPDATE public.exercise_library 
SET name_it = 'Esercizio isometrico per il collo - Frontale e posteriore', description_it = 'Con la testa e il collo in posizione neutra (posizione normale con la testa eretta rivolta in avanti), posiziona entrambe le mani sulla parte frontale della testa. Spingi delicatamente in avanti contraendo i muscoli del collo, ma opponendo resistenza per evitare qualsiasi movimento della testa. Inizia con una tensione leggera e aumenta gradualmente. Continua a respirare normalmente mentre esegui questa contrazione. Mantieni la posizione per il numero di secondi raccomandato. Rilascia lentamente la tensione. Riposa per il tempo indicato e ripeti l''esercizio posizionando le mani sulla nuca.' 
WHERE name = 'Isometric Neck Exercise - Front And Back';

UPDATE public.exercise_library 
SET name_it = 'Esercizio isometrico per il collo - Laterale', description_it = 'Con la testa e il collo in posizione neutra, posiziona la mano sinistra sul lato sinistro della testa. Spingi delicatamente verso sinistra contraendo i muscoli del collo del lato sinistro, ma opponendo resistenza per evitare qualsiasi movimento della testa. Inizia con una tensione leggera e aumenta gradualmente. Continua a respirare normalmente durante la contrazione. Mantieni la posizione per il numero di secondi raccomandato. Rilascia lentamente la tensione. Riposa per il tempo indicato e ripeti l''esercizio posizionando la mano destra sul lato destro della testa.' 
WHERE name = 'Isometric Neck Exercise - Sides';

UPDATE public.exercise_library 
SET name_it = 'Isometric Wipers', description_it = 'Assumi la posizione di piegamento (push-up), sostenendo il peso sulle mani e sulle punte dei piedi, mantenendo il corpo dritto. Le mani devono essere posizionate appena oltre la larghezza delle spalle. Questa è la posizione di partenza. Inizia spostando il peso del corpo il più possibile verso un lato, permettendo al gomito di quel lato di flettersi mentre abbassi il busto. Inverti il movimento estendendo il braccio flesso, spingendo il corpo verso l''alto e lasciandoti poi ricadere sull''altro lato. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Isometric Wipers';

UPDATE public.exercise_library 
SET name_it = 'JM Press', description_it = 'Inizia l''esercizio come faresti per una panca piana a presa stretta. Sdraiati su una panca piana tenendo un bilanciere a braccia distese (completamente estese) con i gomiti stretti. Assicurati che la sbarra sia posizionata in linea diretta sopra la parte alta del petto: questa sarà la tua posizione di partenza. Dalla posizione di massima estensione, abbassa il bilanciere come se stessi eseguendo un''estensione per tricipiti da sdraiato. Inspira durante il movimento. Quando raggiungi metà percorso, lascia arretrare leggermente il bilanciere (circa 2-3 cm) muovendo la parte alta delle braccia verso le gambe fino a quando non sono perpendicolari al busto. Suggerimento: mantieni costante l''angolo dei gomiti mentre porti in avanti la parte alta delle braccia. Espirando, spingi il bilanciere verso l''alto usando i tricipiti, eseguendo una sorta di panca a presa stretta. Torna alla posizione iniziale e ricomincia. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'JM Press';

UPDATE public.exercise_library 
SET name_it = 'Jackknife Sit-Up', description_it = 'Sdraiati supino sul pavimento (o su un tappetino) con le braccia distese oltre la testa e le gambe ben tese. Questa è la posizione di partenza. Espirando, fletti il busto in avanti sollevando contemporaneamente gambe e braccia per incontrarsi in posizione di ''jackknife'' (a libro). Suggerimento: le gambe devono rimanere tese e sollevate con un angolo di circa 35-45 gradi rispetto al pavimento, mentre le braccia devono essere parallele alle gambe. La parte superiore del busto deve essere sollevata da terra. Inspirando, abbassa braccia e gambe tornando alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Jackknife Sit-Up';

UPDATE public.exercise_library 
SET name_it = 'Janda Sit-Up', description_it = 'Posizionati sul pavimento in assetto da sit-up classico: ginocchia flesse a 90 gradi con piedi ben piantati a terra e braccia incrociate sul petto o lungo i fianchi. Questa è la posizione di partenza. Contraendo con forza glutei e bicipiti femorali, inspira e sollevati lentamente (in 3-6 secondi) espirando gradualmente. Suggerimento: è fondamentale contrarre glutei e femorali per disattivare i flessori dell''anca tramite un processo chiamato ''inibizione reciproca'', che permette ai muscoli opposti a quelli contratti di rilassarsi. Inspirando, torna lentamente alla posizione iniziale in modo controllato. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Janda Sit-Up';

UPDATE public.exercise_library 
SET name_it = 'Jefferson Squats', description_it = 'Posiziona un bilanciere a terra. Mettiti in piedi al centro della barra, orientato longitudinalmente rispetto ad essa. Abbassati flettendo le ginocchia, mantenendo la schiena dritta, e afferra la parte anteriore della barra con la mano destra (palmo rivolto verso sinistra, presa neutra). Afferra la parte posteriore della barra con la mano sinistra (palmo rivolto verso destra, presa neutra). Suggerimento: assicurati che la presa sulla barra sia equilibrata. Il busto deve essere posizionato esattamente al centro della barra. Sollevati in piedi portando il peso con te. Suggerimento: i piedi devono essere alla larghezza delle spalle con le punte leggermente rivolte verso l''esterno. Esegui uno squat flettendo le ginocchia e mantenendo la schiena dritta fino a quando le cosce sono parallele al pavimento. Suggerimento: mantieni la schiena il più verticale possibile e la testa alta. Evita che le ginocchia superino le punte dei piedi. Inspira durante questa fase. Spingendo con i piedi, torna alla posizione di partenza. Suggerimento: tieni il bilanciere sospeso a braccia distese con i gomiti bloccati e una leggera flessione. Le braccia fungono solo da ganci; non sollevare il peso con le braccia, usa la forza delle cosce.' 
WHERE name = 'Jefferson Squats';

UPDATE public.exercise_library 
SET name_it = 'Jerk Balance', description_it = 'Questo esercizio aiuta ad imparare ad affondare correttamente durante il jerk e corregge lo spostamento all''indietro durante il movimento. Inizia con il bilanciere caricato in posizione di rack per il jerk, spalle in avanti, busto verticale e piedi leggermente distanziati (split). Inizia il movimento come per un normale jerk: fletti le ginocchia mantenendo il busto verticale e spingi verso l''alto con forza, sfruttando lo slancio e non le braccia per elevare il peso. Mantieni il piede posteriore in posizione, usandolo per spingere il corpo in avanti in un affondo completo (split) mentre porti il peso sopra la testa. Recupera la posizione eretta con il peso sopra la testa.' 
WHERE name = 'Jerk Balance';

UPDATE public.exercise_library 
SET name_it = 'Jerk Dip Squat', description_it = 'Questo movimento rafforza la fase di dip (spinta iniziale) del jerk. Inizia con il bilanciere in posizione di rack, con le spalle protese in avanti per creare un appoggio e il bilanciere che tocca leggermente la gola. I piedi devono essere sotto i fianchi, orientati verso l''esterno in modo confortevole. Mantenendo il busto verticale, esegui un dip flettendo le ginocchia, lasciandole viaggiare in avanti senza spostare i fianchi all''indietro. Il dip non deve essere eccessivo. Torna alla posizione di partenza spingendo con forza attraverso i piedi.' 
WHERE name = 'Jerk Dip Squat';

UPDATE public.exercise_library 
SET name_it = 'Jogging su tapis roulant', description_it = 'Per iniziare, sali sul tapis roulant e seleziona l''opzione desiderata dal menu. La maggior parte dei tapis roulant ha un''impostazione manuale o programmi predefiniti. Solitamente, inserendo età e peso si può stimare il consumo calorico. L''inclinazione può essere regolata per variare l''intensità. I tapis roulant offrono comodità, benefici cardiovascolari e un impatto solitamente inferiore rispetto alla corsa all''aperto. Una persona di circa 68 kg brucia quasi 250 calorie correndo per 30 minuti, rispetto alle oltre 450 calorie della corsa veloce. Mantieni una postura corretta durante l''esercizio e tieni le maniglie solo quando necessario, ad esempio quando scendi o controlli la frequenza cardiaca.' 
WHERE name = 'Jogging, Treadmill';

UPDATE public.exercise_library 
SET name_it = 'Keg Load', description_it = 'Per eseguire il caricamento dei fusti (keg), posizionali a una distanza prestabilita dalla piattaforma di carico, solitamente tra i 9 e i 15 metri. Inizia afferrando la maniglia più vicina del primo fusto, inclinalo di lato per afferrare il bordo opposto della base e sollevalo fino al petto. Più in alto riuscirai a posizionare il fusto, più velocemente potrai muoverti verso la piattaforma. Lo ''shouldering'' (appoggio sulla spalla) solitamente non è consentito. Mantieni una presa salda sul fusto. Muoviti il più rapidamente possibile verso la piattaforma e caricalo, estendendo anche, ginocchia e caviglie per posizionarlo il più in alto possibile. Torna alla posizione di partenza per recuperare il fusto successivo e ripeti fino al completamento dell''esercizio.' 
WHERE name = 'Keg Load';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Arnold Press', description_it = 'Esegui un Clean del kettlebell fino alla spalla, estendendo gambe e anche mentre lo sollevi verso la spalla stessa. Il palmo deve essere rivolto verso l''interno. Guardando dritto davanti a te, spingi il kettlebell verso l''alto sopra la testa, ruotando il polso in modo che il palmo sia rivolto in avanti al culmine del movimento. Riporta il kettlebell nella posizione di partenza con il palmo rivolto verso l''interno.' 
WHERE name = 'Kettlebell Arnold Press';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Dead Clean', description_it = 'Posiziona il kettlebell tra i piedi. Per assumere la posizione di partenza, spingi il bacino indietro e guarda dritto davanti a te. Esegui un Clean del kettlebell fino alla spalla, estendendo gambe e anche durante la risalita. Ruota il polso durante il movimento. Abbassa il kettlebell mantenendo gli ischiocrurali in tensione, la schiena dritta e il bacino spinto all''indietro.' 
WHERE name = 'Kettlebell Dead Clean';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Figure 8', description_it = 'Posiziona un kettlebell tra le gambe e assumi una posizione dei piedi più larga rispetto alle spalle. Piegati in avanti spingendo il bacino all''indietro e mantenendo la schiena piatta. Afferra il kettlebell e passalo all''altra mano facendolo passare tra le gambe. La mano che riceve deve passare da dietro le gambe. Procedi alternando le mani per diverse ripetizioni.' 
WHERE name = 'Kettlebell Figure 8';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Hang Clean', description_it = 'Posiziona il kettlebell tra i piedi. Per assumere la posizione di partenza, spingi il bacino indietro e guarda dritto davanti a te. Esegui un Clean del kettlebell fino alla spalla, estendendo gambe e anche durante la risalita. Ruota il polso durante il movimento. Abbassa il kettlebell in una posizione sospesa tra le gambe mantenendo gli ischiocrurali in tensione. Mantieni sempre la testa alta.' 
WHERE name = 'Kettlebell Hang Clean';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell One-Legged Deadlift', description_it = 'Afferra il manico del kettlebell con una mano. Stai in equilibrio su una gamba sola, quella dello stesso lato della mano che tiene il kettlebell. Mantenendo il ginocchio leggermente flesso, esegui uno stacco a gamba tesa flettendo l''anca ed estendendo la gamba libera dietro di te per mantenere l''equilibrio. Continua ad abbassare il kettlebell finché il busto non è parallelo al terreno, quindi torna alla posizione eretta.' 
WHERE name = 'Kettlebell One-Legged Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Pass Between The Legs', description_it = 'Posiziona un kettlebell tra le gambe e assumi una posizione confortevole. Piegati in avanti spingendo il bacino all''indietro e mantenendo la schiena piatta. Afferra il kettlebell e passalo all''altra mano tra le gambe seguendo un movimento a ''W''. Procedi alternando le mani per diverse ripetizioni.' 
WHERE name = 'Kettlebell Pass Between The Legs';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Pirate Ships', description_it = 'Con una posizione dei piedi larga, tieni il kettlebell con entrambe le mani. Lascialo pendere all''altezza della vita con le braccia tese: questa è la posizione di partenza. Inizia il movimento ruotando verso un lato e facendo oscillare il kettlebell fino all''altezza della testa. Fai una breve pausa al culmine del movimento. Lascia scendere il kettlebell mentre ruoti verso il lato opposto, sollevandolo nuovamente fino all''altezza della testa. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Kettlebell Pirate Ships';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Pistol Squat', description_it = 'Afferra il kettlebell con due mani tenendolo per le corna. Solleva una gamba dal pavimento ed esegui uno squat sull''altra. Scendi in accosciata flettendo il ginocchio e portando il bacino indietro, mantenendo il kettlebell sollevato davanti a te. Mantieni la posizione di massima accosciata per un secondo, quindi inverti il movimento spingendo attraverso il tallone e mantenendo testa e petto alti. Risali e ripeti.' 
WHERE name = 'Kettlebell Pistol Squat';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Seated Press', description_it = 'Siediti sul pavimento con le gambe divaricate in modo confortevole. Esegui un Clean di un kettlebell fino alla spalla. Spingi il kettlebell verso l''alto finché il braccio non è completamente disteso sopra la testa. Torna alla posizione di partenza.' 
WHERE name = 'Kettlebell Seated Press';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Seesaw Press', description_it = 'Porta due kettlebell alle spalle con un clean. Esegui una press con un kettlebell. Abbassa il kettlebell e spingi immediatamente l''altro. Assicurati di eseguire lo stesso numero di ripetizioni su entrambi i lati.' 
WHERE name = 'Kettlebell Seesaw Press';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Sumo High Pull', description_it = 'Posiziona un kettlebell a terra tra i piedi. Assumi una posizione a gambe larghe e afferra il kettlebell con due mani. Spingi i fianchi il più indietro possibile, mantenendo le ginocchia flesse. Tieni petto e testa alti. Questa è la posizione di partenza. Inizia estendendo fianchi e ginocchia, tirando simultaneamente il kettlebell verso le spalle e sollevando i gomiti durante il movimento. Inverti il movimento per tornare alla posizione iniziale.' 
WHERE name = 'Kettlebell Sumo High Pull';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Thruster', description_it = 'Porta due kettlebell alle spalle con un clean, estendendo gambe e fianchi e ruotando i polsi mentre tiri i pesi verso l''alto. Questa è la posizione di partenza. Inizia lo squat flettendo fianchi e ginocchia e scendendo con il bacino tra le gambe. Mantieni la schiena dritta e il busto eretto durante la discesa. Dalla posizione bassa, inverti il movimento estendendo ginocchia e fianchi, spingendo attraverso i talloni. Mentre risali, spingi entrambi i kettlebell sopra la testa estendendo le braccia, sfruttando lo slancio dello squat. Prima di iniziare la ripetizione successiva, riporta i pesi alle spalle.' 
WHERE name = 'Kettlebell Thruster';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Turkish Get-Up (stile affondo)', description_it = 'Sdraiati sulla schiena e porta un kettlebell sopra la testa distendendo il braccio. Piega il ginocchio sullo stesso lato del kettlebell. Mantenendo il braccio teso, ruota sul lato opposto e usa il braccio libero per aiutarti a spingerti verso la posizione di affondo. Usando la mano libera, spingiti fino a una posizione seduta, quindi passa a una posizione in ginocchio. Guardando sempre il kettlebell, alzati lentamente in piedi. Inverti il movimento per tornare alla posizione iniziale e ripeti.' 
WHERE name = 'Kettlebell Turkish Get-Up (Lunge style)';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Turkish Get-Up (stile squat)', description_it = 'Sdraiati sulla schiena e porta un kettlebell sopra la testa distendendo il braccio. Piega il ginocchio sullo stesso lato del kettlebell. Mantenendo il braccio teso, ruota sul lato opposto e usa il braccio libero per aiutarti a spingerti verso la posizione di affondo. Usando la mano libera, spingiti fino a una posizione seduta, quindi passa a una posizione in piedi. Guardando sempre il kettlebell, alzati lentamente in piedi. Inverti il movimento per tornare alla posizione iniziale e ripeti.' 
WHERE name = 'Kettlebell Turkish Get-Up (Squat style)';

UPDATE public.exercise_library 
SET name_it = 'Kettlebell Windmill', description_it = 'Posiziona un kettlebell davanti al piede avanzato, sollevalo con un clean e portalo sopra la testa con il braccio opposto, ruotando il polso in modo che il palmo sia rivolto in avanti. Mantenendo il braccio teso, spingi il bacino verso il lato del braccio che sostiene il carico. Ruota i piedi di quarantacinque gradi rispetto al braccio con il kettlebell. Piegandoti lateralmente all''altezza dei fianchi e spingendo il bacino in fuori, inclinati lentamente finché non riesci a toccare il pavimento con la mano libera. Tieni sempre lo sguardo rivolto al kettlebell. Fermati un secondo dopo aver toccato terra e inverti il movimento per tornare alla posizione iniziale.' 
WHERE name = 'Kettlebell Windmill';

UPDATE public.exercise_library 
SET name_it = 'Kipping Muscle Up', description_it = 'Afferra gli anelli con una ''false grip'', posizionando la base dei palmi sopra gli anelli. Inizia con un leggero slancio delle gambe all''indietro. Contrasta il movimento oscillando le gambe in avanti e verso l''alto, tirando mento e petto all''indietro e trazionando con entrambe le braccia. Quando raggiungi la posizione alta della trazione, porta gli anelli verso le ascelle ruotando le spalle in avanti e lasciando che i gomiti vadano direttamente dietro di te. Questo ti mette nella posizione corretta per proseguire con la fase di dip. Mantenendo controllo e stabilità, distendi le braccia per completare il movimento. Scendi a terra con attenzione.' 
WHERE name = 'Kipping Muscle Up';

UPDATE public.exercise_library 
SET name_it = 'Knee Across The Body', description_it = 'Sdraiati a terra con la gamba destra distesa. Piega la gamba sinistra e abbassala lateralmente oltre il corpo, tenendo il ginocchio verso il pavimento con la mano destra (non deve necessariamente toccare terra se avverti rigidità). Posiziona il braccio sinistro comodamente accanto a te e gira la testa verso sinistra. Immagina di avere un peso legato al coccige: lascia che il bacino ruoti verso il pavimento mentre il petto si distende nella direzione opposta per allungare la zona lombare. Cambia lato.' 
WHERE name = 'Knee Across The Body';

UPDATE public.exercise_library 
SET name_it = 'Circonduzioni delle ginocchia', description_it = 'In piedi, con le gambe unite e le mani sui fianchi, esegui dei movimenti circolari con le ginocchia respirando regolarmente. Ripeti per il numero di volte consigliato.' 
WHERE name = 'Knee Circles';

UPDATE public.exercise_library 
SET name_it = 'Sollevamento ginocchia/bacino alle parallele', description_it = 'Posizionati sull''attrezzo per il leg raise verticale appoggiando gli avambracci sui cuscinetti e afferrando le maniglie. Le braccia devono essere flesse a 90 gradi. Il busto deve essere dritto, la zona lombare premuta contro lo schienale e le gambe tese verso il basso. Questa è la posizione di partenza. Espirando, solleva le gambe mantenendole tese finché non sono approssimativamente parallele al pavimento, quindi mantieni la contrazione per un secondo. Consiglio: non usare slancio o oscillazioni durante l''esercizio. Inspira e torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Knee/Hip Raise On Parallel Bars';

UPDATE public.exercise_library 
SET name_it = 'Knee Tuck Jump', description_it = 'Inizia in una posizione eretta confortevole con le ginocchia leggermente flesse. Tieni le mani davanti a te, palmi rivolti verso il basso e punte delle dita unite all''altezza del petto. Questa sarà la tua posizione di partenza. Esegui rapidamente un mezzo squat e, immediatamente, esplodi verso l''alto. Porta le ginocchia verso il petto, cercando di toccare i palmi delle mani. Salta il più in alto possibile sollevando le ginocchia, quindi assicurati di atterrare correttamente estendendo nuovamente le gambe e assorbendo l''impatto flettendo le ginocchia.' 
WHERE name = 'Knee Tuck Jump';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Arm Drill', description_it = 'Questo esercizio aiuta ad aumentare l''efficienza delle braccia durante la corsa. Inizia in ginocchio, con il piede sinistro in avanti e il ginocchio destro a terra. Esercita pressione attraverso il tallone anteriore per mantenere glutei e muscoli posteriori della coscia attivati. Inizia facendo oscillare le braccia con movimenti lunghi, simili a un pendolo. Chiudi l''angolo del braccio, muovendoti come faresti durante il jogging, passando poi a una corsa e infine a uno sprint. Non appena le mani superano l''anca, accelerale in avanti durante il movimento di sprint per muoverle il più velocemente possibile. Cambia ginocchio e ripeti.' 
WHERE name = 'Kneeling Arm Drill';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Cable Crunch With Alternating Oblique Twists', description_it = 'Collega un accessorio a corda a una carrucola alta e posiziona un tappetino sul pavimento davanti ad essa. Afferra la corda con entrambe le mani e inginocchiati a circa 60 cm dalla torre. Posiziona la corda dietro la testa con le mani vicino alle orecchie. Mantenendo le mani ferme, contrai gli addominali e tira la corda verso il basso con un movimento di crunch fino a quando i gomiti raggiungono le ginocchia. Fai una breve pausa in basso e risali in modo lento e controllato fino a tornare alla posizione di partenza. Ripeti lo stesso movimento di discesa fino a metà strada, momento in cui inizierai a ruotare uno dei gomiti verso il ginocchio opposto. Fai di nuovo una breve pausa in basso e risali in modo controllato. Ripeti il movimento alternando l''altro gomito verso il ginocchio opposto. Continua questa serie di movimenti fino al cedimento muscolare.' 
WHERE name = 'Kneeling Cable Crunch With Alternating Oblique Twists';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Cable Triceps Extension', description_it = 'Posiziona una panca lateralmente davanti a una macchina a carrucola alta. Impugna una barra dritta sopra la testa con le mani a circa 15 cm di distanza e i palmi rivolti verso il basso. Dai le spalle alla macchina e inginocchiati. Appoggia la testa e la parte posteriore delle braccia sulla panca. I gomiti devono essere piegati con gli avambracci rivolti verso la carrucola. Questa è la posizione di partenza. Mantenendo sempre la parte superiore delle braccia vicino alla testa e i gomiti stretti, spingi la barra con un movimento semicircolare finché i gomiti non sono bloccati e le braccia risultano parallele al pavimento. Contrai intensamente i tricipiti e mantieni la posizione per un secondo espirando durante il movimento. Ritorna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Kneeling Cable Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Forearm Stretch', description_it = 'Inizia inginocchiandoti su un tappetino con i palmi delle mani piatti a terra e le dita rivolte verso le ginocchia. Lentamente, inclinati all''indietro mantenendo i palmi a contatto con il pavimento finché non senti un allungamento nei polsi e negli avambracci. Mantieni la posizione per 20-30 secondi.' 
WHERE name = 'Kneeling Forearm Stretch';

UPDATE public.exercise_library 
SET name_it = 'Kneeling High Pulley Row', description_it = 'Seleziona il peso appropriato usando una carrucola posizionata sopra la testa. Collega una corda al cavo e inginocchiati a breve distanza, tenendo la corda davanti a te con entrambe le braccia tese. Questa è la tua posizione di partenza. Inizia il movimento flettendo i gomiti e retrattando completamente le spalle, tirando la corda verso la parte superiore del petto con i gomiti larghi. Dopo una breve pausa, ritorna lentamente alla posizione di partenza.' 
WHERE name = 'Kneeling High Pulley Row';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Hip Flexor', description_it = 'Inginocchiati su un tappetino, porta il ginocchio destro in avanti in modo che la pianta del piede sia a terra ed estendi la gamba sinistra all''indietro con il dorso del piede a terra. Sposta il peso in avanti finché non senti un allungamento all''altezza dell''anca. Mantieni per 15 secondi, quindi ripeti sull''altro lato.' 
WHERE name = 'Kneeling Hip Flexor';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Jump Squat', description_it = 'Inizia in ginocchio sul pavimento con un bilanciere caricato sulle spalle, oppure usa solo il peso del corpo. Può essere eseguito all''interno di un power rack per facilitare lo stacco del bilanciere. Siediti sui talloni finché i glutei non toccano i piedi, mantenendo testa e petto alti. Esplodi verso l''alto con le anche, generando abbastanza potenza per atterrare con i piedi piatti sul pavimento. Prosegui con lo squat spingendo attraverso i talloni ed estendendo le ginocchia fino a raggiungere una posizione eretta.' 
WHERE name = 'Kneeling Jump Squat';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Single-Arm_High_Pulley_Row', description_it = 'Collega una maniglia singola a una carrucola alta e seleziona il peso. Inginocchiati davanti alla torre, afferrando il cavo con una mano e mantenendo il braccio teso. Questa è la posizione di partenza. Partendo con il palmo rivolto in avanti, tira il peso verso il busto flettendo il gomito e retrattando la scapola. Mentre lo fai, ruota il polso in modo che, al completamento del movimento, il palmo sia rivolto verso di te. Dopo una breve pausa, ritorna alla posizione di partenza.' 
WHERE name = 'Kneeling Single-Arm High Pulley Row';

UPDATE public.exercise_library 
SET name_it = 'Kneeling Squat', description_it = 'Regola il bilanciere all''altezza corretta in un power rack. Inginocchiati dietro il bilanciere; può essere utile usare un tappetino per proteggere le ginocchia. Posizionati sotto il bilanciere, appoggiandolo sulla parte alta della schiena. Le scapole devono essere retratte e il bilanciere ben saldo sulla schiena. Stacca il carico. Con lo sguardo rivolto in avanti, siediti all''indietro con il bacino fino a toccare i polpacci. Inverti il movimento, tornando con il busto in posizione eretta.' 
WHERE name = 'Kneeling Squat';

UPDATE public.exercise_library 
SET name_it = 'Landmine 180''s', description_it = 'Posiziona un bilanciere in un supporto landmine o fissalo saldamente in un angolo. Carica il bilanciere con un peso adeguato. Solleva il bilanciere da terra portandolo all''altezza delle spalle con entrambe le mani e braccia tese davanti a te. Adotta una posizione dei piedi larga. Questa sarà la posizione di partenza. Esegui il movimento ruotando il busto e le anche mentre fai oscillare il peso lateralmente fino in basso. Mantieni le braccia tese durante tutto l''esercizio. Inverti il movimento per far oscillare il peso verso il lato opposto. Continua ad alternare il movimento fino al completamento della serie.' 
WHERE name = 'Landmine 180''s';

UPDATE public.exercise_library 
SET name_it = 'Landmine Linear Jammer', description_it = 'Posiziona un bilanciere in un supporto landmine o, in mancanza, fissalo saldamente in un angolo. Carica il bilanciere con un peso adeguato e inserisci l''impugnatura. Solleva il bilanciere da terra portando le impugnature alle spalle. Questa sarà la posizione di partenza. In posizione atletica, esegui uno squat flettendo le anche e portandole indietro, mantenendo le braccia flesse. Inverti il movimento estendendo con forza anche, ginocchia e caviglie, mentre estendi contemporaneamente i gomiti per distendere le braccia. Questo movimento deve essere esplosivo, risalendo dallo squat fino alla completa estensione con la massima potenza possibile. Torna alla posizione di partenza.' 
WHERE name = 'Landmine Linear Jammer';

UPDATE public.exercise_library 
SET name_it = 'Lateral Bound', description_it = 'Assumi una posizione di mezzo squat orientato a 90 gradi rispetto alla direzione di spostamento. Questa sarà la posizione di partenza. Esegui un contro-movimento verso l''interno con la gamba di spinta mentre sposti il peso sulla gamba esterna. Spingi immediatamente ed estendi, cercando di saltare lateralmente il più lontano possibile. All''atterraggio, spingi immediatamente nella direzione opposta, tornando alla posizione di partenza iniziale. Continua alternando il movimento per diverse ripetizioni.' 
WHERE name = 'Lateral Bound';

UPDATE public.exercise_library 
SET name_it = 'Lateral Box Jump', description_it = 'Assumi una comoda posizione eretta con un box basso posizionato lateralmente rispetto a te. Questa sarà la posizione di partenza. Esegui rapidamente un quarto di squat per attivare il riflesso miotatico e inverti immediatamente la direzione per saltare verso l''alto e di lato. Porta le ginocchia abbastanza in alto da garantire che i piedi superino chiaramente il box. Atterra al centro del box, utilizzando le gambe per assorbire l''impatto. Salta con attenzione verso l''altro lato del box e continua alternando il movimento per diverse ripetizioni.' 
WHERE name = 'Lateral Box Jump';

UPDATE public.exercise_library 
SET name_it = 'Lateral Cone Hops', description_it = 'Posiziona una serie di coni in fila a diversi centimetri di distanza l''uno dall''altro. Stai accanto all''estremità della fila di coni, rivolto a 90 gradi rispetto alla direzione di avanzamento. Questa sarà la posizione di partenza. Inizia il salto flettendo le ginocchia per attivare il riflesso miotatico e inverti immediatamente la direzione per spingerti dal suolo, saltando verso l''alto e lateralmente sopra il cono. Usa le gambe per assorbire l''impatto all''atterraggio e sfrutta il rimbalzo per il salto successivo, proseguendo lungo la fila di coni.' 
WHERE name = 'Lateral Cone Hops';

UPDATE public.exercise_library 
SET name_it = 'Alzate Laterali con Bande Elastiche', description_it = 'Inizia posizionandoti in piedi sopra una banda elastica in modo che la tensione inizi fin da subito a braccia distese. Afferra le maniglie con una presa prona (palmi rivolti verso le cosce) leggermente più stretta della larghezza delle spalle. Le maniglie devono poggiare ai lati delle cosce. Le braccia devono essere tese con una leggera flessione dei gomiti e la schiena dritta. Questa sarà la posizione di partenza. Utilizza i muscoli delle spalle per sollevare le maniglie lateralmente espirando. Continua a sollevare le maniglie finché non sono leggermente al di sopra della linea parallela. Consiglio: mentre sollevi, ruota leggermente le mani come se stessi versando dell''acqua e tieni le braccia tese. Mantieni il busto immobile e fai una pausa di un secondo nel punto massimo del movimento. Abbassa lentamente le maniglie verso la posizione di partenza. Inspira durante questa fase del movimento. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lateral Raise - With Bands';

UPDATE public.exercise_library 
SET name_it = 'SMR Gran Dorsale', description_it = 'Sdraiato a terra, posiziona un foam roller sotto la schiena lateralmente, appena dietro l''ascella. Questa sarà la posizione di partenza. Mantieni il braccio del lato che stai trattando dietro e lateralmente a te mentre sposti il peso sui dorsali, mantenendo la parte superiore del corpo sollevata da terra. Mantieni la posizione per 10-30 secondi, quindi cambia lato.' 
WHERE name = 'Latissimus Dorsi-SMR';

UPDATE public.exercise_library 
SET name_it = 'Leg-Over Floor Press', description_it = 'Sdraiati a terra con un kettlebell sul petto, afferrandolo per l''impugnatura. Estendi la gamba del lato di lavoro sopra la gamba del lato non lavorativo. Il braccio libero può essere disteso lateralmente per supporto. Spingi il kettlebell verso l''alto fino a completa estensione. Abbassa il peso finché il gomito tocca terra, mantenendo il kettlebell sopra il gomito. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Leg-Over Floor Press';

UPDATE public.exercise_library 
SET name_it = 'Stretching Ischiocrurali con Gamba Sollevata', description_it = 'Sdraiati supino, fletti un ginocchio e appoggia il piede a terra per stabilizzare la colonna vertebrale. Estendi l''altra gamba verso l''alto. Se senti tensione, potresti non riuscire a stenderla completamente, va bene così. Estendi il ginocchio in modo che la pianta del piede rivolto verso l''alto sia parallela al soffitto (o il più possibile). Raddrizza lentamente le gambe quanto più possibile e poi tira la gamba verso il naso. Cambia gamba.' 
WHERE name = 'Leg-Up Hamstring Stretch';

UPDATE public.exercise_library 
SET name_it = 'Leg Extension', description_it = 'Per questo esercizio è necessario utilizzare una macchina per leg extension. Seleziona il carico, siediti sulla macchina con le gambe sotto il cuscinetto (piedi rivolti in avanti) e le mani che afferrano le maniglie laterali. Questa sarà la posizione di partenza. Consiglio: regola il cuscinetto in modo che poggi sulla parte inferiore della gamba (appena sopra i piedi). Assicurati che le gambe formino un angolo di 90 gradi tra la parte inferiore e superiore. Se l''angolo è inferiore a 90 gradi, il ginocchio supererà la punta dei piedi, creando uno stress eccessivo sull''articolazione. Se la macchina è progettata in questo modo, cerca un''altra attrezzatura o assicurati di fermare il movimento verso il basso una volta raggiunto l''angolo di 90 gradi. Utilizzando i quadricipiti, estendi le gambe al massimo mentre espiri. Assicurati che il resto del corpo rimanga immobile sul sedile. Fai una pausa di un secondo nella posizione di contrazione. Abbassa lentamente il peso alla posizione originale inspirando, assicurandoti di non superare il limite di 90 gradi. Ripeti per il numero di volte consigliato.' 
WHERE name = 'Leg Extensions';

UPDATE public.exercise_library 
SET name_it = 'Leg Lift', description_it = 'In piedi, con i piedi alla larghezza delle spalle, afferra una superficie stabile (come i montanti di un rack o lo schienale di una sedia) per mantenere l''equilibrio. Con o senza cavigliere, solleva una gamba all''indietro come se stessi eseguendo un leg curl, mantenendo l''altra gamba tesa. Espira durante il movimento. Inspira mentre riporti lentamente la gamba a terra. Ripeti per il numero di ripetizioni consigliato e poi cambia gamba.' 
WHERE name = 'Leg Lift';

UPDATE public.exercise_library 
SET name_it = 'Leg Press', description_it = 'Siediti sulla leg press e posiziona i piedi sulla piattaforma alla larghezza delle spalle. Abbassa le barre di sicurezza e spingi la piattaforma fino a distendere le gambe (senza bloccare le ginocchia). Il busto e le gambe dovrebbero formare un angolo di 90 gradi: questa è la posizione di partenza. Inspira e abbassa lentamente la piattaforma finché le cosce e le gambe formano un angolo di 90 gradi. Spingendo principalmente con i talloni e usando i quadricipiti, torna alla posizione iniziale espirando. Al termine, assicurati di bloccare le sicure.' 
WHERE name = 'Leg Press';

UPDATE public.exercise_library 
SET name_it = 'Leg Pull-In', description_it = 'Sdraiati su un tappetino con le gambe tese e le mani lungo i fianchi o sotto i glutei. Questa è la posizione di partenza. Espirando, fletti le ginocchia e porta le cosce verso l''addome finché le ginocchia non sono all''altezza del petto. Contrai gli addominali e mantieni la posizione per un secondo. I polpacci devono rimanere paralleli al pavimento durante il movimento. Inspira tornando alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Leg Pull-In';

UPDATE public.exercise_library 
SET name_it = 'Leverage Chest Press', description_it = 'Carica il peso appropriato e regola il sedile in base alla tua altezza; all''inizio del movimento, le maniglie devono trovarsi vicino alla parte inferiore o centrale dei pettorali. Mantieni petto in fuori, testa alta e scapole addotte. Spingi le maniglie in avanti distendendo i gomiti. Dopo una breve pausa, riporta il peso appena sopra la posizione di partenza, mantenendo la tensione muscolare e senza appoggiare i pesi sui fermi fino al termine della serie.' 
WHERE name = 'Leverage Chest Press';

UPDATE public.exercise_library 
SET name_it = 'Leverage Deadlift', description_it = 'Carica il peso appropriato e posizionati tra le maniglie. Afferrale con una presa comoda, abbassa i fianchi e inspira. Tieni la testa alta guardando in avanti e il petto in fuori. Questa è la posizione di partenza. Solleva il peso distendendo le gambe e il busto, quindi riportalo alla posizione di partenza.' 
WHERE name = 'Leverage Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Leverage Decline Chest Press', description_it = 'Carica il peso appropriato e regola il sedile; all''inizio del movimento le maniglie devono trovarsi vicino alla parte inferiore dei pettorali. Mantieni petto in fuori, testa alta e scapole addotte. Questa è la posizione di partenza. Spingi le maniglie in avanti distendendo i gomiti. Dopo una breve pausa, riporta il peso appena sopra la posizione di partenza, mantenendo la tensione muscolare e senza appoggiare i pesi sui fermi fino al termine della serie.' 
WHERE name = 'Leverage Decline Chest Press';

UPDATE public.exercise_library 
SET name_it = 'Leverage High Row', description_it = 'Carica il peso e regola il sedile in modo da raggiungere le maniglie poste in alto. Regola il cuscino per le ginocchia per rimanere stabile. Afferra le maniglie con una presa prona: questa è la posizione di partenza. Tira le maniglie verso il busto, adducendo le scapole e flettendo i gomiti. Fai una pausa alla fine del movimento e torna lentamente alla posizione iniziale. Per le serie multiple, evita di appoggiare completamente il peso sui fermi per mantenere la tensione muscolare.' 
WHERE name = 'Leverage High Row';

UPDATE public.exercise_library 
SET name_it = 'Leverage Incline Chest Press', description_it = 'Carica il peso appropriato e regola il sedile; all''inizio del movimento le maniglie devono trovarsi vicino alla parte superiore dei pettorali. Mantieni petto in fuori, testa alta e scapole addotte. Questa è la posizione di partenza. Spingi le maniglie in avanti distendendo i gomiti. Dopo una breve pausa, riporta il peso appena sopra la posizione di partenza, mantenendo la tensione muscolare e senza appoggiare i pesi sui fermi fino al termine della serie.' 
WHERE name = 'Leverage Incline Chest Press';

UPDATE public.exercise_library 
SET name_it = 'Leverage Iso Row', description_it = 'Carica il peso e regola il sedile in modo che le maniglie siano all''altezza del petto. Afferrale con una presa neutra o prona: questa è la posizione di partenza. Tira le maniglie verso il busto, adducendo le scapole e flettendo i gomiti. Fai una pausa alla fine del movimento e torna lentamente alla posizione iniziale. Evita di appoggiare completamente il peso sui fermi tra una ripetizione e l''altra per mantenere la tensione muscolare.' 
WHERE name = 'Leverage Iso Row';

UPDATE public.exercise_library 
SET name_it = 'Leverage Shoulder Press', description_it = 'Carica il peso appropriato e regola il sedile; all''inizio del movimento le maniglie devono trovarsi vicino alla parte superiore delle spalle. Mantieni petto in fuori, testa alta e afferra le maniglie con presa prona. Questa è la posizione di partenza. Spingi le maniglie verso l''alto distendendo i gomiti. Dopo una breve pausa, riporta il peso appena sopra la posizione di partenza, mantenendo la tensione muscolare e senza appoggiare i pesi sui fermi fino al termine della serie.' 
WHERE name = 'Leverage Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Leverage Shrug', description_it = 'Carica i perni con un peso adeguato. Posizionati esattamente tra le maniglie. Afferra le maniglie superiori con una presa comoda, quindi abbassa i fianchi mentre inspiri. Guarda in avanti tenendo la testa alta e il petto in fuori. Spingi attraverso il pavimento con i talloni, estendendo fianchi e ginocchia fino a raggiungere la posizione eretta. Mantieni le braccia tese durante tutto il movimento, terminando con le spalle portate indietro. Questa sarà la tua posizione di partenza. Solleva il peso effettuando una scrollata di spalle verso le orecchie, muovendoti verticalmente. Fai una pausa nel punto massimo del movimento, quindi riporta il peso nella posizione iniziale.' 
WHERE name = 'Leverage Shrug';

UPDATE public.exercise_library 
SET name_it = 'Linear 3-Part Start Technique', description_it = 'Questo esercizio ti aiuta ad accelerare il più rapidamente possibile nello sprint partendo da fermo. È utile utilizzare una linea di partenza. Inizia con entrambi i piedi sulla linea. Posiziona il piede sinistro con la punta vicino alla caviglia destra. Posiziona il piede destro a 10-15 cm dietro il sinistro. Poggia la mano destra sulla linea e porta il naso vicino al ginocchio sinistro. Accovacciati sporgendoti in avanti, con la testa più bassa dei fianchi e il peso caricato sulla gamba sinistra. Questa sarà la tua posizione di partenza. Porta la mano sinistra all''indietro, parallela al terreno, ed esplodi in avanti quando sei pronto.' 
WHERE name = 'Linear 3-Part Start Technique';

UPDATE public.exercise_library 
SET name_it = 'Linear Acceleration Wall Drill', description_it = 'Appoggiati a una parete inclinandoti di circa 45 gradi. I piedi devono essere uniti e i glutei contratti. Inizia sollevando rapidamente il ginocchio destro, fai una pausa, quindi spingilo con forza verso il suolo. Cambia gamba, sollevando il ginocchio opposto e colpendo il terreno con decisione. Ripeti ancora una volta con la gamba destra e, non appena il piede tocca terra, aumenta rapidamente la frequenza alternando gamba destra e sinistra il più velocemente possibile.' 
WHERE name = 'Linear Acceleration Wall Drill';

UPDATE public.exercise_library 
SET name_it = 'Linear Depth Jump', description_it = 'Avrai bisogno di due box o panche distanziati di qualche decina di centimetri. Inizia stando in piedi su un box rivolto verso l''altra piattaforma. Per iniziare il movimento, scendi delicatamente a terra tra le due piattaforme, lasciando che ginocchia e fianchi si flettano. Inverti il movimento con un salto esplosivo, estendendo fianchi, ginocchia e caviglie per balzare sull''altra piattaforma. Atterra dolcemente, assorbendo l''impatto con le gambe.' 
WHERE name = 'Linear Depth Jump';

UPDATE public.exercise_library 
SET name_it = 'Log Lift', description_it = 'Inizia in piedi con il log davanti a te. Afferra le maniglie e inizia la fase di clean. Mentre sei piegato per iniziare, cerca di sollevare il log il più in alto possibile, tirandolo verso il petto. Estendi fianchi e ginocchia per completare il clean. Spingi la testa all''indietro e guarda verso l''alto, creando un appoggio sul petto per far riposare il log. Inizia la spinta piegando leggermente le ginocchia e invertendo il movimento (push press); questo genererà lo slancio per avviare il movimento verticale del log. Continua estendendo i gomiti per spingere il log sopra la testa. Non ci sono regole rigide sulla forma, quindi usa la tecnica che trovi più efficace. Mentre spingi il log, assicurati di far passare la testa in avanti a ogni ripetizione, guardando avanti. Ripeti il maggior numero di volte possibile. Cerca di controllare la discesa del log mentre lo riporti a terra.' 
WHERE name = 'Log Lift';

UPDATE public.exercise_library 
SET name_it = 'London Bridges', description_it = 'Attacca una corda da arrampicata a una trave alta o a un supporto trasversale. Sotto di essa, assicurati che la barra della smith machine sia bloccata in posizione con le sicure in modo che non possa muoversi. In alternativa, si può utilizzare un box sicuro. Sali sulla barra, usando la corda per bilanciarti. Questa sarà la posizione di partenza. Mantenendo il corpo dritto, inclinati all''indietro e abbassa il corpo muovendoti lentamente lungo la corda, mano dopo mano. Continua finché non sei perpendicolare al suolo. Mantenendo il corpo dritto, inverti il movimento tornando, mano dopo mano, alla posizione di partenza.' 
WHERE name = 'London Bridges';

UPDATE public.exercise_library 
SET name_it = 'Looking At Ceiling', description_it = 'Inginocchiati sul pavimento, afferrando i talloni con entrambe le mani. Solleva i glutei verso l''alto e in avanti, portando contemporaneamente la testa all''indietro per guardare il soffitto, creando un arco con la schiena.' 
WHERE name = 'Looking At Ceiling';

UPDATE public.exercise_library 
SET name_it = 'Low Cable Crossover', description_it = 'Per la posizione di partenza, posiziona le carrucole in basso, seleziona il peso e afferra una maniglia con ogni mano. Fai un passo avanti per mettere in tensione i cavi. I palmi devono essere rivolti in avanti, le mani sotto la vita e le braccia tese. Questa sarà la posizione di partenza. Con una leggera flessione delle braccia, porta le mani verso l''alto e verso la linea mediana del corpo. Le mani dovrebbero incontrarsi davanti al petto con i palmi rivolti verso l''alto. Dopo una breve pausa, riporta le braccia nella posizione iniziale.' 
WHERE name = 'Low Cable Crossover';

UPDATE public.exercise_library 
SET name_it = 'Low Cable Triceps Extension', description_it = 'Seleziona il peso desiderato e sdraiati supino sulla panca di una macchina per il rematore seduto a cui è attaccata una corda. La testa deve essere rivolta verso il punto di attacco. Afferra le estremità della corda con i palmi rivolti l''uno verso l''altro (presa neutra). Posiziona i gomiti in modo che siano piegati a 90 gradi e la parte superiore delle braccia sia perpendicolare al busto. Consiglio: tieni i gomiti stretti e assicurati che la parte superiore delle braccia punti verso il soffitto mentre gli avambracci puntano verso la carrucola sopra la testa. Questa sarà la posizione di partenza. Mentre espiri, estendi gli avambracci finché non sono dritti e verticali. La parte superiore delle braccia e i gomiti rimangono fermi durante il movimento. Solo gli avambracci devono muoversi. Contrai intensamente i tricipiti per un secondo. Mentre inspiri, torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Low Cable Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Low Pulley Row To Neck', description_it = 'Siediti su una macchina per il rematore ai cavi bassi con una corda attaccata. Afferra le estremità della corda con una presa a palmi rivolti verso il basso e siediti con la schiena dritta e le ginocchia leggermente flesse. Consiglio: mantieni la schiena quasi completamente verticale e le braccia completamente tese davanti a te. Questa sarà la posizione di partenza. Mantenendo il busto fermo, solleva i gomiti e inizia a piegarli tirando la corda verso il collo mentre espiri. Durante tutto il movimento, la parte superiore delle braccia deve rimanere parallela al pavimento. Consiglio: continua il movimento finché le mani non sono quasi all''altezza delle orecchie (gli avambracci non saranno paralleli al pavimento alla fine del movimento, poiché saranno angolati leggermente verso l''alto) e i gomiti sono distanziati dai fianchi. Dopo aver mantenuto la posizione di contrazione per un secondo circa, torna lentamente alla posizione iniziale mentre inspiri. Consiglio: in nessuna fase del movimento il busto deve muoversi. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Low Pulley Row To Neck';

UPDATE public.exercise_library 
SET name_it = 'SMR Lombare', description_it = 'In posizione seduta, posiziona un foam roller sotto la zona lombare. Incrocia le braccia davanti a te e protrai le spalle. Questa sarà la tua posizione di partenza. Solleva i fianchi da terra e inclinati all''indietro, mantenendo il peso sulla zona lombare. Ora sposta leggermente il peso su un lato, mantenendolo lontano dalla colonna vertebrale e concentrandolo sui muscoli laterali. Rotola sulla zona lombare, mantenendo i punti di tensione per 10-30 secondi. Ripeti sull''altro lato.' 
WHERE name = 'Lower Back-SMR';

UPDATE public.exercise_library 
SET name_it = 'Lower Back Curl', description_it = 'Sdraiati a pancia in giù con le braccia distese lungo i fianchi. Questa sarà la tua posizione di partenza. Utilizzando i muscoli lombari, estendi la colonna vertebrale sollevando il petto da terra. Non usare le braccia per spingerti verso l''alto. Tieni la testa alta durante il movimento. Ripeti per 10-20 ripetizioni.' 
WHERE name = 'Lower Back Curl';

UPDATE public.exercise_library 
SET name_it = 'Lunge Pass Through', description_it = 'In piedi con il busto eretto, impugna un kettlebell nella mano destra. Questa sarà la tua posizione di partenza. Fai un passo in avanti con il piede sinistro e abbassa il busto flettendo l''anca e il ginocchio, mantenendo il busto verticale. Abbassa il ginocchio posteriore fin quasi a toccare terra. Durante l''affondo, passa il kettlebell sotto la gamba anteriore verso la mano opposta. Spingendo sul tallone del piede, torna alla posizione di partenza. Ripeti il movimento per il numero di ripetizioni raccomandato, alternando le gambe.' 
WHERE name = 'Lunge Pass Through';

UPDATE public.exercise_library 
SET name_it = 'Lunge Sprint', description_it = 'Regola il bilanciere di una Smith machine a un''altezza adeguata. Posizionati sotto il bilanciere, facendolo poggiare sulla parte alta delle spalle. Sgancia il bilanciere e posiziona i piedi in posizione sfalsata, uno avanti e uno indietro. Questa sarà la tua posizione di partenza. Abbassa il ginocchio posteriore quasi fino a terra, flettendo le ginocchia e abbassando i fianchi. Al termine della discesa, inverte immediatamente il movimento. Spingi in modo esplosivo sul tallone del piede anteriore con una leggera spinta del piede posteriore. Salta e inverte la posizione delle gambe. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Lunge Sprint';

UPDATE public.exercise_library 
SET name_it = 'Lying Bent Leg Groin (Stretch)', description_it = 'Sdraiati sulla schiena con le ginocchia flesse e le piante dei piedi unite. Chiedi al tuo partner di tenere ferme le tue ginocchia. Questa sarà la tua posizione di partenza. Tenta di avvicinare le ginocchia tra loro, mentre il partner impedisce il movimento. Dopo 10-20 secondi, rilassa i muscoli mentre il partner spinge delicatamente le ginocchia verso il pavimento. Comunica al partner quando l''allungamento è sufficiente per evitare infortuni o stiramenti eccessivi.' 
WHERE name = 'Lying Bent Leg Groin';

UPDATE public.exercise_library 
SET name_it = 'Lying Cable Curl', description_it = 'Afferra una barra dritta o un accessorio E-Z bar collegato alla carrucola bassa con entrambe le mani, usando una presa supina (palmi rivolti verso l''alto) alla larghezza delle spalle. Sdraiati supino su un tappetino davanti al pacco pesi con i piedi contro la struttura della macchina e le gambe distese. Con le braccia estese e i gomiti vicini al corpo, fletti leggermente le braccia. Questa sarà la tua posizione di partenza. Mantenendo le braccia ferme e i gomiti vicini al corpo, fletti la barra verso il petto espirando e contraendo i bicipiti. Dopo un secondo di contrazione in alto, torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Lying Cable Curl';

UPDATE public.exercise_library 
SET name_it = 'Lying Cambered Barbell Row', description_it = 'Posiziona un bilanciere curvo (cambered bar) sotto una panca. Sdraiati a pancia in giù sulla panca e afferra la barra con una presa prona (palmi verso il basso) più larga delle spalle. Questa sarà la tua posizione di partenza. Espirando, tira la barra verso l''alto mantenendo i gomiti vicini al corpo; verso il petto per colpire la parte alta/centrale della schiena, o verso lo stomaco per mirare ai dorsali. Dopo un secondo di tenuta in alto, scendi lentamente alla posizione di partenza inspirando.' 
WHERE name = 'Lying Cambered Barbell Row';

UPDATE public.exercise_library 
SET name_it = 'Lying Close-Grip Bar Curl su Carrucola Alta', description_it = 'Posiziona una panca piana davanti a una carrucola alta. Afferra la barra dritta con una presa supina (palmi verso l''alto) larga quanto le spalle. Sdraiati sulla schiena con la testa oltre il bordo della panca. Estendi le braccia sopra le spalle. Il busto e le braccia devono formare un angolo di 90 gradi con i gomiti stretti. Questa sarà la tua posizione di partenza. Espirando, fletti la barra con un movimento semicircolare fino a toccare il mento. Contrai i bicipiti per un secondo in posizione di contrazione massima. Consiglio: durante il movimento si devono muovere solo gli avambracci; le braccia devono rimanere perpendicolari. Torna lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Lying Close-Grip Bar Curl On High Pulley';

UPDATE public.exercise_library 
SET name_it = 'Lying Close-Grip Barbell Triceps Extension dietro la nuca', description_it = 'Impugnando un bilanciere o un E-Z bar con presa prona (palmi in avanti), sdraiati su una panca piana con la testa vicino al bordo. Estendi le braccia davanti a te e porta lentamente la barra con un movimento semicircolare (tenendo le braccia tese) in una posizione sopra la testa. Al termine, le braccia devono essere parallele al pavimento. Questa sarà la posizione di partenza. Consiglio: tieni sempre i gomiti stretti. Inspirando, abbassa la barra flettendo i gomiti e mantenendo la parte superiore del braccio ferma, finché gli avambracci non sono perpendicolari al pavimento. Espirando, riporta la barra alla posizione iniziale con un movimento semicircolare. Contrai intensamente i tricipiti per un secondo. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Lying Close-Grip Barbell Triceps Extension Behind The Head';

UPDATE public.exercise_library 
SET name_it = 'Lying Close-Grip Barbell Triceps Press verso il mento', description_it = 'Impugnando un bilanciere o un E-Z bar con presa prona (palmi in avanti), sdraiati su una panca piana con la testa fuori dal bordo. Estendi le braccia davanti a te tenendo il bilanciere sopra il petto. Le braccia devono essere perpendicolari al busto (90 gradi). Questa sarà la tua posizione di partenza. Inspirando, abbassa la barra con un movimento semicircolare flettendo i gomiti e mantenendoli stretti e fermi. Continua ad abbassare finché la barra non tocca leggermente il mento. Espirando, riporta la barra alla posizione iniziale con un movimento semicircolare, contraendo i tricipiti per un secondo in alto. Consiglio: solo gli avambracci devono muoversi. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Lying Close-Grip Barbell Triceps Press To Chin';

UPDATE public.exercise_library 
SET name_it = 'Lying Crossover', description_it = 'Sdraiati sulla schiena con le gambe distese. Incrocia una gamba sopra il corpo con il ginocchio piegato, cercando di toccare il suolo con il ginocchio. Il tuo partner deve inginocchiarsi accanto a te, tenendo ferma la tua spalla con una mano e controllando la gamba incrociata con l''altra. Questa è la posizione di partenza. Cerca di sollevare il ginocchio piegato da terra mentre il partner oppone resistenza impedendo il movimento. Dopo 10-20 secondi, rilassa la gamba mentre il partner spinge delicatamente il ginocchio verso il pavimento. Ripeti con l''altro lato.' 
WHERE name = 'Lying Crossover';

UPDATE public.exercise_library 
SET name_it = 'Lying Dumbbell Tricep Extension', description_it = 'Sdraiati su una panca piana tenendo due manubri direttamente davanti a te. Le braccia devono essere completamente distese a un angolo di 90 gradi rispetto al busto e al pavimento. I palmi devono essere rivolti verso l''interno e i gomiti devono rimanere stretti. Questa è la posizione di partenza. Espirando e mantenendo le braccia ferme con i gomiti in posizione, abbassa lentamente il peso finché i manubri non sono vicini alle orecchie. A quel punto, mantenendo sempre i gomiti e la parte superiore delle braccia ferme, usa i tricipiti per riportare il peso nella posizione di partenza mentre espiri. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying Dumbbell Tricep Extension';

UPDATE public.exercise_library 
SET name_it = 'Lying Face Down Plate Neck Resistance', description_it = 'Sdraiati a pancia in giù su una panca piana, con tutto il corpo disteso, tenendo un disco di ghisa dietro la testa. Consiglio: posizionati in modo che le spalle siano leggermente oltre l''estremità della panca, così da lasciare la parte superiore del petto, il collo e il viso fuori dalla panca. Questa è la posizione di partenza. Mantenendo il disco saldo sulla nuca, abbassa lentamente la testa (come per dire ''sì'') mentre inspiri. Riporta la testa nella posizione di partenza con un movimento semicircolare mentre espiri. Mantieni la contrazione per un secondo. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying Face Down Plate Neck Resistance';

UPDATE public.exercise_library 
SET name_it = 'Lying Face Up Plate Neck Resistance', description_it = 'Sdraiati supino su una panca piana, con tutto il corpo disteso, tenendo un disco di ghisa sopra la fronte. Consiglio: posizionati in modo che le spalle siano leggermente oltre l''estremità della panca, così da lasciare trapezi, collo e testa fuori dalla panca. Questa è la posizione di partenza. Mantenendo il disco saldo sulla fronte, abbassa lentamente la testa all''indietro con un movimento semicircolare mentre inspiri. Riporta la testa nella posizione di partenza con un movimento semicircolare mentre espiri. Mantieni la contrazione per un secondo. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying Face Up Plate Neck Resistance';

UPDATE public.exercise_library 
SET name_it = 'Lying Glute', description_it = 'Sdraiati sulla schiena con il partner inginocchiato accanto a te. Fletti l''anca di una gamba, sollevandola dal pavimento. Ruota la gamba in modo che il piede si trovi sopra l''anca opposta e la parte inferiore della gamba sia perpendicolare al corpo. Il partner deve tenere fermi ginocchio e caviglia. Questa è la posizione di partenza. Cerca di spingere la gamba verso il partner, che dovrà impedire qualsiasi movimento effettivo. Dopo 10-20 secondi, rilassati completamente mentre il partner spinge delicatamente la caviglia e il ginocchio verso il tuo petto. Comunica al tuo partner quando l''allungamento è sufficiente per evitare infortuni o eccessivo stretching.' 
WHERE name = 'Lying Glute';

UPDATE public.exercise_library 
SET name_it = 'Lying Hamstring', description_it = 'Sdraiati sulla schiena con le gambe distese. Il partner deve essere inginocchiato accanto a te. Solleva una gamba verso il soffitto e fai in modo che il partner ne tenga la caviglia. Il partner può usare la spalla per sostenere la tua gamba, se necessario. Questa è la posizione di partenza. Con il partner che tiene la gamba ferma, cerca di flettere il ginocchio, contraendo i muscoli ischiocrurali per 10-20 secondi. Poi rilassa la gamba, permettendo al partner di spingerla delicatamente verso la testa. Comunica al tuo partner quando l''allungamento è sufficiente per evitare infortuni. Cambia lato una volta completato.' 
WHERE name = 'Lying Hamstring';

UPDATE public.exercise_library 
SET name_it = 'Lying High Bench Barbell Curl', description_it = 'Sdraiati a pancia in giù su una panca piana alta, tenendo un bilanciere con una presa supinata (palmi rivolti verso l''alto). Consiglio: se usi un bilanciere dritto, afferralo alla larghezza delle spalle; se usi una barra EZ, afferrala sulle impugnature interne. Il busto deve essere posizionato in modo che la parte superiore del petto sia oltre l''estremità della panca e il bilanciere penda davanti a te con le braccia distese e perpendicolari al pavimento. Questa è la posizione di partenza. Mantenendo i gomiti stretti e le braccia ferme, solleva il peso con un movimento semicircolare contraendo i bicipiti ed espirando. Mantieni la posizione di massima contrazione per un secondo. Mentre inspiri, torna lentamente alla posizione di partenza. Consiglio: mantieni sempre il controllo del peso ed evita di dondolare. Ricorda, solo gli avambracci devono muoversi durante l''esercizio. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying High Bench Barbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Lying Leg Curls', description_it = 'Regola la leva della macchina in base alla tua altezza e sdraiati a pancia in giù sulla leg curl machine, con il cuscinetto della leva sulla parte posteriore delle gambe (pochi centimetri sotto i polpacci). Consiglio: preferibilmente usa una macchina angolata invece di una piatta, poiché la posizione angolata favorisce il reclutamento degli ischiocrurali. Mantenendo il busto aderente alla panca, assicurati che le gambe siano completamente distese e afferra le maniglie laterali della macchina. Posiziona le punte dei piedi dritte. Questa è la posizione di partenza. Mentre espiri, fletti le gambe il più possibile senza sollevare le cosce dal cuscinetto. Una volta raggiunta la posizione di massima contrazione, mantienila per un secondo. Mentre inspiri, riporta le gambe nella posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying Leg Curls';

UPDATE public.exercise_library 
SET name_it = 'Lying Machine Squat', description_it = 'Regola la macchina in modo da poterti posizionare all''interno con le ginocchia piegate e le cosce leggermente sotto il parallelo. Dopo aver selezionato il peso, posizionati all''interno della macchina supino, con le ginocchia piegate e le cosce leggermente sotto il parallelo rispetto alla piattaforma. Assicurati che le ginocchia non superino la punta dei piedi. L''angolo tra ischiocrurali e polpacci deve essere leggermente inferiore a 90 gradi. La schiena e la testa devono essere ben appoggiate alla macchina, mentre le spalle sono spinte sotto i supporti imbottiti. Afferra le maniglie e posiziona i piedi leggermente verso l''esterno alla larghezza delle spalle. Questa è la posizione di partenza. Spingendo con l''avampiede ed espirando, estendi tutto il corpo contraendo i quadricipiti. Mantieni la posizione contratta per un secondo. Consiglio: poiché parti da sotto il parallelo, puoi scegliere di aiutarti con le mani facendo leva sulle cosce solo durante la prima ripetizione. Accosciati lentamente mentre inspiri, ma invece di scendere completamente, fermati quando le cosce sono parallele alla piattaforma (angolo di 90 gradi tra ischiocrurali e polpacci). Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying Machine Squat';

UPDATE public.exercise_library 
SET name_it = 'Lying One-Arm Lateral Raise', description_it = 'Tenendo un manubrio in una mano, sdraiati con il petto su una panca piana. L''altra mano può essere usata per afferrare la gamba della panca per maggiore stabilità. Posiziona il palmo della mano che regge il manubrio in posizione neutra (palmi rivolti verso il busto) mantenendo il braccio disteso con il gomito leggermente flesso. Questa è la posizione di partenza. Ora solleva il braccio con il manubrio lateralmente finché il gomito non è all''altezza della spalla e il braccio è approssimativamente parallelo al pavimento mentre espiri. Consiglio: mantieni il braccio perpendicolare al busto e disteso durante tutto il movimento. Mantieni la contrazione nel punto più alto per un secondo. Abbassa lentamente il manubrio nella posizione di partenza mentre inspiri. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying One-Arm Lateral Raise';

UPDATE public.exercise_library 
SET name_it = 'Stretching Quadricipiti Prono', description_it = 'Sdraiati a pancia in giù sul pavimento con il tuo partner in ginocchio accanto a te. Fletti un ginocchio e solleva la gamba da terra, cercando di toccare i glutei con il tallone. Il partner dovrà bloccare il ginocchio e la caviglia. Questa sarà la posizione di partenza. Cerca di estendere il ginocchio mentre il partner impedisce qualsiasi movimento reale. Dopo 10-20 secondi, rilassa i muscoli mentre il partner spinge delicatamente il piede verso i glutei, allungando ulteriormente i quadricipiti e i flessori dell''anca. Dopo 10-20 secondi, cambia lato.' 
WHERE name = 'Lying Prone Quadriceps';

UPDATE public.exercise_library 
SET name_it = 'Alzate Laterali a 90° su Panca', description_it = 'Impugnando un manubrio per mano, sdraiati con il petto appoggiato su una panca piana. Posiziona i palmi delle mani in modo neutro (rivolti verso il busto), mantenendo le braccia tese con i gomiti leggermente flessi. Questa sarà la posizione di partenza. Ora solleva le braccia lateralmente fino a quando i gomiti sono all''altezza delle spalle e le braccia sono all''incirca parallele al pavimento, espirando. Consiglio: mantieni le braccia perpendicolari al busto restando in estensione per tutto il movimento. Mantieni la contrazione nel punto massimo per un secondo. Abbassa lentamente i manubri nella posizione di partenza mentre inspiri. Ripeti per il numero di ripetizioni consigliato e poi cambia braccio.' 
WHERE name = 'Lying Rear Delt Raise';

UPDATE public.exercise_library 
SET name_it = 'Curl con Manubri Supino', description_it = 'Sdraiati su una panca piana a pancia in su, tenendo un manubrio in ogni mano sopra le cosce. Porta i manubri ai lati con le braccia distese e i palmi rivolti verso le cosce (presa neutra). Mantenendo le braccia vicino al busto e i gomiti bloccati, abbassa lentamente le braccia (tenendole tese con una leggera flessione del gomito) il più possibile verso il pavimento. Una volta raggiunto il limite, blocca la parte superiore delle braccia: questa sarà la posizione di partenza. Espirando, inizia lentamente a flettere i pesi verso l''alto ruotando contemporaneamente i polsi in modo che i palmi guardino verso l''alto. Continua il movimento finché i bicipiti sono completamente contratti e strizza forte nella posizione finale per un secondo. Consiglio: solo gli avambracci devono muoversi. La parte superiore delle braccia deve rimanere ferma e i gomiti devono restare stretti per tutto il movimento. Torna alla posizione di partenza molto lentamente.' 
WHERE name = 'Lying Supine Dumbbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Rematore T-Bar su Panca', description_it = 'Carica il T-Bar Row Machine con il peso desiderato e regola l''altezza in modo che la parte alta del torace sia sul bordo del cuscinetto. Sdraiati a pancia in giù sul cuscinetto e afferra le maniglie. Puoi usare una presa prona, supina o neutra a seconda della zona della schiena che vuoi enfatizzare. Solleva la barra dal supporto e stendi le braccia davanti a te. Questa sarà la posizione di partenza. Espirando, tira lentamente il peso verso l''alto e contrai i muscoli della schiena al termine del movimento. Consiglio: mantieni la parte superiore delle braccia il più vicino possibile al busto per coinvolgere meglio i dorsali. Non sollevare il corpo dal cuscinetto e non usare i bicipiti per sollevare il peso. Dopo una contrazione di un secondo nel punto massimo, inspira e torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying T-Bar Row';

UPDATE public.exercise_library 
SET name_it = 'French Press su Panca', description_it = 'Sdraiati su una panca piana con un bilanciere EZ o dritto posizionato sul pavimento dietro la testa e i piedi ben saldi a terra. Afferra la barra dietro di te con una presa media prona e sollevala davanti a te, a braccia tese. Consiglio: le braccia devono essere perpendicolari al busto e al pavimento. I gomiti devono essere stretti. Questa è la posizione di partenza. Inspirando, abbassa lentamente il peso finché la barra tocca leggermente la fronte, mantenendo la parte superiore delle braccia e i gomiti fermi. A quel punto, usa i tricipiti per riportare il peso nella posizione di partenza espirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Lying Triceps Press';

UPDATE public.exercise_library 
SET name_it = 'Chest Press Machine', description_it = 'Siediti sulla Chest Press Machine e seleziona il peso. Usa la leva fornita dalla macchina per portare le maniglie in avanti, in modo da poterle afferrare e distendere completamente le braccia. Afferra le maniglie con una presa prona e solleva i gomiti in modo che la parte superiore delle braccia sia parallela al pavimento, ai lati del busto. Consiglio: gli avambracci punteranno in avanti. Una volta portate le maniglie in avanti e distese le braccia, sarai nella posizione di partenza. Ora riporta le maniglie verso di te inspirando. Spingi le maniglie lontano da te mentre fletti i pettorali ed espiri. Mantieni la contrazione per un secondo prima di tornare alla posizione di partenza. Ripeti per il numero di ripetizioni desiderato. Una volta terminato, usa nuovamente la leva per riportare lentamente le maniglie nella posizione originale.' 
WHERE name = 'Machine Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Curl Bicipiti alla Macchina', description_it = 'Regola il sedile all''altezza appropriata e seleziona il peso. Appoggia la parte superiore delle braccia contro i cuscinetti e afferra le maniglie. Questa sarà la posizione di partenza. Esegui il movimento flettendo il gomito e portando l''avambraccio verso la parte superiore del braccio. Fai una pausa nel punto massimo, quindi torna lentamente alla posizione di partenza. Evita di far tornare il peso sui blocchi di arresto fino al completamento della serie per mantenere la tensione muscolare.' 
WHERE name = 'Machine Bicep Curl';

UPDATE public.exercise_library 
SET name_it = 'Curl ai Cavi o Macchina Preacher', description_it = 'Siediti sulla macchina Preacher Curl e seleziona il peso. Posiziona la parte posteriore delle braccia (tricipiti) sull''imbottitura e afferra le maniglie con una presa supina (palmi rivolti verso l''alto). Consiglio: assicurati di mantenere i gomiti stretti durante l''appoggio. Questa sarà la posizione di partenza. Ora solleva le maniglie espirando e contraendo i bicipiti. Nel punto massimo, assicurati di mantenere la contrazione per un secondo. Consiglio: solo gli avambracci devono muoversi. La parte superiore delle braccia deve rimanere ferma e a contatto con l''imbottitura per tutto il tempo. Abbassa lentamente le maniglie nella posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Machine Preacher Curls';

UPDATE public.exercise_library 
SET name_it = 'Shoulder Press Machine', description_it = 'Siediti sulla Shoulder Press Machine e seleziona il peso. Afferra le maniglie ai tuoi lati mantenendo i gomiti flessi e in linea con il busto. Questa sarà la posizione di partenza. Ora solleva le maniglie espirando e distendi completamente le braccia. Nel punto massimo, mantieni la contrazione per un secondo. Abbassa lentamente le maniglie alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Machine Shoulder (Military) Press';

UPDATE public.exercise_library 
SET name_it = 'Estensioni Tricipiti alla Macchina', description_it = 'Regola il sedile all''altezza appropriata e seleziona il peso. Appoggia la parte superiore delle braccia contro i cuscinetti e afferra le maniglie. Questa sarà la posizione di partenza. Esegui il movimento estendendo il gomito e allontanando l''avambraccio dalla parte superiore del braccio. Fai una pausa al completamento del movimento e torna lentamente alla posizione di partenza. Evita di far tornare il peso sui blocchi di arresto fino al termine della serie per mantenere la tensione sui muscoli coinvolti.' 
WHERE name = 'Machine Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Medicine Ball Chest Pass', description_it = 'Per questo esercizio è necessario un partner. In mancanza di esso, il movimento può essere eseguito contro una parete. Inizia posizionandoti di fronte al partner, tenendo la palla medica all''altezza del busto con entrambe le mani. Porta la palla al petto e inverte il movimento estendendo i gomiti. Per applicazioni sportive, è possibile fare un passo in avanti mentre si lancia. Il partner dovrebbe ricevere la palla e rilanciarla verso di te. Ricevi il lancio con entrambe le mani all''altezza del petto.' 
WHERE name = 'Medicine Ball Chest Pass';

UPDATE public.exercise_library 
SET name_it = 'Medicine Ball Full Twist', description_it = 'Per questo esercizio sono necessari una palla medica e un partner. Posizionatevi schiena contro schiena a una distanza di 60-90 cm l''uno dall''altro. Questa sarà la posizione di partenza. Tenete la palla davanti al busto. Aprite le anche e ruotate le spalle contemporaneamente al vostro partner. Per una rotazione completa, tu e il tuo partner dovreste ruotare nella stessa direzione (es. in senso antiorario). Passate la palla al partner; ora entrambi potete ruotare nella direzione opposta per ripetere la procedura.' 
WHERE name = 'Medicine Ball Full Twist';

UPDATE public.exercise_library 
SET name_it = 'Medicine Ball Scoop Throw', description_it = 'Assumi una posizione di mezzo squat con una palla medica tra le mani. Le braccia devono essere distese verso il basso, con la palla vicina ai piedi. Inizia spingendo le anche in avanti mentre estendi le gambe, eseguendo un salto. Contemporaneamente, slancia le braccia verso l''alto e sopra la testa, mantenendole distese, e rilascia la palla nel punto massimo del movimento. L''obiettivo è lanciare la palla il più lontano possibile dietro di te.' 
WHERE name = 'Medicine Ball Scoop Throw';

UPDATE public.exercise_library 
SET name_it = 'Middle Back Shrug', description_it = 'Sdraiati a pancia in giù su una panca inclinata, tenendo un manubrio in ogni mano. Le braccia devono essere completamente distese verso il pavimento. I palmi delle mani devono essere rivolti l''uno verso l''altro. Questa sarà la posizione di partenza. Espirando, contrai le scapole avvicinandole tra loro e mantieni la contrazione per un secondo completo. Suggerimento: questo movimento è simile all''azione inversa di un abbraccio, o a tentare di eseguire delle alzate laterali posteriori come se non avessi le braccia. Inspirando, torna alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Middle Back Shrug';

UPDATE public.exercise_library 
SET name_it = 'Middle Back Stretch', description_it = 'In piedi, con i piedi alla larghezza delle spalle e le mani sui fianchi. Ruota il busto finché non avverti un allungamento. Mantieni la posizione per 10-15 secondi, quindi ruota verso il lato opposto.' 
WHERE name = 'Middle Back Stretch';

UPDATE public.exercise_library 
SET name_it = 'Mixed Grip Chin', description_it = 'Afferra una sbarra per trazioni con una presa di circa 2-3 cm più larga delle spalle, tenendo il palmo di una mano rivolto in avanti e quello dell''altra rivolto verso di te. Questa è la posizione di partenza. Inizia a sollevarti espirando. Suggerimento: con il braccio che ha il palmo rivolto verso di te, concentrati sull''uso dei muscoli dorsali per eseguire il movimento, mantenendo il gomito vicino al busto. Con l''altro braccio, con il palmo rivolto in avanti, i gomiti rimarranno distanziati ma in linea con il busto, concentrandoti sull''uso dei gran dorsali per sollevare il corpo. Dopo un secondo di contrazione in alto, scendi lentamente inspirando. Ripeti per il numero di ripetizioni consigliato. Nella serie successiva, inverti la presa.' 
WHERE name = 'Mixed Grip Chin';

UPDATE public.exercise_library 
SET name_it = 'Monster Walk', description_it = 'Posiziona una fascia elastica attorno alle caviglie e un''altra attorno alle ginocchia. Deve esserci abbastanza tensione da risultare strette quando i piedi sono alla larghezza delle spalle. Per iniziare, fai dei piccoli passi in avanti alternando il piede sinistro e quello destro. Dopo diversi passi, esegui il movimento opposto camminando all''indietro fino al punto di partenza.' 
WHERE name = 'Monster Walk';

UPDATE public.exercise_library 
SET name_it = 'Mountain Climbers', description_it = 'Inizia in posizione di piegamento (pushup), con il peso sostenuto da mani e punte dei piedi. Flettendo ginocchio e anca, porta una gamba in avanti finché il ginocchio non si trova circa sotto l''anca. Questa sarà la posizione di partenza. Inverti in modo esplosivo la posizione delle gambe, estendendo la gamba piegata finché non è dritta e sostenuta dalla punta del piede, e portando l''altro piede in avanti con anca e ginocchio flessi. Ripeti in modo alternato per 20-30 secondi.' 
WHERE name = 'Mountain Climbers';

UPDATE public.exercise_library 
SET name_it = 'Moving Claw Series', description_it = 'Questo esercizio prepara la forma di corsa per migliorare nello sprint. Durante la corsa, assicurati di flettere il ginocchio, puntando a calciare i glutei mentre l''anca si estende. Ricarica il quadricipite mentre la gamba torna in avanti, attaccando il terreno al passo successivo. Assicurati che durante la corsa le braccia facciano da blocco, muovendole rapidamente con un movimento 1-2.' 
WHERE name = 'Moving Claw Series';

UPDATE public.exercise_library 
SET name_it = 'Muscle Snatch', description_it = 'Inizia con un bilanciere carico all''altezza della metà coscia, con una presa larga. I piedi devono essere posizionati sotto le anche, leggermente ruotati verso l''esterno se necessario. Abbassa le anche, tenendo il petto alto e la testa rivolta in avanti. Le spalle devono essere leggermente avanti rispetto al bilanciere. Questa sarà la posizione di partenza. Inizia la tirata spingendo attraverso la parte anteriore dei talloni, sollevando il bilanciere. Transita nella seconda tirata estendendo anche, ginocchia e caviglie, spingendo il bilanciere verso l''alto il più rapidamente possibile. Il bilanciere deve rimanere vicino al corpo. Continua a sollevare il bilanciere fino alla posizione sopra la testa, senza flettere nuovamente le ginocchia.' 
WHERE name = 'Muscle Snatch';

UPDATE public.exercise_library 
SET name_it = 'Muscle Up', description_it = 'Afferra gli anelli utilizzando una ''false grip'', con la base dei palmi sopra gli anelli. Inizia una trazione portando i gomiti verso il basso e flettendoli. Quando raggiungi la posizione alta della trazione, porta gli anelli verso le ascelle ruotando le spalle in avanti e permettendo ai gomiti di muoversi direttamente dietro di te. Questo ti posiziona correttamente per passare alla fase di dip del movimento. Mantenendo controllo e stabilità, distendi le braccia per completare l''esercizio. Fai attenzione durante la discesa a terra.' 
WHERE name = 'Muscle Up';

UPDATE public.exercise_library 
SET name_it = 'Hack Squat a piedi stretti', description_it = 'Appoggia la schiena contro lo schienale della macchina e posiziona le spalle sotto gli appositi supporti. Posiziona le gambe sulla pedana con una stance stretta, inferiore alla larghezza delle spalle, con le punte dei piedi leggermente rivolte verso l''esterno. I piedi dovrebbero distare circa 7-8 cm l''uno dall''altro. Consiglio: mantieni sempre la testa alta e la schiena a contatto con lo schienale. Afferra le maniglie laterali e sgancia le barre di sicurezza. Distendi le gambe senza bloccare le ginocchia: questa è la posizione di partenza. Scendi lentamente flettendo le ginocchia e mantenendo la postura dritta. Scendi finché l''angolo tra cosce e polpacci è leggermente inferiore a 90 gradi (cosce sotto il parallelo). Inspira durante la discesa. Espirando, spingi principalmente sui talloni per tornare alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Narrow Stance Hack Squats';

UPDATE public.exercise_library 
SET name_it = 'Leg Press a piedi stretti', description_it = 'Siediti sulla pressa e posiziona i piedi sulla pedana davanti a te con una stance stretta (meno della larghezza delle spalle) e punte leggermente verso l''esterno. I piedi dovrebbero distare circa 7-8 cm. Consiglio: mantieni la testa alta e la schiena ben appoggiata. Abbassa le sicure e spingi la pedana finché le gambe sono quasi completamente distese, senza bloccare le ginocchia; il busto e le gambe dovrebbero formare un angolo di 90 gradi. Questa è la posizione di partenza. Inspira e scendi lentamente finché cosce e polpacci formano un angolo di 90 gradi. Espirando, spingi principalmente con i talloni usando i quadricipiti per tornare alla posizione iniziale. Ripeti e blocca sempre le sicure a fine esercizio.' 
WHERE name = 'Narrow Stance Leg Press';

UPDATE public.exercise_library 
SET name_it = 'Squat a piedi stretti', description_it = 'Esercizio da eseguire preferibilmente in un rack. Regola il bilanciere all''altezza corretta, posizionati sotto di esso e appoggialo sulla parte alta delle spalle (appena sotto il collo). Solleva il bilanciere dal rack, allontanati e posiziona i piedi con una stance stretta (circa 8-15 cm) e punte leggermente verso l''esterno. Mantieni la testa alta e la schiena dritta. Scendi lentamente flettendo le ginocchia finché l''angolo tra cosce e polpacci è leggermente inferiore a 90 gradi. Inspira durante la discesa. Assicurati che le ginocchia non superino la linea immaginaria perpendicolare alla punta dei piedi. Espirando, spingi sui talloni per tornare alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Narrow Stance Squats';

UPDATE public.exercise_library 
SET name_it = 'Natural Glute Ham Raise', description_it = 'Utilizzando l''imbottitura di una lat machine o una panca scott, posiziona le caviglie sotto i rulli e le ginocchia sul sedile, rivolto in direzione opposta alla macchina. Mantieni una postura eretta. Questa è la posizione di partenza. Scendi controllando il movimento finché le ginocchia sono quasi completamente distese. Mantenendo il controllo, torna alla posizione iniziale. Se non riesci a completare la ripetizione, utilizza una banda elastica, l''aiuto di un partner o spingi su un box per facilitare il movimento.' 
WHERE name = 'Natural Glute Ham Raise';

UPDATE public.exercise_library 
SET name_it = 'SMR Collo', description_it = 'Utilizzando un rullo per massaggi o un matterello, posizionalo dietro la testa contro il collo. Assicurati di non posizionarlo direttamente sulla colonna vertebrale, ma leggermente di lato in modo che prema contro i muscoli paravertebrali. Partendo dalla parte alta del collo, rulla lentamente verso il basso lungo i muscoli, sostando sui punti di tensione per 10-30 secondi.' 
WHERE name = 'Neck-SMR';

UPDATE public.exercise_library 
SET name_it = 'Neck Press', description_it = 'Sdraiati su una panca piana. Con una presa media (che crea un angolo di 90 gradi tra avambracci e braccia a metà movimento), stacca il bilanciere e tienilo sopra il collo con le braccia distese. Inspira e scendi lentamente fino a sentire il bilanciere sul collo. Dopo una breve pausa, spingi il bilanciere verso l''alto espirando e contraendo i pettorali. Distendi le braccia, contrai per un secondo e ricomincia a scendere. Consiglio: la fase di discesa dovrebbe durare il doppio di quella di risalita. Ripeti per le ripetizioni prescritte, poi riponi il bilanciere nel rack.' 
WHERE name = 'Neck Press';

UPDATE public.exercise_library 
SET name_it = 'Crunch Obliqui', description_it = 'Sdraiati a terra con la zona lombare aderente al suolo. Metti una mano dietro la testa e l''altra a terra di lato. Tieni i piedi sollevati e appoggiati su una superficie piana. Solleva la spalla corrispondente alla mano dietro la testa verso il ginocchio opposto (es. gomito destro verso ginocchio sinistro). Dopo il contatto tra gomito e ginocchio, torna lentamente alla posizione di partenza. Inspira durante la fase eccentrica (discesa) ed espira durante quella concentrica (salita). Alterna i lati fino a completare le ripetizioni previste.' 
WHERE name = 'Oblique Crunches';

UPDATE public.exercise_library 
SET name_it = 'Crunch Obliqui a terra', description_it = 'Sdraiati sul fianco destro con le gambe una sopra l''altra e le ginocchia leggermente flesse. Metti la mano sinistra dietro la testa. Esegui un crunch sollevando il gomito sinistro verso l''alto, focalizzandoti sulla contrazione degli obliqui. Sollevati il più possibile, mantieni la contrazione per un secondo e torna lentamente alla posizione di partenza. Inspira durante la discesa ed espira durante la fase di sollevamento.' 
WHERE name = 'Oblique Crunches - On The Floor';

UPDATE public.exercise_library 
SET name_it = 'Olympic Squat', description_it = 'Posiziona il bilanciere sulla parte alta dei trapezi. Mantieni il petto alto e la testa in avanti. Adotta una stance pari alla larghezza dei fianchi con le punte dei piedi leggermente verso l''esterno. Scendi flettendo le ginocchia, evitando il più possibile di portare i fianchi indietro. Le ginocchia devono avanzare rimanendo allineate ai piedi. L''obiettivo è mantenere il busto il più verticale possibile. Scendi completamente mantenendo il peso sulla parte anteriore del tallone. Quando le cosce toccano i polpacci, inverte il movimento spingendo verso l''alto.' 
WHERE name = 'Olympic Squat';

UPDATE public.exercise_library 
SET name_it = 'Stretching Quadricipiti Supino', description_it = 'Sdraiati su una panca piana o uno step, lasciando cadere una gamba e un braccio lateralmente. Piega il ginocchio e afferra la parte superiore del piede. Durante l''esecuzione, fai attenzione a non inarcare la zona lombare. Porta l''ombelico verso la colonna vertebrale per mantenere una posizione neutra. Spingi il piede verso il basso contro la mano. Per enfatizzare lo stretching dell''anca, solleva l''anca della gamba che stai tenendo verso il soffitto. Cambia lato.' 
WHERE name = 'On-Your-Back Quad Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching Quadricipiti Laterale', description_it = 'Inizia sdraiandoti sul fianco destro, con il ginocchio destro piegato a 90 gradi appoggiato sul pavimento davanti a te (questo stabilizza il busto). Piega il ginocchio sinistro dietro di te e afferra il piede sinistro con la mano sinistra. Per allungare il flessore dell''anca, spingi l''anca sinistra in avanti mentre spingi il piede sinistro all''indietro contro la mano. Cambia lato.' 
WHERE name = 'On Your Side Quad Stretch';

UPDATE public.exercise_library 
SET name_it = 'Rematore con manubrio a un braccio', description_it = 'Usa una panca piana e posiziona un manubrio su ciascun lato. Appoggia la gamba destra sull''estremità della panca, piega il busto in avanti partendo dai fianchi finché la parte superiore del corpo non è parallela al pavimento e appoggia la mano destra sull''altra estremità della panca per supporto. Usa la mano sinistra per afferrare il manubrio a terra mantenendo la zona lombare dritta. Il palmo della mano deve essere rivolto verso il busto. Questa è la posizione di partenza. Tira il peso verso l''alto lateralmente rispetto al torace, mantenendo il braccio vicino al fianco e il busto immobile. Espira durante questa fase. Consiglio: concentrati sulla contrazione dei muscoli della schiena una volta raggiunta la posizione di massima contrazione. Assicurati che lo sforzo sia effettuato dai muscoli della schiena e non dalle braccia. Infine, il busto deve rimanere fermo; solo le braccia devono muoversi. Gli avambracci devono servire solo a reggere il manubrio; non cercare di tirare il manubrio usando gli avambracci. Riporta il peso verso il basso nella posizione di partenza. Inspira durante questa fase. Ripeti per il numero di ripetizioni indicato. Cambia braccio e ripeti.' 
WHERE name = 'One-Arm Dumbbell Row';

UPDATE public.exercise_library 
SET name_it = 'Croci con manubrio a un braccio su panca piana', description_it = 'Sdraiati su una panca piana con un manubrio in una mano appoggiato sulla coscia. Il palmo della mano deve avere una presa neutra. Usando la spinta della coscia, esegui un Clean per portare il manubrio davanti a te, tenendo il braccio completamente esteso. Mantieni la presa neutra. La mano che non lavora deve stare a lato, afferrando la panca per supporto. Questa è la posizione di partenza. Il braccio con il peso deve avere una leggera flessione del gomito per evitare stress al tendine del bicipite. Inizia abbassando il braccio lateralmente in un arco ampio finché non senti lo stretching nel torace. Inspira durante questa fase. Consiglio: mantieni il braccio fermo durante tutto il movimento; la rotazione deve avvenire solo a livello dell''articolazione della spalla. Riporta il braccio nella posizione di partenza contraendo i muscoli pettorali ed espirando. Consiglio: utilizza lo stesso arco di movimento usato per la discesa. Mantieni per un secondo la posizione di contrazione e ripeti per il numero di ripetizioni prescritto. Cambia braccio e ripeti.' 
WHERE name = 'One-Arm Flat Bench Dumbbell Flye';

UPDATE public.exercise_library 
SET name_it = 'Flessioni laterali ai cavi alti a un braccio', description_it = 'Collega una maniglia standard a una torre, posizionando la carrucola nella posizione più alta. Posizionati lateralmente rispetto al cavo. Con una mano, afferra la maniglia con una presa inversa (palmo rivolto verso l''alto). Tira il cavo verso il basso finché il gomito tocca il fianco e la maniglia si trova all''altezza della spalla. Posiziona i piedi alla larghezza delle spalle. Metti la mano libera sul fianco per guidare il punto di rotazione. Mantieni il braccio in posizione statica. Contrai l''obliquo per abbassare il peso eseguendo un crunch laterale. Una volta raggiunta la massima contrazione, rilascia lentamente il peso verso la posizione iniziale. Il pacco pesi non deve mai toccare terra durante la serie; l''obiettivo è mantenere una tensione costante. Ripeti fino al cedimento. Successivamente, cambia posizione e ripeti la stessa serie di movimenti sul lato opposto.' 
WHERE name = 'One-Arm High-Pulley Cable Side Bends';

UPDATE public.exercise_library 
SET name_it = 'Alzate laterali a un braccio su panca inclinata', description_it = 'Sdraiati lateralmente su una panca inclinata con un manubrio in mano. Assicurati che la spalla sia premuta contro la panca e che il braccio sia disteso attraverso il corpo con il palmo vicino all''ombelico. Afferra il manubrio con il braccio superiore mantenendolo esteso davanti a te, parallelo al pavimento. Questa è la posizione di partenza. Mantenendo sempre il manubrio parallelo al pavimento, esegui un''alzata laterale. Il braccio deve salire dritto fino a puntare verso il soffitto. Consiglio: espira durante il movimento. Mantieni la posizione per un secondo per sentire la contrazione nelle spalle. Inspirando, abbassa il peso riportandolo nella posizione iniziale. Ripeti per il numero di ripetizioni prescritto. Cambia braccio e ripeti.' 
WHERE name = 'One-Arm Incline Lateral Raise';

UPDATE public.exercise_library 
SET name_it = 'Clean con Kettlebell a un braccio', description_it = 'Posiziona una kettlebell tra i piedi. Mentre ti pieghi per afferrarla, spingi il bacino all''indietro e guarda in avanti. Esegui il Clean portando la kettlebell verso la spalla estendendo gambe e anche mentre sollevi il peso. Ruota il polso durante il movimento. Riporta il peso nella posizione di partenza.' 
WHERE name = 'One-Arm Kettlebell Clean';

UPDATE public.exercise_library 
SET name_it = 'Clean and Jerk con Kettlebell a un braccio', description_it = 'Afferra una kettlebell per l''impugnatura. Esegui il Clean verso la spalla estendendo gambe e anche. Ruota il polso in modo che il palmo sia rivolto in avanti. Fletti leggermente le ginocchia mantenendo il busto eretto. Inverti immediatamente la direzione spingendo con i talloni, come per un piccolo salto per creare slancio. Contemporaneamente, spingi la kettlebell sopra la testa estendendo il braccio, sfruttando l''inerzia del corpo per sollevare il peso. Ricevi il peso sopra la testa tornando in una posizione di squat sotto di esso. Mantenendo il peso in alto, torna in posizione eretta. Riporta il peso a terra per eseguire la ripetizione successiva.' 
WHERE name = 'One-Arm Kettlebell Clean and Jerk';

UPDATE public.exercise_library 
SET name_it = 'Floor Press con Kettlebell a un braccio', description_it = 'Sdraiati a terra tenendo una kettlebell con una mano, con la parte superiore del braccio appoggiata al pavimento. Il palmo deve essere rivolto verso l''interno. Spingi la kettlebell verso il soffitto ruotando il polso. Riporta la kettlebell alla posizione di partenza e ripeti.' 
WHERE name = 'One-Arm Kettlebell Floor Press';

UPDATE public.exercise_library 
SET name_it = 'Jerk con Kettlebell a un braccio', description_it = 'Afferra una kettlebell per l''impugnatura. Esegui il Clean verso la spalla estendendo gambe e anche. Ruota il polso in modo che il palmo sia rivolto in avanti. Questa è la posizione di partenza. Fletti leggermente le ginocchia mantenendo il busto eretto. Inverti immediatamente la direzione spingendo con i talloni, creando slancio. Spingi la kettlebell sopra la testa estendendo il braccio, usando l''inerzia del corpo. Ricevi il peso sopra la testa tornando in una posizione di squat sotto di esso. Mantenendo il peso in alto, torna in posizione eretta. Riporta il peso verso il basso per eseguire la ripetizione successiva.' 
WHERE name = 'One-Arm Kettlebell Jerk';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Military Press laterale', description_it = 'Esegui un Clean del kettlebell portandolo alla spalla, estendendo gambe e anche mentre tiri il kettlebell verso di te. Durante il movimento, ruota il polso in modo che il palmo sia rivolto verso l''interno; questa è la posizione di partenza. Guarda il kettlebell e spingilo verso l''alto e verso l''esterno fino a completa estensione sopra la testa. Riporta il kettlebell alla spalla in modo controllato e ripeti. Contrai con forza dorsali, glutei e addome per maggiore stabilità e potenza.' 
WHERE name = 'One-Arm Kettlebell Military Press To The Side';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Para Press', description_it = 'Esegui un Clean del kettlebell portandolo alla spalla, estendendo gambe e anche mentre tiri il kettlebell verso di te. Ruota il polso in modo che il palmo sia rivolto in avanti; questa è la posizione di partenza. Mantieni il gomito rivolto verso l''esterno e spingi il kettlebell verso l''alto e l''esterno fino a completa estensione sopra la testa. Riporta il kettlebell alla spalla in modo controllato e ripeti. Contrai con forza dorsali, glutei e addome per maggiore stabilità e potenza.' 
WHERE name = 'One-Arm Kettlebell Para Press';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Push Press', description_it = 'Afferra il kettlebell per l''impugnatura ed esegui un Clean portandolo alla spalla, ruotando il polso in modo che il palmo sia rivolto in avanti; questa è la posizione di partenza. Esegui un leggero piegamento sulle ginocchia mantenendo il busto eretto. Inverti immediatamente il movimento spingendo energicamente sui talloni, come per un salto, per creare slancio. Contemporaneamente, spingi il kettlebell sopra la testa fino alla completa estensione del braccio, sfruttando l''inerzia del corpo. Abbassa il peso per eseguire la ripetizione successiva.' 
WHERE name = 'One-Arm Kettlebell Push Press';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Row', description_it = 'Posiziona un kettlebell davanti ai piedi. Piega leggermente le ginocchia, spingi il bacino all''indietro e fletti il busto per raggiungere la posizione di partenza. Afferra il kettlebell e tiralo verso l''addome, retrando la scapola e flettendo il gomito. Mantieni la schiena dritta. Abbassa il peso e ripeti.' 
WHERE name = 'One-Arm Kettlebell Row';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Snatch', description_it = 'Posiziona un kettlebell tra i piedi. Piega le ginocchia e spingi il bacino all''indietro per assumere la corretta posizione di partenza. Guarda dritto davanti a te e fai oscillare il kettlebell tra le gambe. Inverti immediatamente il movimento, spingendo con forza di anche e ginocchia per accelerare il kettlebell verso l''alto. Mentre il kettlebell sale verso la spalla, ruota la mano e spingi verso l''alto, sfruttando l''inerzia per ricevere il peso con il braccio completamente esteso sopra la testa.' 
WHERE name = 'One-Arm Kettlebell Snatch';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Split Jerk', description_it = 'Afferra il kettlebell ed esegui un Clean portandolo alla spalla con il palmo rivolto in avanti; questa è la posizione di partenza. Esegui un leggero piegamento sulle ginocchia mantenendo il busto eretto. Inverti immediatamente il movimento spingendo sui talloni per creare slancio. Contemporaneamente, spingi il kettlebell sopra la testa e, contemporaneamente, portati in posizione di affondo con una gamba avanti e una dietro per ricevere il peso. Mantenendo il peso sopra la testa, torna in posizione eretta unendo i piedi. Abbassa il peso per la ripetizione successiva.' 
WHERE name = 'One-Arm Kettlebell Split Jerk';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Split Snatch', description_it = 'Afferra il kettlebell per l''impugnatura con una mano. Esegui uno squat, quindi inverte il movimento estendendo anche, ginocchia e caviglie per sollevare il kettlebell sopra la testa. Dopo la completa estensione del corpo, scendi in posizione di affondo (una gamba avanti e una indietro) per ricevere il peso sopra la testa. Assicurati di spingere con le anche e bloccare il peso con il braccio teso in un unico movimento fluido. Torna in posizione eretta mantenendo il peso in alto, unisci i piedi e abbassa il peso per tornare alla posizione di partenza.' 
WHERE name = 'One-Arm Kettlebell Split Snatch';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Kettlebell Swings', description_it = 'Esegui uno swing con il kettlebell utilizzando una sola mano, sfruttando la spinta esplosiva delle anche per far oscillare il peso, mantenendo la schiena neutra e il core contratto durante tutto l''arco del movimento.' 
WHERE name = 'One-Arm Kettlebell Swings';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Long Bar Row', description_it = 'Posiziona un bilanciere in un supporto (landmine) o in un angolo per fissarlo. Carica un peso adeguato all''estremità. Stai di fianco al bilanciere, afferralo con una mano vicino al collare e, usando gambe e anche, portati in posizione eretta. Assumi una posizione a ginocchia flesse con il bacino all''indietro e il petto alto; il braccio deve essere teso verso il basso. Questa è la posizione di partenza. Tira il peso verso il fianco retrando la spalla e flettendo il gomito, senza strattonare. Dopo una breve pausa, torna alla posizione di partenza.' 
WHERE name = 'One-Arm Long Bar Row';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Medicine Ball Slam', description_it = 'Inizia in posizione eretta con una postura atletica sfalsata. Tieni una palla medica in una mano, dallo stesso lato della gamba arretrata. Solleva la palla medica sopra la testa, estendendo anche, ginocchia e caviglie per prepararti al lancio. Alla massima estensione, fletti spalle, colonna vertebrale e anche per scagliare con forza la palla a terra direttamente davanti a te. Afferra la palla al rimbalzo e continua per il numero di ripetizioni desiderato.' 
WHERE name = 'One-Arm Medicine Ball Slam';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Open Palm Kettlebell Clean', description_it = 'Posiziona una kettlebell tra i piedi. Afferra l''impugnatura con una mano e solleva la kettlebell rapidamente, lasciandola ruotare in modo che la sfera della kettlebell atterri sul palmo della mano. Lancia la kettlebell in avanti e riprendi l''impugnatura con la mano. Riporta la kettlebell a terra e ripeti. Assicurati di allenare entrambe le braccia.' 
WHERE name = 'One-Arm Open Palm Kettlebell Clean';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Overhead Kettlebell Squats', description_it = 'Esegui un Clean e un Press con una kettlebell utilizzando un solo braccio. Porta la kettlebell alla spalla estendendo gambe e anche mentre tiri la kettlebell verso di te, ruotando il polso. Spingi il peso sopra la testa estendendo il gomito: questa è la posizione di partenza. Guardando dritto davanti a te e mantenendo la kettlebell bloccata sopra la testa, fletti ginocchia e anche e abbassa il busto tra le gambe, mantenendo testa e petto alti. Fermati nella posizione bassa per un secondo prima di risalire, facendo forza sui talloni.' 
WHERE name = 'One-Arm Overhead Kettlebell Squats';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Side Deadlift', description_it = 'Posizionati lateralmente rispetto al centro di un bilanciere. Fletti le ginocchia e abbassati fino a raggiungere il bilanciere. Afferra la sbarra come se stessi impugnando una valigetta (i palmi rivolti verso di te poiché la sbarra è trasversale). Potrebbe essere necessario l''uso di fasce per i polsi se utilizzi un carico elevato. Questa è la posizione di partenza. Usa le gambe per sollevare il bilanciere espirando. Le braccia devono estendersi completamente mentre sollevi il carico fino a trovarti in posizione eretta. Torna lentamente verso il basso inspirando. Consiglio: Assicurati di flettere le ginocchia durante la discesa per evitare infortuni. Ripeti per il numero di ripetizioni consigliato, poi cambia braccio.' 
WHERE name = 'One-Arm Side Deadlift';

UPDATE public.exercise_library 
SET name_it = 'One-Arm Side Laterals', description_it = 'Afferra un manubrio con una mano. Usa l''altra mano per reggerti a un supporto stabile, come una panca inclinata. Inclinati verso il braccio che solleva il peso, allontanandoti dalla mano che poggia sulla panca per mantenere l''equilibrio. Resta con il busto dritto e il manubrio lungo il fianco, palmo rivolto verso di te. Mantieni il busto fermo (senza oscillare) e solleva il manubrio lateralmente con il gomito leggermente flesso e la mano leggermente inclinata in avanti, come se stessi versando acqua da una brocca. Continua finché il braccio non è parallelo al pavimento. Espira durante il sollevamento e fai una pausa di un secondo in alto. Scendi lentamente inspirando. Ripeti per il numero di ripetizioni previsto, poi cambia braccio.' 
WHERE name = 'One-Arm Side Laterals';

UPDATE public.exercise_library 
SET name_it = 'One-Legged Cable Kickback', description_it = 'Aggancia una cavigliera a un cavo basso e fissala alla caviglia. Posizionati a circa 60 cm dal pacco pesi, afferrando il telaio per supporto. Mantenendo ginocchia e anche leggermente flesse e gli addominali contratti, contrai i glutei per "calciare" lentamente la gamba all''indietro, seguendo un arco semicircolare il più in alto possibile, espirando. Consiglio: alla massima estensione, contrai i glutei per un secondo per massimizzare la contrazione. Torna lentamente in avanti, resistendo alla trazione del cavo fino alla posizione iniziale. Ripeti per le ripetizioni previste, poi cambia gamba.' 
WHERE name = 'One-Legged Cable Kickback';

UPDATE public.exercise_library 
SET name_it = 'One Arm Against Wall', description_it = 'In posizione eretta, appoggia un braccio flesso contro una parete o lo stipite di una porta. Inclinati lentamente verso il braccio finché non avverti uno stretching dei dorsali.' 
WHERE name = 'One Arm Against Wall';

UPDATE public.exercise_library 
SET name_it = 'One Arm Chin-Up', description_it = 'Per questo esercizio, posiziona un asciugamano attorno a una sbarra per trazioni. Afferra la sbarra con il palmo rivolto verso di te; una mano afferra la sbarra e l''altra l''asciugamano. Porta il busto indietro di circa 30 gradi inarcando leggermente la zona lombare e spingendo il petto in fuori. Tira il busto verso l''alto finché la sbarra non tocca la parte alta del petto, spingendo spalle e braccia verso il basso e indietro. Espira durante la salita. Consiglio: concentrati sulla contrazione dei muscoli dorsali una volta raggiunta la massima altezza. Il busto deve rimanere fermo nello spazio e muoversi solo tramite le braccia. Gli avambracci non devono fare altro che reggere la presa. Dopo un secondo di contrazione, inspira e scendi lentamente fino a estensione completa delle braccia. Ripeti e cambia braccio.' 
WHERE name = 'One Arm Chin-Up';

UPDATE public.exercise_library 
SET name_it = 'One Arm Dumbbell Bench Press', description_it = 'Sdraiati su una panca piana con un manubrio in mano appoggiato sulla coscia. Usa la spinta della coscia per portare il manubrio in posizione, tenendolo davanti a te alla larghezza della spalla. Usa la mano libera per stabilizzarlo. Ruota il polso in avanti in modo che il palmo sia rivolto in avanti. Questa è la posizione di partenza. Scendi lentamente verso il fianco inspirando, mantenendo il pieno controllo del manubrio. Consiglio: usa la mano libera per bilanciare il manubrio se necessario. Espirando, spingi il manubrio verso l''alto usando i pettorali. Blocca il braccio in alto, contrai il petto, mantieni per un secondo e scendi lentamente. La fase di discesa dovrebbe durare il doppio di quella di salita. Ripeti e cambia braccio.' 
WHERE name = 'One Arm Dumbbell Bench Press';

UPDATE public.exercise_library 
SET name_it = 'One Arm Dumbbell Preacher Curl', description_it = 'Afferra un manubrio con il braccio destro e appoggia la parte superiore del braccio sulla panca Scott o su una panca inclinata. Il manubrio deve essere tenuto all''altezza della spalla. Questa è la posizione di partenza. Inspira e abbassa lentamente il manubrio finché il braccio non è esteso e il bicipite completamente allungato. Espira e contrai il bicipite per sollevare il peso finché il bicipite non è contratto e il manubrio all''altezza della spalla. Per una contrazione completa, assicurati che il mignolo sia più in alto del pollice. Contrai intensamente il bicipite per un secondo, poi ripeti. Cambia braccio.' 
WHERE name = 'One Arm Dumbbell Preacher Curl';

UPDATE public.exercise_library 
SET name_it = 'One Arm Floor Press', description_it = 'Sdraiati su una superficie piana con la schiena a terra o su un tappetino. Tieni le ginocchia flesse. Fatti passare il bilanciere da un partner. Il braccio deve essere quasi completamente esteso, come nella posizione di partenza di una panca piana, ma con presa neutra (palmi rivolti verso il busto). Tieni l''altra mano lungo il fianco. Inizia l''esercizio abbassando il bilanciere finché il gomito non tocca terra. Inspira durante questa fase eccentrica. Risali fino alla posizione di partenza espirando durante la fase concentrica. Ripeti per le ripetizioni consigliate, poi cambia braccio.' 
WHERE name = 'One Arm Floor Press';

UPDATE public.exercise_library 
SET name_it = 'Lat Pulldown a un braccio', description_it = 'Seleziona un peso adeguato e regola il supporto per le ginocchia per aiutarti a mantenere la posizione. Afferra la maniglia con una presa prona. Questa sarà la tua posizione di partenza. Tira la maniglia verso il basso, avvicinando il gomito al fianco mentre fletti il braccio. Fai una pausa nella parte inferiore del movimento, quindi ritorna lentamente alla posizione iniziale. Per le ripetizioni successive, evita di riappoggiare completamente il peso per mantenere la tensione sui muscoli coinvolti.' 
WHERE name = 'One Arm Lat Pulldown';

UPDATE public.exercise_library 
SET name_it = 'Estensione tricipiti con manubrio a un braccio (presa prona)', description_it = 'Sdraiati su una panca tenendo un manubrio a braccio teso. Il braccio deve essere perpendicolare al corpo. Il palmo della mano deve essere rivolto verso i piedi, poiché per questo esercizio è richiesta una presa prona. Posiziona l''altra mano sul bicipite per supporto. Inizia ad abbassare lentamente il manubrio mentre inspiri. Successivamente, solleva il manubrio contraendo i tricipiti. Ricordati di espirare durante la fase concentrica (la parte di sollevamento dell''esercizio). Ripeti per il numero di volte previsto, quindi cambia braccio e ripeti.' 
WHERE name = 'One Arm Pronated Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Estensione tricipiti con manubrio a un braccio (presa supinata)', description_it = 'Sdraiati su una panca tenendo un manubrio a braccio teso. Il braccio deve essere perpendicolare al corpo. Il palmo della mano deve essere rivolto verso il viso, poiché per questo esercizio è richiesta una presa supinata. Posiziona l''altra mano sul bicipite per supporto. Inizia ad abbassare lentamente il manubrio mentre inspiri. Successivamente, solleva il manubrio contraendo i tricipiti. Ricordati di espirare durante la fase concentrica (la parte di sollevamento dell''esercizio). Ripeti per il numero di volte previsto, quindi cambia braccio e ripeti.' 
WHERE name = 'One Arm Supinated Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Mezza Locusta', description_it = 'Sdraiati a pancia in giù sul pavimento. Posiziona la mano sinistra sotto l''anca sinistra per proteggere l''osso iliaco e il pube. Piega il ginocchio destro in modo da poter afferrare il piede con la mano destra. Solleva il piede in aria e contemporaneamente solleva le spalle dal pavimento. Questo movimento allunga anche il flessore dell''anca destra, il petto e le spalle. Cambia lato. Se non avverti fastidio alla schiena, puoi provare a eseguire l''esercizio con entrambe le braccia e le gambe contemporaneamente.' 
WHERE name = 'One Half Locust';

UPDATE public.exercise_library 
SET name_it = 'Appeso a una mano', description_it = 'Afferra una barra per trazioni con una mano, utilizzando una presa prona. Tieni i piedi sul pavimento o su uno scalino. Lascia che la maggior parte del tuo peso sia sostenuta dalla mano, mantenendo i piedi a terra. Mantieni la posizione per 10-20 secondi, poi cambia mano.' 
WHERE name = 'One Handed Hang';

UPDATE public.exercise_library 
SET name_it = 'Ginocchio al petto', description_it = 'Sdraiati a terra. Distendi una gamba e porta l''altro ginocchio al petto. Fai presa sotto l''articolazione del ginocchio per proteggere la rotula. Tira delicatamente il ginocchio verso il naso. Cambia lato. Questo esercizio allunga i glutei e la parte bassa della schiena della gamba piegata, e il flessore dell''anca della gamba distesa.' 
WHERE name = 'One Knee To Chest';

UPDATE public.exercise_library 
SET name_it = 'Squat bulgaro con bilanciere', description_it = 'Posizionati a circa 60-90 cm di distanza da una panca, dando le spalle ad essa. Tieni un bilanciere a terra davanti a te. Consiglio: i piedi devono essere alla larghezza delle spalle. Piega le ginocchia e usa una presa prona, con le mani più larghe delle spalle, per sollevare il bilanciere fino a portarlo al petto. Solleva il bilanciere sopra la testa e poggialo sulla base del collo. Porta un piede all''indietro appoggiando la punta sulla panca. L''altro piede deve rimanere fermo davanti a te. Tieni la testa alta e la schiena dritta. Consiglio: assicurati che la schiena sia dritta e il petto in fuori. Mentre inspiri, abbassati lentamente finché la coscia non è parallela al pavimento. Il ginocchio dovrebbe essere allineato sopra la punta del piede. Spingendo con petto e fianchi, contrai i quadricipiti e risali nella posizione iniziale mentre espiri. Ripeti per le serie previste, quindi cambia gamba.' 
WHERE name = 'One Leg Barbell Squat';

UPDATE public.exercise_library 
SET name_it = 'Clean con kettlebell a palmo aperto', description_it = 'Posiziona una kettlebell tra i piedi. Esegui un Clean estendendo gambe e anche mentre sollevi la kettlebell verso le spalle. Rilascia la presa mentre sale, lasciando che la kettlebell ruoti in modo che la parte sferica si appoggi sui palmi delle tue mani. Rilascia la kettlebell davanti a te, afferrando nuovamente l''impugnatura con entrambe le mani. Riporta la kettlebell nella posizione iniziale e ripeti.' 
WHERE name = 'Open Palm Kettlebell Clean';

UPDATE public.exercise_library 
SET name_it = 'Otis-Up', description_it = 'Blocca i piedi e sdraiati sul pavimento con le ginocchia piegate. Tieni un peso con entrambe le mani al petto. Questa è la posizione di partenza. Inizia il movimento flettendo fianchi e colonna vertebrale per sollevare il busto da terra. Mentre sali, spingi il peso verso l''alto sopra la testa. Riporta il peso al petto mentre esegui il movimento inverso del sit-up, assicurandoti di non tornare completamente a terra.' 
WHERE name = 'Otis-Up';

UPDATE public.exercise_library 
SET name_it = 'Curl ai cavi alti', description_it = 'Imposta un peso confortevole su entrambi i lati della macchina ai cavi. Nota: assicurati che il carico sia uguale su entrambi i lati. Regola l''altezza delle carrucole in modo che siano più alte delle tue spalle. Posizionati al centro e afferra le maniglie con una presa supina (palmi verso l''alto). Le braccia devono essere completamente distese e parallele al pavimento, piedi alla larghezza delle spalle. Il corpo deve essere ben allineato tra le maniglie. Questa è la posizione di partenza. Mentre espiri, contrai lentamente i bicipiti fino a far toccare gli avambracci ai bicipiti. Mentre inspiri, riporta le braccia nella posizione iniziale. Nota: il corpo deve rimanere fermo durante l''esercizio, muovendo solo gli avambracci. Ripeti per le serie prescritte.' 
WHERE name = 'Overhead Cable Curl';

UPDATE public.exercise_library 
SET name_it = 'Overhead Lat Stretch', description_it = 'Siediti dritto sul pavimento con il partner dietro di te. Solleva un braccio dritto verso l''alto e fletti il gomito, cercando di toccare la mano sulla schiena. Il partner deve trattenere il tuo tricipite e il polso. Questa sarà la posizione di partenza. Tenta di tirare la parte superiore del braccio verso il fianco mentre il partner ti oppone resistenza impedendoti di farlo. Dopo 10-20 secondi, rilassa il braccio e consenti al partner di allungare ulteriormente il gran dorsale applicando una leggera pressione sul tricipite. Mantieni la posizione per 10-20 secondi, quindi cambia lato.' 
WHERE name = 'Overhead Lat';

UPDATE public.exercise_library 
SET name_it = 'Overhead Slam', description_it = 'Impugna una palla medica con entrambe le mani e resta in piedi con i piedi alla larghezza delle spalle. Questa sarà la posizione di partenza. Inizia il movimento sollevando la palla sopra la testa ed estendendo completamente il corpo. Inverti il movimento, scagliando la palla a terra direttamente davanti a te con la massima forza possibile. Ricevi la palla con entrambe le mani al rimbalzo e ripeti il movimento.' 
WHERE name = 'Overhead Slam';

UPDATE public.exercise_library 
SET name_it = 'Overhead Squat', description_it = 'Inizia con un bilanciere a terra davanti a te. I piedi devono essere più larghi della larghezza delle spalle. Piega le ginocchia e usa una presa prona (palmi rivolti verso di te) per afferrare il bilanciere con le mani a una distanza superiore alla larghezza delle spalle. Solleva il bilanciere fino a portarlo sul petto. Porta il bilanciere sopra e leggermente dietro la testa, assicurandoti che le braccia siano completamente estese. Tieni la testa alta e la schiena dritta. Contrai le scapole. Questa è la posizione di partenza. Espirando, abbassa lentamente il peso piegando le ginocchia finché le cosce non sono parallele al suolo. Suggerimento: mantieni la schiena dritta per evitare infortuni e tieni le braccia sempre estese sopra la testa. Usa la spinta dei piedi e delle gambe per tornare alla posizione di partenza espirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Overhead Squat';

UPDATE public.exercise_library 
SET name_it = 'Overhead Stretch', description_it = 'In piedi, intreccia le dita e rivolgi i palmi verso il soffitto. Mantieni le spalle basse mentre estendi le braccia verso l''alto. Per un allungamento completo del busto, tira il coccige verso il basso e stabilizza il tronco. Allunga i muscoli della parte anteriore e posteriore del busto.' 
WHERE name = 'Overhead Stretch';

UPDATE public.exercise_library 
SET name_it = 'Overhead Triceps Stretch', description_it = 'Siediti dritto sul pavimento con il partner dietro di te. Solleva un braccio dritto verso l''alto e fletti il gomito, cercando di toccare la mano sulla schiena. Il partner deve trattenere il tuo gomito e il polso. Questa sarà la posizione di partenza. Tenta di estendere il braccio dritto verso l''alto mentre il partner ti oppone resistenza. Dopo 10-20 secondi, rilassa il braccio e consenti al partner di allungare ulteriormente il tricipite applicando una leggera pressione sul polso. Mantieni la posizione per 10-20 secondi, quindi cambia lato.' 
WHERE name = 'Overhead Triceps';

UPDATE public.exercise_library 
SET name_it = 'Pallof Press', description_it = 'Collega una maniglia standard a un cavo, posizionandolo preferibilmente all''altezza delle spalle; in alternativa, un cavo basso è sufficiente. Mettiti di fianco alla torre, afferra la maniglia con entrambe le mani e allontanati fino ad avere il braccio teso, mantenendo il cavo in tensione. Con i piedi alla larghezza dei fianchi e le ginocchia leggermente flesse, tieni la maniglia al centro del petto. Questa è la posizione di partenza. Spingi la maniglia lontano dal petto, estendendo completamente le braccia. Il core deve essere contratto e attivo. Mantieni la posizione per alcuni secondi prima di tornare alla posizione di partenza. Al termine della serie, ripeti girandoti verso il lato opposto.' 
WHERE name = 'Pallof Press';

UPDATE public.exercise_library 
SET name_it = 'Pallof Press con rotazione', description_it = 'Collega una maniglia standard a un cavo, posizionandolo all''altezza delle spalle. Mettiti di fianco al cavo, afferra la maniglia con una mano e allontanati finché il braccio non è teso e il cavo in tensione. Allinea il braccio teso con il cavo. Con i piedi alla larghezza dei fianchi, porta la maniglia al petto e afferrala con l''altra mano. Ora entrambe le mani sono sulla maniglia. Guardando in avanti, spingi la maniglia lontano dal petto, mantenendo il core contratto. Mantenendo i fianchi fermi, ruota il busto lontano dal cavo di un quarto di giro. Mantieni la posizione rigida e le braccia dritte. Torna lentamente alla posizione neutra. Con la tensione laterale ancora attiva sul core, porta le mani al petto e spingi immediatamente verso l''esterno per tornare a una posizione di completa estensione. Questo costituisce una ripetizione. Ripeti fino a esaurimento, poi cambia lato.' 
WHERE name = 'Pallof Press With Rotation';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con manubri (palmi in giù) su panca', description_it = 'Posiziona due manubri su un lato di una panca piana. Inginocchiati di fronte alla panca. Afferra i manubri con una presa prona (palmi rivolti verso il basso) e appoggia gli avambracci sulla panca, lasciando che i polsi sporgano dal bordo. Fletti i polsi verso l''alto espirando. Abbassa lentamente i polsi alla posizione di partenza inspirando. Gli avambracci devono rimanere fermi; il movimento deve coinvolgere solo i polsi. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Palms-Down Dumbbell Wrist Curl Over A Bench';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con bilanciere (palmi in giù) su panca', description_it = 'Posiziona un bilanciere su un lato di una panca piana. Inginocchiati di fronte alla panca. Afferra il bilanciere con una presa prona (palmi rivolti verso il basso) e appoggia gli avambracci sulla panca, lasciando che i polsi sporgano dal bordo. Fletti i polsi verso l''alto espirando. Abbassa lentamente i polsi alla posizione di partenza inspirando. Gli avambracci devono rimanere fermi; il movimento deve coinvolgere solo i polsi. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Palms-Down Wrist Curl Over A Bench';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con bilanciere (palmi in su) su panca', description_it = 'Posiziona un bilanciere su un lato di una panca piana. Inginocchiati di fronte alla panca. Afferra il bilanciere con una presa supinata (palmi rivolti verso l''alto) e appoggia gli avambracci sulla panca, lasciando che i polsi sporgano dal bordo. Fletti i polsi verso l''alto espirando. Abbassa lentamente i polsi alla posizione di partenza inspirando. Gli avambracci devono rimanere fermi; il movimento deve coinvolgere solo i polsi. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Palms-Up Barbell Wrist Curl Over A Bench';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con manubri su panca (palmi verso l''alto)', description_it = 'Posiziona due manubri su un lato di una panca piana. Inginocchiati di fronte alla panca. Afferra i manubri con una presa supinata (palmi verso l''alto) e appoggia gli avambracci sulla panca, lasciando che i polsi sporgano dal bordo. Esegui il curl dei polsi verso l''alto espirando. Ritorna lentamente alla posizione iniziale inspirando. Mantieni gli avambracci fermi: il movimento deve coinvolgere esclusivamente i polsi. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Palms-Up Dumbbell Wrist Curl Over A Bench';

UPDATE public.exercise_library 
SET name_it = 'Dip alle parallele', description_it = 'Posizionati tra le barre parallele. Afferra ciascuna barra con una mano e datti una piccola spinta per portarti nella posizione iniziale con le braccia distese. Fletti i gomiti per abbassare il corpo finché le braccia non superano i 90 gradi. Evita di oscillare e mantieni una postura corretta durante la discesa. Inverti il movimento estendendo i gomiti per tornare alla posizione iniziale. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Parallel Bar Dip';

UPDATE public.exercise_library 
SET name_it = 'Retroversione del bacino in ponte', description_it = 'Sdraiati con i piedi a terra e i talloni allineati sotto le ginocchia. Solleva solo l''osso sacro verso il soffitto per allungare la zona lombare (senza sollevare l''intera colonna vertebrale) e contrai l''addome. Per eseguire il ponte, solleva l''intera colonna vertebrale, mantenendo il collo a terra.' 
WHERE name = 'Pelvic Tilt Into Bridge';

UPDATE public.exercise_library 
SET name_it = 'SMR per i muscoli peronieri', description_it = 'Sdraiati su un fianco, sostenendo il peso sull''avambraccio e su un foam roller posizionato sulla parte esterna della parte inferiore della gamba. La gamba superiore può essere appoggiata su quella inferiore o incrociata davanti ad essa. Solleva i fianchi da terra e inizia a rullare dal ginocchio fino sopra la caviglia sul lato della gamba, fermandoti sui punti di tensione per 10-30 secondi. Ripeti sull''altra gamba.' 
WHERE name = 'Peroneals-SMR';

UPDATE public.exercise_library 
SET name_it = 'Stretching per i muscoli peronieri', description_it = 'Da seduto, fai passare una cintura, una corda o una fascia attorno a un piede. Con la gamba estesa e il tallone sollevato da terra, tira la fascia per invertire il piede, portando la parte interna del piede verso di te. Mantieni la posizione per 10-20 secondi, quindi cambia lato.' 
WHERE name = 'Peroneals Stretch';

UPDATE public.exercise_library 
SET name_it = 'Hip Bridge su Physioball', description_it = 'Sdraiati su una palla in modo che la parte superiore della schiena sia supportata, mentre i fianchi rimangono sollevati. Entrambi i piedi devono essere ben appoggiati a terra, alla larghezza delle spalle o più. Estendi i fianchi utilizzando glutei e bicipiti femorali per sollevare il bacino verso l''alto. Fermati al culmine del movimento e ritorna alla posizione iniziale.' 
WHERE name = 'Physioball Hip Bridge';

UPDATE public.exercise_library 
SET name_it = 'Pin Press', description_it = 'I Pin Press eliminano la fase eccentrica della panca piana, sviluppando la forza esplosiva iniziale e permettendo di allenare specifici range di movimento. Posiziona il bilanciere su un power rack impostando i perni all''altezza desiderata (dal blocco completo a pochi centimetri dal petto). Sdraiati sulla panca, posizionandoti come per una normale panca piana, con i piedi ben piantati e la schiena inarcata. Solleva le scapole dalla panca e adducile (avvicinale tra loro). Spingi i trapezi contro la panca. Mantieni una postura rigida. Afferra il bilanciere con una presa standard o alla larghezza delle spalle per focalizzarti sui tricipiti. Mantenendo polsi e gomiti allineati, spingi il bilanciere verso l''alto con massima forza. Tieni i gomiti stretti fino alla distensione completa. Riponi il bilanciere sui perni e fai una pausa prima della ripetizione successiva.' 
WHERE name = 'Pin Presses';

UPDATE public.exercise_library 
SET name_it = 'SMR per il piriforme', description_it = 'Siediti con i glutei sopra un foam roller. Fletti le ginocchia e incrocia una gamba posizionando la caviglia sul ginocchio opposto. Sposta il peso sul lato della gamba incrociata, rotolando sui glutei finché non senti tensione nella parte superiore. Puoi intensificare lo stretching usando una mano per tirare il ginocchio flesso verso il petto. Mantieni per 10-30 secondi, poi cambia lato.' 
WHERE name = 'Piriformis-SMR';

UPDATE public.exercise_library 
SET name_it = 'Plank', description_it = 'Posizionati a terra a pancia in giù, sostenendo il peso sulle punte dei piedi e sugli avambracci. Le braccia devono essere flesse e perpendicolari alle spalle. Mantieni il corpo in linea retta e tieni la posizione il più a lungo possibile. Per aumentare la difficoltà, è possibile sollevare un braccio o una gamba.' 
WHERE name = 'Plank';

UPDATE public.exercise_library 
SET name_it = 'Plate Pinch', description_it = 'Afferra due dischi dal bordo largo e uniscili con i lati lisci rivolti verso l''esterno. Usa le dita per afferrare il lato esterno di un disco e il pollice per l''altro, tenendo i dischi uniti. Stringi i dischi con forza. Mantieni questa posizione il più a lungo possibile. Ripeti per il numero di serie prescritto nel tuo programma. Cambia braccio e ripeti.' 
WHERE name = 'Plate Pinch';

UPDATE public.exercise_library 
SET name_it = 'Plate Twist', description_it = 'Sdraiati sul pavimento o su un tappetino da fitness con le gambe completamente distese e il busto sollevato. Afferra il disco (plate) lateralmente con entrambe le mani davanti agli addominali, tenendo le braccia leggermente flesse. Incrocia lentamente le gambe vicino alle caviglie e sollevale da terra, mantenendo le ginocchia leggermente flesse. Nota: inclina leggermente il busto all''indietro per mantenere l''equilibrio durante l''esercizio. Questa è la posizione di partenza. Ruota il disco verso sinistra e tocca il pavimento. Espira durante il movimento. Torna alla posizione di partenza inspirando, quindi ripeti il movimento verso il lato destro del corpo. Suggerimento: esegui il movimento sempre in modo lento e controllato. Scatti bruschi possono causare infortuni alla schiena. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Plate Twist';

UPDATE public.exercise_library 
SET name_it = 'Platform Hamstring Slides', description_it = 'Per questo esercizio è necessario un pavimento in legno o una superficie simile. Sdraiati sulla schiena con le gambe distese. Posiziona un asciugamano da palestra o un piccolo peso sotto il tallone. Questa è la posizione di partenza. Inizia il movimento flettendo il ginocchio, mantenendo l''altra gamba tesa. Continua a portare il tallone verso di te facendolo scivolare sul pavimento. Una volta raggiunta la massima flessione del ginocchio, inverte il movimento per tornare alla posizione di partenza.' 
WHERE name = 'Platform Hamstring Slides';

UPDATE public.exercise_library 
SET name_it = 'Plie Dumbbell Squat', description_it = 'Impugna un manubrio dalla base con entrambe le mani e resta in piedi. Divarica le gambe a una larghezza superiore a quella delle spalle, con le ginocchia leggermente flesse e le punte dei piedi rivolte verso l''esterno. Nota: le braccia devono rimanere ferme durante l''esecuzione. Questa è la posizione di partenza. Piega lentamente le ginocchia e abbassati finché le cosce non sono parallele al pavimento. Inspira durante questa fase eccentrica dell''esercizio. Spingi principalmente facendo forza sui talloni per riportare il corpo nella posizione di partenza, espirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Plie Dumbbell Squat';

UPDATE public.exercise_library 
SET name_it = 'Plyo Kettlebell Pushups', description_it = 'Posiziona una kettlebell a terra. Mettiti in posizione di push-up (flessioni) sulle punte dei piedi, con una mano a terra e l''altra sulla kettlebell, braccia tese. Questa è la posizione di partenza. Inizia abbassandoti il più possibile mantenendo la schiena dritta. Con un movimento rapido ed esplosivo, inverte la direzione spingendo verso l''alto e spostandoti sull''altro lato della kettlebell, cambiando mano. Continua il movimento scendendo e ripetendo il cambio di lato.' 
WHERE name = 'Plyo Kettlebell Pushups';

UPDATE public.exercise_library 
SET name_it = 'Plyo Push-up', description_it = 'Mettiti in posizione prona a terra, sostenendo il peso sulle mani e sulle punte dei piedi. Le braccia devono essere completamente distese con le mani a una larghezza pari a quella delle spalle. Mantieni il corpo dritto per tutta la durata del movimento. Questa è la posizione di partenza. Scendi flettendo i gomiti e portando il petto verso terra. Nella parte inferiore, inverte il movimento spingendo verso l''alto tramite l''estensione dei gomiti il più velocemente possibile. Cerca di spingere il busto verso l''alto finché le mani non si staccano da terra. Torna alla posizione di partenza e ripeti. Per una maggiore difficoltà, aggiungi un battito di mani mentre sei sospeso a mezz''aria.' 
WHERE name = 'Plyo Push-up';

UPDATE public.exercise_library 
SET name_it = 'Stretching del Tibiale Posteriore', description_it = 'Da seduto, fai passare una cintura, una corda o una banda elastica attorno a un piede. Questa è la posizione di partenza. Con la gamba distesa e il tallone sollevato da terra, tira la cintura in modo che il piede ruoti verso l''esterno (eversione), tirando il bordo esterno del piede verso di te. Mantieni la posizione per 10-20 secondi, poi cambia lato.' 
WHERE name = 'Posterior Tibialis Stretch';

UPDATE public.exercise_library 
SET name_it = 'Power Clean', description_it = 'Posizionati con i piedi leggermente più larghi delle spalle e le punte leggermente rivolte verso l''esterno. Accovacciati e afferra il bilanciere con una presa chiusa e prona, leggermente più larga delle spalle e all''esterno delle ginocchia, con le braccia completamente distese. Posiziona il bilanciere a circa 2-3 cm dagli stinchi e sopra la pianta dei piedi. Schiena piatta o leggermente inarcata, petto in fuori e scapole retratte. Testa in posizione neutra (allineata alla colonna vertebrale) e sguardo in avanti. Inspira durante questa fase. Solleva il bilanciere estendendo con forza anche e ginocchia mentre espiri. Suggerimento: il busto deve mantenere la stessa inclinazione. Non piegare la vita e non far salire le anche prima delle spalle. Tieni il bilanciere il più vicino possibile agli stinchi. Quando supera le ginocchia, spingi le anche in avanti e fletti leggermente le ginocchia per evitare di bloccarle. A questo punto, le cosce dovrebbero essere a contatto con il bilanciere. Trattieni il respiro fino alla fase successiva. Inspira, quindi estendi rapidamente anche e ginocchia portandoti sulle punte. Mantieni il bilanciere vicino al corpo. Quando la parte inferiore del corpo è completamente estesa, fai una scrollata di spalle rapida verso l''alto senza flettere i gomiti. Espira durante questa fase. Quando le spalle raggiungono il punto massimo, fletti i gomiti per iniziare a portarti sotto il bilanciere. Continua a tirare le braccia il più in alto possibile. Dopo la massima estensione, entra sotto il bilanciere ruotando le braccia attorno e sotto di esso. Fletti contemporaneamente anche e ginocchia in un quarto di squat. Una volta sotto, solleva i gomiti per posizionare le braccia parallele al pavimento. Ricevi il bilanciere sopra le clavicole e i muscoli delle spalle anteriori. Mantieni il busto eretto e la testa neutra. Torna in posizione eretta estendendo anche e ginocchia. Abbassa il bilanciere riducendo gradualmente la tensione delle braccia per un ritorno controllato sulle cosce, inspirando. Fletti anche e ginocchia per ammortizzare l''impatto. Accovacciati fino a toccare il pavimento. Ricomincia dalla Fase 1.' 
WHERE name = 'Power Clean';

UPDATE public.exercise_library 
SET name_it = 'Power Clean from Blocks', description_it = 'Con il bilanciere posizionato su dei blocchi all''altezza desiderata, afferralo appena fuori dalle gambe. Abbassa le anche caricando il peso sui talloni, schiena dritta, testa in avanti, petto in fuori e spalle leggermente oltre il bilanciere. Questa è la posizione di partenza. Inizia la prima trazione spingendo sui talloni ed estendendo le ginocchia. L''angolo della schiena deve rimanere costante e le braccia dritte. Quando il bilanciere raggiunge la metà delle cosce, inizia l''estensione delle anche. Con un movimento simile a un salto, accelera estendendo anche, ginocchia e caviglie. Non è necessario tirare attivamente con le braccia. Alla fine della seconda trazione, il corpo deve essere completamente esteso, inclinato leggermente all''indietro, con le braccia tese. Passa alla terza trazione scrollando le spalle e flettendo le braccia con i gomiti verso l''alto e l''esterno. Entra sotto il bilanciere per riceverlo sulle spalle, ruotando i gomiti. Recupera la posizione eretta con il bilanciere sulle spalle, quindi riporta il peso sui blocchi.' 
WHERE name = 'Power Clean from Blocks';

UPDATE public.exercise_library 
SET name_it = 'Power Jerk', description_it = 'In piedi, con il bilanciere poggiato sulle spalle anteriori. Con i piedi sotto le anche, fletti le ginocchia senza spostare le anche all''indietro. Scendi solo leggermente, quindi inverte la direzione con la massima potenza possibile. Spingi sui talloni per generare velocità e forza, assicurandoti di spostare la testa quando il bilanciere lascia le spalle. Non appena i piedi si staccano da terra, portali nella posizione di ricezione il più velocemente possibile. Mentre il bilanciere sale, il tuo sforzo di spinta ti spingerà verso il basso. I piedi devono trovarsi in una posizione leggermente più larga, con le ginocchia parzialmente flesse. Ricevi il bilanciere con le braccia bloccate sopra la testa. Torna in posizione eretta.' 
WHERE name = 'Power Jerk';

UPDATE public.exercise_library 
SET name_it = 'Power Partials', description_it = 'In piedi con il busto eretto e un manubrio in ogni mano lungo i fianchi. I gomiti devono essere vicini al busto e i palmi rivolti verso il corpo. Piedi alla larghezza delle spalle. Questa è la posizione di partenza. Mantenendo le braccia dritte e il busto immobile, solleva i pesi lateralmente fino all''altezza delle spalle espirando. Senti la contrazione per un secondo e inizia ad abbassare i pesi tornando alla posizione di partenza inspirando. Suggerimento: tieni i palmi rivolti verso il basso con il mignolo leggermente più alto durante il movimento per concentrare lo sforzo principalmente sulle spalle. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Power Partials';

UPDATE public.exercise_library 
SET name_it = 'Power Snatch', description_it = 'Inizia con un bilanciere carico a terra. La sbarra deve essere vicina o a contatto con gli stinchi; impugna la sbarra con una presa larga. I piedi devono essere posizionati direttamente sotto le anche, ruotati verso l''esterno secondo necessità. Abbassa le anche mantenendo il petto alto e la testa rivolta in avanti. Le spalle devono trovarsi leggermente oltre la sbarra. Questa è la posizione di partenza. Inizia la prima trazione spingendo attraverso l''avampiede e sollevando il bilanciere da terra. L''angolo della schiena deve rimanere costante finché la sbarra non supera le ginocchia. Transita nella seconda trazione estendendo anche, ginocchia e caviglie, spingendo il bilanciere verso l''alto il più rapidamente possibile. Il bilanciere deve rimanere vicino al corpo. Al culmine dell''estensione, esegui una scrollata di spalle e permetti ai gomiti di flettersi lateralmente. Mentre sposti i piedi nella posizione di ricezione, leggermente più ampia, tirati sotto la sbarra mentre la porti sopra la testa. Il bilanciere va ricevuto in uno squat parziale. Continua a sollevare la sbarra fino alla posizione di blocco sopra la testa. Torna in posizione eretta con il peso sopra la testa.' 
WHERE name = 'Power Snatch';

UPDATE public.exercise_library 
SET name_it = 'Power Snatch dai blocchi', description_it = 'Inizia con un bilanciere carico posizionato su blocchi o supporti all''altezza desiderata. Usa una presa larga. I piedi devono essere sotto le anche, ruotati verso l''esterno se necessario. Abbassa le anche, petto in fuori e testa rivolta in avanti. Le spalle devono essere appena oltre la sbarra, con i gomiti rivolti verso l''esterno. Questa è la posizione di partenza. Avvia la prima trazione spingendo attraverso l''avampiede per sollevare il bilanciere dai blocchi. Transita nella seconda trazione estendendo anche, ginocchia e caviglie, spingendo il bilanciere verso l''alto rapidamente. Il bilanciere deve restare vicino al corpo. Al picco dell''estensione, esegui una scrollata di spalle lasciando flettere i gomiti lateralmente. Mentre sposti i piedi nella posizione di ricezione, tirati energicamente sotto la sbarra sollevandola sopra la testa. I piedi devono portarsi appena oltre la larghezza delle anche. Ricevi la sbarra in uno squat profondo con le braccia completamente estese sopra la testa. Mantenendo la sbarra allineata sopra l''avampiede, testa e petto alti, spingi sui talloni per tornare in posizione eretta. Riponi con cura il peso sui blocchi.' 
WHERE name = 'Power Snatch from Blocks';

UPDATE public.exercise_library 
SET name_it = 'Power Stairs', description_it = 'Nelle Power Stairs, degli attrezzi vengono spostati su una scala. A scopo di allenamento, si possono utilizzare un pneumatico o una cassa. Inizia afferrando l''attrezzo con entrambe le mani. Tieni i piedi larghi, testa e petto alti. Spingi verso il terreno con i talloni, estendendo ginocchia e anche per sollevare il peso da terra. Mentre ti inclini all''indietro, prova a sollevare il peso sul gradino, che solitamente è alto circa 40-45 cm. Puoi usare le gambe per aiutare a spingere il peso sul gradino. Ripeti per 3-5 volte e continua con un peso maggiore, muovendoti il più velocemente possibile.' 
WHERE name = 'Power Stairs';

UPDATE public.exercise_library 
SET name_it = 'Preacher Curl', description_it = 'Per eseguire questo movimento avrai bisogno di una panca Scott e di un bilanciere EZ. Afferra il bilanciere EZ all''impugnatura interna stretta (è preferibile farsi passare il bilanciere da qualcuno o prenderlo dal supporto frontale della panca). I palmi delle mani devono essere rivolti verso l''alto e leggermente inclinati verso l''interno a causa della forma del bilanciere. Con le braccia posizionate contro l''imbottitura della panca e il petto appoggiato ad essa, tieni il bilanciere all''altezza delle spalle. Questa è la posizione di partenza. Inspirando, abbassa lentamente il bilanciere finché le braccia non sono estese e i bicipiti completamente allungati. Espirando, usa i bicipiti per sollevare il peso finché i bicipiti non sono completamente contratti e il bilanciere all''altezza delle spalle. Contrai intensamente i bicipiti e mantieni la posizione per un secondo. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Preacher Curl';

UPDATE public.exercise_library 
SET name_it = 'Preacher Hammer Dumbbell Curl', description_it = 'Posiziona la parte superiore delle braccia sopra la panca Scott tenendo un manubrio in ciascuna mano con i palmi rivolti l''uno verso l''altro (presa neutra). Inspirando, abbassa lentamente i manubri finché le braccia non sono estese e i bicipiti completamente allungati. Espirando, usa i bicipiti per sollevare il peso finché i bicipiti non sono completamente contratti e i manubri all''altezza delle spalle. Contrai intensamente i bicipiti per un secondo nella posizione di massima contrazione e ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Preacher Hammer Dumbbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Press Sit-Up', description_it = 'Per iniziare, sdraiati su una panca con un bilanciere appoggiato sul petto. Posiziona le gambe in modo che siano bloccate sull''estensione della panca per addominali. Questa è la posizione di partenza. Inspirando, contrai addominali e glutei. Contemporaneamente, solleva il busto come in un normale sit-up ed esegui una distensione del bilanciere sopra la testa espirando. Consiglio: usa le braccia per spingere il bilanciere verso l''alto durante l''esercizio, mantenendo il focus sulla muscolatura addominale. Riporta il busto alla posizione di partenza mentre abbassi il bilanciere verso il torace. Ricordati di inspirare durante la fase di discesa. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Press Sit-Up';

UPDATE public.exercise_library 
SET name_it = 'Prone Manual Hamstring', description_it = 'Per questo esercizio è necessario un partner. Sdraiati a pancia in giù con le gambe dritte. L''assistente posizionerà la mano sul tuo tallone. Per iniziare, fletti il ginocchio per sollevare la gamba. Il tuo partner deve fornire resistenza, iniziando con una pressione leggera e aumentandola man mano che il movimento viene completato. Comunica con il partner per monitorare il livello di resistenza appropriato. Fai una pausa nella parte alta del movimento e torna alla posizione di partenza mentre il partner continua a fornire resistenza nel verso opposto.' 
WHERE name = 'Prone Manual Hamstring';

UPDATE public.exercise_library 
SET name_it = 'Prowler Sprint', description_it = 'Posiziona la slitta su una superficie adatta, caricandola con un peso adeguato. La slitta deve offrire una resistenza sufficiente a richiedere impegno, ma non essere così pesante da rallentarti eccessivamente. Puoi utilizzare le impugnature verticali o quelle basse per questo esercizio. Appoggia le mani sulle impugnature con le braccia distese, spingendo contro l''attrezzo. Mantenendo una postura corretta, spingi contro il terreno con passi brevi e alternati. Muoviti il più velocemente possibile per una breve distanza.' 
WHERE name = 'Prowler Sprint';

UPDATE public.exercise_library 
SET name_it = 'Pull Through', description_it = 'Inizia in piedi a breve distanza da una carrucola bassa con una corda o un''impugnatura attaccata. Rivolgi le spalle alla macchina, posizionandoti a cavalcioni del cavo con i piedi ben distanziati. Inizia il movimento allungandoti tra le gambe il più possibile, piegandoti sulle anche. Mantieni le ginocchia leggermente flesse. Tenendo le braccia dritte, estendi le anche per tornare in posizione eretta. Evita di sollevare il carico usando le spalle; tutto il movimento deve originare dalle anche.' 
WHERE name = 'Pull Through';

UPDATE public.exercise_library 
SET name_it = 'Pullups (Trazioni alla sbarra)', description_it = 'Afferra la sbarra per le trazioni con i palmi rivolti in avanti usando la presa prescritta. Nota sulle prese: per una presa larga, le mani devono essere a una distanza maggiore della larghezza delle spalle. Per una presa media, la distanza deve essere pari alla larghezza delle spalle e, per una presa stretta, inferiore ad essa. Con entrambe le braccia distese davanti a te che tengono la sbarra, porta il busto leggermente all''indietro (circa 30 gradi) inarcando la zona lombare e spingendo il petto in fuori. Questa è la posizione di partenza. Solleva il busto fino a far toccare la sbarra alla parte superiore del petto, portando spalle e braccia verso il basso e indietro. Espira durante questa fase. Consiglio: concentrati sulla contrazione dei muscoli dorsali una volta raggiunta la posizione di massima contrazione. La parte superiore del busto deve rimanere ferma mentre si sposta nello spazio e solo le braccia devono muoversi. Gli avambracci devono solo sostenere la presa sulla sbarra. Dopo un secondo di contrazione, inizia a inspirare e abbassa lentamente il busto alla posizione iniziale finché le braccia non sono completamente distese e i dorsali completamente allungati. Ripeti il movimento per il numero di ripetizioni prescritto.' 
WHERE name = 'Pullups';

UPDATE public.exercise_library 
SET name_it = 'Push-Up a presa larga', description_it = 'Mettiti in posizione di plank con le mani ben distanziate tra loro, sostenendo il corpo sulle punte dei piedi e sulle mani. Le braccia devono essere tese e il corpo in linea retta. Non lasciare che i fianchi si abbassino; questa sarà la posizione di partenza. Per iniziare, fletti i gomiti abbassando il petto verso il pavimento mentre inspiri. Utilizzando i muscoli pettorali, spingi la parte superiore del corpo verso l''alto fino alla posizione iniziale distendendo i gomiti. Espira durante questa fase. Dopo una breve pausa nella posizione di massima contrazione, ripeti il movimento per il numero di ripetizioni prescritto.' 
WHERE name = 'Push-Up Wide';

UPDATE public.exercise_library 
SET name_it = 'Push-Up - Posizione stretta per tricipiti', description_it = 'Sdraiati a terra a faccia in giù e posiziona le mani a una larghezza inferiore a quella delle spalle. Assicurati di mantenere il busto sollevato con le braccia tese. Abbassati finché il petto non sfiora quasi il pavimento mentre inspiri. Utilizzando i tricipiti e parte dei muscoli pettorali, spingi il busto verso l''alto tornando alla posizione di partenza e contrai i pettorali. Espira durante questa fase. Dopo un secondo di pausa nella posizione di massima contrazione, ripeti il movimento per il numero di ripetizioni prescritto.' 
WHERE name = 'Push-Ups - Close Triceps Position';

UPDATE public.exercise_library 
SET name_it = 'Push-Up con piedi rialzati', description_it = 'Sdraiati a terra a faccia in giù e posiziona le mani a circa 90 cm di distanza l''una dall''altra, mantenendo il busto sollevato con le braccia tese. Appoggia le punte dei piedi su una panca piana; questo solleverà il corpo. Nota: maggiore è l''altezza della panca, maggiore sarà la resistenza dell''esercizio. Abbassati finché il petto non sfiora quasi il pavimento mentre inspiri. Utilizzando i pettorali, spingi il busto verso l''alto tornando alla posizione di partenza e contrai i pettorali. Espira durante questa fase. Dopo un secondo di pausa nella posizione di massima contrazione, ripeti il movimento per il numero di ripetizioni prescritto.' 
WHERE name = 'Push-Ups With Feet Elevated';

UPDATE public.exercise_library 
SET name_it = 'Push-Up con piedi su fitball', description_it = 'Sdraiati a terra a faccia in giù e posiziona le mani a circa 90 cm di distanza l''una dall''altra, mantenendo il busto sollevato con le braccia tese. Appoggia le punte dei piedi sopra una fitball per sollevare il corpo. Abbassati finché il petto non sfiora quasi il pavimento mentre inspiri. Utilizzando i pettorali, spingi il busto verso l''alto tornando alla posizione di partenza e contrai i pettorali. Espira durante questa fase. Dopo un secondo di pausa nella posizione di massima contrazione, ripeti il movimento per il numero di ripetizioni prescritto.' 
WHERE name = 'Push-Ups With Feet On An Exercise Ball';

UPDATE public.exercise_library 
SET name_it = 'Push Press', description_it = 'In posizione eretta con il bilanciere appoggiato sulle spalle, esegui un leggero ''dip'' (piegamento delle ginocchia) senza spostare i fianchi all''indietro. Spingi con forza attraverso i talloni per generare velocità e spinta, estendendo contemporaneamente le braccia per portare il bilanciere sopra la testa. Torna alla posizione di partenza assorbendo l''impatto con le gambe.' 
WHERE name = 'Push Press';

UPDATE public.exercise_library 
SET name_it = 'Push Press - Dietro la nuca', description_it = 'In posizione eretta con il bilanciere posizionato sulla parte posteriore delle spalle, inizia con il ''dip''. Con i piedi allineati sotto i fianchi, fletti le ginocchia senza spostare i fianchi all''indietro. Scendi solo leggermente e inverte la direzione con la massima potenza. Spingi attraverso i talloni per generare velocità e forza, muovendo il bilanciere lungo una traiettoria verticale. Sfrutta lo slancio generato per completare la spinta sopra la testa estendendo le braccia. Torna alla posizione di partenza usando le gambe per assorbire l''impatto.' 
WHERE name = 'Push Press - Behind the Neck';

UPDATE public.exercise_library 
SET name_it = 'Push-Up con rotazione in side plank', description_it = 'Assumi la posizione di push-up sulle punte dei piedi con le mani appena oltre la larghezza delle spalle. Esegui un push-up flettendo i gomiti e mantenendo il corpo dritto. Risalendo, sposta il peso sul lato sinistro del corpo, ruotando lateralmente e portando il braccio destro verso il soffitto in posizione di side plank. Riporta il braccio a terra per un altro push-up e ruota poi verso l''altro lato. Ripeti la serie alternando i lati per 10 o più ripetizioni.' 
WHERE name = 'Push Up to Side Plank';

UPDATE public.exercise_library 
SET name_it = 'Push-up (Piegamenti)', description_it = 'Sdraiati a terra a faccia in giù, posiziona le mani a circa 90 cm di distanza e tieni il busto sollevato a braccia tese. Abbassati finché il petto non sfiora quasi il pavimento mentre inspiri. Espira e spingi il busto verso l''alto fino alla posizione di partenza, contraendo i pettorali. Dopo una breve pausa nella posizione di massima contrazione, inizia nuovamente la discesa per il numero di ripetizioni desiderato.' 
WHERE name = 'Pushups';

UPDATE public.exercise_library 
SET name_it = 'Push-up (Posizioni mani larghe e strette)', description_it = 'Sdraiati a terra a faccia in giù con il corpo dritto, le punte dei piedi a terra e le mani posizionate più larghe delle spalle (per la presa larga) o più strette (per la presa stretta). Mantieni il busto sollevato a braccia tese. Abbassati finché il petto non sfiora quasi il pavimento mentre inspiri. Utilizzando i pettorali, spingi il busto verso l''alto tornando alla posizione di partenza e contrai i pettorali. Espira durante questa fase. Dopo un secondo di pausa nella posizione di massima contrazione, ripeti il movimento per il numero di ripetizioni prescritto.' 
WHERE name = 'Pushups (Close and Wide Hand Positions)';

UPDATE public.exercise_library 
SET name_it = 'Pyramid (esercizio con palla)', description_it = 'Inizia facendo rotolare il busto in avanti sopra la palla finché i fianchi non poggiano su di essa, diventando il punto più alto del corpo. Appoggia mani e piedi a terra. Braccia e gambe possono essere leggermente flesse o dritte, a seconda delle dimensioni della palla, della flessibilità e della lunghezza degli arti. Questo esercizio aiuta anche a sviluppare la forza stabilizzatrice del busto e delle spalle.' 
WHERE name = 'Pyramid';

UPDATE public.exercise_library 
SET name_it = 'Stretching dei quadricipiti', description_it = 'Sdraiati su un fianco. Avvolgi una cinghia, una corda o una banda elastica attorno al piede superiore. Fletti il ginocchio ed estendi l''anca, cercando di toccare i glutei con il tallone mentre tieni la cinghia con le mani. Questa sarà la posizione di partenza. Tenendo la cinghia sopra la spalla o sopra la testa, tira delicatamente per aumentare lo stretching del quadricipite. Mantieni per 10-20 secondi, quindi cambia lato.' 
WHERE name = 'Quad Stretch';

UPDATE public.exercise_library 
SET name_it = 'SMR dei quadricipiti', description_it = 'Sdraiati a pancia in giù sul pavimento con il peso sostenuto dalle mani o dagli avambracci. Posiziona un foam roller sotto una gamba, a livello del quadricipite, mantenendo il piede sollevato da terra. Assicurati di rilassare la gamba il più possibile. Questa sarà la posizione di partenza. Spostando quanto più peso possibile sulla gamba da trattare, rotola sul foam roller dalla zona sopra il ginocchio fino a sotto l''anca, mantenendo la pressione sui punti di tensione per 10-30 secondi. Cambia lato.' 
WHERE name = 'Quadriceps-SMR';

UPDATE public.exercise_library 
SET name_it = 'Quick Leap', description_it = 'Per questo esercizio avrai bisogno di un box (piattaforma). Inizia di fronte al box, in piedi a 30-60 cm dal bordo. Utilizzando la spinta delle anche, salta sul box atterrando su entrambe le gambe. Assicurati di atterrare con le gambe flesse e i piedi piatti. Immediatamente dopo l''atterraggio, estendi completamente tutto il corpo e slancia le braccia verso l''alto per esplodere dal box. Usa le gambe per ammortizzare l''impatto dell''atterraggio.' 
WHERE name = 'Quick Leap';

UPDATE public.exercise_library 
SET name_it = 'Rack Delivery', description_it = 'Questo esercizio insegna a portare il bilanciere nella posizione di ''rack'' sulle spalle. Inizia tenendo il bilanciere nella posizione ''scarecrow'' (spaventapasseri), con la parte superiore delle braccia parallela al pavimento e gli avambracci rivolti verso il basso. Usa una ''hook grip'', con le dita che avvolgono i pollici. Inizia ruotando i gomiti attorno al bilanciere, portandolo sulle spalle. Man mano che i gomiti avanzano, rilassa la presa. Le spalle devono essere in protrazione, creando un supporto per il bilanciere, che deve sfiorare la gola. È importante che il bilanciere rimanga sempre vicino al corpo, poiché con carichi maggiori qualsiasi distanza risulterebbe in un urto indesiderato. Quando il movimento diventa più fluido, è possibile aumentare velocità e carico.' 
WHERE name = 'Rack Delivery';

UPDATE public.exercise_library 
SET name_it = 'Rack Pull con bande elastiche', description_it = 'Posizionati in un power rack con il bilanciere sui perni. I perni devono essere impostati all''altezza desiderata: appena sotto le ginocchia, appena sopra, o a metà coscia. Attacca le bande alla base del rack o fissale con dei manubri, quindi aggancia l''altra estremità al bilanciere. Potrebbe essere necessario avvolgere le bande per creare tensione. Posizionati contro il bilanciere in una corretta posizione di stacco (deadlift). I piedi devono essere sotto le anche, la presa alla larghezza delle spalle, la schiena inarcata e le anche spinte indietro per coinvolgere i femorali. Poiché il peso è solitamente elevato, puoi usare una presa mista, una ''hook grip'' o delle cinghie. Con lo sguardo in avanti, estendi anche e ginocchia, tirando il peso verso l''alto fino al bloccaggio. Assicurati di tirare le spalle indietro completando il movimento. Riporta il peso sui perni e ripeti.' 
WHERE name = 'Rack Pull with Bands';

UPDATE public.exercise_library 
SET name_it = 'Rack Pulls', description_it = 'Posizionati in un power rack con il bilanciere sui perni. I perni devono essere impostati all''altezza desiderata: appena sotto le ginocchia, appena sopra, o a metà coscia. Posizionati contro il bilanciere in una corretta posizione di stacco (deadlift). I piedi devono essere sotto le anche, la presa alla larghezza delle spalle, la schiena inarcata e le anche spinte indietro per coinvolgere i femorali. Poiché il peso è solitamente elevato, puoi usare una presa mista, una ''hook grip'' o delle cinghie. Con lo sguardo in avanti, estendi anche e ginocchia, tirando il peso verso l''alto fino al bloccaggio. Assicurati di tirare le spalle indietro completando il movimento. Riporta il peso sui perni e ripeti.' 
WHERE name = 'Rack Pulls';

UPDATE public.exercise_library 
SET name_it = 'Rear Leg Raises', description_it = 'Mettiti in quadrupedia su un tappetino da fitness. Lo sguardo deve essere rivolto in avanti e le ginocchia devono formare un angolo di 90 gradi tra femorali e polpacci. Questa è la posizione di partenza. Estendi una gamba verso l''alto e all''indietro. Sia il ginocchio che l''anca devono estendersi. Esegui 5-10 ripetizioni, quindi cambia lato.' 
WHERE name = 'Rear Leg Raises';

UPDATE public.exercise_library 
SET name_it = 'Cyclette orizzontale (Recumbent Bike)', description_it = 'Per iniziare, siediti sulla cyclette e regola il sedile in base alla tua altezza. Seleziona l''opzione desiderata dal menu; potrebbe essere necessario iniziare a pedalare per accenderla. Puoi usare l''impostazione manuale o selezionare un programma. Solitamente, puoi inserire età e peso per stimare le calorie bruciate. Il livello di resistenza può essere modificato durante l''allenamento. Le maniglie possono essere utilizzate per monitorare la frequenza cardiaca e mantenere l''intensità adeguata. Le cyclette orizzontali offrono praticità, benefici cardiovascolari e un impatto inferiore rispetto ad altre attività. Una persona di 68 kg brucerà circa 230 calorie pedalando a un ritmo moderato per 30 minuti, rispetto alle 450 o più calorie bruciate correndo.' 
WHERE name = 'Recumbent Bike';

UPDATE public.exercise_library 
SET name_it = 'Return Push from Stance', description_it = 'Per questo esercizio avrai bisogno di un partner. Inizia in una posizione atletica a 2 o 3 punti. Al segnale, mettiti in posizione per ricevere il passaggio dal tuo partner. Prendi la palla medica con entrambe le mani e rilanciala immediatamente al partner. Puoi modificare questo esercizio variando i percorsi di corsa.' 
WHERE name = 'Return Push from Stance';

UPDATE public.exercise_library 
SET name_it = 'Reverse Band Bench Press', description_it = 'Posiziona una panca all''interno di un power rack, con il bilanciere all''altezza corretta. Inizia ancorando le bande ai pioli o alla parte superiore del rack, assicurandoti di essere posizionato correttamente sotto di esse. Collega l''altra estremità al bilanciere. Sdraiati sulla panca, metti i piedi sotto di te e inarca la schiena. Usando il bilanciere per sostenere il peso, solleva le spalle dalla panca e falle rientrare in retrazione, stringendo le scapole. Usa i piedi per spingere i trapezi contro la panca. Mantieni questa posizione corporea contratta durante tutto il movimento. Indipendentemente dalla larghezza della presa, questa dovrebbe coprire l''anello sul bilanciere. Estrai il bilanciere dal rack senza portare le spalle in protrazione. Concentrati sullo stringere la sbarra cercando di ''tirarla verso l''esterno''. Abbassa il bilanciere verso la parte bassa del petto o la parte alta dello stomaco. Il bilanciere, il polso e il gomito devono rimanere sempre allineati. Fai una pausa quando il bilanciere tocca il busto, quindi spingilo verso l''alto con la massima forza possibile. I gomiti devono rimanere stretti fino al bloccaggio finale.' 
WHERE name = 'Reverse Band Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Reverse Band Box Squat', description_it = 'Inizia all''interno di un power rack con un box di altezza adeguata posizionato dietro di te. Fissa le bande elastiche sui pioli o alla parte superiore del rack, assicurandoti che si trovino direttamente sopra il bilanciere durante lo squat. Aggancia l''altra estremità alla barra.
Posizionati sotto il bilanciere e appoggialo sulla parte alta della schiena. Avvicina le scapole e ruota i gomiti in avanti, cercando di flettere il bilanciere sulle spalle. Stacca il bilanciere dal rack, crea un arco teso nella parte bassa della schiena e fai un passo indietro per posizionarti. Tieni i piedi più larghi per enfatizzare il lavoro su schiena, glutei, adduttori e femorali, o più stretti per uno sviluppo maggiore dei quadricipiti. Mantieni lo sguardo rivolto in avanti.
Con schiena, spalle e core in tensione, spingi le ginocchia e i glutei verso l''esterno iniziando la discesa. Siediti all''indietro con le anche finché non sei seduto sul box. Idealmente, le tibie dovrebbero essere perpendicolari al suolo. Fai una pausa quando raggiungi il box e rilassa i flessori dell''anca. Non rimbalzare mai sul box.
Mantenendo il peso sui talloni e spingendo piedi e ginocchia verso l''esterno, spingi verso l''alto dal box guidando il movimento con la testa. Continua la risalita mantenendo la tensione dalla testa ai piedi. Riponi il bilanciere sul rack con attenzione.' 
WHERE name = 'Reverse Band Box Squat';

UPDATE public.exercise_library 
SET name_it = 'Reverse Band Deadlift', description_it = 'Posiziona il bilanciere in un power rack. Aggancia le bande alla parte superiore del rack, utilizzando i pioli o la struttura stessa, e fissa l''altra estremità al bilanciere.
Avvicinati alla barra in modo che sia centrata sopra i piedi, posizionati a una larghezza pari a quella delle anche. Fletti le anche per afferrare il bilanciere a larghezza spalle, lasciando che le scapole si protraggano. Solitamente si utilizza una presa prona o una presa mista (supina/prona) per i carichi più pesanti.
Con i piedi e la presa ben impostati, fai un respiro profondo, abbassa le anche e piega le ginocchia finché le tibie non toccano il bilanciere. Guarda in avanti, tieni il petto alto e la schiena arcuata, quindi inizia a spingere sui talloni per sollevare il peso.
Dopo che il bilanciere ha superato le ginocchia, tira energicamente la barra verso di te, avvicinando le scapole mentre spingi le anche in avanti verso il bilanciere.
Abbassa il bilanciere flettendo le anche e guidandolo verso il pavimento.' 
WHERE name = 'Reverse Band Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Reverse Band Power Squat', description_it = 'Inizia in un power rack con i perni e il bilanciere all''altezza appropriata. Dopo aver caricato il bilanciere, fissa le bande alla parte superiore del rack utilizzando i pioli o il telaio stesso. Aggancia l''altra estremità delle bande al bilanciere.
Posizionati sotto la barra e appoggiala sulla parte posteriore delle spalle. Avvicina le scapole e ruota i gomiti in avanti, cercando di flettere la barra sulle spalle. Stacca la barra dal rack, crea un arco teso nella parte bassa della schiena e torna in posizione. Tieni i piedi larghi per enfatizzare il lavoro su schiena, glutei, adduttori e femorali.
Mantieni lo sguardo in avanti. Con schiena, spalle e core tesi, spingi ginocchia e glutei verso l''esterno e inizia la discesa. Siediti all''indietro con le anche il più possibile. Idealmente, le tibie dovrebbero essere perpendicolari al suolo. Una posizione più bassa del bilanciere richiede una maggiore inclinazione del busto per mantenere la barra sopra i talloni. Continua fino a superare il parallelo, definito come il punto in cui la piega dell''anca è in linea con la parte superiore del ginocchio.
Mantenendo il peso sui talloni e spingendo piedi e ginocchia verso l''esterno, spingi verso l''alto guidando il movimento con la testa. Continua la salita mantenendo la tensione da capo a piedi, fino a tornare nella posizione iniziale.' 
WHERE name = 'Reverse Band Power Squat';

UPDATE public.exercise_library 
SET name_it = 'Reverse Band Sumo Deadlift', description_it = 'Inizia con un bilanciere caricato a terra all''interno di un power rack. Fissa le bande alla parte superiore del rack utilizzando i pioli o la struttura stessa. Aggancia l''altra estremità al bilanciere.
Avvicinati alla barra in modo che intersechi la metà dei piedi. I piedi devono essere posizionati molto larghi, vicino ai dischi. Fletti le anche per afferrare la barra. Le braccia devono essere direttamente sotto le spalle, all''interno delle gambe; puoi usare una presa prona, mista o hook grip. Rilassa le spalle, il che di fatto allunga le braccia.
Fai un respiro, poi abbassa le anche, guardando in avanti con il petto alto. Spingi contro il pavimento, allargando i piedi, con il peso distribuito sulla parte posteriore dei piedi. Estendi anche e ginocchia.
Quando il bilanciere supera le ginocchia, inclinati leggermente all''indietro, spingi le anche verso il bilanciere e contrai le scapole.
Riporta il peso a terra flettendo le anche e controllando il carico durante la discesa.' 
WHERE name = 'Reverse Band Sumo Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Reverse Barbell Curl', description_it = 'In piedi con il busto eretto, impugna un bilanciere a larghezza spalle con i gomiti vicini al corpo. I palmi delle mani devono essere rivolti verso il basso (presa prona). Questa è la posizione di partenza.
Mantenendo le braccia ferme, solleva il peso contraendo i bicipiti ed espirando. Solo gli avambracci devono muoversi. Continua il movimento finché i bicipiti sono completamente contratti e il bilanciere è all''altezza delle spalle. Mantieni la posizione di contrazione per un secondo strizzando il muscolo.
Inizia lentamente a riportare il bilanciere nella posizione iniziale mentre inspiri.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Reverse Barbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Reverse Barbell Preacher Curls', description_it = 'Afferra un bilanciere EZ con una presa a larghezza spalle e palmi rivolti verso il basso (prona).
Posiziona la parte superiore delle braccia sopra la panca Scott (preacher bench) con le braccia estese. Questa è la posizione di partenza.
Espirando, usa i bicipiti per sollevare il peso finché i bicipiti sono completamente contratti e il bilanciere è all''altezza delle spalle. Strizza i bicipiti con forza per un secondo nella posizione di massima contrazione.
Inspirando, abbassa lentamente il bilanciere finché le braccia sono distese e i bicipiti completamente allungati.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Reverse Barbell Preacher Curls';

UPDATE public.exercise_library 
SET name_it = 'Reverse Cable Curl', description_it = 'In piedi con il busto eretto, impugna una barra collegata a un cavo basso con una presa prona (palmi verso il basso) a larghezza spalle. Tieni i gomiti vicini al busto. Questa è la posizione di partenza.
Mantenendo le braccia ferme, solleva il peso contraendo i bicipiti ed espirando. Solo gli avambracci devono muoversi. Continua il movimento finché i bicipiti sono completamente contratti e la barra è all''altezza delle spalle. Mantieni la posizione di contrazione per un secondo strizzando il muscolo.
Inizia lentamente a riportare la barra nella posizione iniziale mentre inspiri.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Reverse Cable Curl';

UPDATE public.exercise_library 
SET name_it = 'Reverse Crunch', description_it = 'Sdraiati sul pavimento con le gambe completamente distese e le braccia lungo i fianchi con i palmi a terra. Le braccia devono rimanere ferme per tutta la durata dell''esercizio.
Porta le gambe verso l''alto in modo che le cosce siano perpendicolari al pavimento, con i piedi uniti e paralleli al suolo. Questa è la posizione di partenza.
Mentre inspiri, muovi le gambe verso il busto ruotando il bacino all''indietro e sollevando le anche dal pavimento. Alla fine del movimento, le ginocchia dovrebbero toccare il petto.
Mantieni la contrazione per un secondo e torna nella posizione iniziale espirando.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Reverse Crunch';

UPDATE public.exercise_library 
SET name_it = 'Reverse Flyes', description_it = 'Per iniziare, sdraiati su una panca inclinata con il petto e lo stomaco premuti contro lo schienale. Impugna un manubrio in ogni mano con i palmi rivolti l''uno verso l''altro (presa neutra).
Estendi le braccia davanti a te in modo che siano perpendicolari all''inclinazione della panca. Le gambe devono rimanere ferme facendo pressione con l''avampiede. Questa è la posizione di partenza.
Mantenendo una leggera flessione dei gomiti, sposta i pesi verso l''esterno e lontano l''uno dall''altro (lateralmente) con un movimento ad arco, espirando. Consiglio: cerca di avvicinare le scapole tra loro per ottenere i migliori risultati.
Le braccia devono essere sollevate finché non sono parallele al pavimento.
Percepisci la contrazione e abbassa lentamente i pesi nella posizione di partenza mentre inspiri.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Reverse Flyes';

UPDATE public.exercise_library 
SET name_it = 'Reverse Flyes With External Rotation', description_it = 'Per iniziare, sdraiati su una panca inclinata a 30 gradi con il petto e lo stomaco premuti contro lo schienale.
Impugna un manubrio in ogni mano con i palmi rivolti verso il pavimento. Le braccia devono essere davanti a te, perpendicolari all''inclinazione della panca. Consiglio: i gomiti devono avere una leggera flessione. Le gambe devono rimanere ferme facendo pressione con l''avampiede (i talloni non devono toccare il pavimento). Questa è la posizione di partenza.
Mantenendo una leggera flessione dei gomiti, sposta i pesi verso l''esterno con un movimento ad arco espirando.
Durante il sollevamento, ruota esternamente i polsi di 90 gradi, passando da una presa prona (palmi verso il basso) a una presa neutra (palmi rivolti l''uno verso l''altro). Consiglio: cerca di avvicinare le scapole tra loro per massimizzare i risultati.
Le braccia devono essere sollevate fino all''altezza della testa.
Percepisci la contrazione e abbassa lentamente i pesi nella posizione di partenza mentre inspiri.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Reverse Flyes With External Rotation';

UPDATE public.exercise_library 
SET name_it = 'Rocket Jump', description_it = 'Inizia in una posizione rilassata con i piedi alla larghezza delle spalle e le braccia vicine al corpo. Per iniziare il movimento, esegui mezzo squat ed esplodi verso l''alto il più in alto possibile. Estendi completamente tutto il corpo, allungando le braccia sopra la testa il più possibile. Durante l''atterraggio, ammortizza l''impatto attraverso le gambe.' 
WHERE name = 'Rocket Jump';

UPDATE public.exercise_library 
SET name_it = 'Rocking Standing Calf Raise', description_it = 'Per sicurezza, questo esercizio va eseguito all''interno di un rack per squat. Regola il bilanciere all''altezza giusta, posizionati sotto di esso e caricalo sulla parte posteriore delle spalle (appena sotto il collo). Afferra il bilanciere con entrambe le mani e sollevalo dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto. Allontanati dal rack e posiziona le gambe a una larghezza media, con le punte dei piedi leggermente rivolte verso l''esterno. Tieni sempre la testa alta, la schiena dritta e le ginocchia leggermente flesse, mai bloccate. Questa è la posizione di partenza. Espira e solleva i talloni estendendo le caviglie il più possibile contraendo i polpacci. Mantieni le ginocchia ferme. Mantieni la posizione di contrazione per un secondo, poi torna lentamente alla posizione iniziale inspirando, fino ad avvertire l''allungamento dei polpacci. Successivamente, espira e solleva le punte dei piedi contraendo i muscoli tibiali. Mantieni per un secondo e torna alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Rocking Standing Calf Raise';

UPDATE public.exercise_library 
SET name_it = 'Rocky Pull-Ups/Pulldowns', description_it = 'Afferra la sbarra per le trazioni con i palmi rivolti in avanti e una presa larga. Con le braccia tese, inclina il busto all''indietro di circa 30 gradi, inarcando leggermente la parte bassa della schiena e spingendo il petto in fuori. Questa è la posizione di partenza. Tira il busto verso l''alto finché la sbarra non tocca la parte superiore del petto, spingendo le spalle e la parte superiore delle braccia verso il basso e all''indietro. Espira durante questa fase. Consiglio: concentrati sulla contrazione dei muscoli della schiena nella parte alta del movimento. Il busto deve rimanere fermo nello spazio, solo le braccia devono muoversi. Dopo un secondo di contrazione, inspira e torna lentamente alla posizione iniziale. Successivamente, ripeti il movimento mantenendo il busto dritto e portando la sbarra dietro il collo invece che al petto. Consiglio: sposta leggermente la testa in avanti per facilitare l''esecuzione. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Rocky Pull-Ups/Pulldowns';

UPDATE public.exercise_library 
SET name_it = 'Stacco Rumeno (Romanian Deadlift)', description_it = 'Posiziona un bilanciere a terra davanti a te e afferralo con una presa prona (palmi verso il basso) leggermente più larga delle spalle. Consiglio: in base al carico, potresti aver bisogno di fasce per i polsi o di una piattaforma rialzata per migliorare il range di movimento. Fletti leggermente le ginocchia mantenendo le tibie verticali, le anche spinte all''indietro e la schiena dritta. Questa è la posizione di partenza. Mantenendo schiena e braccia completamente tese, usa le anche per sollevare il bilanciere espirando. Consiglio: il movimento deve essere fluido e controllato. Una volta in piedi, abbassa il bilanciere spingendo le anche indietro e flettendo solo leggermente le ginocchia, diversamente dallo squat. Consiglio: fai un respiro profondo all''inizio, trattieni il fiato durante la discesa ed espira al completamento del movimento. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Romanian Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Stacco Rumeno da Deficit', description_it = 'Inizia in piedi tenendo un bilanciere a braccia tese davanti a te. Puoi stare su una piattaforma rialzata per aumentare il range di movimento. Inizia flettendo leggermente le ginocchia, quindi fletti le anche spingendo il sedere il più indietro possibile, abbassando il busto fin dove la flessibilità lo consente. La schiena deve rimanere in totale estensione e il bilanciere deve restare a contatto con le gambe. Eseguito correttamente, si deve avvertire una forte tensione nei muscoli femorali. Inverti il movimento per tornare alla posizione di partenza.' 
WHERE name = 'Romanian Deadlift from Deficit';

UPDATE public.exercise_library 
SET name_it = 'Arrampicata su corda (Rope Climb)', description_it = 'Afferra la corda con entrambe le mani sopra la testa. Tira la corda verso il basso ed effettua un piccolo salto. Avvolgi la corda attorno a una gamba, usando i piedi per bloccarla. Allunga le braccia il più in alto possibile, stringendo bene la corda. Rilascia la presa dei piedi mentre ti sollevi con le braccia, portando le ginocchia al petto. Blocca nuovamente la corda con i piedi e alzati per afferrare la corda più in alto. Continua fino a raggiungere la cima. Per scendere, allenta la presa dei piedi sulla corda e scivola verso il basso usando un movimento alternato delle mani.' 
WHERE name = 'Rope Climb';

UPDATE public.exercise_library 
SET name_it = 'Rope Crunch', description_it = 'Inginocchiati a 30-60 cm da una macchina a cavi con una corda attaccata. Dopo aver scelto il peso, afferra la corda con entrambe le mani sopra la testa. Il busto deve essere dritto nella posizione iniziale. Per iniziare, fletti la colonna vertebrale cercando di portare la gabbia toracica verso le gambe mentre tiri il cavo verso il basso. Fermati alla fine del movimento e torna lentamente alla posizione iniziale. L''esercizio può essere eseguito con torsioni o lateralmente per colpire gli obliqui.' 
WHERE name = 'Rope Crunch';

UPDATE public.exercise_library 
SET name_it = 'Salto con la corda', description_it = 'Afferra le estremità della corda con le mani e posiziona la corda dietro di te a terra. Solleva le braccia e fai girare la corda sopra la testa portandola davanti a te; quando tocca terra, saltala. Trova un ritmo costante che riesci a mantenere. È possibile utilizzare diverse velocità e tecniche per variare l''allenamento. Il salto con la corda è stimolante, sfida la coordinazione e richiede molta energia.' 
WHERE name = 'Rope Jumping';

UPDATE public.exercise_library 
SET name_it = 'Pull-down a braccia tese con corda', description_it = 'Attacca una corda a una carrucola alta e seleziona il peso. Stai a circa un metro di distanza dalla carrucola con i piedi sfalsati e afferra la corda con entrambe le mani. Inclinati in avanti dai fianchi, mantenendo la schiena dritta e le braccia tese in avanti. Questa è la posizione di partenza. Mantenendo le braccia tese, estendi la spalla per tirare la corda verso le cosce. Fermati alla fine del movimento, contraendo i dorsali. Torna alla posizione di partenza senza lasciare che il peso si appoggi completamente sulla pila.' 
WHERE name = 'Rope Straight-Arm Pulldown';

UPDATE public.exercise_library 
SET name_it = 'Circonduzione delle spalle (Round the World)', description_it = 'Stai in piedi con le gambe unite, tenendo un bastone o una sbarra. Afferra il bastone dietro le anche con una presa più larga delle spalle. I palmi devono essere rivolti verso il basso e i pollici verso l''esterno. Solleva lentamente le braccia sopra la testa facendole passare dietro la schiena. Non forzare se senti resistenza nel sollevamento.' 
WHERE name = 'Round The World Shoulder Stretch';

UPDATE public.exercise_library 
SET name_it = 'Vogatore', description_it = 'Per iniziare, siediti sul vogatore. Assicurati che i talloni poggino comodamente contro la base dei pedali e che le cinghie siano ben strette. Seleziona il programma desiderato, se previsto. Siediti dritto e fletti il busto in avanti partendo dalle anche. Il movimento del vogatore si divide in tre fasi. La prima è la fase di spinta in avanti: le ginocchia sono piegate verso il petto e la parte superiore del corpo è leggermente inclinata in avanti, mantenendo una postura corretta. Successivamente, spingi sui pedali ed estendi le gambe portando le mani verso la parte superiore dell''addome, contraendo le scapole all''indietro. Per evitare sforzi eccessivi alla schiena, utilizza principalmente i muscoli delle gambe e delle anche. La fase di recupero consiste semplicemente nel distendere le braccia, piegare le ginocchia e riportare il corpo in avanti per ricominciare la prima fase.' 
WHERE name = 'Rowing, Stationary';

UPDATE public.exercise_library 
SET name_it = 'Runner''s Stretch', description_it = 'È più semplice eseguire questo stretching partendo in piedi: porta una gamba all''indietro e abbassa lentamente il busto verso il pavimento. Mantieni il tallone della gamba anteriore ben saldo a terra (se si solleva, sposta l''altra gamba più indietro). Appoggia le mani ai lati della gamba anteriore. Per intensificare l''allungamento, spingi il bacino verso l''alto e poi abbassalo gradualmente verso il pavimento. In questo modo allungherai il flessore dell''anca della gamba posteriore e i muscoli ischiocrurali e i glutei della gamba anteriore.' 
WHERE name = 'Runner''s Stretch';

UPDATE public.exercise_library 
SET name_it = 'Corsa sul tapis roulant', description_it = 'Per iniziare, sali sul tapis roulant e seleziona l''opzione desiderata dal menu. La maggior parte dei tapis roulant dispone di un''impostazione manuale o di programmi preimpostati. Solitamente, inserendo età e peso, è possibile stimare le calorie bruciate durante l''esercizio. L''inclinazione può essere regolata per modificare l''intensità dell''allenamento. I tapis roulant offrono comodità, benefici cardiovascolari e generalmente un impatto inferiore rispetto alla corsa all''aperto. Una persona di circa 68 kg brucia oltre 450 calorie correndo a 13 km/h per 30 minuti. Mantieni una postura corretta durante la corsa e utilizza le maniglie solo quando necessario, ad esempio durante la discesa o per controllare la frequenza cardiaca.' 
WHERE name = 'Running, Treadmill';

UPDATE public.exercise_library 
SET name_it = 'Russian Twist', description_it = 'Sdraiati a terra posizionando i piedi sotto un supporto fisso o facendoteli tenere da un partner. Le gambe devono essere piegate alle ginocchia. Solleva la parte superiore del corpo in modo da creare una forma a V immaginaria con le cosce. Le braccia devono essere completamente distese davanti a te, perpendicolari al busto, con le mani unite. Questa è la posizione di partenza. Espirando, ruota il busto verso destra finché le braccia non saranno parallele al pavimento. Mantieni la contrazione per un secondo e torna alla posizione di partenza espirando. Ora ripeti il movimento verso il lato opposto seguendo la stessa tecnica. Esegui il numero di ripetizioni raccomandato.' 
WHERE name = 'Russian Twist';

UPDATE public.exercise_library 
SET name_it = 'Sandbag Load', description_it = 'Per sollevare e caricare sacchi di sabbia (sandbag) o altri oggetti, parti posizionando gli attrezzi a una certa distanza dalla piattaforma di carico, solitamente 15 metri. Inizia sollevando il sandbag. I sandbag sono estremamente scomodi da maneggiare e la tecnica di sollevamento può variare in base al modello. Cerca di avvolgere il sacco il più possibile, estendendo anche e ginocchia per sollevarlo in alto. Il posizionamento sulle spalle solitamente non è consentito. Muoviti il più velocemente possibile verso la piattaforma e carica l''oggetto, estendendo anche, ginocchia e caviglie per arrivare il più in alto possibile. Riponilo sulla piattaforma assicurandoti che non cada. Torna alla posizione di partenza per recuperare il sandbag successivo e ripeti fino al termine dell''esercizio.' 
WHERE name = 'Sandbag Load';

UPDATE public.exercise_library 
SET name_it = 'Scapular Pull-Up', description_it = 'Afferra una sbarra per trazioni con una presa prona. Dalla posizione di sospensione, sollevati di alcuni centimetri senza flettere le braccia. Esegui il movimento deprimendo le scapole con un movimento simile a una scrollata invertita. Fai una pausa al termine del movimento, quindi torna lentamente alla posizione di partenza prima di eseguire le ripetizioni successive.' 
WHERE name = 'Scapular Pull-Up';

UPDATE public.exercise_library 
SET name_it = 'Scissor Kick', description_it = 'Per iniziare, sdraiati con la schiena ben premuta contro il pavimento o su un tappetino fitness. Le braccia devono essere completamente distese ai lati con i palmi rivolti verso il basso. Nota: le braccia devono rimanere ferme per tutta la durata dell''esercizio. Con le ginocchia leggermente flesse, solleva le gambe in modo che i talloni siano a circa 15 cm da terra. Questa è la posizione di partenza. Ora solleva la gamba sinistra a un angolo di circa 45 gradi mentre abbassi la destra, finché il tallone non si trova a circa 5-7 cm dal suolo. Inverti il movimento sollevando la gamba destra e abbassando la sinistra. Ricorda di respirare durante l''esecuzione. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Scissor Kick';

UPDATE public.exercise_library 
SET name_it = 'Scissors Jump', description_it = 'Assumi la posizione di affondo con un piede in avanti, ginocchio piegato e ginocchio posteriore quasi a contatto con il suolo. Assicurati che il ginocchio anteriore sia allineato con la mezzeria del piede. Estendendo entrambe le gambe, salta il più in alto possibile, facendo oscillare le braccia per ottenere slancio. Durante il salto, scambia la posizione delle gambe, portando quella anteriore dietro e quella posteriore davanti. All''atterraggio, ammortizza l''impatto con le gambe tornando nella posizione di affondo e ripeti.' 
WHERE name = 'Scissors Jump';

UPDATE public.exercise_library 
SET name_it = 'Seated Band Hamstring Curl', description_it = 'Fissa una banda elastica vicino al suolo e posiziona una panca a poca distanza. Siediti sulla panca e fissa la banda attorno alle caviglie, iniziando con le gambe distese. Questa sarà la tua posizione di partenza. Fletti le ginocchia portando i piedi verso la panca. Potrebbe essere necessario inclinarsi leggermente all''indietro per evitare che i piedi tocchino il suolo. Fai una pausa al completamento del movimento, quindi torna lentamente alla posizione di partenza.' 
WHERE name = 'Seated Band Hamstring Curl';

UPDATE public.exercise_library 
SET name_it = 'Seated Barbell Military Press', description_it = 'Siediti su una panca per Military Press con il bilanciere dietro la nuca. Fatti passare il bilanciere da uno spotter (scelta migliore per la cuffia dei rotatori) o prendilo tu stesso con attenzione usando una presa prona (palmi rivolti in avanti). Suggerimento: la presa deve essere più larga delle spalle e creare un angolo di 90 gradi tra avambraccio e braccio durante la discesa. Una volta impugnato il bilanciere correttamente, sollevalo sopra la testa distendendo le braccia. Tieni il bilanciere all''altezza delle spalle, leggermente davanti al capo: questa è la posizione di partenza. Abbassa lentamente il bilanciere fino alla clavicola inspirando. Solleva nuovamente il bilanciere fino alla posizione iniziale espirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Seated Barbell Military Press';

UPDATE public.exercise_library 
SET name_it = 'Seated Barbell Twist', description_it = 'Siediti sul bordo di una panca piana con un bilanciere appoggiato sopra le cosce. I piedi devono essere alla larghezza delle spalle. Afferra la barra con i palmi rivolti verso il basso, mantenendo le mani a una larghezza superiore a quella delle spalle. Solleva il bilanciere sopra la testa fino a estendere completamente le braccia. Abbassa il bilanciere dietro la testa finché non poggia alla base del collo. Questa è la posizione di partenza. Mantenendo piedi e testa fermi, ruota il busto da un lato all''altro per sentire la contrazione degli obliqui. Non ruotare eccessivamente per evitare infortuni; muoviti solo quanto permesso dalla flessibilità del tronco. Consiglio: usa un movimento lento e controllato. Espira durante la rotazione e inspira tornando alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Seated Barbell Twist';

UPDATE public.exercise_library 
SET name_it = 'Seated Bent-Over One-Arm Dumbbell Triceps Extension', description_it = 'Siediti sul bordo di una panca piana con un manubrio in una mano, usando una presa neutra (palmi rivolti verso di te). Piega leggermente le ginocchia e porta il busto in avanti flettendo il bacino, mantenendo la schiena dritta finché non è quasi parallela al pavimento. Tieni la testa alta. Il braccio con il manubrio deve essere vicino al busto e allineato ad esso (sollevato finché non è parallelo al pavimento, con l''avambraccio rivolto verso il basso). Consiglio: dovrebbe esserci un angolo di 90 gradi tra avambraccio e braccio. Questa è la posizione di partenza. Mantenendo il braccio fermo, usa i tricipiti per sollevare il peso espirando, finché l''avambraccio non è parallelo al pavimento e il braccio completamente esteso. Si muove solo l''avambraccio. Dopo un secondo di contrazione in alto, abbassa lentamente il manubrio nella posizione iniziale inspirando. Ripeti per il numero di ripetizioni prescritto, poi cambia braccio.' 
WHERE name = 'Seated Bent-Over One-Arm Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Seated Bent-Over Rear Delt Raise', description_it = 'Posiziona due manubri davanti a una panca piana. Siediti sul bordo della panca con le gambe unite e i manubri dietro i polpacci. Fletti il busto mantenendo la schiena dritta per afferrare i manubri con i palmi rivolti l''uno verso l''altro. Questa è la posizione di partenza. Mantenendo il busto fermo e le braccia leggermente flesse ai gomiti, solleva i manubri lateralmente finché entrambe le braccia non sono parallele al pavimento. Espira durante il sollevamento (evita di dondolare il busto o di portare le braccia all''indietro invece che lateralmente). Dopo un secondo di contrazione in alto, abbassa lentamente i manubri nella posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Seated Bent-Over Rear Delt Raise';

UPDATE public.exercise_library 
SET name_it = 'Seated Bent-Over Two-Arm Dumbbell Triceps Extension', description_it = 'Siediti sul bordo di una panca piana con un manubrio in ogni mano, usando una presa neutra. Piega leggermente le ginocchia e porta il busto in avanti, flettendo il bacino e mantenendo la schiena dritta finché non è quasi parallela al pavimento. Tieni la testa alta. Le braccia con i manubri devono essere vicine al busto e allineate (sollevate finché non sono parallele al pavimento, con gli avambracci rivolti verso il basso). Consiglio: mantieni un angolo di 90 gradi tra avambracci e braccia. Questa è la posizione di partenza. Mantenendo le braccia ferme, usa i tricipiti per sollevare i pesi espirando, finché gli avambracci non sono paralleli al pavimento e le braccia completamente estese. Si muovono solo gli avambracci. Dopo un secondo di contrazione in alto, abbassa lentamente i manubri nella posizione iniziale inspirando. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Seated Bent-Over Two-Arm Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Seated Biceps', description_it = 'Siediti sul pavimento con le ginocchia flesse e un partner in piedi dietro di te. Estendi le braccia dritte dietro di te con i palmi rivolti l''uno verso l''altro. Il partner terrà i tuoi polsi. Questa è la posizione di partenza. Cerca di flettere i gomiti mentre il partner oppone resistenza impedendo il movimento. Dopo 10-20 secondi, rilassa le braccia mentre il partner tira delicatamente i polsi verso l''alto per allungare i bicipiti. Comunica con il partner per regolare l''intensità dello stretching ed evitare infortuni.' 
WHERE name = 'Seated Biceps';

UPDATE public.exercise_library 
SET name_it = 'Seated Cable Rows', description_it = 'Per questo esercizio è necessaria una macchina per il rematore ai cavi bassi con una V-bar (presa neutra, palmi rivolti l''uno verso l''altro). Siediti sulla macchina e posiziona i piedi sulla piattaforma anteriore, mantenendo le ginocchia leggermente flesse e non bloccate. Sporgiti in avanti mantenendo l''allineamento naturale della schiena e afferra la V-bar. Con le braccia estese, tira indietro finché il busto non forma un angolo di 90 gradi rispetto alle gambe. La schiena dovrebbe essere leggermente inarcata e il petto in fuori. Dovresti sentire un leggero allungamento dei dorsali. Questa è la posizione di partenza. Mantenendo il busto fermo, tira le maniglie verso l''addome tenendo le braccia vicine al corpo. Espira durante il movimento. Al termine, contrai intensamente i muscoli della schiena per un secondo, quindi torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Seated Cable Rows';

UPDATE public.exercise_library 
SET name_it = 'Seated Cable Shoulder Press', description_it = 'Regola il carico su un livello appropriato, siediti e afferra le maniglie. Le braccia devono formare un angolo di circa 90 gradi rispetto al corpo, con testa e petto alti. Anche i gomiti devono essere piegati a circa 90 gradi. Questa è la posizione di partenza. Inizia estendendo i gomiti e unendo le maniglie sopra la testa. Dopo una pausa in alto, torna alla posizione di partenza. Assicurati di mantenere la tensione sui cavi. Puoi eseguire questo movimento anche senza schienale e alternando le braccia.' 
WHERE name = 'Seated Cable Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Seated Calf Raise', description_it = 'Siediti sulla macchina e posiziona le punte dei piedi sulla parte inferiore della piattaforma, lasciando i talloni sospesi. Scegli la posizione dei piedi (in avanti, verso l''interno o verso l''esterno). Posiziona le cosce sotto l''imbottitura della leva, regolandola in base alla tua altezza. Metti le mani sopra l''imbottitura per evitare che scivoli in avanti. Solleva leggermente la leva spingendo con i talloni e rilascia la barra di sicurezza. Questa è la posizione di partenza. Abbassa lentamente i talloni flettendo le caviglie finché i polpacci non sono completamente allungati, inspirando durante il movimento. Solleva i talloni estendendo le caviglie il più in alto possibile contraendo i polpacci ed espirando. Mantieni la contrazione in alto per un secondo. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Seated Calf Raise';

UPDATE public.exercise_library 
SET name_it = 'Seated Calf Stretch', description_it = 'Siediti dritto su un tappetino da fitness. Piega un ginocchio e appoggia il piede a terra per stabilizzare il busto. Distendi l''altra gamba e fletti la caviglia. Usando una fascia, un asciugamano o la mano (se riesci ad arrivare), tira le dita dei piedi verso di te. Mantieni la posizione per 10-20 secondi, poi cambia lato.' 
WHERE name = 'Seated Calf Stretch';

UPDATE public.exercise_library 
SET name_it = 'Seated Close-Grip Concentration Barbell Curl', description_it = 'Siediti su una panca piana con un bilanciere (o un E-Z bar) tra le gambe. Tieni le gambe divaricate, le ginocchia flesse e i piedi a terra. Usa le braccia per sollevare il bilanciere e appoggia la parte posteriore delle braccia sopra l''interno coscia (circa 8-9 cm sopra il ginocchio). È necessaria una presa supinata più stretta delle spalle. Consiglio: il braccio deve essere disteso e il bilanciere vicino al pavimento. Questa è la posizione di partenza. Mantenendo le braccia ferme, fletti il bilanciere verso l''alto contraendo i bicipiti ed espirando. Solo gli avambracci devono muoversi. Continua finché i bicipiti non sono completamente contratti e il bilanciere è all''altezza delle spalle. Mantieni la contrazione per un secondo strizzando i bicipiti. Inizia lentamente a riportare il bilanciere alla posizione iniziale inspirando. Consiglio: evita qualsiasi dondolio. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Seated Close-Grip Concentration Barbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Curl con manubri da seduto', description_it = 'Siediti su una panca piana con un manubrio in ogni mano, braccia distese lungo i fianchi. I gomiti devono rimanere vicini al busto. Ruota i palmi delle mani verso il busto; questa è la posizione di partenza. Mantenendo la parte superiore del braccio ferma, fletti i pesi e inizia a ruotare i polsi non appena i manubri superano le cosce, in modo che i palmi siano rivolti in avanti al termine del movimento. Contrai i bicipiti espirando, assicurandoti che solo gli avambracci si muovano. Continua il movimento finché i bicipiti non sono completamente contratti e i manubri all''altezza delle spalle. Mantieni la posizione di contrazione per un secondo, strizzando i bicipiti. Torna lentamente alla posizione di partenza inspirando e ruotando i polsi in presa neutra. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Dumbbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Curl per bicipiti interno con manubri da seduto', description_it = 'Siediti sul bordo di una panca piana con un manubrio in ogni mano, braccia distese. Gomiti vicini al busto. Ruota i palmi in posizione neutra (uno verso l''altro); questa è la posizione di partenza. Mantenendo le braccia ferme, fletti i manubri verso l''esterno e verso l''alto, ruotando i palmi verso l''esterno durante il sollevamento e mantenendo gli avambracci in linea con i deltoidi laterali. Suggerimento: solo gli avambracci devono muoversi. Continua finché i bicipiti sono completamente contratti e i manubri sono all''altezza delle spalle. Mantieni la contrazione per un secondo. Ritorna lentamente alla posizione iniziale inspirando, ricordando di ruotare le braccia verso l''interno per tornare alla presa neutra. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Dumbbell Inner Biceps Curl';

UPDATE public.exercise_library 
SET name_it = 'Wrist curl con manubri da seduto (palmi verso il basso)', description_it = 'Posiziona due manubri sul pavimento davanti a una panca piana. Siediti sul bordo della panca con le gambe divaricate alla larghezza delle spalle e i piedi ben saldi a terra. Afferra i manubri e appoggia gli avambracci sulle cosce con i palmi rivolti verso il basso; i polsi devono sporgere oltre il bordo delle ginocchia. Inizia flettendo i polsi verso l''alto ed espirando. Abbassa lentamente i polsi alla posizione iniziale inspirando. Consiglio: gli avambracci devono rimanere fermi; il movimento deve essere eseguito esclusivamente dai polsi. Ripeti per il numero di ripetizioni consigliato. Al termine, appoggia i manubri a terra.' 
WHERE name = 'Seated Dumbbell Palms-Down Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Wrist curl con manubri da seduto (palmi verso l''alto)', description_it = 'Posiziona due manubri sul pavimento davanti a una panca piana. Siediti sul bordo della panca con le gambe divaricate alla larghezza delle spalle e i piedi a terra. Afferra i manubri e appoggia gli avambracci sulle cosce con i palmi rivolti verso l''alto; i polsi devono sporgere oltre il bordo delle ginocchia. Inizia flettendo i polsi verso l''alto ed espirando. Abbassa lentamente i polsi alla posizione iniziale inspirando. Consiglio: gli avambracci devono rimanere fermi; il movimento deve essere eseguito esclusivamente dai polsi. Ripeti per il numero di ripetizioni consigliato. Al termine, appoggia i manubri a terra.' 
WHERE name = 'Seated Dumbbell Palms-Up Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Press con manubri da seduto', description_it = 'Afferra i manubri e siediti su una panca con schienale, appoggiando i pesi verticalmente sulle cosce. Solleva i manubri uno alla volta aiutandoti con le gambe fino a portarli all''altezza delle spalle. Ruota i polsi in modo che i palmi siano rivolti in avanti; questa è la posizione di partenza. Espirando, spingi i manubri verso l''alto finché non si toccano. Dopo una pausa di un secondo, torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Leg pull-in da seduto su panca', description_it = 'Siediti su una panca con le gambe distese davanti a te, leggermente al di sotto della parallela, e le mani che tengono i bordi della panca. Il busto deve essere inclinato all''indietro di circa 45 gradi. Questa è la posizione di partenza. Porta le ginocchia verso di te avvicinando contemporaneamente il busto; espira durante il movimento. Dopo una pausa di un secondo, torna alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Flat Bench Leg Pull-In';

UPDATE public.exercise_library 
SET name_it = 'Stretching per bicipiti femorali da seduto', description_it = 'Siediti su un tappetino con la gamba destra distesa davanti a te e la gamba sinistra piegata, con il piede contro l''interno coscia destro. Inclinati in avanti partendo dalle anche e allungati verso la caviglia finché non senti allungare il bicipite femorale. Mantieni la posizione per 15 secondi, poi ripeti sull''altro lato.' 
WHERE name = 'Seated Floor Hamstring Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching per deltoide anteriore da seduto', description_it = 'Siediti dritto a terra con le gambe piegate e un partner in piedi dietro di te. Stendi le braccia lateralmente, palmi rivolti a terra. Cerca di portare le braccia il più indietro possibile mentre il partner tiene i tuoi polsi; questa è la posizione di partenza. Mantenendo i gomiti dritti, cerca di portare le braccia in avanti mentre il partner ti oppone una leggera resistenza impedendo il movimento per 10-20 secondi. Ora rilassa i muscoli e lascia che il partner aumenti delicatamente lo stretching su spalle e petto. Mantieni per 10-20 secondi.' 
WHERE name = 'Seated Front Deltoid';

UPDATE public.exercise_library 
SET name_it = 'Stretching per glutei da seduto', description_it = 'Da seduto con le ginocchia piegate, incrocia una caviglia sopra il ginocchio opposto. Il partner si posiziona dietro di te. Inclinati in avanti mentre il partner sostiene le tue spalle con le mani; questa è la posizione di partenza. Cerca di spingere il busto all''indietro per 10-20 secondi, mentre il partner impedisce il movimento. Rilassa i muscoli mentre il partner aumenta lo stretching spingendo delicatamente il busto in avanti per 10-20 secondi.' 
WHERE name = 'Seated Glute';

UPDATE public.exercise_library 
SET name_it = 'Good morning da seduto', description_it = 'Posiziona un box all''interno di un power rack con i pin all''altezza appropriata. Entra sotto il bilanciere e posizionalo sulla parte alta della schiena, non sopra i trapezi. Contrai le scapole e ruota i gomiti in avanti, cercando di flettere il bilanciere sulle spalle. Rimuovi il bilanciere dal rack, mantenendo un arco lombare accentuato. Testa rivolta in avanti. Con schiena, spalle e core in tensione, spingi le ginocchia e il bacino all''indietro e inizia la discesa. Siediti sul box; questa è la posizione di partenza. Mantenendo il bilanciere in posizione, fletti il busto in avanti dalle anche il più possibile. Fai una pausa appena sopra i pin e inverte il movimento fino a tornare in posizione eretta.' 
WHERE name = 'Seated Good Mornings';

UPDATE public.exercise_library 
SET name_it = 'Stretching per i bicipiti femorali da seduto', description_it = 'In posizione seduta con le gambe distese, fatti assistere da un partner che rimarrà in piedi dietro di te. Inclinati in avanti mentre il partner sostiene le tue spalle con le mani. Questa sarà la posizione di partenza. Cerca di spingere il busto all''indietro per 10-20 secondi, mentre il partner impedisce qualsiasi movimento effettivo del busto. Successivamente, rilassa i muscoli mentre il partner aumenta l''allungamento spingendo delicatamente il busto in avanti per altri 10-20 secondi.' 
WHERE name = 'Seated Hamstring';

UPDATE public.exercise_library 
SET name_it = 'Stretching da seduto per bicipiti femorali e polpacci', description_it = 'Avvolgi una cintura, una corda o una fascia attorno a un piede. Siediti con entrambe le gambe distese; questa sarà la posizione di partenza. Inclinandoti leggermente in avanti, tira la cintura per avvicinare le punte dei piedi verso di te. Mantieni la posizione per 10-20 secondi e poi ripeti con l''altra gamba.' 
WHERE name = 'Seated Hamstring and Calf Stretch';

UPDATE public.exercise_library 
SET name_it = 'Neck Resistance con Head Harness da seduto', description_it = 'Posiziona l''imbracatura per il collo (head harness) sul pavimento all''estremità di una panca piana. Una volta selezionato il carico, siediti sulla panca con i piedi più larghi rispetto alla larghezza delle spalle e le punte dei piedi rivolte verso l''esterno. Muovi lentamente il busto in avanti fino a renderlo quasi parallelo al pavimento. Con entrambe le mani, posiziona l''imbracatura saldamente attorno alla testa. Suggerimento: assicurati che i pesi poggino ancora sul pavimento per evitare sforzi eccessivi al collo. Afferra quindi il peso con entrambe le mani e riporta il busto in posizione quasi perpendicolare al pavimento. Nota: la testa e il busto devono essere leggermente inclinati in avanti per eseguire questo esercizio. Appoggia le mani sulle ginocchia; questa è la posizione di partenza. Abbassa lentamente il collo finché il mento non tocca la parte superiore del torace, inspirando. Espirando, riporta il collo nella posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Head Harness Neck Resistance';

UPDATE public.exercise_library 
SET name_it = 'Seated Leg Curl', description_it = 'Regola la leva della macchina in base alla tua altezza e siediti con la schiena ben appoggiata allo schienale. Posiziona la parte posteriore della parte inferiore della gamba sopra la leva imbottita (pochi centimetri sotto i polpacci) e fissa il cuscinetto sopra le cosce, appena sopra le ginocchia. Afferra le maniglie laterali, tieni le punte dei piedi dritte (o utilizza una delle altre due posizioni dei piedi) e assicurati che le gambe siano completamente distese davanti a te. Questa è la posizione di partenza. Espirando, tira la leva della macchina il più possibile verso la parte posteriore delle cosce flettendo le ginocchia. Mantieni il busto immobile. Mantieni la contrazione per un secondo e torna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Leg Curl';

UPDATE public.exercise_library 
SET name_it = 'Seated Leg Tucks', description_it = 'Siediti su una panca con le gambe distese davanti a te, leggermente al di sotto del piano parallelo, e le braccia che impugnano i lati della panca. Il busto deve essere inclinato all''indietro di circa 45 gradi rispetto alla panca. Questa è la posizione di partenza. Porta le ginocchia verso di te avvicinando contemporaneamente il busto ad esse. Espira durante il movimento. Dopo una pausa di un secondo, torna alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Leg Tucks';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con manubrio a una mano (palmi rivolti verso il basso) da seduto', description_it = 'Siediti su una panca piana con un manubrio nella mano destra. Tieni i piedi ben appoggiati a terra, a una distanza leggermente superiore alla larghezza delle spalle. Inclinati in avanti e appoggia l''avambraccio destro sulla parte superiore della coscia destra con il palmo rivolto verso il basso. Suggerimento: assicurati che la parte posteriore del polso poggi sulle ginocchia. Questa è la posizione di partenza. Abbassa il manubrio il più possibile mantenendo una presa salda, inspirando durante il movimento. Ora fletti il polso portando il manubrio il più in alto possibile, contraendo gli avambracci ed espirando. Mantieni la contrazione per un secondo prima di abbassare nuovamente. Suggerimento: il movimento deve avvenire solo a livello del polso. Esegui il numero di ripetizioni consigliato, quindi cambia braccio.' 
WHERE name = 'Seated One-Arm Dumbbell Palms-Down Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con manubrio a una mano (palmi rivolti verso l''alto) da seduto', description_it = 'Siediti su una panca piana con un manubrio nella mano destra. Tieni i piedi ben appoggiati a terra, a una distanza leggermente superiore alla larghezza delle spalle. Inclinati in avanti e appoggia l''avambraccio destro sulla parte superiore della coscia destra con il palmo rivolto verso l''alto. Suggerimento: assicurati che la parte anteriore del polso poggi sulle ginocchia. Questa è la posizione di partenza. Abbassa il manubrio il più possibile mantenendo una presa salda, inspirando durante il movimento. Ora fletti il polso portando il manubrio il più in alto possibile, contraendo gli avambracci ed espirando. Mantieni la contrazione per un secondo prima di abbassare nuovamente. Suggerimento: il movimento deve avvenire solo a livello del polso. Esegui il numero di ripetizioni consigliato, quindi cambia braccio.' 
WHERE name = 'Seated One-Arm Dumbbell Palms-Up Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Rematore al cavo basso a una mano da seduto', description_it = 'Per la posizione di partenza, siediti sulla macchina e appoggia i piedi sulla piattaforma anteriore o sulla barra, mantenendo le ginocchia leggermente flesse e non bloccate. Inclinati in avanti mantenendo l''allineamento naturale della schiena e afferra la maniglia singola con la mano sinistra, con il palmo rivolto verso il basso. Con il braccio esteso, tira all''indietro finché il busto non forma un angolo di 90 gradi rispetto alle gambe. La schiena deve essere leggermente arcuata e il petto in fuori. Dovresti sentire un buon allungamento del gran dorsale. Il braccio destro può rimanere lungo il fianco. Questa è la posizione di partenza. Mantenendo il busto immobile, tira la maniglia verso il busto tenendo il braccio vicino al corpo e ruotando il polso, in modo che quando la mano raggiunge l''addome si trovi in posizione neutra (palmo rivolto verso il busto). Espira durante il movimento e contrai intensamente i muscoli della schiena. Mantieni la contrazione per un secondo e torna lentamente alla posizione originale inspirando. Suggerimento: ricordati di ruotare il polso tornando alla posizione di partenza in modo che il palmo sia nuovamente rivolto verso il basso. Ripeti per il numero di ripetizioni consigliato e poi cambia braccio.' 
WHERE name = 'Seated One-arm Cable Pulley Rows';

UPDATE public.exercise_library 
SET name_it = 'Stretching overhead da seduto', description_it = 'Siediti in posizione eretta su un tappetino. Unisci le piante dei piedi, tenendole a circa 15-20 cm davanti ai fianchi. Appoggia una mano sul pavimento accanto a te e porta l''altra mano dietro la testa. Solleva il gomito verso il soffitto mentre inclini il busto verso il lato opposto. Mantieni la posizione per 10-20 secondi, poi cambia lato.' 
WHERE name = 'Seated Overhead Stretch';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con bilanciere (palmi verso l''alto) da seduto', description_it = 'Impugna un bilanciere con entrambe le mani e i palmi rivolti verso l''alto; mani distanziate circa alla larghezza delle spalle. Tieni i piedi ben appoggiati a terra, a una distanza leggermente superiore alla larghezza delle spalle. Inclinati in avanti e appoggia gli avambracci sopra le cosce, con i palmi verso l''alto. Suggerimento: assicurati che la parte anteriore dei polsi poggi sulle ginocchia. Questa è la posizione di partenza. Abbassa il bilanciere il più possibile inspirando e mantenendo una presa salda. Ora fletti il bilanciere verso l''alto il più possibile contraendo gli avambracci ed espirando. Mantieni la contrazione al vertice per un secondo. Suggerimento: solo i polsi devono muoversi.' 
WHERE name = 'Seated Palm-Up Barbell Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl con bilanciere da seduto (palmi verso il basso)', description_it = 'Impugna un bilanciere con entrambe le mani, con i palmi rivolti verso il basso e le mani distanziate circa quanto la larghezza delle spalle. Appoggia i piedi a terra, a una distanza leggermente superiore alla larghezza delle spalle. Inclinati in avanti e appoggia gli avambracci sulle cosce con i palmi rivolti verso il basso. Suggerimento: assicurati che la parte posteriore dei polsi poggi sopra le ginocchia. Questa è la posizione di partenza. Abbassa il bilanciere il più possibile inspirando e mantenendo una presa salda. Ora fletti il bilanciere verso l''alto il più possibile contraendo gli avambracci ed espirando. Mantieni la contrazione per un secondo. Suggerimento: solo i polsi devono muoversi.' 
WHERE name = 'Seated Palms-Down Barbell Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Alzate laterali da seduto', description_it = 'Prendi due manubri e siediti sul bordo di una panca piana con i piedi ben piantati a terra. Impugna i manubri con i palmi rivolti verso l''interno e le braccia distese lungo i fianchi. Questa è la posizione di partenza. Mantenendo il busto fermo (senza dondolare), solleva i manubri lateralmente con una leggera flessione del gomito e le mani leggermente inclinate in avanti, come se dovessi versare dell''acqua in un bicchiere. Continua a salire finché le braccia non sono parallele al pavimento. Espira durante il movimento e fai una pausa di un secondo nella parte alta. Abbassa lentamente i manubri fino alla posizione di partenza espirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Side Lateral Raise';

UPDATE public.exercise_library 
SET name_it = 'Triceps Press da seduto', description_it = 'Siediti su una panca con schienale, afferra un manubrio con entrambe le mani e tienilo sopra la testa a braccia tese. Suggerimento: se il peso è molto elevato, fatti aiutare da qualcuno. La resistenza deve poggiare sui palmi delle mani con i pollici che la circondano. Il palmo della mano deve essere rivolto verso l''interno. Questa è la posizione di partenza. Mantenendo la parte superiore delle braccia vicino alla testa (gomiti chiusi) e perpendicolari al pavimento, abbassa il peso con un movimento semicircolare dietro la testa finché gli avambracci non toccano i bicipiti. Suggerimento: la parte superiore delle braccia deve rimanere ferma e devono muoversi solo gli avambracci. Inspira durante questa fase. Torna alla posizione di partenza usando i tricipiti per sollevare il manubrio ed espirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Triceps Press';

UPDATE public.exercise_library 
SET name_it = 'Wrist Curl ai cavi bassi da seduto (palmi verso l''alto)', description_it = 'Posiziona una panca di fronte a una macchina a cavi bassi dotata di barra o impugnatura per EZ Curl. Allontana la panca in modo che, portando l''impugnatura sopra le cosce, il cavo sia in tensione. Afferra l''impugnatura con entrambe le mani, palmi rivolti verso l''alto, con una presa pari alla larghezza delle spalle. Siediti sulla panca con i piedi ben piantati a terra. Inclinati in avanti e appoggia gli avambracci sulle cosce con la parte posteriore dei polsi sulle ginocchia. Questa è la posizione di partenza. Abbassa la barra il più possibile inspirando e mantenendo una presa salda. Ora fletti la barra verso l''alto il più possibile contraendo gli avambracci. Suggerimento: solo i polsi devono muoversi, non gli avambracci. Dopo una breve contrazione in alto, torna alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Seated Two-Arm Palms-Up Low-Pulley Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'See-Saw Press (Distensioni alternate)', description_it = 'Afferra un manubrio per mano e mettiti in piedi. Esegui un Clean (porta i pesi a livello delle spalle) e ruota i polsi in modo che i palmi siano rivolti verso di te, come per prepararti a una Arnold Press. Questa è la posizione di partenza. Inizia a estendere il braccio sinistro sopra la testa ruotando il polso in modo che il palmo sia rivolto in avanti durante la salita. I gomiti devono aprirsi verso l''esterno mentre sollevi il peso. Contemporaneamente, fletti il busto verso il lato opposto. Suggerimento: se eseguito correttamente, sembrerà che tu stia cercando di raggiungere qualcosa sopra la testa sul lato destro del corpo con il braccio sinistro. Espira durante il movimento. Una volta raggiunta la massima estensione, inspira e ripeti il movimento sul lato opposto. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'See-Saw Press (Alternating Side Press)';

UPDATE public.exercise_library 
SET name_it = 'Shotgun Row', description_it = 'Collega un''impugnatura singola a un cavo basso. Dopo aver selezionato il peso, mettiti a circa 60 cm di distanza con una posizione dei piedi sfalsata (wide-split stance). Il braccio deve essere teso e la spalla protesa in avanti. Questa è la posizione di partenza. Esegui il movimento ritraendo la spalla e flettendo il gomito. Durante la trazione, supina il polso ruotando il palmo verso l''alto. Dopo una breve pausa, torna alla posizione di partenza.' 
WHERE name = 'Shotgun Row';

UPDATE public.exercise_library 
SET name_it = 'Circonduzioni delle spalle', description_it = 'Con le spalle rilassate e le braccia lungo i fianchi (o in grembo se sei seduto), ruota delicatamente le spalle in avanti, verso l''alto, all''indietro e verso il basso. Inverti la direzione. Puoi eseguire l''esercizio alternando le spalle o muovendole entrambe contemporaneamente.' 
WHERE name = 'Shoulder Circles';

UPDATE public.exercise_library 
SET name_it = 'Shoulder Press con elastici', description_it = 'Inizia stando in piedi su una fascia elastica in modo che ci sia tensione a braccia tese. Afferra le maniglie e sollevale finché le mani non si trovano all''altezza delle spalle. Ruota i polsi in modo che i palmi siano rivolti in avanti. I gomiti devono essere piegati, con braccia e avambracci allineati al busto. Questa è la posizione di partenza. Espirando, spingi le maniglie verso l''alto finché le braccia non sono completamente distese sopra la testa.' 
WHERE name = 'Shoulder Press - With Bands';

UPDATE public.exercise_library 
SET name_it = 'Scrollate delle spalle (Shoulder Raise)', description_it = 'Rilassa le braccia lungo i fianchi, solleva le spalle verso le orecchie e poi riportale verso il basso.' 
WHERE name = 'Shoulder Raise';

UPDATE public.exercise_library 
SET name_it = 'Stretching delle spalle', description_it = 'Porta il braccio sinistro trasversalmente davanti al petto e tienilo teso.' 
WHERE name = 'Shoulder Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching Laterale a Terra', description_it = 'Sdraiati sul fianco sinistro, flettendo il ginocchio sinistro davanti a te per stabilizzare il busto (usa anche i muscoli addominali per mantenere la posizione). Stendi la gamba destra e appoggia il piede destro a terra dietro il sinistro. Distendi il braccio destro sopra la testa e tira delicatamente il polso destro per allungare l''intero lato destro del corpo. Cambia lato.' 
WHERE name = 'Side-Lying Floor Stretch';

UPDATE public.exercise_library 
SET name_it = 'Side Bridge', description_it = 'Sdraiati su un fianco con le gambe tese. Solleva il bacino da terra facendo perno sull''avambraccio e sul lato del piede, mantenendo il corpo allineato in una linea retta dalla testa ai talloni. Contrai il core e mantieni la posizione per il tempo indicato.' 
WHERE name = 'Side Bridge';

UPDATE public.exercise_library 
SET name_it = 'Side Hop-Sprint', description_it = 'Mettiti di lato rispetto a un cono o un ostacolo. Inizia l''esercizio saltando lateralmente oltre l''ostacolo, sfruttando la spinta dell''atterraggio per tornare saltando al punto di partenza. Esegui il numero prescritto di ripetizioni il più velocemente possibile e termina lo scatto dopo l''ultimo salto.' 
WHERE name = 'Side Hop-Sprint';

UPDATE public.exercise_library 
SET name_it = 'Side Jackknife', description_it = 'Sdraiati su un fianco con le gambe tese e le braccia distese sopra la testa. Contemporaneamente, solleva le gambe e il busto cercando di toccare le caviglie con le mani, contraendo gli obliqui. Ritorna lentamente alla posizione di partenza senza appoggiare completamente le gambe a terra.' 
WHERE name = 'Side Jackknife';

UPDATE public.exercise_library 
SET name_it = 'Alzate Laterali', description_it = 'Impugna due manubri stando in piedi con il busto eretto e le braccia lungo i fianchi, palmi rivolti verso il corpo. Questa è la posizione di partenza. Mantenendo il busto fermo (senza oscillare), solleva i manubri lateralmente con una leggera flessione dei gomiti e le mani leggermente inclinate in avanti, come se stessi versando acqua da una brocca. Continua a salire finché le braccia sono parallele al pavimento. Espira durante il movimento e fai una pausa di un secondo in cima. Scendi lentamente nella posizione di partenza mentre inspiri. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Side Lateral Raise';

UPDATE public.exercise_library 
SET name_it = 'Alzate Laterali a Frontali', description_it = 'In posizione eretta, tieni un paio di manubri lungo i fianchi. Mantenendo i gomiti leggermente flessi, solleva i pesi direttamente davanti a te fino all''altezza delle spalle, evitando oscillazioni o slanci. Al culmine, sposta i pesi lateralmente mantenendo le braccia tese. Abbassa i pesi con un movimento controllato. Nella ripetizione successiva, solleva i pesi davanti a te fino all''altezza delle spalle prima di portarli lateralmente verso i fianchi. Ritorna alla posizione di partenza.' 
WHERE name = 'Side Laterals to Front Raise';

UPDATE public.exercise_library 
SET name_it = 'Slanci Laterali della Gamba', description_it = 'Stai in piedi vicino a una sedia, che puoi usare come supporto. Appoggia il peso su una sola gamba. Mantenendo l''altra gamba tesa, sollevala il più possibile lateralmente, poi riportala giù con un movimento oscillatorio incrociandola davanti alla gamba d''appoggio. Ripeti questo movimento oscillatorio 5-10 volte, aumentando gradualmente l''ampiezza del movimento.' 
WHERE name = 'Side Leg Raises';

UPDATE public.exercise_library 
SET name_it = 'Stretching dell''Inguine sul Fianco', description_it = 'Sdraiati sul fianco destro e piega il ginocchio destro davanti a te per stabilizzare il busto. Appoggia la testa sulla mano o sulla spalla destra. Solleva la gamba sinistra e afferrala dietro il ginocchio (più facile) o dal piede (più difficile). Tira il ginocchio sinistro verso la spalla sinistra e contemporaneamente premi il piede o il ginocchio verso il pavimento. Per intensificare lo stretching, stendi la gamba sinistra. Cambia lato.' 
WHERE name = 'Side Lying Groin Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching Laterale del Collo', description_it = 'Partendo con le spalle rilassate, inclina delicatamente la testa verso la spalla. Aiuta l''allungamento con una leggera trazione esercitata con la mano sul lato della testa.' 
WHERE name = 'Side Neck Stretch';

UPDATE public.exercise_library 
SET name_it = 'Salto in Lungo Laterale da Fermo', description_it = 'Inizia in piedi con i piedi alla larghezza delle anche in posizione atletica. Testa e petto alti, ginocchia e anche leggermente flesse. Inclinandoti verso destra, estendi anche, ginocchia e caviglie per saltare in aria. Usa le braccia per guidare il movimento, saltando il più lontano possibile verso destra. Atterra rivolto nella stessa direzione con i piedi alla larghezza delle anche, assorbendo l''impatto con la parte inferiore del corpo.' 
WHERE name = 'Side Standing Long Jump';

UPDATE public.exercise_library 
SET name_it = 'Side To Side Chins', description_it = 'Afferra la sbarra per trazioni con i palmi rivolti in avanti usando una presa larga. Con entrambe le braccia distese davanti a te che tengono la sbarra con una presa larga, porta il busto leggermente all''indietro di circa 30 gradi, creando una leggera curvatura nella parte bassa della schiena e spingendo il petto in fuori. Questa è la tua posizione di partenza. Solleva il busto inclinandoti verso sinistra finché la sbarra non tocca quasi la parte alta del petto, tirando le spalle e la parte superiore delle braccia verso il basso e all''indietro. Espira durante questa fase del movimento. Consiglio: concentrati sulla contrazione dei muscoli della schiena una volta raggiunta la posizione di massima contrazione. La parte superiore del busto deve rimanere ferma durante il movimento (senza dondolare) e solo le braccia devono muoversi. Gli avambracci non devono compiere altro lavoro se non quello di mantenere la presa sulla sbarra. Dopo un secondo di contrazione, inspira mentre torni alla posizione di partenza. Ora, solleva il busto inclinandoti verso destra finché la sbarra non tocca quasi la parte alta del petto, tirando le spalle e la parte superiore delle braccia verso il basso e all''indietro. Espira durante questa fase. Consiglio: concentrati sulla contrazione dei muscoli dorsali una volta raggiunta la posizione di massima contrazione. La parte superiore del busto deve rimanere ferma e solo le braccia devono muoversi. Dopo un secondo di contrazione, torna alla posizione di partenza. Ripeti i passaggi descritti fino al completamento delle ripetizioni previste per ogni lato.' 
WHERE name = 'Side To Side Chins';

UPDATE public.exercise_library 
SET name_it = 'Side Wrist Pull', description_it = 'Questo stretching è più efficace se eseguito in piedi. Incrocia il braccio sinistro oltre la linea mediana del corpo e tieni il polso sinistro con la mano destra all''altezza dei fianchi. Inizia l''allungamento con il braccio sinistro piegato. Lentamente distendi, tira e solleva il braccio fino all''altezza della spalla, come mostrato. Senti l''allungamento originarsi dalla schiena, non dalle spalle, ed evita di tirare eccessivamente l''articolazione della spalla. Cambia lato.' 
WHERE name = 'Side Wrist Pull';

UPDATE public.exercise_library 
SET name_it = 'Side to Side Box Shuffle', description_it = 'Stai a un lato della scatola (box) con il piede sinistro appoggiato al centro. Per iniziare, salta lateralmente oltre il box, atterrando con il piede destro sopra il box e il piede sinistro a terra. Oscilla le braccia per favorire il movimento. Continua a spostarti lateralmente avanti e indietro attraverso il box.' 
WHERE name = 'Side to Side Box Shuffle';

UPDATE public.exercise_library 
SET name_it = 'Single-Arm Cable Crossover', description_it = 'Inizia posizionando le carrucole in alto, seleziona il peso desiderato e afferra una maniglia con ogni mano. Fai un passo in avanti davanti a entrambe le carrucole con le braccia distese davanti a te, portando le mani vicine. Testa e petto devono essere sollevati mentre ti inclini in avanti, con i piedi sfalsati. Questa è la tua posizione di partenza. Mantenendo il braccio sinistro fermo, lascia che il braccio destro si estenda lateralmente, mantenendo una leggera flessione del gomito. Il braccio destro deve essere perpendicolare al corpo, approssimativamente all''altezza della spalla. Ritorna alla posizione iniziale riportando la mano verso la linea mediana del corpo. Mantieni la posizione per un secondo e ripeti il movimento sul lato opposto. Continua ad alternare per il numero di ripetizioni prescritte.' 
WHERE name = 'Single-Arm Cable Crossover';

UPDATE public.exercise_library 
SET name_it = 'Single-Arm Linear Jammer', description_it = 'Posiziona un bilanciere in un supporto landmine o fissalo saldamente in un angolo. Carica il bilanciere con un peso adeguato. Solleva il bilanciere da terra portandolo alle spalle con una o entrambe le mani. Adotta una posizione dei piedi larga. Questa è la posizione di partenza. Esegui il movimento estendendo il gomito e spingendo il peso verso l''alto. Muoviti in modo esplosivo, estendendo completamente anche e ginocchia per generare la massima forza. Ritorna alla posizione di partenza.' 
WHERE name = 'Single-Arm Linear Jammer';

UPDATE public.exercise_library 
SET name_it = 'Single-Arm Push-Up', description_it = 'Inizia in posizione prona a terra. Mettiti in posizione sostenendo il peso sulle punte dei piedi e su un solo braccio. Il braccio di lavoro deve essere posizionato direttamente sotto la spalla, completamente disteso. Le gambe devono essere tese e, per questo movimento, potresti aver bisogno di una base d''appoggio più ampia, posizionando i piedi più distanti rispetto a un normale push-up. Mantieni una postura corretta e metti la mano libera dietro la schiena. Questa è la posizione di partenza. Abbassati flettendo il gomito finché non tocchi terra. Scendi lentamente e inverte il movimento estendendo il braccio per tornare alla posizione iniziale.' 
WHERE name = 'Single-Arm Push-Up';

UPDATE public.exercise_library 
SET name_it = 'Single-Cone Sprint Drill', description_it = 'Questo esercizio serve a migliorare la rapidità dei piedi. È necessario un singolo cono. Inizia in piedi accanto al cono con un braccio indietro e uno in avanti. Esegui un rapido movimento dei piedi (chopping) il più velocemente possibile, bloccando con le braccia. Gira attorno al cono, mantenendo le ginocchia alte e con un movimento rapido e deciso dei piedi. Riposa dopo aver completato tre giri attorno al cono.' 
WHERE name = 'Single-Cone Sprint Drill';

UPDATE public.exercise_library 
SET name_it = 'Single-Leg High Box Squat', description_it = 'Posiziona un box all''interno di un rack. Fissa una fascia o una corda sopra il box. In piedi davanti ad esso, sali sul box portandoti in posizione eretta, lasciando l''altra gamba sospesa nel vuoto. Aggrappati alla fascia per mantenere l''equilibrio. Continua a salire e scendere con la stessa gamba prima di passare al lato opposto.' 
WHERE name = 'Single-Leg High Box Squat';

UPDATE public.exercise_library 
SET name_it = 'Single-Leg Hop Progression', description_it = 'Disponi una fila di coni davanti a te. Assumi una posizione eretta rilassata, in equilibrio su una gamba. Solleva il ginocchio della gamba opposta. Questa è la posizione di partenza. Salta in avanti, atterrando con la stessa gamba oltre il cono. Usa un salto con contromovimento per saltare da un cono all''altro. Alla fine, girati e torna indietro utilizzando l''altra gamba.' 
WHERE name = 'Single-Leg Hop Progression';

UPDATE public.exercise_library 
SET name_it = 'Single-Leg Lateral Hop', description_it = 'Stai a lato di un cono o di un ostacolo. Per la posizione di partenza, rimani in equilibrio su una gamba con il ginocchio leggermente piegato. Per iniziare, esegui un controsalto per saltare lateralmente oltre il cono. Atterra sulla gamba con cui hai saltato e rimbalza immediatamente tornando verso la posizione di partenza. Continua a saltellare avanti e indietro.' 
WHERE name = 'Single-Leg Lateral Hop';

UPDATE public.exercise_library 
SET name_it = 'Leg Extension Singolo', description_it = 'Siediti sulla macchina e regolala in modo corretto. Il cuscinetto deve poggiare sulla parte inferiore della tibia, senza toccare la caviglia. Regola il sedile in modo che il fulcro sia allineato con il ginocchio. Seleziona un peso adatto alle tue capacità. Mantenendo una buona postura, estendi completamente una gamba, facendo una pausa nella parte alta del movimento. Torna alla posizione iniziale senza lasciar cadere il peso, mantenendo la tensione sul muscolo. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Single-Leg Leg Extension';

UPDATE public.exercise_library 
SET name_it = 'Single-Leg Stride Jump', description_it = 'Mettiti di lato rispetto a un box con il piede interno appoggiato sopra, vicino al bordo. Inizia facendo oscillare le braccia verso l''alto mentre spingi con la gamba poggiata sul box, saltando il più in alto possibile. Cerca di portare il ginocchio opposto verso l''alto. Atterra nella stessa posizione di partenza, usando la gamba interna per ammortizzare l''impatto.' 
WHERE name = 'Single-Leg Stride Jump';

UPDATE public.exercise_library 
SET name_it = 'Single Dumbbell Raise', description_it = 'Con una posizione dei piedi larga, tieni un manubrio con entrambe le mani, afferrando la testa del manubrio anziché l''impugnatura. Le braccia devono essere distese e lasciate cadere all''altezza della vita. Questa sarà la posizione di partenza. Solleva il peso fino a superare il livello delle spalle, mantenendo le braccia tese. Il busto e le anche devono rimanere immobili durante tutto il movimento. Torna alla posizione iniziale e ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Single Dumbbell Raise';

UPDATE public.exercise_library 
SET name_it = 'Single Leg Butt Kick', description_it = 'Inizia stando in piedi su una gamba sola, con il ginocchio piegato sollevato. Questa è la posizione di partenza. Eseguendo un salto con contro-movimento, spingi verso l''alto estendendo anca, ginocchio e caviglia della gamba d''appoggio. Fletti immediatamente il ginocchio cercando di toccare i glutei con il tallone della gamba che salta. Riporta la gamba in una posizione parzialmente flessa sotto le anche e atterra. La gamba opposta deve rimanere relativamente nella stessa posizione durante l''esercizio.' 
WHERE name = 'Single Leg Butt Kick';

UPDATE public.exercise_library 
SET name_it = 'Single Leg Glute Bridge', description_it = 'Sdraiati a terra con i piedi ben appoggiati e le ginocchia piegate. Solleva una gamba da terra, portando il ginocchio al petto. Questa sarà la posizione di partenza. Esegui il movimento spingendo sul tallone, estendendo l''anca verso l''alto e sollevando i glutei da terra. Estendi il più possibile, fai una pausa e torna alla posizione iniziale.' 
WHERE name = 'Single Leg Glute Bridge';

UPDATE public.exercise_library 
SET name_it = 'Single Leg Push-off', description_it = 'Stai in piedi sul pavimento con un piede appoggiato su un box, con il tallone vicino al bordo. Spingi con il piede sul box, cercando di guadagnare quanta più altezza possibile estendendo anca e ginocchio. Atterra con lo stesso piede sul box, riportando l''altro piede nella posizione iniziale.' 
WHERE name = 'Single Leg Push-off';

UPDATE public.exercise_library 
SET name_it = 'Sit-Up', description_it = 'Sdraiati sul pavimento posizionando i piedi sotto un supporto fisso o facendoli tenere da un compagno. Le gambe devono essere piegate alle ginocchia. Metti le mani dietro la nuca e intreccia le dita. Questa è la posizione di partenza. Solleva la parte superiore del corpo in modo da creare una forma a V immaginaria con le cosce. Espira durante questa fase dell''esercizio. Una volta sentita la contrazione per un secondo, abbassa la parte superiore del corpo tornando alla posizione iniziale mentre inspiri. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Sit-Up';

UPDATE public.exercise_library 
SET name_it = 'Sit Squats', description_it = 'Stai in piedi con i piedi alla larghezza delle spalle. Questa sarà la posizione di partenza. Inizia il movimento flettendo ginocchia e anche, spingendo le anche all''indietro come per sederti. Continua finché non hai eseguito parte dello squat, restando sopra il parallelo, e inverti rapidamente il movimento fino a tornare alla posizione iniziale. Ripeti per 5-10 ripetizioni.' 
WHERE name = 'Sit Squats';

UPDATE public.exercise_library 
SET name_it = 'Pattinaggio', description_it = 'Il pattinaggio a rotelle è un''attività divertente ed efficace per migliorare la forma cardiorespiratoria e la resistenza muscolare. Richiede un buon equilibrio e una buona coordinazione. È necessario apprendere le basi del pattinaggio, tra cui curvare e frenare, e indossare dispositivi di protezione per evitare possibili lesioni. Puoi pattinare a un ritmo confortevole per 30 minuti consecutivi. Se desideri una sfida cardio, esegui il pattinaggio a intervalli: pattina velocemente per due minuti ogni cinque, usando i tre minuti rimanenti per recuperare. Una persona di circa 68 kg brucia tipicamente circa 175 calorie in 30 minuti di pattinaggio a ritmo moderato, simile a una camminata veloce.' 
WHERE name = 'Skating';

UPDATE public.exercise_library 
SET name_it = 'Sled Drag - Harness', description_it = 'Per iniziare, carica la slitta con il peso desiderato e collega la cinghia di trazione. Puoi tirare usando le maniglie, un''imbracatura (harness) o collegando la cinghia a una cintura di zavorra. Indipendentemente dal fatto di tirare in avanti o all''indietro, inclinati nella direzione di marcia e avanza estendendo anche e ginocchia.' 
WHERE name = 'Sled Drag - Harness';

UPDATE public.exercise_library 
SET name_it = 'Camminata all''indietro con slitta sopra la testa', description_it = 'Collega due maniglie a una slitta tramite una corda o una catena. Carica la slitta con un peso leggero. Rivolto verso la slitta, indietreggia finché la corda non è in tensione. Tieni le mani direttamente sopra la testa con i gomiti estesi. Questa sarà la posizione di partenza. Cammina all''indietro mantenendo le braccia sollevate sopra la testa. Evita movimenti bruschi.' 
WHERE name = 'Sled Overhead Backward Walk';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti sopra la testa con slitta', description_it = 'Collega due maniglie a una slitta usando una catena o una corda. Carica la slitta con un peso adeguato. Dando le spalle alla slitta, allontanati finché la corda non è in tensione. Solleva le mani sopra la testa, tenendole unite con i palmi rivolti l''uno verso l''altro. I gomiti devono puntare verso l''alto e essere flessi. Questa sarà la posizione di partenza. Estendi il gomito per raddrizzare il braccio, assicurandoti che la parte superiore del braccio rimanga ferma per isolare i tricipiti. A estensione completa, fai un passo avanti per allentare la tensione. Puoi tenere i piedi sfalsati per maggiore stabilità.' 
WHERE name = 'Sled Overhead Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Sled Push (Spinta con slitta)', description_it = 'Carica la slitta con il peso desiderato. Assumi una postura atletica, inclinati verso la slitta con le braccia completamente estese afferrando le maniglie. Spingi la slitta il più velocemente possibile, concentrandoti sull''estensione di anche e ginocchia per rafforzare la catena posteriore.' 
WHERE name = 'Sled Push';

UPDATE public.exercise_library 
SET name_it = 'Reverse Flye con slitta', description_it = 'Collega due maniglie a una slitta tramite una corda o una catena. Carica la slitta con un peso leggero. Rivolto verso la slitta, indietreggia finché la corda non è in tensione. Afferra entrambe le maniglie a braccia tese all''altezza della vita. Piega leggermente le ginocchia e mantieni il petto e la testa alti. Questa sarà la posizione di partenza. Senza flettere i gomiti, tira le maniglie verso l''alto e verso l''esterno, eseguendo un''alzata posteriore (reverse fly) con una leggera rotazione esterna. I palmi devono essere rivolti in avanti durante il movimento. Torna alla posizione di partenza facendo un paio di passi indietro per ripristinare la tensione sulla corda.' 
WHERE name = 'Sled Reverse Flye';

UPDATE public.exercise_library 
SET name_it = 'Rematore con slitta', description_it = 'Collega due maniglie a una slitta tramite una corda o una catena. Carica la slitta con un peso adeguato. Rivolto verso la slitta, indietreggia finché la corda non è in tensione. Afferrando una maniglia per mano, piega leggermente le ginocchia, tieni la testa e il petto alti e parti con le braccia estese. Per iniziare il movimento, fletti i gomiti mentre retrahi le scapole, tirando la slitta verso di te. Fai uno o due passi indietro per rimettere in tensione la corda e ripeti.' 
WHERE name = 'Sled Row';

UPDATE public.exercise_library 
SET name_it = 'Sledgehammer Swings (Colpi di mazza)', description_it = 'Per questo esercizio sono necessari un pneumatico e una mazza. Posizionati di fronte al pneumatico a circa 60 cm di distanza con una postura sfalsata. Impugna la mazza: se sei destrorso, la mano sinistra deve stare alla base del manico, mentre la destra più vicina alla testa della mazza. Mentre sollevi la mazza, la mano destra scorre verso la testa; mentre cali il colpo, la mano destra scivolerà verso il basso per unirsi alla sinistra. Colpisci il pneumatico con la massima forza possibile, controllando il rimbalzo della mazza. Ripeti dall''altro lato.' 
WHERE name = 'Sledgehammer Swings';

UPDATE public.exercise_library 
SET name_it = 'Alzate per le spalle su panca inclinata (Smith Machine)', description_it = 'Posiziona una panca inclinata sotto la Smith Machine. Regola il bilanciere a un''altezza raggiungibile da sdraiato con le braccia quasi completamente estese. Una volta selezionato il peso, sdraiati sulla panca assicurandoti che le spalle siano allineate sotto il bilanciere. Con una presa prona (palmi in avanti) alla larghezza delle spalle, sgancia il bilanciere e tienilo dritto sopra di te con una leggera flessione dei gomiti. Questa sarà la posizione di partenza. Espirando, solleva il bilanciere finché le braccia non sono completamente estese. Nota: la contrazione deve essere percepita intorno alle spalle. Dopo una pausa di un secondo, riporta il bilanciere alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi il bilanciere nel rack.' 
WHERE name = 'Smith Incline Shoulder Raise';

UPDATE public.exercise_library 
SET name_it = 'Scrollate dietro la schiena (Smith Machine)', description_it = 'Con il bilanciere all''altezza delle cosce, carica un peso adeguato. Stai in piedi con il bilanciere dietro di te, impugnalo con una presa prona alla larghezza delle spalle e sbloccalo. Mantieni una postura eretta con testa e petto alti e braccia estese. Questa sarà la posizione di partenza. Inizia il movimento sollevando le spalle verso l''alto (scrollata). Non flettere braccia o polsi durante l''esecuzione. Dopo una breve pausa, riporta il peso alla posizione di partenza. Ripeti per il numero di ripetizioni desiderato prima di bloccare il bilanciere nel rack.' 
WHERE name = 'Smith Machine Behind the Back Shrug';

UPDATE public.exercise_library 
SET name_it = 'Panca piana (Smith Machine)', description_it = 'Posiziona una panca piana sotto la Smith Machine. Regola il bilanciere a un''altezza raggiungibile da sdraiato con le braccia quasi completamente estese. Sdraiati sulla panca, afferra il bilanciere con una presa prona più larga delle spalle, sbloccalo dal rack e tienilo dritto sopra di te a braccia bloccate. Questa sarà la posizione di partenza. Inspirando, scendi lentamente finché non senti il bilanciere sul centro del petto. Dopo una pausa di un secondo, spingi il bilanciere verso l''alto espirando, utilizzando i muscoli pettorali. Blocca le braccia nella posizione contratta, tieni per un secondo e ricomincia a scendere lentamente. Consiglio: la fase di discesa dovrebbe durare almeno il doppio di quella di salita. Al termine, blocca il bilanciere nel rack.' 
WHERE name = 'Smith Machine Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Rematore con bilanciere (Smith Machine)', description_it = 'Regola il bilanciere della Smith Machine a un''altezza di circa 5 cm sotto le ginocchia. Piega leggermente le ginocchia e porta il busto in avanti flettendo la vita, mantenendo la schiena dritta finché non è quasi parallela al pavimento. Consiglio: mantieni la testa alta. Afferra il bilanciere con una presa prona (overhand) e sbloccalo dal rack. Lascialo pendere davanti a te con le braccia estese perpendicolari al pavimento e al busto. Questa è la posizione di partenza. Mantenendo il busto fermo, solleva il bilanciere espirando, tenendo i gomiti vicini al corpo e senza forzare gli avambracci (usali solo come ganci). Nella posizione di massima contrazione, contrai i muscoli della schiena e tieni per un secondo. Abbassa lentamente il peso alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Smith Machine Bent Over Row';

UPDATE public.exercise_library 
SET name_it = 'Calf Raise alla Smith Machine', description_it = 'Posiziona un blocco o un disco di peso sotto la sbarra della Smith machine. Regola la sbarra a un''altezza adatta alla tua statura. Una volta scelta l''altezza corretta e caricato il peso, sali sui dischi appoggiando l''avampiede e posiziona la sbarra sulla parte alta della schiena (sulle spalle). Afferra la sbarra con entrambe le mani rivolte in avanti. Ruota la sbarra per sganciarla: questa sarà la tua posizione di partenza. Solleva i talloni il più in alto possibile facendo leva sull''avampiede, contraendo il polpaccio nel punto massimo di contrazione. Le ginocchia devono rimanere estese. Mantieni la posizione di contrazione per un secondo prima di iniziare a scendere. Ritorna lentamente alla posizione di partenza espirando mentre abbassi i talloni. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Smith Machine Calf Raise';

UPDATE public.exercise_library 
SET name_it = 'Close-Grip Bench Press alla Smith Machine', description_it = 'Posiziona una panca piana sotto la Smith machine. Regola il bilanciere a un''altezza raggiungibile quando sei sdraiato e con le braccia quasi completamente estese. Una volta selezionato il peso, sdraiati sulla panca. Usando una presa stretta e prona (palmi rivolti in avanti), larga circa quanto le spalle, sblocca la sbarra e tienila dritta sopra di te con le braccia distese. Questa sarà la tua posizione di partenza. Inspirando, scendi lentamente finché la sbarra non tocca la parte centrale del petto. Suggerimento: a differenza della panca piana tradizionale, mantieni i gomiti vicini al busto per massimizzare il coinvolgimento dei tricipiti. Dopo una pausa di un secondo, riporta la sbarra alla posizione di partenza espirando e spingendo usando i tricipiti. Blocca le braccia nella posizione contratta, tieni per un secondo e ricomincia a scendere lentamente. Suggerimento: la fase di discesa dovrebbe durare almeno il doppio di quella di risalita. Ripeti per il numero di ripetizioni prescritto. Al termine, riaggancia la sbarra.' 
WHERE name = 'Smith Machine Close-Grip Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Decline Press alla Smith Machine', description_it = 'Posiziona una panca declinata nel rack in modo che la sbarra si trovi sopra il tuo petto. Carica un peso adeguato e sdraiati sulla panca. Ruota la sbarra per sganciarla e distendi completamente le braccia. La schiena dovrebbe essere leggermente arcuata e le scapole addotte. Questa sarà la posizione di partenza. Inizia il movimento flettendo le braccia e abbassando la sbarra verso il petto. Fermati brevemente, quindi estendi le braccia per spingere il peso verso la posizione di partenza. Dopo aver completato il numero di ripetizioni desiderato, ruota la sbarra per riagganciarla.' 
WHERE name = 'Smith Machine Decline Press';

UPDATE public.exercise_library 
SET name_it = 'Hang Power Clean alla Smith Machine', description_it = 'Posiziona la sbarra all''altezza delle ginocchia e carica un peso adeguato. Afferra la sbarra con presa prona, leggermente più larga delle spalle, e sganciala dalla macchina. Le braccia devono essere completamente distese con testa e petto alti. I gomiti devono essere rivolti verso l''esterno con le spalle indietro e verso il basso. I fianchi devono essere arretrati, caricando la tensione sui bicipiti femorali. Questa sarà la posizione di partenza. Inizia il movimento estendendo con forza anche e ginocchia, accelerando verso la sbarra. Mantieni le braccia tese durante questa parte del movimento. Al termine dell''estensione, fletti nuovamente anche e ginocchia per abbassare il corpo. Permetti alle braccia di flettersi, ruotando i gomiti attorno alla sbarra per riceverla sulle spalle. Estendi anche e ginocchia per tornare in posizione eretta con la sbarra sulle spalle per completare il movimento.' 
WHERE name = 'Smith Machine Hang Power Clean';

UPDATE public.exercise_library 
SET name_it = 'Hip Raise alla Smith Machine', description_it = 'Posiziona una panca nel rack e carica un peso adeguato sulla sbarra. Sdraiati sulla panca appoggiando la pianta dei piedi contro la sbarra. Sblocca la sbarra e distendi le gambe. Potresti aver bisogno di usare le mani come supporto. Per una maggiore stabilità, afferra i lati della Smith machine. Questa sarà la posizione di partenza. Inizia il movimento ruotando il bacino e flettendo la colonna vertebrale per sollevare i fianchi dalla panca. Mantieni una leggera flessione delle ginocchia durante tutto il movimento. Dopo una breve pausa, riporta i fianchi sulla panca. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Smith Machine Hip Raise';

UPDATE public.exercise_library 
SET name_it = 'Incline Bench Press alla Smith Machine', description_it = 'Posiziona una panca inclinata sotto la Smith machine. Regola il bilanciere a un''altezza raggiungibile da sdraiato con le braccia quasi completamente estese. Una volta selezionato il peso, sdraiati sulla panca assicurandoti che la parte superiore del petto sia allineata con il bilanciere. Con una presa prona (palmi in avanti) più larga delle spalle, sblocca la sbarra e tienila sopra di te con le braccia distese. Questa sarà la posizione di partenza. Inspirando, scendi lentamente finché la sbarra non tocca la parte superiore del petto. Dopo una pausa di un secondo, riporta la sbarra alla posizione di partenza espirando, usando i muscoli del petto. Blocca le braccia nella posizione contratta, tieni per un secondo e ricomincia a scendere. Suggerimento: la fase di discesa dovrebbe durare almeno il doppio di quella di risalita. Ripeti per le ripetizioni prescritte. Al termine, riaggancia la sbarra.' 
WHERE name = 'Smith Machine Incline Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Leg Press alla Smith Machine', description_it = 'Posiziona la sbarra della Smith machine a circa 60 cm dal suolo, assicurandoti che poggi sui fermi di sicurezza. Dopo aver caricato un peso adeguato, sdraiati sotto la sbarra. Appoggia la parte centrale dei piedi sulla sbarra e porta le ginocchia al petto. Questa sarà la posizione di partenza. Inizia il movimento spingendo la sbarra verso l''alto con i piedi, estendendo anche e ginocchia. Non bloccare completamente le ginocchia. Al culmine del movimento, fermati brevemente prima di tornare alla posizione di partenza.' 
WHERE name = 'Smith Machine Leg Press';

UPDATE public.exercise_library 
SET name_it = 'Upright Row a un braccio alla Smith Machine', description_it = 'Con la sbarra all''altezza delle cosce, carica un peso adeguato. Afferra la sbarra con una presa larga, sgancia il peso e libera l''altra mano. Il braccio deve essere disteso mentre sei in piedi, con testa e petto alti. Questa sarà la posizione di partenza. Inizia il movimento flettendo il gomito e sollevando la parte superiore del braccio, tenendo il gomito verso l''esterno. Continua finché il braccio non è parallelo al pavimento. Dopo una breve pausa, torna alla posizione di partenza. Ripeti per il numero di ripetizioni desiderato prima di riagganciare il peso.' 
WHERE name = 'Smith Machine One-Arm Upright Row';

UPDATE public.exercise_library 
SET name_it = 'Overhead Shoulder Press alla Smith Machine', description_it = 'Per iniziare, posiziona una panca piana (preferibilmente con supporto per la schiena) sotto la Smith machine. Regola il bilanciere a un''altezza tale che, da seduto, le braccia siano quasi completamente estese per raggiungerlo. Una volta definita l''altezza, siediti leggermente dietro il bilanciere in modo che ci sia una linea retta immaginaria tra la punta del naso e il bilanciere. I piedi devono rimanere fermi. Afferra il bilanciere con i palmi rivolti in avanti, sbloccalo e sollevalo finché le braccia non sono completamente distese. Questa è la posizione di partenza. Abbassa lentamente il bilanciere fino al livello del mento inspirando. Quindi, espirando, solleva nuovamente il bilanciere alla posizione di partenza usando le spalle. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Smith Machine Overhead Shoulder Press';

UPDATE public.exercise_library 
SET name_it = 'Pistol Squat alla Smith Machine', description_it = 'Per iniziare, regola la sbarra a un''altezza adatta alla tua statura. Posizionati sotto di essa e appoggia la sbarra sulla parte alta della schiena (sulle spalle). Afferra la sbarra con le mani rivolte in avanti, sbloccala e sollevala dal rack estendendo le gambe. Porta un piede in avanti di circa 30 cm rispetto alla sbarra. Distendi l''altra gamba davanti a te, tenendola sollevata da terra. Guarda sempre avanti e mantieni la colonna vertebrale in posizione neutra o leggermente arcuata. Questa sarà la posizione di partenza. Mantenendo una postura corretta, abbassati flettendo ginocchio e anca, scendendo fin dove la flessibilità lo consente. Fermati brevemente nel punto più basso, quindi torna alla posizione di partenza spingendo sul tallone e estendendo ginocchio e anca.' 
WHERE name = 'Smith Machine Pistol Squat';

UPDATE public.exercise_library 
SET name_it = 'Reverse Calf Raises alla Smith Machine', description_it = 'Regola il bilanciere della Smith Machine in base alla tua altezza e posiziona una piattaforma rialzata direttamente sotto la sbarra. Sali sulla piattaforma appoggiando gli avampiedi e lasciando i talloni sospesi. Posiziona le punte dei piedi in avanti con una larghezza pari a quella delle spalle. Posiziona le spalle sotto il bilanciere, mantieni la posizione dei piedi e spingi il bilanciere verso l''alto estendendo anche e ginocchia finché il busto non è eretto. Le ginocchia devono rimanere leggermente flesse, mai bloccate. Questa è la posizione di partenza. Suggerimento: il bilanciere sulla schiena serve solo per l''equilibrio. Espirando, solleva i talloni estendendo al massimo le punte dei piedi e contraendo il polpaccio. Assicurati che le ginocchia rimangano immobili. Non piegarle mai. Mantieni la posizione di contrazione per un secondo prima di scendere. Inspirando, torna lentamente alla posizione di partenza abbassando i talloni. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Smith Machine Reverse Calf Raises';

UPDATE public.exercise_library 
SET name_it = 'Squat alla Smith Machine', description_it = 'Per iniziare, imposta la sbarra all''altezza corretta. Una volta caricato il bilanciere, posizionati sotto di esso con la parte posteriore delle spalle (appena sotto il collo) appoggiata alla sbarra. Impugna il bilanciere con entrambe le mani (palmi rivolti in avanti), sbloccalo e sollevalo dal rack spingendo con le gambe e raddrizzando il busto. Posiziona le gambe a una larghezza media, pari a quella delle spalle, con le punte dei piedi leggermente rivolte verso l''esterno. Mantieni la testa alta e la schiena dritta. Questa è la posizione di partenza. Inizia ad abbassare lentamente il bilanciere flettendo le ginocchia e mantenendo la postura dritta. Scendi finché l''angolo tra coscia e polpaccio è leggermente inferiore a 90 gradi (punto in cui le cosce sono sotto il parallelo rispetto al pavimento). Inspira durante questa fase. Suggerimento: se l''esercizio è eseguito correttamente, le ginocchia non devono superare la linea immaginaria perpendicolare alle punte dei piedi. Espirando, spingi sui talloni per sollevare il bilanciere, raddrizzando le gambe fino alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Smith Machine Squat';

UPDATE public.exercise_library 
SET name_it = 'Stiff-Legged Deadlift alla Smith Machine', description_it = 'Imposta la sbarra della Smith Machine all''altezza della metà delle cosce. Afferra il bilanciere con una presa prona (palmi in avanti) alla larghezza delle spalle. Potresti aver bisogno di fasce per i polsi se utilizzi un carico elevato. Solleva il bilanciere estendendo completamente le braccia e mantenendo la schiena dritta. Stai con il busto eretto e i piedi alla larghezza delle spalle. Le ginocchia devono essere leggermente flesse. Questa è la posizione di partenza. Mantenendo le ginocchia ferme, abbassa il bilanciere verso i piedi flettendo il busto in avanti, mantenendo la schiena dritta. Spostati come se dovessi raccogliere qualcosa da terra finché non senti allungare i bicipiti femorali. Espira durante il movimento. Non appena senti l''allungamento, risali estendendo anche e busto fino alla posizione di partenza, inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Smith Machine Stiff-Legged Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Upright Row alla Smith Machine', description_it = 'Imposta la sbarra della Smith Machine all''altezza della metà delle cosce. Afferra il bilanciere con una presa prona (palmi in avanti) alla larghezza delle spalle. Solleva il bilanciere estendendo le braccia, mantenendo la schiena dritta e i gomiti leggermente flessi. Questa è la posizione di partenza. Espirando, solleva il bilanciere usando le spalle, mantenendolo vicino al corpo. Continua a sollevare finché la sbarra non sfiora quasi il mento. Suggerimento: i gomiti devono guidare il movimento; mantienili sempre più alti degli avambracci. Mantieni il busto fermo e fai una pausa di un secondo in alto. Inspira mentre torni lentamente alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Smith Machine Upright Row';

UPDATE public.exercise_library 
SET name_it = 'Single-Leg Split Squat alla Smith Machine', description_it = 'Posiziona una panca piana a 60-90 cm dietro la Smith Machine. Imposta la sbarra all''altezza corretta, posizionati sotto di essa con la parte posteriore delle spalle appoggiata e sbloccala. Posiziona un piede in avanti sotto la sbarra e appoggia il collo del piede opposto sulla panca. Questa è la posizione di partenza. Abbassa lentamente il bilanciere flettendo il ginocchio della gamba anteriore e mantenendo la schiena dritta e la testa alta. Scendi finché l''angolo tra coscia e polpaccio è leggermente inferiore a 90 gradi. Inspira durante la discesa. Suggerimento: il ginocchio non deve superare la linea immaginaria perpendicolare alla punta del piede. Espirando, spingi sul tallone per tornare alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato e poi cambia gamba.' 
WHERE name = 'Smith Single-Leg Split Squat';

UPDATE public.exercise_library 
SET name_it = 'Snatch', description_it = 'Posiziona i piedi alla larghezza delle spalle con il bilanciere sopra l''attaccatura delle dita dei piedi. Con una presa prona, fletti le ginocchia e, mantenendo la schiena piatta, afferra la sbarra con una presa più larga delle spalle. Abbassa il bacino come se dovessi sederti su una sedia. Questa è la posizione di partenza. Spingi con i piedi come se il pavimento fosse una piattaforma mobile, sollevando il bilanciere vicino alle gambe. Quando la sbarra arriva a metà coscia, estendi esplosivamente gambe, anche e busto. Esegui una scrollata di spalle mentre porti la sbarra in alto, tenendo i gomiti verso l''esterno e sopra il bilanciere il più a lungo possibile. Con un movimento rapido, posizionati sotto il bilanciere, bloccando le braccia sopra la testa in posizione di squat. Concludi alzandoti dalla posizione di squat mantenendo il bilanciere sopra la testa, piedi allineati e braccia completamente tese.' 
WHERE name = 'Snatch';

UPDATE public.exercise_library 
SET name_it = 'Snatch Balance', description_it = 'Parti con i piedi in posizione di trazione, il bilanciere poggiato sulla parte superiore della schiena e una presa larga da Snatch. Con un rapido affondo e una spinta delle ginocchia, scendi aggressivamente sotto il bilanciere, portando i piedi nella posizione di ricezione. Ricevi il bilanciere a braccia tese sopra la testa nella parte bassa dello squat. Il busto deve rimanere verticale mentre abbassi il bacino tra le gambe. Scendi fino alla massima profondità, poi torna in posizione eretta. Abbassa il carico con cautela.' 
WHERE name = 'Snatch Balance';

UPDATE public.exercise_library 
SET name_it = 'Snatch Deadlift', description_it = 'Lo Snatch Deadlift rafforza la prima fase della trazione dello Snatch. Inizia con una presa larga da Snatch, piedi sotto le anche e leggermente rivolti verso l''esterno. Accovacciati fino alla sbarra mantenendo la schiena in estensione e la testa in avanti. Inizia il movimento spingendo sui talloni e sollevando il bacino. L''angolo della schiena deve rimanere costante finché la sbarra non supera le ginocchia. A quel punto, spingi il bacino in avanti mentre ti inclini leggermente all''indietro. Riporta la sbarra sulla pedana invertendo il movimento.' 
WHERE name = 'Snatch Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Snatch Pull', description_it = 'Con il bilanciere a terra vicino alle tibie, impugna con presa larga da Snatch. Abbassa il bacino, peso sui talloni, schiena dritta, petto in fuori e spalle leggermente avanti rispetto alla sbarra. Questa è la posizione di partenza. Esegui la prima trazione spingendo sui talloni ed estendendo le ginocchia, mantenendo l''angolo della schiena e le braccia tese fino a superare le ginocchia. Segue la seconda trazione, fonte principale di accelerazione: quando la sbarra raggiunge la metà coscia, estendi energicamente anche, ginocchia e caviglie in un movimento simile a un salto. Non è necessario tirare attivamente con le braccia; il corpo deve essere completamente esteso e leggermente inclinato all''indietro. L''estensione finale deve essere esplosiva e rapida, evitando di prolungarla inutilmente.' 
WHERE name = 'Snatch Pull';

UPDATE public.exercise_library 
SET name_it = 'Snatch Shrug', description_it = 'Parti con una presa larga e il bilanciere che pende all''altezza della metà coscia. Puoi usare una presa a uncino (hook grip) o prona. La schiena deve essere dritta e leggermente inclinata in avanti. Esegui una scrollata di spalle verso le orecchie. Anche se questo esercizio permette solitamente carichi superiori allo Snatch, evita di sovraccaricare al punto da rallentare l''esecuzione.' 
WHERE name = 'Snatch Shrug';

UPDATE public.exercise_library 
SET name_it = 'Snatch from Blocks', description_it = 'Inizia con un bilanciere carico posizionato su blocchi o supporti all''altezza desiderata. Impugna il bilanciere con una presa larga. I piedi devono essere posizionati sotto le anche, ruotati verso l''esterno secondo necessità. Abbassa le anche mantenendo il petto alto e lo sguardo in avanti. Le spalle devono trovarsi appena davanti al bilanciere, con i gomiti rivolti verso l''esterno. Questa sarà la posizione di partenza. Inizia la prima trazione spingendo attraverso la parte anteriore dei talloni, sollevando il bilanciere dai blocchi. Passa alla seconda trazione estendendo anche, ginocchia e caviglie, spingendo il bilanciere verso l''alto il più velocemente possibile. Il bilanciere deve rimanere vicino al corpo. Alla massima estensione, effettua una scrollata di spalle e permetti ai gomiti di flettersi lateralmente. Mentre porti i piedi nella posizione di ricezione, tirati energicamente sotto il bilanciere sollevandolo sopra la testa. I piedi dovrebbero spostarsi appena oltre la larghezza delle anche, ruotati secondo necessità. Ricevi il bilanciere con il corpo il più in basso possibile e le braccia completamente estese sopra la testa. Mantenendo il bilanciere allineato sopra la parte anteriore dei talloni, la testa e il petto alti, spingi attraverso i talloni per tornare in posizione eretta. Riponi con cura il bilanciere sui blocchi.' 
WHERE name = 'Snatch from Blocks';

UPDATE public.exercise_library 
SET name_it = 'Speed Band Overhead Triceps', description_it = 'Per questo esercizio, ancora una banda elastica al suolo. Si può utilizzare una panca inclinata ancorando la banda alla base e stando in piedi sopra la panca, oppure stando in piedi direttamente sulla banda. Per iniziare, porta la banda dietro la testa tenendola con una presa prona e i gomiti alti. Questa è la posizione di partenza. Per eseguire il movimento, estendi il gomito per raddrizzare le braccia, assicurandoti di mantenere ferma la parte superiore delle braccia. Fai una pausa e torna alla posizione di partenza.' 
WHERE name = 'Speed Band Overhead Triceps';

UPDATE public.exercise_library 
SET name_it = 'Speed Box Squat', description_it = 'Attacca al bilanciere delle bande elastiche ancorate saldamente vicino al suolo. Potrebbe essere necessario avvolgerle per ottenere una tensione adeguata. Usa un box di altezza appropriata. Carica il bilanciere con un peso che richieda sforzo, ma che non comprometta la velocità; solitamente tra il 50% e il 70% del tuo massimale. Posiziona il bilanciere sulla parte alta della schiena, scapole addotte, schiena inarcata e corpo in tensione dalla testa ai piedi. Questa è la posizione di partenza. Stacca il bilanciere e posizionati davanti al box. Siediti all''indietro con le anche finché non tocchi il box, assicurandoti di scendere in modo controllato senza crollare sulla superficie. Fai una breve pausa, quindi esplodi verso l''alto estendendo anche e ginocchia.' 
WHERE name = 'Speed Box Squat';

UPDATE public.exercise_library 
SET name_it = 'Speed Squats', description_it = 'Questo esercizio va eseguito preferibilmente all''interno di un rack per motivi di sicurezza. Imposta il bilanciere all''altezza corretta, posizionati sotto di esso e appoggialo sulla parte posteriore delle spalle (appena sotto il collo). Impugna il bilanciere con entrambe le mani e sollevalo dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto. Allontanati dal rack e posiziona le gambe a una larghezza media (larghezza spalle) con le punte dei piedi leggermente rivolte verso l''esterno. Mantieni lo sguardo alto e la schiena dritta. Questa è la posizione di partenza. Inizia ad abbassare il bilanciere flettendo le ginocchia e mantenendo la postura dritta. Scendi finché l''angolo tra cosce e polpacci è leggermente inferiore a 90 gradi (cosce sotto il parallelo). Inspira durante la discesa. Suggerimento: le ginocchia non devono superare la linea immaginaria che parte dalle punte dei piedi per evitare stress eccessivo. Inizia la risalita il più velocemente possibile, senza usare lo slancio, espirando e spingendo sui talloni per tornare alla posizione eretta. Esegui il movimento alla massima velocità consentita da una forma perfetta.' 
WHERE name = 'Speed Squats';

UPDATE public.exercise_library 
SET name_it = 'Spell Caster', description_it = 'Impugna un manubrio in ogni mano con una presa prona. Tieni i piedi ben distanziati con anche e ginocchia estese. Questa è la posizione di partenza. Inizia il movimento tirando entrambi i manubri verso un fianco, ruotando il busto. Mantenendo le braccia dritte e i manubri paralleli al suolo, ruota il busto per far oscillare i pesi verso il lato opposto. Continua ad alternare, ruotando da un lato all''altro fino al completamento della serie.' 
WHERE name = 'Spell Caster';

UPDATE public.exercise_library 
SET name_it = 'Spider Crawl', description_it = 'Inizia in posizione prona a terra. Sostieni il peso su mani e punte dei piedi, con i piedi uniti e il corpo dritto. Le braccia devono essere flesse a 90 gradi. Questa è la posizione di partenza. Inizia il movimento sollevando un piede da terra. Ruota esternamente la gamba e porta il ginocchio verso il gomito il più in avanti possibile. Torna alla posizione di partenza e ripeti dal lato opposto.' 
WHERE name = 'Spider Crawl';

UPDATE public.exercise_library 
SET name_it = 'Spider Curl', description_it = 'Posiziona il bilanciere sulla parte della panca Scott dove solitamente ci si siede, assicurandoti che sia bilanciato. Spostati sul lato anteriore della panca (quello dove solitamente si appoggiano le braccia) e posizionati con il busto e lo stomaco appoggiati contro lo schienale inclinato a 45 gradi. Assicurati che i piedi siano ben piantati a terra e appoggia le braccia sulla parte superiore del cuscinetto. Afferra il bilanciere con una presa supina (palmi verso l''alto), larghezza spalle o leggermente più stretta. Solleva lentamente il bilanciere espirando. Mantieni la posizione di contrazione per un secondo strizzando i bicipiti. Torna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Spider Curl';

UPDATE public.exercise_library 
SET name_it = 'Spinal Stretch', description_it = 'Siediti su una sedia con la schiena dritta e i piedi appoggiati a terra. Intreccia le dita dietro la testa, con i gomiti rivolti verso l''esterno e il mento basso. Ruota la parte superiore del corpo verso un lato per circa 3 volte fin dove possibile. Quindi, piegati in avanti e ruota il busto per portare il gomito verso il pavimento all''interno del ginocchio. Torna in posizione eretta e ripeti dall''altro lato.' 
WHERE name = 'Spinal Stretch';

UPDATE public.exercise_library 
SET name_it = 'Split Clean', description_it = 'Con il bilanciere a terra vicino alle tibie, impugnalo con una presa prona appena oltre le gambe. Abbassa le anche con il peso sui talloni, schiena dritta, sguardo avanti, petto alto e spalle appena davanti al bilanciere. Questa è la posizione di partenza. Inizia la prima trazione spingendo sui talloni ed estendendo le ginocchia. L''angolo della schiena deve rimanere invariato e le braccia distese. Muovi il peso con controllo fin sopra le ginocchia. Passa alla seconda trazione: quando il bilanciere raggiunge la metà coscia, estendi le anche. Con un movimento simile a un salto, accelera estendendo anche, ginocchia e caviglie. Non c''è bisogno di tirare attivamente con le braccia; alla fine della seconda trazione, il corpo deve essere completamente esteso. Passa alla terza trazione scrollando energicamente le spalle e flettendo le braccia con i gomiti rivolti verso l''alto e l''esterno. Tirati rapidamente sotto il bilanciere ruotando i gomiti. Ricevi il bilanciere in posizione di affondo (split), portando un piede avanti e uno indietro. Il bilanciere deve poggiare sulle spalle, toccando leggermente la gola. Recupera subito spingendo sui talloni, mantenendo il busto eretto, e unisci i piedi.' 
WHERE name = 'Split Clean';

UPDATE public.exercise_library 
SET name_it = 'Split Jerk', description_it = 'Partendo con il bilanciere poggiato sulla parte anteriore delle spalle, inizia il dip (fase di spinta). Con i piedi sotto le anche, fletti le ginocchia senza spostare le anche all''indietro. Scendi leggermente e inverte la direzione il più potentemente possibile. Spingi sui talloni per creare velocità e forza, assicurandoti di spostare la testa all''indietro mentre il bilanciere si stacca dalle spalle. Nel momento in cui i piedi si staccano da terra, portali nella posizione di ricezione il più velocemente possibile. Nel breve momento in cui i piedi non spingono contro il suolo, lo sforzo di spingere il bilanciere ti farà scendere sotto di esso. I piedi devono trovarsi in una posizione di affondo (split), uno avanti e uno indietro, con le ginocchia parzialmente flesse. Ricevi il bilanciere con le braccia bloccate sopra la testa. Torna in posizione eretta unendo i piedi.' 
WHERE name = 'Split Jerk';

UPDATE public.exercise_library 
SET name_it = 'Split Jump', description_it = 'Assumi una posizione di affondo con un piede avanti e il ginocchio piegato, con il ginocchio posteriore quasi a contatto con il suolo. Assicurati che il ginocchio anteriore sia allineato con la linea mediana del piede. Spingendo con entrambe le gambe, salta il più in alto possibile, facendo oscillare le braccia per slanciarti. Durante il salto, unisci i piedi e riportali nella posizione iniziale mentre atterri. Ammortizza l''impatto tornando nella posizione di partenza.' 
WHERE name = 'Split Jump';

UPDATE public.exercise_library 
SET name_it = 'Split Snatch', description_it = 'Inizia con un bilanciere caricato a terra. La sbarra deve essere vicina o a contatto con le tibie; utilizza una presa larga. I piedi devono essere sotto le anche, leggermente ruotati verso l''esterno se necessario. Abbassa le anche mantenendo il petto alto e lo sguardo in avanti. Le spalle devono essere leggermente davanti alla sbarra. Questa è la posizione di partenza. Inizia il primo strappo spingendo attraverso l''avampiede per sollevare il bilanciere. L''angolo della schiena deve rimanere costante finché il bilanciere non supera le ginocchia. Passa al secondo strappo estendendo anche, ginocchia e caviglie, spingendo la sbarra verso l''alto il più velocemente possibile. Il bilanciere deve rimanere vicino al corpo. Alla massima estensione, solleva le spalle (shrug) e fletti i gomiti lateralmente. Mentre porti i piedi nella posizione di ricezione, tirati energicamente sotto la sbarra mentre la porti sopra la testa. I piedi devono scattare in posizione split, un piede avanti e uno indietro. Ricevi il bilanciere col corpo il più in basso possibile e le braccia completamente estese sopra la testa. Mantenendo il bilanciere allineato sopra i talloni, la testa e il petto alti, spingi attraverso i talloni per tornare in posizione eretta, unendo i piedi. Riporta il peso a terra con cura.' 
WHERE name = 'Split Snatch';

UPDATE public.exercise_library 
SET name_it = 'Split Squat con manubri', description_it = 'Posizionati in uno stance sfalsato con il piede posteriore sollevato e quello anteriore avanti. Tieni un manubrio in ciascuna mano, lasciandoli pendere lungo i fianchi. Questa è la posizione di partenza. Inizia la discesa flettendo ginocchio e anca per abbassare il corpo. Mantieni una postura corretta durante tutto il movimento. Tieni il ginocchio anteriore in linea con il piede durante l''esecuzione. Al punto più basso, spingi sul tallone per estendere ginocchio e anca e tornare alla posizione iniziale.' 
WHERE name = 'Split Squat with Dumbbells';

UPDATE public.exercise_library 
SET name_it = 'Split Squat (Jumping)', description_it = 'Inizia in posizione eretta. Salta portandoti in una posizione a gambe divise, con una gamba avanti e una indietro, flettendo le ginocchia e abbassando leggermente le anche. Durante la discesa, inverte immediatamente la direzione, saltando e invertendo la posizione delle gambe. Ripeti 5-10 volte per gamba.' 
WHERE name = 'Split Squats';

UPDATE public.exercise_library 
SET name_it = 'Squat Jerk', description_it = 'In piedi con il bilanciere appoggiato sulla parte anteriore delle spalle, inizia con il dip. Con i piedi sotto le anche, fletti le ginocchia senza spostare le anche all''indietro. Scendi solo leggermente e inverte il movimento con la massima potenza. Spingi sui talloni per generare velocità e forza, assicurandoti di spostare la testa all''indietro mentre il bilanciere lascia le spalle. Nel momento in cui i piedi lasciano il suolo, devono posizionarsi nella posizione di ricezione il più velocemente possibile. Nel breve istante in cui i piedi non spingono contro la pedana, lo sforzo per spingere il bilanciere verso l''alto spingerà l''atleta verso il basso. I piedi devono posizionarsi energicamente appena fuori dalle anche, ruotati verso l''esterno se necessario. Ricevi il bilanciere in uno squat completo con le braccia tese sopra la testa. Mantenendo il bilanciere allineato sopra i talloni, testa e petto alti, spingi sui talloni per tornare in piedi. Riporta il peso a terra con cura.' 
WHERE name = 'Squat Jerk';

UPDATE public.exercise_library 
SET name_it = 'Squat con elastici', description_it = 'Fissa gli elastici alle estremità del bilanciere, assicurandoli a perni, al rack o a manubri in modo da ottenere la tensione desiderata. Inizia posizionandoti sotto il bilanciere sulla parte alta della schiena. Stringi le scapole e ruota i gomiti in avanti, cercando di flettere il bilanciere sulle spalle. Stacca il bilanciere dal rack, crea un arco teso nella zona lombare e fai un passo indietro. Tieni i piedi larghi per enfatizzare il lavoro su schiena, glutei, adduttori e femorali. Guarda dritto davanti a te. Con schiena, spalle e core contratti, spingi le ginocchia e i glutei verso l''esterno iniziando la discesa. Spingi le anche il più indietro possibile. Idealmente, le tibie dovrebbero essere perpendicolari al terreno. Una posizione più bassa del bilanciere richiede una maggiore inclinazione del busto per mantenerlo sopra i talloni. Continua fino a superare il parallelo, definito come il punto in cui la piega dell''anca è in linea con la parte superiore del ginocchio. Mantenendo il peso sui talloni e spingendo piedi e ginocchia verso l''esterno, spingi verso l''alto guidando il movimento con la testa. Continua fino a tornare nella posizione iniziale, mantenendo tutto il corpo in tensione.' 
WHERE name = 'Squat with Bands';

UPDATE public.exercise_library 
SET name_it = 'Squat con catene', description_it = 'Per montare le catene, fai passare la catena guida sulle estremità del bilanciere. La catena pesante deve essere fissata con un moschettone. Regola la lunghezza in modo che alcune maglie tocchino ancora il suolo nella parte alta del movimento. Inizia posizionandoti sotto il bilanciere sulla schiena. Stringi le scapole e ruota i gomiti in avanti, cercando di flettere il bilanciere. Stacca il bilanciere dal rack, crea un arco teso nella zona lombare e fai un passo indietro. Tieni i piedi larghi per enfatizzare il lavoro su schiena, glutei, adduttori e femorali. Guarda dritto davanti a te. Con schiena, spalle e core contratti, spingi ginocchia e glutei verso l''esterno e inizia la discesa. Spingi le anche il più indietro possibile. Idealmente, le tibie dovrebbero essere perpendicolari al terreno. Una posizione più bassa del bilanciere richiede una maggiore inclinazione del busto per mantenerlo sopra i talloni. Continua fino a superare il parallelo, definito come il punto in cui la piega dell''anca è in linea con la parte superiore del ginocchio. Mantenendo il peso sui talloni e spingendo piedi e ginocchia verso l''esterno, spingi verso l''alto guidando il movimento con la testa. Continua fino a tornare nella posizione iniziale, mantenendo tutto il corpo in tensione.' 
WHERE name = 'Squat with Chains';

UPDATE public.exercise_library 
SET name_it = 'Squat con spostamento dischi', description_it = 'Posiziona il bilanciere sul rack appena sotto l''altezza delle spalle. Metti un disco a terra un paio di passi dietro il rack. Dopo aver caricato il bilanciere, posizionati sotto di esso e appoggialo sulla parte posteriore delle spalle. Afferra il bilanciere con entrambe le mani e sollevalo dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto. Allontanati dal rack e adotta uno stance largo con le punte dei piedi leggermente rivolte verso l''esterno, posizionando un piede sul disco a terra. Tieni la testa alta. Questa è la posizione di partenza. Inizia ad abbassare lentamente il bilanciere flettendo ginocchia e anche. Continua fino a quando l''angolo tra coscia e polpaccio diventa leggermente inferiore a 90 gradi. Risali espirando e spingendo sul pavimento con i talloni mentre estendi anche e ginocchia. Al vertice del movimento, fai un passo laterale unendo i piedi sul lato opposto del disco. Usando il piede interno, spingi il disco facendolo scivolare sul pavimento dove ti trovavi prima. Posiziona il piede interno sul disco e adotta nuovamente uno stance largo per la ripetizione successiva.' 
WHERE name = 'Squat with Plate Movers';

UPDATE public.exercise_library 
SET name_it = 'Squat con elastici (banda sotto i piedi)', description_it = 'Assicurati che l''elastico sia equamente distribuito tra il lato destro e sinistro del corpo. Afferra entrambe le estremità dell''elastico e posiziona entrambi i piedi al centro di esso. I piedi devono essere alla larghezza delle spalle. Tenendo gli elastici, dovrebbero trovarsi alla stessa altezza su entrambi i lati. Usa una presa prona (palmi rivolti in avanti) e tieni le maniglie vicino al viso. Questa è la posizione di partenza. Inizia a flettere le ginocchia e ad abbassare le gambe finché le cosce non sono parallele al pavimento, espirando. Spingi attraverso i talloni per tornare nella posizione di partenza mentre espiri. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Squats - With Bands';

UPDATE public.exercise_library 
SET name_it = 'Stairmaster', description_it = 'Sali sullo Stairmaster e seleziona l''opzione desiderata dal menu. Puoi scegliere un''impostazione manuale o selezionare un programma predefinito. Solitamente, puoi inserire età e peso per stimare le calorie bruciate durante l''esercizio. Muovi le gambe su e giù seguendo un ritmo costante, spingendo i pedali verso il basso senza arrivare a toccare il pavimento. Si raccomanda di mantenere la presa sui manubri per non perdere l''equilibrio. I manubri possono essere utilizzati per monitorare la frequenza cardiaca e mantenere un''intensità adeguata. Lo Stairmaster offre comodità, benefici cardiovascolari e generalmente un impatto minore rispetto alla corsa all''aperto. È tipicamente molto più impegnativo di altre macchine cardio.' 
WHERE name = 'Stairmaster';

UPDATE public.exercise_library 
SET name_it = 'Standing Alternating Dumbbell Press', description_it = 'In piedi, impugna un manubrio per mano. Porta i manubri all''altezza delle spalle con i palmi rivolti in avanti e i gomiti rivolti verso l''esterno. Questa è la posizione di partenza.
Distendi un braccio per spingere il manubrio verso l''alto, mantenendo l''altro braccio fermo. Evita di inclinare il busto o dare strattoni durante il movimento.
Dopo una breve pausa, riporta il peso nella posizione di partenza.
Ripeti con il lato opposto, continuando ad alternare le braccia.' 
WHERE name = 'Standing Alternating Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Standing Barbell Calf Raise', description_it = 'Per sicurezza, questo esercizio va eseguito all''interno di un rack. Regola il bilanciere su un rack all''altezza delle tue spalle. Una volta caricato, posizionati sotto la sbarra e appoggiala sulla parte posteriore delle spalle (appena sotto il collo).
Impugna il bilanciere con entrambe le mani e sollevalo dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto.
Allontanati dal rack e posiziona i piedi alla larghezza delle spalle con le punte leggermente rivolte verso l''esterno. Tieni la testa alta e la schiena dritta. Le ginocchia devono rimanere leggermente flesse, mai bloccate. Questa è la posizione di partenza. Suggerimento: per un maggiore range di movimento, puoi posizionare l''avampiede su un rialzo, prestando attenzione all''equilibrio.
Espirando, solleva i talloni estendendo le caviglie il più possibile e contraendo i polpacci. Assicurati che le ginocchia rimangano immobili. Mantieni la posizione di contrazione per un secondo prima di scendere.
Inspira e torna lentamente alla posizione di partenza abbassando i talloni fino ad avvertire l''allungamento dei polpacci.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Barbell Calf Raise';

UPDATE public.exercise_library 
SET name_it = 'Standing Barbell Press Behind Neck', description_it = 'Esegui l''esercizio all''interno di un rack. Regola il bilanciere su un rack all''altezza delle spalle, posizionati sotto di esso e appoggialo sulla parte posteriore delle spalle (appena sotto il collo).
Impugna la sbarra con entrambe le mani e sollevala dal rack spingendo con le gambe e raddrizzando il busto.
Allontanati dal rack, posiziona i piedi alla larghezza delle spalle con le punte leggermente rivolte verso l''esterno e mantieni la schiena dritta. Questa è la posizione di partenza.
Espirando, solleva il bilanciere sopra la testa distendendo completamente le braccia.
Mantieni la contrazione per un secondo, quindi inspira e abbassa il bilanciere fino alla posizione di partenza.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Barbell Press Behind Neck';

UPDATE public.exercise_library 
SET name_it = 'Standing Bent-Over One-Arm Dumbbell Triceps Extension', description_it = 'Con un manubrio in una mano e il palmo rivolto verso il busto, fletti leggermente le ginocchia e inclinati in avanti piegandoti dal bacino, mantenendo la schiena dritta finché non è quasi parallela al pavimento. Tieni la testa alta.
Il braccio deve rimanere vicino al busto e parallelo al pavimento, mentre l''avambraccio punta verso il suolo. Suggerimento: tra avambraccio e braccio deve esserci un angolo di 90 gradi. Questa è la posizione di partenza.
Mantenendo fermo il braccio, espira ed estendi l''avambraccio usando i tricipiti finché l''intero braccio è teso e parallelo al pavimento. Solo l''avambraccio deve muoversi.
Dopo un secondo di contrazione, inspira e torna lentamente alla posizione di partenza.
Ripeti per le ripetizioni prescritte, quindi cambia braccio.' 
WHERE name = 'Standing Bent-Over One-Arm Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Standing Bent-Over Two-Arm Dumbbell Triceps Extension', description_it = 'Con un manubrio per mano e i palmi rivolti verso il busto, fletti leggermente le ginocchia e piegati in avanti dal bacino mantenendo la schiena dritta, quasi parallela al suolo. Tieni la testa alta. Le braccia devono essere vicine al busto e parallele al pavimento, con gli avambracci rivolti verso il suolo. Suggerimento: tra avambraccio e braccio deve esserci un angolo di 90 gradi. Questa è la posizione di partenza.
Mantenendo le braccia ferme, espira ed estendi gli avambracci usando i tricipiti fino a quando le braccia sono completamente distese e parallele al pavimento. Solo gli avambracci devono muoversi.
Dopo un secondo di contrazione, inspira e torna lentamente alla posizione di partenza.
Ripeti per il numero di ripetizioni prescritte.' 
WHERE name = 'Standing Bent-Over Two-Arm Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Standing Biceps Cable Curl', description_it = 'In piedi, con il busto eretto, impugna la sbarra collegata a una carrucola bassa. Afferrala alla larghezza delle spalle, tieni i gomiti vicini al busto e i palmi rivolti verso l''alto (presa supinata). Questa è la posizione di partenza.
Mantenendo le braccia ferme, espira e fletti le braccia contraendo i bicipiti. Solo gli avambracci devono muoversi. Continua finché i bicipiti sono completamente contratti e la sbarra è all''altezza delle spalle. Mantieni la posizione per un secondo contraendo il muscolo.
Inspira e torna lentamente alla posizione di partenza.
Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Biceps Cable Curl';

UPDATE public.exercise_library 
SET name_it = 'Standing Biceps Stretch', description_it = 'Unisci le mani dietro la schiena con i palmi a contatto, distendi le braccia e ruotale in modo che i palmi siano rivolti verso il basso.
Solleva le braccia finché non avverti una tensione di allungamento nei bicipiti.' 
WHERE name = 'Standing Biceps Stretch';

UPDATE public.exercise_library 
SET name_it = 'Standing Bradford Press', description_it = 'Posiziona un bilanciere caricato su un rack all''altezza delle spalle. Con una presa prona alla larghezza delle spalle, inizia con il bilanciere appoggiato sulla parte anteriore delle spalle. Questa è la posizione di partenza.
Inizia il sollevamento distendendo i gomiti per portare il bilanciere sopra la testa. Evita di bloccare i gomiti mentre porti il peso dietro la nuca.
Abbassa il bilanciere dietro la testa finché i gomiti non formano un angolo retto.
Solleva nuovamente il bilanciere sopra la testa distendendo i gomiti.
Abbassa il bilanciere fino alla posizione di partenza.
Continua ad alternare fino a completare il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Bradford Press';

UPDATE public.exercise_library 
SET name_it = 'Standing Cable Chest Press', description_it = 'Posiziona le due carrucole all''altezza del petto e seleziona il carico. In piedi, a circa 30-60 cm davanti ai cavi, impugna un cavo per mano. Puoi tenere una posizione sfalsata dei piedi per una maggiore stabilità.
Posiziona le braccia con un angolo di 90 gradi e le scapole addotte. Questa è la posizione di partenza.
Mantenendo il resto del corpo immobile, distendi i gomiti per spingere le maniglie in avanti, avvicinandole l''una all''altra.
Fai una pausa al culmine del movimento e torna alla posizione di partenza.' 
WHERE name = 'Standing Cable Chest Press';

UPDATE public.exercise_library 
SET name_it = 'Standing Cable Lift', description_it = 'Collega una maniglia a una torre e sposta il cavo sulla posizione di carrucola più bassa.
Posizionati di fianco alla torre, afferra la maniglia con una mano e allontanati fino a sentire la tensione del cavo; il braccio teso deve essere allineato con il cavo.
Con i piedi alla larghezza delle spalle, accovacciati e afferra la maniglia con entrambe le mani, mantenendo le braccia completamente distese.
In un unico movimento fluido, tira la maniglia verso l''alto e attraverso il corpo finché le braccia non sono completamente distese sopra la testa.
Mantieni la schiena dritta e le braccia vicine al corpo mentre ruoti il piede posteriore e distendi le gambe per ottenere un range di movimento completo.
Riporta le braccia e il corpo nella posizione neutra in modo lento e controllato.
Ripeti fino ad esaurimento.
Cambia posizione e ripeti la serie di movimenti sul lato opposto.' 
WHERE name = 'Standing Cable Lift';

UPDATE public.exercise_library 
SET name_it = 'Standing Cable Wood Chop', description_it = 'Collega una maniglia standard a una torretta per cavi, posizionando la carrucola all''altezza massima. Mettiti di lato rispetto alla torretta, afferra la maniglia con una mano e allontanati fino a tendere il cavo; dovresti essere a circa una lunghezza di braccio dalla carrucola. Il braccio teso deve essere allineato con il cavo. Con i piedi alla larghezza delle spalle, afferra la maniglia con l''altra mano, mantenendo entrambe le braccia completamente estese. In un unico movimento fluido, tira la maniglia verso il basso e diagonalmente verso il ginocchio opposto, ruotando il busto. Mantieni schiena e braccia dritte e il core contratto, facendo perno sul piede posteriore e piegando le ginocchia per un range di movimento completo. Mantieni la postura e le braccia tese, quindi torna lentamente alla posizione neutra in modo controllato. Ripeti fino al cedimento, poi cambia lato e ripeti la serie.' 
WHERE name = 'Standing Cable Wood Chop';

UPDATE public.exercise_library 
SET name_it = 'Standing Calf Raises (Calf Raise alla macchina)', description_it = 'Regola il cuscinetto della macchina in base alla tua altezza. Posiziona le spalle sotto i cuscinetti e le punte dei piedi in avanti (o nelle altre posizioni descritte nel capitolo). L''avampiede deve poggiare sull''apposito rialzo, con i talloni nel vuoto. Spingi la leva verso l''alto estendendo anche e ginocchia finché il busto non è eretto. Mantieni le ginocchia leggermente flesse, mai bloccate. Questa è la posizione di partenza. Espirando, solleva i talloni estendendo al massimo le caviglie e contraendo i polpacci. Assicurati che le ginocchia rimangano ferme e non si pieghino. Mantieni la contrazione per un secondo prima di scendere. Inspirando, torna lentamente alla posizione iniziale abbassando i talloni finché i polpacci non sono allungati. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Standing Calf Raises';

UPDATE public.exercise_library 
SET name_it = 'Standing Concentration Curl', description_it = 'Impugna un manubrio e chinati in avanti. Lascia che il braccio che lavora penda perpendicolare al suolo con il gomito rivolto verso l''esterno. Questa è la posizione di partenza. Fletti il gomito per sollevare il peso, mantenendo la parte superiore del braccio ferma. Al culmine della ripetizione, contrai il bicipite e fai una pausa. Abbassa il manubrio tornando alla posizione di partenza. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Standing Concentration Curl';

UPDATE public.exercise_library 
SET name_it = 'Standing Dumbbell Calf Raise', description_it = 'In piedi, con il busto eretto, impugna due manubri lungo i fianchi. Posiziona l''avampiede su un supporto stabile (alto circa 5-7 cm) lasciando i talloni sospesi. Questa è la posizione di partenza. Con le punte dei piedi dritte, verso l''interno o verso l''esterno, espira e solleva i talloni contraendo i polpacci. Mantieni la contrazione per un secondo. Inspirando, torna lentamente alla posizione iniziale abbassando i talloni. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Standing Dumbbell Calf Raise';

UPDATE public.exercise_library 
SET name_it = 'Standing Dumbbell Press', description_it = 'In piedi con i piedi alla larghezza delle spalle, impugna un manubrio per mano. Porta i manubri all''altezza della testa con i gomiti piegati a circa 90 gradi. Questa è la posizione di partenza. Mantenendo una tecnica rigorosa, senza spinta delle gambe o oscillazioni del busto, estendi i gomiti per sollevare i pesi contemporaneamente fin sopra la testa. Fai una pausa e torna lentamente alla posizione iniziale.' 
WHERE name = 'Standing Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Standing Dumbbell Reverse Curl', description_it = 'In piedi, impugna un manubrio in ogni mano con una presa prona (palmi rivolti verso il basso). Le braccia devono essere completamente distese e i piedi alla larghezza delle spalle. Questa è la posizione di partenza. Mantenendo la parte superiore del braccio ferma, espira e fletti i gomiti contraendo i bicipiti. Solo gli avambracci devono muoversi. Continua finché i bicipiti non sono contratti e i manubri sono all''altezza delle spalle. Mantieni la contrazione per un secondo, contraendo il muscolo. Inspirando, torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Standing Dumbbell Reverse Curl';

UPDATE public.exercise_library 
SET name_it = 'Standing Dumbbell Straight-Arm Front Delt Raise Above Head', description_it = 'Impugna i manubri davanti alle cosce, con i palmi rivolti verso le gambe. Mantieni le braccia tese con una leggera flessione dei gomiti (bloccati in quella posizione). Questa è la posizione di partenza. Espirando, solleva i manubri con un movimento semicircolare fino sopra la testa. Inspirando, torna lentamente alla posizione iniziale seguendo lo stesso percorso. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Standing Dumbbell Straight-Arm Front Delt Raise Above Head';

UPDATE public.exercise_library 
SET name_it = 'Standing Dumbbell Triceps Extension', description_it = 'In piedi, afferra un manubrio con entrambe le mani. Sollevalo sopra la testa finché le braccia non sono completamente estese. Il peso deve poggiare sui palmi con i pollici che lo avvolgono, rivolti verso il soffitto. Questa è la posizione di partenza. Mantenendo la parte superiore delle braccia vicino alla testa e i gomiti perpendicolari al suolo, abbassa il manubrio dietro la testa con un movimento semicircolare finché gli avambracci non toccano i bicipiti. Suggerimento: la parte superiore delle braccia deve restare ferma. Inspira durante la discesa. Usa i tricipiti per sollevare il peso tornando alla posizione iniziale ed espira durante lo sforzo. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Standing Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Standing Dumbbell Upright Row', description_it = 'Impugna un manubrio per mano con presa prona (palmi verso il corpo) leggermente più stretta della larghezza delle spalle. I manubri poggiano sulle cosce, le braccia sono tese con i gomiti leggermente piegati e la schiena dritta. Questa è la posizione di partenza. Espirando, solleva i manubri usando i deltoidi laterali; mantieni i manubri vicini al corpo e guida il movimento con i gomiti. Solleva finché i manubri quasi toccano il mento. Suggerimento: i gomiti devono rimanere sempre più alti degli avambracci. Mantieni il busto fermo e fai una pausa al culmine del movimento. Inspirando, abbassa lentamente i manubri alla posizione di partenza. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Standing Dumbbell Upright Row';

UPDATE public.exercise_library 
SET name_it = 'Standing Elevated Quad Stretch', description_it = 'In piedi, posizionati a circa 60-90 cm da una panca o uno step. Solleva una gamba all''indietro e poggia il piede sullo step (sul collo del piede o sull''avampiede, in base alla comodità). Mantieni il ginocchio della gamba di supporto leggermente piegato, evitando che superi la punta del piede. Cambia gamba.' 
WHERE name = 'Standing Elevated Quad Stretch';

UPDATE public.exercise_library 
SET name_it = 'Sollevamento frontale del bilanciere sopra la testa in piedi', description_it = 'Per iniziare, mettiti in piedi con un bilanciere tra le mani. Impugna la sbarra con i palmi rivolti verso il basso e una presa leggermente più stretta della larghezza delle spalle. I piedi devono essere alla larghezza delle spalle. Tieni i gomiti leggermente flessi. Questa è la posizione di partenza. Espirando, solleva il bilanciere fino a portarlo direttamente sopra la testa. Assicurati di mantenere i gomiti leggermente flessi durante l''esecuzione di ogni ripetizione. Una volta avvertita la contrazione, inspira e inizia ad abbassare il bilanciere fino alla posizione di partenza. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Front Barbell Raise Over Head';

UPDATE public.exercise_library 
SET name_it = 'Stretching del gastrocnemio in piedi', description_it = 'Posiziona il tallone destro su un gradino con il ginocchio teso e chinati in avanti per afferrare la punta del piede destro con la mano destra. Il ginocchio sinistro deve essere leggermente flesso e la schiena dritta. Scarica il peso sulla gamba sinistra e appoggia la mano sinistra sulla coscia sinistra. Tira le dita del piede destro verso il ginocchio finché non senti allungare il polpaccio.' 
WHERE name = 'Standing Gastrocnemius Calf Stretch';

UPDATE public.exercise_library 
SET name_it = 'Stretching di ischiocrurali e polpacci in piedi', description_it = 'Inizia facendo passare una fascia, una corda o un asciugamano attorno a un piede. In piedi, porta avanti il piede interessato. Fletti la gamba posteriore mantenendo tesa quella anteriore. Ora solleva la punta del piede anteriore da terra e chinati in avanti. Usando la fascia, tira la parte superiore del piede per aumentare l''allungamento del polpaccio. Mantieni la posizione per 10-20 secondi e ripeti con l''altro piede.' 
WHERE name = 'Standing Hamstring and Calf Stretch';

UPDATE public.exercise_library 
SET name_it = 'Circonduzioni dell''anca in piedi', description_it = 'Inizia in piedi su una gamba, tenendoti a un supporto verticale. Solleva il ginocchio della gamba libera a 90 gradi. Questa è la posizione di partenza. Apri l''anca il più possibile, cercando di disegnare un ampio cerchio con il ginocchio. Esegui il movimento lentamente per il numero di ripetizioni indicato, quindi ripeti sull''altro lato.' 
WHERE name = 'Standing Hip Circles';

UPDATE public.exercise_library 
SET name_it = 'Stretching dei flessori dell''anca in piedi', description_it = 'Stai in piedi con la colonna vertebrale in verticale e il piede sinistro leggermente più avanti del destro. Piega entrambe le ginocchia e solleva il tallone posteriore da terra spingendo l''anca destra in avanti. Nota: in questa posizione è difficile ottenere uno stretching profondo e completo, poiché è complicato rilassare il flessore dell''anca mentre ci si poggia sopra. Cambia lato.' 
WHERE name = 'Standing Hip Flexors';

UPDATE public.exercise_library 
SET name_it = 'Inner Biceps Curl in piedi', description_it = 'In piedi, tieni un manubrio per mano lungo i fianchi. I gomiti devono essere vicini al busto e le gambe divaricate alla larghezza delle spalle. Ruota i palmi delle mani in una posizione neutra. Questa è la posizione di partenza. Mantenendo la parte superiore delle braccia ferma, espira ed esegui un curl verso l''esterno contraendo i bicipiti. Ruota il polso in modo che, a sollevamento completo, la presa sia supinata (palmi rivolti verso l''alto). Solo gli avambracci devono muoversi. Continua finché i bicipiti non sono completamente contratti e i manubri sono all''altezza delle spalle. Suggerimento: tieni gli avambracci allineati con i deltoidi esterni. Mantieni la contrazione per un secondo, strizzando i bicipiti. Inspira e abbassa lentamente i manubri fino alla posizione iniziale. Ricorda di ruotare i polsi durante la discesa per tornare alla presa neutra. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Inner-Biceps Curl';

UPDATE public.exercise_library 
SET name_it = 'Stretching laterale in piedi', description_it = 'Divarica i piedi leggermente più delle anche e mantieni le ginocchia leggermente flesse. Appoggia la mano destra sul fianco destro per sostenere la colonna. Solleva il braccio sinistro in verticale e porta la mano dietro la testa. Mantieni la posizione mentre inclini il busto verso destra. Distribuisci il peso uniformemente tra le due gambe (non spostarlo sul fianco sinistro). Cambia lato.' 
WHERE name = 'Standing Lateral Stretch';

UPDATE public.exercise_library 
SET name_it = 'Leg Curl in piedi', description_it = 'Regola la leva del macchinario in base alla tua altezza. Inclinati in avanti con il busto di circa 30-45 gradi (una posizione angolata favorisce il reclutamento degli ischiocrurali) con l''imbottitura della leva dietro la gamba destra (appena sotto il polpaccio) e la parte anteriore della gamba appoggiata sull''imbottitura della macchina. Mantenendo il busto inclinato, assicurati che la gamba sia completamente tesa e afferra le maniglie laterali. Punta le dita dei piedi in avanti. Questa è la posizione di partenza. Espirando, fletti la gamba destra il più possibile senza sollevare la coscia dall''imbottitura. Una volta raggiunta la massima contrazione, mantieni la posizione per un secondo. Inspira e riporta la gamba nella posizione iniziale. Ripeti per il numero di ripetizioni raccomandato. Esegui lo stesso esercizio con la gamba sinistra.' 
WHERE name = 'Standing Leg Curl';

UPDATE public.exercise_library 
SET name_it = 'Salto in lungo da fermo', description_it = 'Questo esercizio è ideale se eseguito sulla sabbia o su una superficie morbida. Assicurati di poter misurare la distanza. Mettiti in posizione di semi-squat con i piedi alla larghezza delle spalle. Sfruttando un ampio slancio delle braccia e una contro-oscillazione delle gambe, salta in avanti il più lontano possibile. Cerca di atterrare con i piedi ben distesi in avanti. Misura la distanza dal punto di atterraggio al punto di partenza e registra i risultati.' 
WHERE name = 'Standing Long Jump';

UPDATE public.exercise_library 
SET name_it = 'Sollevamento laterale ai cavi bassi', description_it = 'Mettiti in piedi sul lato destro rispetto a una carrucola bassa. Con la mano sinistra, incrocia il corpo e afferra la maniglia singola con una presa prona (palmi verso il basso). Tieni il braccio davanti a te. La mano destra può afferrare la struttura per supporto ed equilibrio. Mantieni la schiena eretta e i piedi alla larghezza delle spalle. Questa è la posizione di partenza. Espirando, solleva la mano sinistra diagonalmente davanti al corpo fino all''altezza della spalla. Senti la contrazione per un secondo in cima, poi inspira e abbassa lentamente la maniglia fino alla posizione iniziale. Ripeti per il numero di ripetizioni raccomandato. Cambia braccio e ripeti l''esercizio.' 
WHERE name = 'Standing Low-Pulley Deltoid Raise';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti a un braccio ai cavi bassi in piedi', description_it = 'Afferra una maniglia singola con la mano sinistra vicino alla macchina a cavi bassi. Voltati dando le spalle alla macchina, tenendo la maniglia al fianco con il braccio completamente esteso. Ora usa entrambe le mani per portare la maniglia direttamente sopra la testa con il palmo rivolto in avanti. Mantieni la parte superiore del braccio completamente verticale (perpendicolare al pavimento) e appoggia la mano destra sul gomito sinistro per tenerlo fermo. Questa è la posizione di partenza. Tenendo le braccia vicine alla testa (gomiti chiusi) e perpendicolari al pavimento, abbassa il carico con un movimento semicircolare dietro la testa finché gli avambracci non toccano i bicipiti. Suggerimento: la parte superiore delle braccia deve rimanere ferma e solo gli avambracci devono muoversi. Inspira durante questa fase. Torna alla posizione di partenza usando i tricipiti per sollevare la maniglia. Espira durante questa fase. Ripeti per il numero di ripetizioni raccomandato. Cambia braccio e ripeti l''esercizio.' 
WHERE name = 'Standing Low-Pulley One-Arm Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Military Press in piedi', description_it = 'Inizia posizionando un bilanciere all''altezza del petto su un rack per squat. Dopo aver caricato i pesi, afferra il bilanciere con una presa prona (palmi rivolti in avanti). Assicurati che la presa sia più larga della larghezza delle spalle. Piega leggermente le ginocchia e appoggia il bilanciere sulle clavicole. Solleva il bilanciere tenendolo aderente al petto. Fai un passo indietro e posiziona i piedi alla larghezza delle spalle. Una volta presa la giusta impugnatura, spingi il bilanciere sopra la testa bloccando le braccia. Fermati all''altezza delle spalle, leggermente davanti alla testa. Questa è la posizione di partenza. Abbassa lentamente il bilanciere fino alle clavicole mentre inspiri. Riporta il bilanciere alla posizione di partenza mentre espiri. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Military Press';

UPDATE public.exercise_library 
SET name_it = 'Squeeze con dischi olimpionici in piedi', description_it = 'Per iniziare, resta in piedi con la schiena dritta e tieni un disco per pesi con una mano, afferrandolo dal bordo con una presa neutra (palmi rivolti verso l''interno). I piedi devono essere alla larghezza delle spalle. Questa sarà la posizione di partenza. Abbassa i dischi finché le dita non sono quasi estese ma riescono ancora a reggere il peso. Inspira mentre abbassi i dischi. Ora solleva i dischi fino alla posizione di partenza espirando e chiudendo le mani. Ripeti per il numero di ripetizioni prescritte dal tuo programma.' 
WHERE name = 'Standing Olympic Plate Hand Squeeze';

UPDATE public.exercise_library 
SET name_it = 'Curl ai cavi a un braccio in piedi', description_it = 'Inizia afferrando una maniglia singola collegata alla puleggia bassa. Assicurati di essere abbastanza lontano dalla macchina in modo che il braccio sostenga il peso. Mantieni la parte superiore del braccio ferma, perpendicolare al pavimento, con il gomito vicino al corpo e il palmo rivolto in avanti. Il braccio che non lavora può essere appoggiato sulla vita per mantenere l''equilibrio. Inizia lentamente a flettere il braccio portando la maniglia verso l''alto, mantenendo la parte superiore del braccio ferma, finché l''avambraccio non tocca il bicipite, espirando. Suggerimento: solo l''avambraccio deve muoversi. Mantieni la contrazione strizzando il bicipite, quindi abbassa la maniglia alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato. Cambia braccio ed esegui l''esercizio.' 
WHERE name = 'Standing One-Arm Cable Curl';

UPDATE public.exercise_library 
SET name_it = 'Curl con manubrio a un braccio su panca inclinata', description_it = 'Mettiti dietro una panca inclinata come se dovessi fare da spotter. Tieni un manubrio in una mano e appoggia il braccio sulla panca inclinata con una presa supinata (palmo rivolto verso l''alto). Posiziona l''altra mano sull''angolo o sul lato della panca inclinata. Il petto deve essere premuto contro la parte superiore della panca e i piedi ben piantati a terra con una posizione ampia. Questa è la posizione di partenza. Mantenendo la parte superiore del braccio ferma, fletti il manubrio verso l''alto contraendo il bicipite ed espirando. Solo l''avambraccio deve muoversi. Continua il movimento finché il bicipite non è completamente contratto e il manubrio è all''altezza della spalla. Mantieni la contrazione per un secondo. Ritorna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato. Cambia braccio ed esegui l''esercizio.' 
WHERE name = 'Standing One-Arm Dumbbell Curl Over Incline Bench';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti a un braccio con manubrio in piedi', description_it = 'Inizia in piedi con un manubrio in una mano. I piedi devono essere alla larghezza delle spalle. Distendi completamente il braccio con il manubrio sopra la testa. Suggerimento: il mignolo della mano deve essere rivolto verso il soffitto e il palmo rivolto in avanti. Questa è la posizione di partenza. Tenendo la parte superiore del braccio vicina alla testa (gomito chiuso) e perpendicolare al pavimento, abbassa il carico con un movimento semicircolare dietro la testa finché l''avambraccio non tocca il bicipite. Suggerimento: la parte superiore del braccio deve rimanere ferma. Inspira durante questa fase. Torna alla posizione di partenza usando i tricipiti per sollevare il manubrio. Espira durante questa fase. Ripeti per il numero di ripetizioni raccomandato. Cambia braccio e ripeti l''esercizio.' 
WHERE name = 'Standing One-Arm Dumbbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti sopra la testa con bilanciere in piedi', description_it = 'Inizia in piedi, tenendo un bilanciere (o un bilanciere EZ) con una presa prona (palmi rivolti in avanti) e le mani più strette della larghezza delle spalle. I piedi devono essere alla larghezza delle spalle. Solleva il bilanciere sopra la testa finché le braccia non sono completamente distese. Mantieni i gomiti chiusi. Questa è la posizione di partenza. Tenendo le braccia vicine alla testa e perpendicolari al pavimento, abbassa il carico con un movimento semicircolare dietro la testa finché gli avambracci non toccano i bicipiti. Suggerimento: la parte superiore delle braccia deve rimanere ferma e solo gli avambracci devono muoversi. Inspira durante questa fase. Torna alla posizione di partenza usando i tricipiti per sollevare il bilanciere. Espira durante questa fase. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Overhead Barbell Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Press a un braccio con manubrio (presa neutra) in piedi', description_it = 'Inizia con un manubrio in una mano, braccio completamente esteso lateralmente con una presa neutra. Usa l''altro braccio per tenerti a una panca inclinata e mantenere l''equilibrio. I piedi devono essere alla larghezza delle spalle. Solleva lentamente il manubrio fino a creare un angolo di 90 gradi con il braccio. Nota: l''avambraccio deve essere perpendicolare al pavimento. Mantieni sempre una presa neutra. Solleva lentamente il manubrio finché il braccio non è completamente esteso. Questa è la posizione di partenza. Inspira mentre abbassi il peso finché il braccio non forma di nuovo un angolo di 90 gradi. Senti la contrazione per un secondo, poi solleva il peso verso la posizione di partenza espirando. Ricorda di sostenerti alla panca e mantenere i piedi ben posizionati per l''equilibrio. Ripeti per il numero di ripetizioni raccomandato. Cambia braccio e ripeti l''esercizio.' 
WHERE name = 'Standing Palm-In One-Arm Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Press con manubri (presa neutra) in piedi', description_it = 'Inizia con un manubrio in ogni mano, braccia completamente estese lateralmente con una presa neutra. I piedi devono essere alla larghezza delle spalle. Solleva lentamente i manubri fino a creare un angolo di 90 gradi con le braccia. Nota: gli avambracci devono essere perpendicolari al pavimento. Questa è la posizione di partenza. Mantieni la presa neutra per tutto l''esercizio. Solleva lentamente i manubri finché le braccia non sono completamente estese. Inspira mentre abbassi i pesi fino a tornare a un angolo di 90 gradi. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Standing Palms-In Dumbbell Press';

UPDATE public.exercise_library 
SET name_it = 'Wrist curl dietro la schiena con bilanciere in piedi', description_it = 'Inizia in piedi, tenendo un bilanciere dietro i glutei a braccia tese con una presa prona (palmi rivolti indietro, lontano dai glutei) e le mani alla larghezza delle spalle. Guarda dritto davanti a te con i piedi alla larghezza delle spalle. Questa è la posizione di partenza. Espirando, solleva lentamente il bilanciere flettendo i polsi con un movimento semicircolare verso il soffitto. Nota: il polso deve essere l''unica parte del corpo a muoversi durante l''esercizio. Mantieni la contrazione per un secondo e abbassa il bilanciere alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato. Una volta finito, abbassa il bilanciere sul rack o a terra piegando le ginocchia. Suggerimento: è più facile prenderlo da un rack o farsi aiutare da un compagno.' 
WHERE name = 'Standing Palms-Up Barbell Behind The Back Wrist Curl';

UPDATE public.exercise_library 
SET name_it = 'Basculamento del bacino in piedi', description_it = 'Inizia con i piedi alla larghezza delle anche. Piega leggermente le ginocchia per mantenerle morbide e flessibili. Puoi muovere il bacino in avanti e indietro alcune volte prima di mantenere il coccige ruotato in avanti in questo allungamento.' 
WHERE name = 'Standing Pelvic Tilt';

UPDATE public.exercise_library 
SET name_it = 'Standing Rope Crunch', description_it = 'Aggancia una corda a una carrucola alta e seleziona un peso adeguato. Mettiti in piedi dando le spalle alla torre dei cavi. Impugna la corda con entrambe le mani sopra le spalle, tenendola vicino alla parte superiore del petto. Questa è la posizione di partenza. Esegui il movimento flettendo la colonna vertebrale, contraendo l''addome per portare il peso verso il basso il più possibile. Mantieni la massima contrazione per un istante prima di tornare alla posizione di partenza.' 
WHERE name = 'Standing Rope Crunch';

UPDATE public.exercise_library 
SET name_it = 'Stretching del soleo e del tendine d''Achille in piedi', description_it = 'In piedi con i piedi alla larghezza delle anche, un piede leggermente davanti all''altro. Piega entrambe le ginocchia, mantenendo il tallone posteriore a terra. Cambia lato.' 
WHERE name = 'Standing Soleus And Achilles Stretch';

UPDATE public.exercise_library 
SET name_it = 'Toccate delle punte in piedi', description_it = 'Mettiti in piedi con spazio sufficiente davanti e dietro di te. Piegati in vita, mantenendo le gambe tese, finché non riesci a rilassarti lasciando che la parte superiore del corpo penda in avanti. Lascia cadere le braccia e le mani naturalmente. Mantieni la posizione per 10-20 secondi.' 
WHERE name = 'Standing Toe Touches';

UPDATE public.exercise_library 
SET name_it = 'Estensioni tricipiti con asciugamano in piedi', description_it = 'Inizia in piedi con entrambe le braccia completamente distese sopra la testa, impugnando un''estremità di un asciugamano con entrambe le mani. I gomiti devono essere chiusi e le braccia perpendicolari al pavimento, con i palmi rivolti l''uno verso l''altro; i piedi devono essere alla larghezza delle spalle. Questa è la posizione di partenza. Chiedi al tuo partner di afferrare l''altra estremità dell''asciugamano per applicare resistenza. Mantenendo la parte superiore delle braccia vicina alla testa (gomiti chiusi) e perpendicolare al pavimento, abbassa la resistenza con un movimento semicircolare dietro la testa finché gli avambracci non toccano i bicipiti. Consiglio: la parte superiore delle braccia deve rimanere ferma e devono muoversi solo gli avambracci. Inspira durante questa fase. Torna alla posizione di partenza usando i tricipiti per sollevare l''asciugamano. Espira durante questa fase. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Standing Towel Triceps Extension';

UPDATE public.exercise_library 
SET name_it = 'Lancio della palla medica sopra la testa in piedi', description_it = 'In piedi con i piedi alla larghezza delle spalle, tieni una palla medica con entrambe le mani. Per iniziare, porta la palla medica profondamente dietro la testa piegando leggermente le ginocchia e inclinando il busto all''indietro. Lancia con forza la palla in avanti, flettendo le anche e utilizzando tutto il corpo per completare il movimento. La palla medica può essere lanciata a un partner o contro una parete, ricevendola al rimbalzo.' 
WHERE name = 'Standing Two-Arm Overhead Throw';

UPDATE public.exercise_library 
SET name_it = 'Star Jump', description_it = 'Inizia in una posizione rilassata con i piedi alla larghezza delle spalle e le braccia vicine al corpo. Per iniziare il movimento, esegui mezzo squat ed esplodi verso l''alto il più in alto possibile. Estendi completamente tutto il corpo, allargando gambe e braccia verso l''esterno. Durante l''atterraggio, riporta gli arti verso il centro e ammortizza l''impatto attraverso le gambe.' 
WHERE name = 'Star Jump';

UPDATE public.exercise_library 
SET name_it = 'Step-up con sollevamento ginocchio', description_it = 'In piedi di fronte a un box o una panca di altezza adeguata con i piedi uniti. Questa è la posizione di partenza. Inizia il movimento salendo sul box con il piede sinistro. Estendi l''anca e il ginocchio della gamba anteriore per portarti in posizione eretta sul box. Mentre sei in piedi sul box con la gamba sinistra, fletti il ginocchio e l''anca destra, portando il ginocchio il più in alto possibile. Inverti il movimento per scendere dal box e ripeti la sequenza con la gamba opposta.' 
WHERE name = 'Step-up with Knee Raise';

UPDATE public.exercise_library 
SET name_it = 'Step Mill', description_it = 'Per iniziare, sali sullo step mill e seleziona l''opzione desiderata dal menu. Puoi scegliere un''impostazione manuale o selezionare un programma preimpostato. Solitamente puoi inserire età e peso per stimare le calorie bruciate durante l''esercizio. Fai attenzione a non inciampare mentre sali le scale. Si raccomanda di mantenere la presa sui manubri per evitare di cadere. Lo step mill offre comodità, benefici cardiovascolari e solitamente ha un impatto minore rispetto alla corsa all''aperto, offrendo un tasso di consumo calorico simile. È solitamente molto più intenso di altri attrezzi cardio. Una persona di 68 kg brucerà in media oltre 300 calorie in 30 minuti, rispetto alle circa 175 calorie della camminata.' 
WHERE name = 'Step Mill';

UPDATE public.exercise_library 
SET name_it = 'Stacco a gambe tese con bilanciere', description_it = 'Afferra un bilanciere con una presa prona (palmi rivolti verso il basso). Potresti aver bisogno di fasce da polso se utilizzi un peso significativo. In piedi con il busto dritto e i piedi alla larghezza delle spalle o più stretti. Le ginocchia devono essere leggermente flesse. Questa è la posizione di partenza. Mantenendo le ginocchia ferme, abbassa il bilanciere verso la parte superiore dei piedi flettendoti dalle anche e mantenendo la schiena dritta. Continua a muoverti in avanti come se volessi raccogliere qualcosa da terra finché non senti allungare i muscoli posteriori della coscia. Inspira durante l''esecuzione di questo movimento. Riporta il busto in posizione eretta estendendo le anche finché non torni nella posizione iniziale. Espira durante l''esecuzione del movimento. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Stiff-Legged Barbell Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Stacco a gambe tese con manubri', description_it = 'Afferra due manubri tenendoli lungo i fianchi a braccia tese. Stai in piedi con il busto dritto e i piedi a una larghezza pari o inferiore a quella delle spalle. Le ginocchia devono essere leggermente flesse. Questa è la tua posizione di partenza. Mantenendo le ginocchia ferme, abbassa i manubri oltre la punta dei piedi piegandoti in vita e tenendo la schiena dritta. Continua il movimento in avanti come se dovessi raccogliere qualcosa da terra, finché non senti allungare i muscoli femorali. Espira durante questa fase. Torna nella posizione di partenza estendendo fianchi e busto fino a raddrizzarti. Inspira durante il movimento. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Stiff-Legged Dumbbell Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Good Morning a gambe tese con bilanciere', description_it = 'Questo esercizio va eseguito preferibilmente all''interno di un rack per motivi di sicurezza. Imposta il bilanciere su un rack all''altezza appropriata. Una volta caricato il bilanciere, posizionati sotto di esso e appoggialo sulla parte posteriore delle spalle (appena sotto il collo). Afferra il bilanciere con entrambe le mani e sollevalo dal rack spingendo con le gambe e raddrizzando contemporaneamente il busto. Allontanati dal rack e posiziona le gambe a una larghezza media, pari a quella delle spalle. Tieni sempre la testa alta e la schiena dritta; guardare verso il basso compromette l''equilibrio. Questa è la posizione di partenza. Mantenendo le gambe ferme, piegati in avanti all''altezza delle anche espirando. Abbassa il busto finché non è parallelo al pavimento. Risali nella posizione di partenza mentre espiri. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Stiff Leg Barbell Good Morning';

UPDATE public.exercise_library 
SET name_it = 'Stomach Vacuum', description_it = 'Inizia stando in piedi con i piedi alla larghezza delle spalle. Appoggia le mani sui fianchi. Questa è la posizione di partenza. Ora inspira lentamente quanta più aria possibile e poi inizia a espirare completamente, tirando l''addome verso l''interno il più possibile e mantieni la posizione. Cerca di visualizzare l''ombelico che tocca la colonna vertebrale. Una contrazione isometrica dura circa 20 secondi. Durante il mantenimento, cerca di respirare normalmente. Quindi inspira e riporta lo stomaco nella posizione iniziale. Una volta acquisita pratica, cerca di eseguire l''esercizio per più di 20 secondi. Consiglio: puoi arrivare progressivamente a 40-60 secondi. Ripeti per il numero di serie consigliato.' 
WHERE name = 'Stomach Vacuum';

UPDATE public.exercise_library 
SET name_it = 'Pullover con manubrio a braccia tese', description_it = 'Posiziona un manubrio in verticale su una panca piana. Assicurati che sia stabile, quindi sdraiati perpendicolarmente alla panca (con il busto di traverso), appoggiando solo le scapole sulla superficie. I fianchi devono essere più bassi della panca e le gambe piegate con i piedi ben piantati a terra. Anche la testa rimarrà fuori dalla panca. Afferra il manubrio con entrambe le mani e tienilo dritto sopra il petto a braccia tese. Entrambi i palmi devono spingere contro la parte inferiore di uno dei dischi del manubrio. Questa è la tua posizione di partenza. Attenzione: assicurati sempre che il manubrio sia ben serrato per evitare che i dischi cadano. Mantenendo le braccia tese, abbassa lentamente il peso descrivendo un arco dietro la testa, inspirando finché non senti allungare il torace. A quel punto, riporta il manubrio nella posizione iniziale seguendo lo stesso arco ed espirando. Trattieni il peso nella posizione iniziale per un secondo e ripeti.' 
WHERE name = 'Straight-Arm Dumbbell Pullover';

UPDATE public.exercise_library 
SET name_it = 'Pulldown a braccia tese', description_it = 'Inizia afferrando la barra lunga fissata alla carrucola alta di una macchina per lat machine, utilizzando una presa prona (palmi verso il basso) più larga delle spalle. Fai un paio di passi indietro. Piega il busto in avanti di circa 30 gradi tenendo le braccia completamente distese davanti a te con i gomiti leggermente flessi. Se le braccia non sono completamente tese, fai un altro passo indietro. Una volta in posizione, contrai i dorsali. Mantenendo le braccia tese, tira la barra verso il basso fino a portare le mani vicino alle cosce, espirando durante il movimento. Torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Straight-Arm Pulldown';

UPDATE public.exercise_library 
SET name_it = 'Rematore con bilanciere su panca', description_it = 'Posiziona un bilanciere carico su un''estremità della panca. Stando in piedi sulla panca dietro la barra, afferrala con una presa prona di media larghezza. Tieni i fianchi indietro e il petto in fuori, mantenendo la colonna vertebrale in posizione neutra. Questa è la posizione di partenza. Tira la barra verso il busto retrando le scapole e flettendo i gomiti. Usa un movimento controllato senza strattoni. Dopo una breve pausa, riporta lentamente la barra nella posizione iniziale, assicurandoti di scendere completamente.' 
WHERE name = 'Straight Bar Bench Mid Rows';

UPDATE public.exercise_library 
SET name_it = 'Alzate a braccia tese su panca inclinata', description_it = 'Posiziona un bilanciere a terra dietro la parte superiore di una panca inclinata. Sdraiati sulla panca a faccia in giù. Con una presa prona, solleva il bilanciere da terra mantenendo le braccia tese. Lascia che la barra penda verso il basso. Questa è la posizione di partenza. Solleva il bilanciere davanti alla testa mantenendo le braccia estese. Torna alla posizione di partenza.' 
WHERE name = 'Straight Raises on Incline Bench';

UPDATE public.exercise_library 
SET name_it = 'Stride Jump Crossover', description_it = 'Mettiti di lato rispetto a un box con il piede interno appoggiato sopra di esso, vicino al bordo. Inizia oscillando le braccia verso l''alto mentre spingi con la gamba sul box, saltando il più in alto possibile. Cerca di portare il ginocchio opposto verso l''alto. Atterra nella posizione opposta a quella di partenza, sull''altro lato del box. Il piede che inizialmente era sul box si troverà ora a terra, mentre l''altro sarà sopra il box. Ripeti il movimento tornando al lato di partenza.' 
WHERE name = 'Stride Jump Crossover';

UPDATE public.exercise_library 
SET name_it = 'Stacco Sumo', description_it = 'Inizia con un bilanciere a terra. Avvicinati alla barra in modo che questa intersechi il centro dei piedi. I piedi devono essere molto larghi, vicino ai collari. Piega i fianchi per afferrare la barra. Le braccia devono essere direttamente sotto le spalle, all''interno delle gambe; puoi usare una presa prona, mista o a uncino (hook grip). Rilassa le spalle per allungare le braccia. Inspira, abbassa i fianchi, guarda dritto davanti a te e tieni il petto alto. Spingi attraverso il pavimento allargando i piedi, con il peso sulla parte posteriore dei piedi. Estendi fianchi e ginocchia. Quando la barra supera le ginocchia, sposta le anche in avanti verso il bilanciere e unisci le scapole. Riporta il peso a terra piegandoti sui fianchi e controllando il carico durante la discesa.' 
WHERE name = 'Sumo Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Stacco Sumo con elastici', description_it = 'Per eseguire lo stacco con elastici corti, avvolgili semplicemente attorno al bilanciere prima di iniziare e posiziona i piedi all''interno. Assicurati che gli elastici siano sotto la parte posteriore del piede, esattamente nel punto in cui spingi verso il pavimento. Inizia con un bilanciere a terra. Avvicinati alla barra in modo che questa intersechi il centro dei piedi. I piedi devono essere molto larghi, vicino ai collari. Piega i fianchi per afferrare la barra. Le braccia devono essere direttamente sotto le spalle, all''interno delle gambe. Inspira, abbassa i fianchi, guarda dritto davanti a te e tieni il petto alto. Spingi attraverso il pavimento allargando i piedi. Estendi fianchi e ginocchia. Quando la barra supera le ginocchia, sposta le anche in avanti verso il bilanciere e unisci le scapole. Riporta il peso a terra piegandoti sui fianchi e controllando il carico durante la discesa.' 
WHERE name = 'Sumo Deadlift with Bands';

UPDATE public.exercise_library 
SET name_it = 'Sumo Deadlift con catene', description_it = 'Puoi fissare le catene ai manicotti del bilanciere o semplicemente farle passare sopra di esso, in modo da ottenere un aumento di carico maggiore durante la fase di sollevamento. Cerca di tenere le estremità delle catene lontane dai dischi per evitare che vi urtino durante la discesa. Inizia con un bilanciere caricato a terra. Posizionati in modo che il bilanciere intersechi la metà dei piedi. I piedi devono essere molto distanti, vicino ai collari. Fletti le anche per afferrare il bilanciere. Le braccia devono trovarsi direttamente sotto le spalle, all''interno delle gambe; puoi utilizzare una presa prona, una presa mista o una presa a gancio (hook grip). Rilassa le spalle, il che allungherà le braccia. Inspira, quindi abbassa le anche, guardando avanti con la testa e tenendo il petto alto. Spingi attraverso il pavimento, divaricando i piedi e mantenendo il peso sulla parte posteriore dei piedi. Estendi anche e ginocchia. Quando il bilanciere supera le ginocchia, sposta leggermente il busto all''indietro e spingi le anche verso il bilanciere, contraendo le scapole. Riporta il peso a terra flettendo le anche e controllando il movimento durante la discesa.' 
WHERE name = 'Sumo Deadlift with Chains';

UPDATE public.exercise_library 
SET name_it = 'Superman', description_it = 'Per iniziare, sdraiati a pancia in giù sul pavimento o su un tappetino. Le braccia devono essere completamente distese davanti a te. Questa è la posizione di partenza. Solleva simultaneamente braccia, gambe e petto dal pavimento e mantieni la contrazione per 2 secondi. Consiglio: contrai la zona lombare per ottenere i migliori risultati. Ricordati di espirare durante il movimento. Nota: quando mantieni la posizione contratta, dovresti ricordare Superman in volo. Torna lentamente alla posizione di partenza abbassando braccia, gambe e petto mentre inspiri. Ripeti per il numero di ripetizioni prescritto nel tuo programma.' 
WHERE name = 'Superman';

UPDATE public.exercise_library 
SET name_it = 'Supine Chest Throw', description_it = 'Questo esercizio è ottimo per i passaggi al petto quando non hai un partner o una parete sufficientemente resistente. Sdraiati a terra sulla schiena con le ginocchia flesse. Inizia con la palla sul petto, tenendola con entrambe le mani nella parte inferiore. Esplodi verso l''alto, distendendo i gomiti per lanciare la palla direttamente sopra di te il più in alto possibile. Afferra la palla con entrambe le mani mentre ricade.' 
WHERE name = 'Supine Chest Throw';

UPDATE public.exercise_library 
SET name_it = 'Supine One-Arm Overhead Throw', description_it = 'Sdraiati a terra sulla schiena con le ginocchia flesse. Tieni la palla con una mano, distendendo completamente il braccio dietro la testa. Questa sarà la tua posizione di partenza. Inizia il movimento dalla spalla, lanciando la palla direttamente davanti a te mentre ti sollevi, cercando di ottenere la massima distanza. La palla può essere lanciata a un partner o fatta rimbalzare contro una parete.' 
WHERE name = 'Supine One-Arm Overhead Throw';

UPDATE public.exercise_library 
SET name_it = 'Supine Two-Arm Overhead Throw', description_it = 'Sdraiati a terra sulla schiena con le ginocchia flesse. Tieni la palla con entrambe le mani, distendendo completamente le braccia dietro la testa. Questa sarà la tua posizione di partenza. Inizia il movimento dalla spalla, lanciando la palla direttamente davanti a te mentre ti sollevi, cercando di ottenere la massima distanza. La palla può essere lanciata a un partner o fatta rimbalzare contro una parete.' 
WHERE name = 'Supine Two-Arm Overhead Throw';

UPDATE public.exercise_library 
SET name_it = 'Suspended Fallout', description_it = 'Regola le cinghie in modo che le maniglie siano a un''altezza appropriata, sotto il livello della vita. Inizia in piedi afferrando le maniglie. Inclinati verso le cinghie, portandoti in una posizione di piegamento inclinato. Questa sarà la tua posizione di partenza. Mantenendo le braccia tese, inclinati ulteriormente verso le cinghie, avvicinando il corpo al suolo e permettendo alle spalle di estendersi, sollevando le braccia sopra la testa. Mantieni la colonna vertebrale in posizione neutra e il corpo dritto; le spalle devono essere le uniche articolazioni a muoversi. Fai una pausa al picco della contrazione, quindi torna alla posizione di partenza.' 
WHERE name = 'Suspended Fallout';

UPDATE public.exercise_library 
SET name_it = 'Suspended Push-Up', description_it = 'Ancora le cinghie in sospensione saldamente alla parte superiore di un rack o di un altro supporto. Inclinandoti verso le cinghie, prendi una maniglia in ogni mano e mettiti in posizione di plank per piegamenti. Dovresti essere il più parallelo possibile al suolo con le braccia completamente estese, mantenendo una buona postura. Mantenendo il busto dritto e rigido, scendi lentamente flettendo i gomiti. Continua finché i gomiti superano i 90 gradi, facendo una pausa prima di estenderli per tornare alla posizione di partenza.' 
WHERE name = 'Suspended Push-Up';

UPDATE public.exercise_library 
SET name_it = 'Suspended Reverse Crunch', description_it = 'Fissa un set di cinghie in sospensione con le maniglie a circa 30 cm da terra. Mettiti in posizione di plank per piegamenti dando le spalle al rack. Inserisci i piedi nelle maniglie. Mantieni una postura dritta, evitando che i fianchi cedano. Questa sarà la posizione di partenza. Inizia il movimento flettendo ginocchia e anche, portando le ginocchia verso il busto. Mentre lo fai, inclina il bacino in avanti, permettendo alla colonna vertebrale di flettersi. Al termine del movimento controllato, torna alla posizione di partenza.' 
WHERE name = 'Suspended Reverse Crunch';

UPDATE public.exercise_library 
SET name_it = 'Suspended Row', description_it = 'Sospendi le cinghie all''altezza del petto. Prendi una maniglia per mano e inclinati all''indietro. Mantieni il corpo eretto, con testa e petto alti. Le braccia devono essere completamente distese. Questa sarà la posizione di partenza. Inizia flettendo i gomiti per avviare il movimento. Durante il movimento, protrai le scapole. Al completamento del gesto, fai una pausa e torna alla posizione di partenza.' 
WHERE name = 'Suspended Row';

UPDATE public.exercise_library 
SET name_it = 'Suspended Split Squat', description_it = 'Sospendi le cinghie in modo che le maniglie siano a 45-75 cm dal pavimento. Dando le spalle al punto di ancoraggio, posiziona il piede posteriore nella maniglia dietro di te. Mantieni lo sguardo in avanti e il petto alto, con il ginocchio leggermente flesso. Questa sarà la posizione di partenza. Scendi flettendo ginocchio e anche, avvicinandoti al suolo. Mantieni il peso sul tallone del piede a terra e mantieni la postura corretta durante tutto l''esercizio. Al punto più basso, inverte il movimento, estendendo anca e ginocchio per tornare alla posizione di partenza.' 
WHERE name = 'Suspended Split Squat';

UPDATE public.exercise_library 
SET name_it = 'Svend Press', description_it = 'Parti in posizione eretta. Premi due dischi leggeri l''uno contro l''altro con le mani. Tieni i dischi uniti vicino al petto per creare una contrazione isometrica dei muscoli pettorali. Le dita devono essere rivolte in avanti. Questa è la posizione di partenza. Stringi i dischi tra i palmi ed estendi le braccia direttamente davanti a te con un movimento controllato. Fai una pausa al culmine del movimento e torna lentamente alla posizione iniziale.' 
WHERE name = 'Svend Press';

UPDATE public.exercise_library 
SET name_it = 'T-Bar Row con maniglia', description_it = 'Posiziona un bilanciere in un supporto landmine o in un angolo per evitare che si sposti. Carica un peso adeguato all''estremità. Posizionati sopra il bilanciere e aggancia una maniglia Double D vicino al collare. Usando gambe e anche, sollevati in posizione eretta. Assumi una posizione con piedi larghi, anche spinte all''indietro e petto in fuori. Le braccia devono essere tese. Questa è la posizione di partenza. Tira il peso verso la parte superiore dell''addome retrattando le scapole e flettendo i gomiti. Non strattonare il peso e non eseguire il movimento con slanci scorretti. Dopo una breve pausa, torna alla posizione iniziale.' 
WHERE name = 'T-Bar Row with Handle';

UPDATE public.exercise_library 
SET name_it = 'Tate Press', description_it = 'Sdraiati su una panca piana con un manubrio in ogni mano appoggiato sulle cosce. I palmi delle mani devono essere rivolti l''uno verso l''altro. Usando le cosce per aiutare il sollevamento, porta i manubri nella posizione iniziale davanti a te, all''altezza delle spalle. Nota: le braccia devono essere più larghe delle spalle con una presa prona (palmi in avanti) e i gomiti devono puntare verso l''esterno. Mantenendo la parte superiore delle braccia ferma, sposta lentamente i manubri verso l''interno e verso il basso con un movimento semicircolare finché non toccano la parte alta del petto, inspirando durante la fase. Mantieni il controllo totale e non appoggiare i manubri sul petto. Espirando, spingi i manubri verso l''alto usando i tricipiti con lo stesso movimento semicircolare inverso. Cerca di tenere i manubri uniti mentre salgono. Distendi le braccia nella posizione contratta, mantieni per un secondo e riparti lentamente. Consiglio: la fase di discesa dovrebbe durare almeno il doppio di quella di salita. Ripeti per il numero di ripetizioni previsto.' 
WHERE name = 'Tate Press';

UPDATE public.exercise_library 
SET name_it = 'The Straddle', description_it = 'Inizia in posizione seduta, con la schiena dritta. Allarga le gambe davanti a te formando una V. Con le mani a terra, inclinati in avanti il più possibile. Mantieni la posizione per 10-20 secondi.' 
WHERE name = 'The Straddle';

UPDATE public.exercise_library 
SET name_it = 'Abductor Machine', description_it = 'Siediti sulla macchina abductor e seleziona un peso confortevole. Una volta posizionate correttamente le gambe, impugna le maniglie laterali. L''intera parte superiore del corpo (dalla vita in su) deve rimanere ferma. Questa è la posizione di partenza. Espirando, spingi lentamente contro la macchina per allontanare le gambe l''una dall''altra. Senti la contrazione per un secondo e torna lentamente alla posizione iniziale inspirando. Nota: mantieni il busto fermo per evitare infortuni. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Thigh Abductor';

UPDATE public.exercise_library 
SET name_it = 'Adductor Machine', description_it = 'Siediti sulla macchina adductor e seleziona un peso confortevole. Posiziona le gambe sugli appositi cuscinetti e impugna le maniglie laterali. L''intera parte superiore del corpo (dalla vita in su) deve rimanere ferma. Questa è la posizione di partenza. Espirando, spingi lentamente contro la macchina per avvicinare le gambe tra loro. Senti la contrazione per un secondo e torna lentamente alla posizione iniziale inspirando. Nota: mantieni il busto fermo ed evita movimenti bruschi per prevenire infortuni. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Thigh Adductor';

UPDATE public.exercise_library 
SET name_it = 'Tire Flip (Ribaltamento pneumatico)', description_it = 'Afferra la parte inferiore dello pneumatico sul battistrada e posiziona i piedi leggermente all''indietro. Il petto deve spingere contro lo pneumatico. Per sollevare, distendi anche, ginocchia e caviglie, spingendo in avanti e verso l''alto. Quando lo pneumatico raggiunge un angolo di 45 gradi, fai un passo avanti e spingi con un ginocchio contro lo pneumatico. Contemporaneamente, sposta la presa sulla parte superiore e spingi in avanti con la massima forza per completare il ribaltamento. Ripeti se necessario.' 
WHERE name = 'Tire Flip';

UPDATE public.exercise_library 
SET name_it = 'Toe Touchers', description_it = 'Sdraiati a terra o su un tappetino con la schiena ben premuta al suolo. Le braccia devono essere lungo i fianchi con i palmi rivolti verso il basso. Le gambe devono essere unite. Solleva lentamente le gambe finché non sono quasi perpendicolari al pavimento, mantenendo una leggera flessione alle ginocchia. I piedi devono essere paralleli al soffitto. Porta le braccia in avanti, distese a un angolo di 45 gradi rispetto al pavimento. Questa è la posizione di partenza. Mantenendo la zona lombare premuta a terra, solleva lentamente il busto e cerca di toccare le punte dei piedi con le mani, espirando durante il movimento. Torna lentamente alla posizione iniziale inspirando, mantenendo le braccia tese verso le punte dei piedi. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Toe Touchers';

UPDATE public.exercise_library 
SET name_it = 'Rotazione del busto', description_it = 'In piedi, tieni una palla fitness con entrambe le mani. Estendi le braccia davanti a te. Questa è la posizione di partenza. Ruota il busto di lato, seguendo la palla con lo sguardo mentre ti muovi. Ora ruota verso la direzione opposta. Ripeti per 10-20 ripetizioni.' 
WHERE name = 'Torso Rotation';

UPDATE public.exercise_library 
SET name_it = 'Trail Running/Walking', description_it = 'Correre o camminare sui sentieri stimola immediatamente la circolazione e il battito cardiaco. Assicurati di indossare calzature adatte. Mentre usi i muscoli dei polpacci e dei glutei per salire, ginocchia, articolazioni e caviglie assorbono gran parte dell''impatto in discesa. Fai passi più brevi durante la discesa, mantieni le ginocchia flesse per ridurre l''impatto e rallenta per evitare cadute. Una persona di 68 kg (150 libbre) può bruciare oltre 200 calorie in 30 minuti di camminata in salita, rispetto alle 175 su superficie piana. Se si corre sul sentiero, la stessa persona può bruciare ben oltre 500 calorie in 30 minuti.' 
WHERE name = 'Trail Running/Walking';

UPDATE public.exercise_library 
SET name_it = 'Stacco con Trap Bar', description_it = 'Carica una trap bar (nota anche come hex bar) con un peso adeguato poggiato a terra. Posizionati al centro dell''attrezzo e afferra entrambe le impugnature. Abbassa il bacino, guarda in avanti tenendo la testa alta e mantieni il petto in fuori. Inizia il movimento spingendo attraverso i talloni ed estendendo anche e ginocchia. Evita in ogni momento di inarcare la schiena. Al termine del movimento, riporta il peso a terra mantenendo il controllo.' 
WHERE name = 'Trap Bar Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Kickback con manubri per tricipiti', description_it = 'Inizia con un manubrio in ogni mano e i palmi rivolti verso il busto. Mantieni la schiena dritta con una leggera flessione delle ginocchia e inclinati in avanti con il busto, che dovrebbe risultare quasi parallelo al pavimento. Tieni la testa alta. Le braccia devono restare vicine al busto e parallele al pavimento, mentre gli avambracci devono puntare verso il basso, formando un angolo di 90 gradi con le braccia. Questa è la posizione di partenza. Espira e, mantenendo le braccia ferme, utilizza i tricipiti per sollevare i pesi fino a completa estensione. Concentrati sul movimento dell''avambraccio. Dopo una breve pausa in fase di massima contrazione, inspira e abbassa lentamente i manubri fino alla posizione iniziale. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Tricep Dumbbell Kickback';

UPDATE public.exercise_library 
SET name_it = 'Stretching laterale per tricipiti', description_it = 'Porta il braccio destro davanti al corpo verso la spalla sinistra, afferrando il gomito con la mano sinistra fino a sentire un allungamento del tricipite. Ripeti poi con l''altro braccio.' 
WHERE name = 'Tricep Side Stretch';

UPDATE public.exercise_library 
SET name_it = 'Estensioni sopra la testa con corda', description_it = 'Collega una corda a una carrucola bassa. Dopo aver selezionato un peso adeguato, afferra la corda con entrambe le mani e dai le spalle alla macchina. Posiziona le mani dietro la testa con i gomiti rivolti verso l''alto. I gomiti devono essere inizialmente flessi; puoi sfalsare la posizione dei piedi e inclinarti leggermente in avanti per una maggiore stabilità. Questa è la posizione di partenza. Esegui il movimento estendendo i gomiti verso l''alto, mantenendo la parte superiore delle braccia fissa. Contrai i tricipiti al culmine del movimento e torna lentamente alla posizione iniziale.' 
WHERE name = 'Triceps Overhead Extension with Rope';

UPDATE public.exercise_library 
SET name_it = 'Pushdown per tricipiti', description_it = 'Collega una sbarra dritta o angolata a una carrucola alta e afferrala con una presa prona (palmi rivolti verso il basso) a larghezza spalle. In posizione eretta con il busto dritto e una leggera inclinazione in avanti, tieni le braccia vicine al corpo e perpendicolari al pavimento. Gli avambracci puntano verso la carrucola. Questa è la posizione di partenza. Spingi la sbarra verso il basso usando i tricipiti finché le braccia non sono completamente estese perpendicolarmente al pavimento. Le braccia devono restare ferme lungo i fianchi, muovendo solo gli avambracci. Espira durante il movimento. Dopo una breve pausa in contrazione, risali lentamente verso il punto di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Triceps Pushdown';

UPDATE public.exercise_library 
SET name_it = 'Pushdown per tricipiti con corda', description_it = 'Collega una corda a una carrucola alta e afferrala con una presa neutra (palmi rivolti l''uno verso l''altro). In posizione eretta con il busto dritto e una leggera inclinazione in avanti, tieni le braccia vicine al corpo e perpendicolari al pavimento. Gli avambracci puntano verso la carrucola. Questa è la posizione di partenza. Usa i tricipiti per spingere la corda verso il basso, portando le estremità ai lati delle cosce. Al termine del movimento, le braccia sono completamente estese. Le braccia devono restare ferme lungo i fianchi, muovendo solo gli avambracci. Espira durante il movimento. Dopo una breve pausa in contrazione, risali lentamente verso il punto di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Triceps Pushdown - Rope Attachment';

UPDATE public.exercise_library 
SET name_it = 'Pushdown per tricipiti con V-Bar', description_it = 'Collega una V-Bar a una carrucola alta e afferrala con presa prona a larghezza spalle. In posizione eretta, busto dritto e leggera inclinazione in avanti, tieni le braccia vicine al corpo e perpendicolari al pavimento. Gli avambracci puntano verso la carrucola. I pollici devono trovarsi più in alto rispetto ai mignoli. Questa è la posizione di partenza. Usando i tricipiti, spingi la barra verso il basso fino a toccare la parte anteriore delle cosce, estendendo completamente le braccia. Le braccia devono restare ferme lungo i fianchi, muovendo solo gli avambracci. Espira durante il movimento. Dopo una breve pausa in contrazione, risali lentamente verso il punto di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Triceps Pushdown - V-Bar Attachment';

UPDATE public.exercise_library 
SET name_it = 'Stretching per tricipiti', description_it = 'Porta la mano dietro la testa, afferra il gomito e tira delicatamente. Mantieni la posizione per 10-20 secondi, poi cambia lato.' 
WHERE name = 'Triceps Stretch';

UPDATE public.exercise_library 
SET name_it = 'Tuck Crunch', description_it = 'Sdraiati a terra con la schiena ben appoggiata. Braccia distese lungo i fianchi con i palmi rivolti verso il basso. Incrocia una caviglia sull''altra. Solleva lentamente le gambe finché le cosce non sono perpendicolari al pavimento, con le ginocchia leggermente flesse. Porta le braccia incrociate sul petto. Questa è la posizione di partenza. Mantenendo la parte bassa della schiena a contatto col suolo, solleva lentamente il busto espirando. Inizia a scendere lentamente verso la posizione iniziale inspirando. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Tuck Crunch';

UPDATE public.exercise_library 
SET name_it = 'Preacher Curl con due manubri', description_it = 'Afferra un manubrio per mano e appoggia la parte superiore delle braccia su una panca Scott (preacher bench) o una panca inclinata. I manubri devono trovarsi all''altezza delle spalle. Questa è la posizione di partenza. Inspira e abbassa lentamente i manubri fino a estendere completamente le braccia e allungare i bicipiti. Espira e usa i bicipiti per sollevare i pesi fino a quando i bicipiti non sono completamente contratti e i manubri all''altezza delle spalle. Stringi i bicipiti con forza per un secondo in fase di contrazione e ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Two-Arm Dumbbell Preacher Curl';

UPDATE public.exercise_library 
SET name_it = 'Two-Arm Kettlebell Clean', description_it = 'Posiziona due kettlebell tra i piedi. Per assumere la posizione di partenza, spingi il bacino all''indietro e guarda dritto davanti a te. Esegui il clean dei kettlebell verso le spalle estendendo gambe e anche mentre sollevi i pesi verso l''alto. Ruota i polsi durante il movimento. Riporta i kettlebell nella posizione di partenza e ripeti.' 
WHERE name = 'Two-Arm Kettlebell Clean';

UPDATE public.exercise_library 
SET name_it = 'Two-Arm Kettlebell Jerk', description_it = 'Esegui un clean con due kettlebell portandoli alle spalle, estendendo gambe e anche e ruotando i polsi in modo che i palmi siano rivolti in avanti. Fletti leggermente le ginocchia e inverte rapidamente il movimento spingendo entrambi i pesi sopra la testa. Subito dopo la spinta iniziale, fletti nuovamente le ginocchia per posizionarti sotto i kettlebell. Una volta che le braccia sono completamente distese, torna in posizione eretta per completare l''esercizio.' 
WHERE name = 'Two-Arm Kettlebell Jerk';

UPDATE public.exercise_library 
SET name_it = 'Two-Arm Kettlebell Military Press', description_it = 'Esegui un clean con due kettlebell portandoli alle spalle, estendendo gambe e anche e ruotando i polsi in modo che i palmi siano rivolti in avanti. Spingi i kettlebell verso l''alto e verso l''esterno. Quando i pesi superano la testa, inclina leggermente il busto in avanti in modo che i kettlebell si trovino dietro la nuca. Assicurati di contrarre i dorsali, i glutei e l''addome per una maggiore stabilità.' 
WHERE name = 'Two-Arm Kettlebell Military Press';

UPDATE public.exercise_library 
SET name_it = 'Two-Arm Kettlebell Row', description_it = 'Posiziona due kettlebell davanti ai piedi. Fletti leggermente le ginocchia e spingi il bacino all''indietro il più possibile mentre ti inclini in avanti per assumere la posizione di partenza. Afferra entrambi i kettlebell e portali verso l''addome, retrattando le scapole e flettendo i gomiti. Mantieni la schiena dritta. Scendi e ripeti.' 
WHERE name = 'Two-Arm Kettlebell Row';

UPDATE public.exercise_library 
SET name_it = 'Underhand Cable Pulldowns', description_it = 'Siediti alla lat machine con una barra larga collegata alla carrucola superiore. Regola i cuscinetti per le ginocchia in base alla tua altezza per evitare che il corpo venga sollevato dalla resistenza. Afferra la barra con i palmi rivolti verso il busto (presa suina) e le mani a una larghezza inferiore a quella delle spalle. Con le braccia tese, inclina il busto indietro di circa 30 gradi, creando una leggera curvatura nella parte bassa della schiena e spingendo il petto in fuori. Espirando, tira la barra verso la parte superiore del petto, portando spalle e braccia verso il basso e all''indietro. Suggerimento: concentrati sulla contrazione dei muscoli della schiena e mantieni i gomiti vicini al corpo. Il busto deve rimanere immobile. Dopo un secondo di contrazione, inspira e torna lentamente alla posizione di partenza con le braccia completamente distese. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Underhand Cable Pulldowns';

UPDATE public.exercise_library 
SET name_it = 'Upper Back-Leg Grab', description_it = 'Da seduto, piegati in avanti e abbraccia le cosce dal basso con entrambe le braccia. Mantieni le ginocchia unite e le gambe distese mentre porti il petto verso le ginocchia. Puoi allungare ulteriormente la parte centrale della schiena tirandola lontano dalle ginocchia mentre le tieni abbracciate.' 
WHERE name = 'Upper Back-Leg Grab';

UPDATE public.exercise_library 
SET name_it = 'Upper Back Stretch', description_it = 'Intreccia le dita con i pollici rivolti verso il basso, incurva le spalle e spingi le mani in avanti.' 
WHERE name = 'Upper Back Stretch';

UPDATE public.exercise_library 
SET name_it = 'Upright Barbell Row', description_it = 'Afferra un bilanciere con una presa prona leggermente inferiore alla larghezza delle spalle. Il bilanciere deve poggiare sulla parte superiore delle cosce con le braccia tese e i gomiti leggermente flessi. Mantieni la schiena dritta. Espirando, usa i deltoidi laterali per sollevare il bilanciere, portando i gomiti verso l''alto e verso l''esterno. Mantieni il bilanciere vicino al corpo fino a sfiorare quasi il mento. Suggerimento: sono i gomiti a guidare il movimento e devono sempre rimanere più alti degli avambracci. Mantieni il busto fermo e fai una pausa di un secondo nella parte alta. Scendi lentamente espirando e ripeti.' 
WHERE name = 'Upright Barbell Row';

UPDATE public.exercise_library 
SET name_it = 'Upright Cable Row', description_it = 'Afferra una barra dritta collegata a una carrucola bassa con una presa prona (palmi verso le cosce) leggermente inferiore alla larghezza delle spalle. Il bilanciere poggia sulle cosce, braccia tese con gomiti leggermente flessi e schiena dritta. Espirando, usa i deltoidi laterali per sollevare la barra, mantenendola vicina al corpo fino a sfiorare il mento. Suggerimento: i gomiti devono guidare il movimento e rimanere più alti degli avambracci. Mantieni il busto fermo e fai una pausa di un secondo in alto. Scendi lentamente in fase di inspirazione e ripeti.' 
WHERE name = 'Upright Cable Row';

UPDATE public.exercise_library 
SET name_it = 'Upright Row - With Bands', description_it = 'Mettiti in piedi sopra una fascia elastica in modo che la tensione inizi a braccia distese. Afferra le maniglie con una presa prona (palmi verso le cosce) leggermente inferiore alla larghezza delle spalle, con le maniglie che poggiano sulle cosce. Braccia tese, gomiti leggermente flessi e schiena dritta. Espirando, solleva le maniglie usando i deltoidi laterali, mantenendole vicine al corpo fino a sfiorare il mento. Suggerimento: sono i gomiti a guidare il movimento, restando sempre più alti degli avambracci. Mantieni il busto fermo e fai una pausa di un secondo in alto. Scendi lentamente inspirando e ripeti.' 
WHERE name = 'Upright Row - With Bands';

UPDATE public.exercise_library 
SET name_it = 'Allungamento verso l''alto', description_it = 'Estendi entrambe le mani direttamente sopra la testa, con i palmi che si toccano. Spingi lentamente le mani verso l''alto e all''indietro, mantenendo la schiena dritta.' 
WHERE name = 'Upward Stretch';

UPDATE public.exercise_library 
SET name_it = 'V-Bar Pulldown', description_it = 'Siediti alla lat machine con una V-Bar collegata alla carrucola superiore. Regola il cuscinetto per le ginocchia in base alla tua altezza; questo impedirà al corpo di sollevarsi a causa della resistenza. Afferra la V-Bar con i palmi rivolti l''uno verso l''altro (presa neutra). Spingi il petto in fuori e inclinati leggermente all''indietro (circa 30 gradi) per attivare meglio i dorsali. Questa è la posizione di partenza. Usando i dorsali, tira la barra verso il basso contraendo le scapole. Continua finché il petto non sfiora la V-Bar, espirando durante il movimento. Suggerimento: mantieni il busto fermo per tutta l''esecuzione. Dopo una breve pausa di un secondo nella posizione di massima contrazione, torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'V-Bar Pulldown';

UPDATE public.exercise_library 
SET name_it = 'V-Bar Pullup', description_it = 'Posiziona il centro della V-Bar al centro della sbarra per trazioni (assumendo che la postazione non disponga già di prese neutre). Le impugnature della V-Bar devono essere rivolte verso il basso per permetterti di appenderti. Una volta fissata, afferra la sbarra da entrambi i lati e sospenditi. Spingi il petto in fuori e inclinati leggermente all''indietro per coinvolgere meglio i dorsali. Questa è la posizione di partenza. Usando i dorsali, solleva il busto inclinando leggermente la testa all''indietro per non urtare la sbarra. Continua finché il petto non sfiora la V-Bar, espirando durante il movimento. Dopo una pausa di un secondo in contrazione, abbassati lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'V-Bar Pullup';

UPDATE public.exercise_library 
SET name_it = 'Vertical Swing', description_it = 'Lascia che il manubrio penda a braccia tese tra le gambe, impugnandolo con entrambe le mani. Mantieni la schiena dritta e la testa alta. Oscilla il manubrio tra le gambe flettendo le anche e piegando leggermente le ginocchia. Inverti il movimento con potenza estendendo anche, ginocchia e caviglie per slanciare il manubrio sopra la testa. All''atterraggio, assorbi l''impatto con le gambe e riporta il manubrio verso il busto prima della ripetizione successiva.' 
WHERE name = 'Vertical Swing';

UPDATE public.exercise_library 
SET name_it = 'Camminata su tapis roulant', description_it = 'Per iniziare, sali sul tapis roulant e seleziona l''opzione desiderata dal menu. La maggior parte dei tapis roulant ha un''impostazione manuale o programmi preimpostati. Solitamente puoi inserire età e peso per stimare le calorie bruciate. L''inclinazione può essere regolata per variare l''intensità. Il tapis roulant offre comodità e benefici cardiovascolari, solitamente con un impatto minore rispetto alla camminata all''aperto. Mantieni un ritmo da moderato a veloce, non una passeggiata rilassata. Sebbene sia un''attività a bassa intensità, offre ottimi benefici. Una persona di circa 68 kg brucerà circa 175 calorie camminando a 6,4 km/h per 30 minuti, contro le 450 calorie della corsa a velocità doppia. Mantieni una postura corretta e usa i manubri solo se necessario, come per scendere o controllare la frequenza cardiaca.' 
WHERE name = 'Walking, Treadmill';

UPDATE public.exercise_library 
SET name_it = 'Iperestensioni su fitball con sovraccarico', description_it = 'Sdraiati sulla fitball con il busto appoggiato alla palla e parallelo al pavimento. La punta dei piedi deve poggiare a terra per mantenere l''equilibrio. Tieni un disco di peso sotto il mento o dietro la nuca. Questa è la posizione di partenza. Solleva lentamente il busto flettendo la vita e la parte bassa della schiena, espirando durante il movimento. Mantieni la contrazione per un secondo, quindi torna lentamente alla posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato nel tuo programma.' 
WHERE name = 'Weighted Ball Hyperextension';

UPDATE public.exercise_library 
SET name_it = 'Side bend su fitball con sovraccarico', description_it = 'Sdraiati su una fitball con il fianco sinistro (vita, anca e spalla) premuto contro la palla. I piedi devono essere a terra con le gambe incrociate. Tieni un disco di peso con la mano destra vicino alla testa. Suggerimento: assicurati che la parte liscia del disco sia a contatto con la testa. Metti il braccio sinistro sul busto con il palmo sugli obliqui; il gomito sinistro deve formare un angolo retto. Questa è la posizione di partenza. Solleva il fianco eseguendo una flessione laterale della vita ed espirando. Mantieni la contrazione per un secondo, quindi scendi lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni raccomandato, poi cambia lato.' 
WHERE name = 'Weighted Ball Side Bend';

UPDATE public.exercise_library 
SET name_it = 'Dip su panca con sovraccarico', description_it = 'Posiziona una panca dietro di te e una davanti. Con le panche perpendicolari al corpo, afferra il bordo di una panca con le mani larghe quanto le spalle, braccia tese. Le gambe devono essere distese sulla panca davanti, parallele al pavimento, mentre il busto rimane perpendicolare. Fatti assistere da un partner per posizionare un manubrio sulle tue cosce. Nota: l''esercizio va eseguito con un partner per evitare infortuni. Questa è la posizione di partenza. Scendi lentamente inspirando, piegando i gomiti finché non formano un angolo leggermente inferiore a 90 gradi. Suggerimento: tieni i gomiti il più vicino possibile al corpo e gli avambracci sempre rivolti verso il basso. Usa i tricipiti per spingerti verso l''alto ed espirare. Ripeti per le ripetizioni consigliate.' 
WHERE name = 'Weighted Bench Dip';

UPDATE public.exercise_library 
SET name_it = 'Crunch con sovraccarico', description_it = 'Sdraiati sulla schiena con i piedi appoggiati a terra o su una panca, ginocchia piegate a 90 gradi. Tieni un peso contro il petto o esteso sopra il busto. Questa è la posizione di partenza. Espira e solleva lentamente le spalle da terra di circa 10 cm, mantenendo la parte bassa della schiena a contatto col suolo. Al culmine, contrai gli addominali e tieni per una breve pausa. Inspira e torna lentamente alla posizione di partenza.' 
WHERE name = 'Weighted Crunches';

UPDATE public.exercise_library 
SET name_it = 'Jump squat con sovraccarico', description_it = 'Posiziona un bilanciere leggermente caricato sulle spalle, oppure usa un giubbotto zavorrato, una sandbag o altra resistenza. Il peso deve essere abbastanza leggero da non rallentare significativamente il movimento. Piedi appena oltre la larghezza delle spalle, testa e petto alti. Questa è la posizione di partenza. Esegui un mezzo squat e inverti immediatamente il movimento esplodendo verso l''alto, estendendo anche, ginocchia e caviglie. Mantieni una buona postura durante il salto. All''atterraggio, assorbi l''impatto con le gambe.' 
WHERE name = 'Weighted Jump Squat';

UPDATE public.exercise_library 
SET name_it = 'Trazioni alla sbarra con sovraccarico', description_it = 'Aggancia un peso a una cintura da dip e fissalo in vita. Afferra la sbarra per le trazioni con i palmi rivolti in avanti. Per una presa media, le mani devono essere posizionate alla larghezza delle spalle. Entrambe le braccia devono essere tese davanti a te mentre impugni la sbarra. Inclina il busto all''indietro di circa 30 gradi, crea una curvatura nella zona lombare e spingi il petto in fuori. Questa è la posizione di partenza. Espira e solleva il busto finché la testa non supera l''altezza delle mani. Concentrati sulla contrazione delle scapole verso il basso e all''indietro nel punto di massima chiusura. Dopo una breve pausa in contrazione, inspira e abbassa lentamente il busto fino alla posizione iniziale, con le braccia distese e i dorsali completamente allungati.' 
WHERE name = 'Weighted Pull Ups';

UPDATE public.exercise_library 
SET name_it = 'Sissy Squat con sovraccarico', description_it = 'In piedi, con i piedi alla larghezza delle spalle e le punte sollevate, usa una mano per sorreggerti alla struttura del rack e l''altra per tenere un disco contro il petto. Questa è la posizione di partenza. Mentre ti sorreggi con un braccio, fletti le ginocchia e abbassa lentamente il busto verso terra, portando bacino e ginocchia in avanti. Inspira durante la discesa e fermati quando le gambe formano un angolo di circa 90 gradi. Mantieni la posizione di allungamento per un secondo. Dopo la pausa, usa i muscoli delle cosce per riportare il busto alla posizione iniziale espirando. Ripeti per il numero di volte consigliato.' 
WHERE name = 'Weighted Sissy Squat';

UPDATE public.exercise_library 
SET name_it = 'Sit-up con sovraccarico (con elastici)', description_it = 'Fissa gli elastici alla base della panca inclinata. Posiziona le maniglie verso l''interno della panca in modo da poterle afferrare una volta sdraiato. Inserisci le gambe nell''apposito supporto della panca finché non sono bloccate. Afferra le maniglie degli elastici con una presa prona (palmi in avanti). Portale vicino alle clavicole e ruota i polsi in una presa neutra (palmi rivolti verso il busto). Nota: le braccia devono rimanere ferme durante tutto l''esercizio. Questa è la posizione di partenza. Espirando, solleva il busto finché non è perpendicolare al pavimento. Mantieni la contrazione per un secondo, quindi inspira e torna lentamente alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Weighted Sit-Ups - With Bands';

UPDATE public.exercise_library 
SET name_it = 'Squat con sovraccarico', description_it = 'Posiziona due panche piane alla larghezza delle spalle. Sali sopra di esse e allaccia la cintura con sovraccarico in vita, utilizzando il peso desiderato. Assicurati che le punte dei piedi siano rivolte verso l''esterno. In posizione eretta, con il peso che pende tra le gambe, tieni le braccia completamente distese lungo i fianchi. Questa è la posizione di partenza. Inizia a flettere le ginocchia mantenendo la postura dritta e lo sguardo alto. Scendi finché l''angolo tra coscia e polpaccio è leggermente inferiore a 90 gradi (le cosce devono essere sotto il parallelo rispetto al pavimento). Inspira durante questa fase. Consiglio: se eseguito correttamente, la parte anteriore delle ginocchia deve formare una linea immaginaria retta con le punte dei piedi. Se le ginocchia superano questa linea, stai sovraccaricando l''articolazione in modo errato. Spingi sulla parte anteriore del piede per risalire, estendendo le gambe fino alla posizione iniziale ed espirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Weighted Squat';

UPDATE public.exercise_library 
SET name_it = 'Panca piana bilanciere presa larga', description_it = 'Sdraiati su una panca piana con i piedi ben saldi a terra. Utilizza una presa prona larga (circa 7-8 cm oltre la larghezza delle spalle per lato), stacca il bilanciere e tienilo sopra di te a braccia tese. Il bilanciere deve essere perpendicolare al busto e al pavimento. Questa è la posizione di partenza. Inspira e scendi lentamente finché il bilanciere tocca la parte centrale del petto. Dopo un secondo di pausa, espira e spingi il bilanciere verso l''alto usando i pettorali. Blocca le braccia, contrai i pettorali per un secondo, poi ricomincia a scendere lentamente. Consiglio: la fase di discesa dovrebbe durare il doppio di quella di salita. Ripeti per le ripetizioni prescritte.' 
WHERE name = 'Wide-Grip Barbell Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Panca declinata bilanciere presa larga', description_it = 'Sdraiati su una panca declinata con i piedi bloccati nell''apposito supporto. Utilizza una presa prona larga (circa 7-8 cm oltre la larghezza delle spalle per lato), stacca il bilanciere e tienilo sopra di te a braccia tese. Il bilanciere deve essere perpendicolare al busto e al pavimento. Questa è la posizione di partenza. Inspira e scendi lentamente finché il bilanciere tocca la parte bassa del petto. Dopo un secondo di pausa, espira e spingi il bilanciere verso l''alto usando i pettorali. Blocca le braccia, contrai i pettorali per un secondo, poi ricomincia a scendere lentamente. Consiglio: la fase di discesa dovrebbe durare il doppio di quella di salita. Ripeti per le ripetizioni prescritte.' 
WHERE name = 'Wide-Grip Decline Barbell Bench Press';

UPDATE public.exercise_library 
SET name_it = 'Pullover con bilanciere su panca declinata presa larga', description_it = 'Sdraiati su una panca declinata con le gambe ben bloccate. Afferra il bilanciere dietro la testa con una presa prona larga (più ampia delle spalle). Solleva lentamente il bilanciere da terra usando le braccia. Una volta posizionato correttamente, le braccia devono essere tese e perpendicolari al pavimento. Questa è la posizione di partenza. Abbassa il bilanciere con un movimento semicircolare come se volessi portarlo a terra, ma fermati quando le braccia sono parallele al pavimento. Consiglio: mantieni le braccia completamente tese per tutto il movimento, che deve avvenire solo dall''articolazione della spalla. Inspira durante la discesa. Espirando, riporta il bilanciere alla posizione iniziale mantenendo il pieno controllo. Ripeti per il numero di ripetizioni prescritte. Al termine della serie, abbassa lentamente il bilanciere fino all''altezza della testa e riponilo.' 
WHERE name = 'Wide-Grip Decline Barbell Pullover';

UPDATE public.exercise_library 
SET name_it = 'Lat machine presa larga', description_it = 'Siediti alla lat machine con la barra larga fissata alla carrucola. Regola il bloccaggio per le ginocchia in base alla tua altezza per evitare di essere sollevato dal carico. Afferra la barra con i palmi rivolti in avanti usando la presa prescritta (larga significa oltre la larghezza delle spalle). Con le braccia tese davanti a te, inclina il busto all''indietro di circa 30 gradi, inarca leggermente la zona lombare e spingi il petto in fuori. Questa è la posizione di partenza. Espira e tira la barra verso la parte alta del petto portando spalle e braccia verso il basso e indietro. Consiglio: concentrati sulla contrazione dei muscoli della schiena nel punto di massima chiusura. Il busto deve rimanere fermo e solo le braccia devono muoversi. Non tirare usando gli avambracci. Dopo un secondo di contrazione, torna lentamente alla posizione iniziale espandendo i dorsali. Inspira durante questa fase. Ripeti per le ripetizioni prescritte.' 
WHERE name = 'Wide-Grip Lat Pulldown';

UPDATE public.exercise_library 
SET name_it = 'Lat machine dietro la nuca presa larga', description_it = 'Siediti alla lat machine e regola il bloccaggio per le ginocchia. Afferra la barra con presa prona larga (più ampia delle spalle). Con le braccia tese, inclina leggermente busto e testa in avanti, immaginando una linea retta dal centro della barra alla base del collo. Questa è la posizione di partenza. Espira e tira la barra verso la nuca portando spalle e braccia verso il basso e indietro. Consiglio: contrai i muscoli della schiena nel punto di massima chiusura. Il busto deve rimanere fermo e solo le braccia devono muoversi; gli avambracci devono solo sostenere la presa. Dopo un secondo di contrazione, risali lentamente fino alla posizione iniziale, estendendo completamente i dorsali. Inspira durante la risalita. Ripeti per le ripetizioni prescritte.' 
WHERE name = 'Wide-Grip Pulldown Behind The Neck';

UPDATE public.exercise_library 
SET name_it = 'Trazioni dietro la nuca presa larga', description_it = 'Afferra la sbarra per le trazioni con una presa prona larga. Con le braccia tese, inclina busto e testa in avanti in modo da creare una linea immaginaria dalla sbarra alla base del collo. Questa è la posizione di partenza. Tira il busto verso l''alto finché la sbarra non è vicino alla nuca, portando spalle e braccia verso il basso e indietro e inclinando leggermente la testa in avanti. Espira durante questa fase. Consiglio: concentrati sulla contrazione dei muscoli della schiena nel punto di massima chiusura. Il busto deve rimanere fermo durante il movimento, che deve essere guidato solo dalle braccia. Dopo un secondo di contrazione, inspira e scendi lentamente fino alla posizione iniziale, estendendo completamente i dorsali. Ripeti per le ripetizioni prescritte.' 
WHERE name = 'Wide-Grip Rear Pull-Up';

UPDATE public.exercise_library 
SET name_it = 'Curl con Bilanciere in Piedi Presa Larga', description_it = 'In piedi, con il busto eretto, impugna un bilanciere con una presa larga. I palmi delle mani devono essere rivolti in avanti e i gomiti vicini al busto. Questa è la posizione di partenza. Tenendo le braccia ferme, fletti i pesi in avanti contraendo i bicipiti ed espirando. Consiglio: solo gli avambracci devono muoversi. Continua il movimento finché i bicipiti non sono completamente contratti e il bilanciere è all''altezza delle spalle. Mantieni la posizione di contrazione per un secondo contraendo intensamente i bicipiti. Torna lentamente alla posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Wide-Grip Standing Barbell Curl';

UPDATE public.exercise_library 
SET name_it = 'Squat con Bilanciere a Gambe Larghe', description_it = 'Questo esercizio va eseguito preferibilmente all''interno di un rack per motivi di sicurezza. Regola il bilanciere su un''altezza adeguata. Posizionati sotto il bilanciere e appoggialo sulla parte posteriore delle spalle (appena sotto il collo). Impugna il bilanciere con entrambe le mani e sollevalo dal rack spingendo con le gambe e raddrizzando il busto. Allontanati dal rack e posiziona le gambe con un''apertura superiore alla larghezza delle spalle, con le punte dei piedi leggermente rivolte verso l''esterno. Mantieni lo sguardo fisso in avanti e la schiena dritta. Questa è la posizione di partenza. Scendi lentamente flettendo le ginocchia, mantenendo il busto dritto. Continua fino a quando l''angolo tra le cosce e i polpacci è leggermente inferiore a 90 gradi (le cosce scendono sotto il parallelo rispetto al pavimento). Inspira durante la discesa. Consiglio: le ginocchia devono allinearsi verticalmente con le punte dei piedi; se le ginocchia superano questa linea, l''esercizio è eseguito in modo errato e sovraccarica l''articolazione. Risali espirando, spingendo con i talloni fino alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Wide Stance Barbell Squat';

UPDATE public.exercise_library 
SET name_it = 'Stacchi a Gambe Tese con Posizione Larga', description_it = 'Parti con un bilanciere a terra. Assumi una posizione larga delle gambe e flettiti sui fianchi per afferrare il bilanciere. Porta i fianchi il più indietro possibile mantenendo le gambe quasi tese. Mantieni la schiena dritta e testa e petto alti. Questa è la posizione di partenza. Esegui il movimento spingendo i fianchi in avanti e lasciando le braccia distese. Continua finché non sei completamente in piedi, poi torna lentamente alla posizione iniziale. Per le ripetizioni successive, non è necessario che il peso tocchi il pavimento.' 
WHERE name = 'Wide Stance Stiff Legs';

UPDATE public.exercise_library 
SET name_it = 'Wind Sprints (Corsa sul posto alla sbarra)', description_it = 'Appenditi a una sbarra per trazioni con una presa prona. Braccia e gambe devono essere distese. Questa è la posizione di partenza. Solleva rapidamente un ginocchio il più in alto possibile, evitando di oscillare con il corpo o con le gambe. Inverti immediatamente il movimento, riportando la gamba nella posizione iniziale e sollevando contemporaneamente l''altro ginocchio il più in alto possibile. Continua ad alternare le gambe finché la serie non è completata.' 
WHERE name = 'Wind Sprints';

UPDATE public.exercise_library 
SET name_it = 'Windmills (a terra)', description_it = 'Sdraiati sulla schiena con le braccia distese lateralmente e le gambe dritte. Questa è la posizione di partenza. Solleva una gamba e portala rapidamente oltre il corpo, cercando di toccare il suolo vicino alla mano opposta. Torna alla posizione di partenza e ripeti con l''altra gamba. Continua ad alternare per 10-20 ripetizioni.' 
WHERE name = 'Windmills';

UPDATE public.exercise_library 
SET name_it = 'World''s Greatest Stretch', description_it = 'Questo è uno stretching in tre fasi. Inizia facendo un affondo in avanti, con il piede anteriore ben appoggiato a terra e le dita del piede posteriore in appoggio. Con le ginocchia flesse, scendi finché il ginocchio posteriore quasi tocca terra. Mantieni il busto eretto per 10-20 secondi. Ora, appoggia a terra il braccio dello stesso lato della gamba anteriore, posizionando il gomito vicino al piede. L''altra mano deve essere appoggiata a terra, parallela al piede anteriore, per dare supporto. Dopo 10-20 secondi, posiziona le mani ai lati del piede anteriore, solleva le dita del piede anteriore da terra e distendi la gamba. Potrebbe essere necessario riposizionare la gamba posteriore. Mantieni per 10-20 secondi, quindi ripeti l''intera sequenza sull''altro lato.' 
WHERE name = 'World''s Greatest Stretch';

UPDATE public.exercise_library 
SET name_it = 'Circonduzioni dei Polsi', description_it = 'In piedi con i piedi alla larghezza delle spalle. Solleva le braccia lateralmente finché non sono completamente distese e parallele al pavimento, allineate con le spalle. Consiglio: il corpo deve formare una "T". I palmi devono essere rivolti verso il basso. Questa è la posizione di partenza. Mantenendo il corpo immobile ad eccezione dei polsi, ruota entrambi i polsi in avanti eseguendo un movimento circolare. Consiglio: immagina di disegnare dei cerchi usando le mani come se fossero pennelli. Respira normalmente durante l''esecuzione. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Wrist Circles';

UPDATE public.exercise_library 
SET name_it = 'Wrist Roller', description_it = 'In piedi, con i piedi alla larghezza delle spalle, afferra un wrist roller con una presa prona (palmi rivolti verso il basso). Solleva lentamente le braccia finché non sono completamente distese e parallele al pavimento davanti a te. Nota: assicurati che la corda non sia avvolta attorno al rullo. Il corpo deve restare fermo, muovi solo gli avambracci. Questa è la posizione di partenza. Ruota un polso alla volta verso l''alto per avvolgere la corda attorno al rullo e sollevare il peso. Una volta che il peso ha raggiunto la sbarra, scendilo lentamente ruotando i polsi nel verso opposto finché il peso torna al punto di partenza. Ripeti per il numero di ripetizioni prescritto.' 
WHERE name = 'Wrist Roller';

UPDATE public.exercise_library 
SET name_it = 'Rotazioni dei Polsi con Bilanciere', description_it = 'Impugna un bilanciere con entrambe le mani, palmi rivolti verso il basso, mani alla larghezza delle spalle. Questa è la posizione di partenza. Alternando le mani, esegui il movimento estendendo il polso come se stessi arrotolando un giornale. Continua ad alternare fino ad esaurimento. Inverti il movimento flettendo i polsi e ruotando nella direzione opposta. Continua ad alternare fino ad esaurimento.' 
WHERE name = 'Wrist Rotations with Straight Bar';

UPDATE public.exercise_library 
SET name_it = 'Yoke Walk', description_it = 'Il Yoke Walk si esegue solitamente con l''apposito telaio (yoke), ma può essere svolto anche con altri oggetti pesanti. Inizia posizionando l''attrezzo sulla parte posteriore delle spalle. Con lo sguardo rivolto in avanti e la schiena inarcata, solleva lo yoke spingendo con i talloni. Inizia a camminare il più velocemente possibile facendo passi brevi e rapidi. Puoi afferrare i montanti laterali per stabilizzare l''attrezzo. Prosegui per la distanza indicata (solitamente 20-30 metri) il più velocemente possibile.' 
WHERE name = 'Yoke Walk';

UPDATE public.exercise_library 
SET name_it = 'Zercher Squats', description_it = 'Per ragioni di sicurezza, questo esercizio va eseguito preferibilmente all''interno di un rack. Inizia posizionando il bilanciere su un rack a un''altezza adeguata, compresa tra la vita e il petto. Una volta caricato il bilanciere, incrocia le mani e posiziona la sbarra tra l''avambraccio e il braccio. Solleva il bilanciere in modo che poggi stabilmente sull''incavo dei gomiti; se la posizione è corretta, sembrerà che tu abbia le braccia incrociate con il bilanciere che le attraversa. Allontanati dal rack e posiziona i piedi a una larghezza media, pari a quella delle spalle, con le punte leggermente rivolte verso l''esterno. Mantieni la testa alta e la schiena dritta durante tutto il movimento per evitare di perdere l''equilibrio. Questa è la posizione di partenza. Inizia ad abbassarti flettendo le ginocchia, mantenendo la postura eretta e lo sguardo in avanti. Scendi finché l''angolo tra coscia e polpaccio è leggermente inferiore a 90 gradi (ovvero quando le cosce sono sotto la linea parallela al pavimento). Inspira durante questa fase. Consiglio: se l''esercizio è eseguito correttamente, le ginocchia non dovrebbero superare la linea immaginaria perpendicolare alla punta dei piedi; se le superano, stai sovraccaricando l''articolazione in modo errato. Risali espirando, facendo pressione sulla parte anteriore del piede mentre distendi le gambe per tornare alla posizione iniziale. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Zercher Squats';

UPDATE public.exercise_library 
SET name_it = 'Zottman Curl', description_it = 'In piedi, busto eretto e un manubrio in ciascuna mano lungo i fianchi. I gomiti devono essere vicini al busto e i palmi delle mani rivolti l''uno verso l''altro. Questa è la posizione di partenza. Mantenendo fermi i gomiti, solleva i manubri contraendo i bicipiti ed espirando. Durante il movimento, ruota i polsi in posizione suinata (palmi rivolti verso l''alto). Continua finché i bicipiti non sono completamente contratti e i manubri all''altezza delle spalle. Mantieni la contrazione per un secondo, strizzando i bicipiti. A questo punto, ruota i polsi in posizione pronata (palmi rivolti verso il basso), con il pollice più in alto rispetto al mignolo. Abbassa lentamente i manubri mantenendo la presa pronata. Quando i manubri arrivano vicino alle cosce, ruota nuovamente i polsi per tornare alla presa neutra (palmi rivolti verso il corpo). Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Zottman Curl';

UPDATE public.exercise_library 
SET name_it = 'Zottman Preacher Curl', description_it = 'Afferra un manubrio per mano e appoggia le braccia sulla panca Scott (preacher bench) o su una panca inclinata. I manubri devono essere tenuti all''altezza delle spalle con i gomiti flessi e i palmi rivolti verso il basso. Questa è la posizione di partenza. Inspirando, abbassa lentamente i manubri mantenendo i palmi rivolti verso il basso, finché le braccia non sono estese e i bicipiti completamente allungati. A questo punto, ruota i polsi affinché i palmi siano rivolti verso l''alto. Espirando, usa i bicipiti per sollevare i pesi fino a completa contrazione, portando i manubri all''altezza delle spalle; assicurati di tenere il mignolo più in alto del pollice per una contrazione ottimale. Strizza i bicipiti per un secondo e ruota nuovamente i polsi verso il basso. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Zottman Preacher Curl';

UPDATE public.exercise_library 
SET name_it = 'Alzate posteriori con manubri a busto flesso con testa su panca', description_it = 'In piedi, tieni un manubrio in ogni mano con una panca inclinata davanti a te. Mantenendo la schiena dritta e la sua naturale curvatura, piegati in avanti fino a far toccare la fronte alla panca. Lascia le braccia a penzoloni davanti a te, perpendicolari al suolo. I palmi delle mani devono essere rivolti l''uno verso l''altro e il busto parallelo al pavimento. Questa è la posizione di partenza. Mantenendo il busto fermo e le braccia tese con un leggero piegamento ai gomiti, solleva i manubri lateralmente fino a quando le braccia non saranno parallele al pavimento. Espira durante la salita. Attenzione: evita di oscillare con il busto o di portare le braccia all''indietro invece che lateralmente. Dopo una contrazione di un secondo nel punto massimo, abbassa lentamente i manubri nella posizione iniziale. Ripeti per il numero di ripetizioni raccomandato.' 
WHERE name = 'Bent Over Dumbbell Rear Delt Raise With Head On Bench';

UPDATE public.exercise_library 
SET name_it = 'Alzate laterali a busto flesso ai cavi bassi', description_it = 'Seleziona il carico e afferra la maniglia del cavo basso con la mano destra. Piegati in vita fino a portare il busto quasi parallelo al pavimento. Le gambe devono essere leggermente flesse e la mano sinistra appoggiata sulla coscia sinistra. Il braccio destro deve pendere dalla spalla davanti a te con il gomito leggermente flesso. Questa è la posizione di partenza. Solleva il braccio destro, mantenendo il gomito leggermente flesso, lateralmente fino a quando il braccio è parallelo al pavimento e in linea con l''orecchio destro. Espira durante il movimento. Abbassa lentamente il peso nella posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato e cambia braccio.' 
WHERE name = 'Bent Over Low-Pulley Side Lateral';

UPDATE public.exercise_library 
SET name_it = 'Rematore con bilanciere a un braccio (Landmine Row)', description_it = 'Carica dei dischi su un''estremità di un bilanciere olimpionico. Assicurati che l''altra estremità sia bloccata nell''angolo di due pareti o contro un oggetto pesante affinché non scivoli. Piegati in avanti mantenendo il busto il più possibile parallelo al suolo e le ginocchia leggermente flesse. Afferra il bilanciere con un braccio subito dietro i dischi e appoggia l''altra mano sul ginocchio. Questa è la posizione di partenza. Tira il bilanciere verso l''alto tenendo il gomito vicino al corpo (per massimizzare lo stimolo dorsale) finché i dischi non toccano la parte bassa del petto. Contrai i muscoli della schiena nel punto massimo per un secondo. Espira durante la fase di trazione. Suggerimento: evita oscillazioni del busto. Solo il braccio deve muoversi. Abbassa lentamente il bilanciere nella posizione iniziale per allungare bene i dorsali. Suggerimento: non far toccare i dischi a terra. Per un range di movimento ottimale, si consiglia l''uso di dischi piccoli (da 10-15 kg). Ripeti per il numero di ripetizioni consigliato e cambia braccio.' 
WHERE name = 'Bent Over One-Arm Long Bar Row';

UPDATE public.exercise_library 
SET name_it = 'Rematore con bilanciere a due braccia (Landmine Row)', description_it = 'Carica dei dischi su un''estremità di un bilanciere olimpionico. Assicurati che l''altra estremità sia bloccata nell''angolo di due pareti o contro un oggetto pesante affinché non scivoli. Piegati in avanti mantenendo il busto il più possibile parallelo al suolo e le ginocchia leggermente flesse. Afferra il bilanciere con entrambe le mani subito dietro i dischi. Questa è la posizione di partenza. Tira il bilanciere verso l''alto tenendo i gomiti vicini al corpo (per massimizzare lo stimolo dorsale) finché i dischi non toccano la parte bassa del petto. Contrai i muscoli della schiena nel punto massimo per un secondo. Espira durante la fase di trazione. Suggerimento: utilizza una maniglia a V o un attacco per cavi inserendolo sotto l''estremità del bilanciere. Abbassa lentamente il bilanciere nella posizione iniziale per allungare bene i dorsali. Suggerimento: non far toccare i dischi a terra. Per un range di movimento ottimale, si consiglia l''uso di dischi piccoli (da 10-15 kg). Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Bent Over Two-Arm Long Bar Row';

UPDATE public.exercise_library 
SET name_it = 'Rematore con due manubri a busto flesso', description_it = 'Con un manubrio per mano (palmi rivolti verso il busto), fletti leggermente le ginocchia e porta il busto in avanti flettendo la vita; mantieni la schiena dritta finché non è quasi parallela al pavimento. Suggerimento: tieni la testa alta. I pesi devono pendere direttamente davanti a te con le braccia perpendicolari al pavimento. Questa è la posizione di partenza. Mantenendo il busto fermo, solleva i manubri lateralmente (espirando), tenendo i gomiti vicini al corpo (non sforzare gli avambracci, usali solo per la presa). Nel punto di massima contrazione, strizza i muscoli della schiena e tieni per un secondo. Abbassa lentamente il peso nella posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Bent Over Two-Dumbbell Row';

UPDATE public.exercise_library 
SET name_it = 'Rematore con due manubri a busto flesso (palmi rivolti all''interno)', description_it = 'Con un manubrio per mano (palmi rivolti l''uno verso l''altro), fletti leggermente le ginocchia e porta il busto in avanti flettendo la vita, mantenendo la schiena dritta finché non è quasi parallela al pavimento. Suggerimento: tieni la testa alta. I pesi devono pendere direttamente davanti a te con le braccia perpendicolari al pavimento. Questa è la posizione di partenza. Mantenendo il busto fermo, solleva i manubri lateralmente espirando, avvicinando le scapole tra loro. Nel punto di massima contrazione, strizza i muscoli della schiena e tieni per un secondo. Abbassa lentamente il peso nella posizione iniziale inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Bent Over Two-Dumbbell Row With Palms In';

UPDATE public.exercise_library 
SET name_it = 'Bent Press', description_it = 'Porta il kettlebell alla spalla (Clean) estendendo gambe e anche mentre lo sollevi. Ruota il polso durante il movimento. Questa è la posizione di partenza. Inizia inclinando il busto sul lato opposto al kettlebell, continuando finché non riesci a toccare terra con la mano libera, tenendo lo sguardo fisso sul kettlebell. Contemporaneamente, spingi il peso verticalmente estendendo il gomito e mantenendo il braccio perpendicolare al suolo. Torna in posizione eretta con il kettlebell sopra la testa. Riporta il kettlebell alla spalla e ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Bent Press';

UPDATE public.exercise_library 
SET name_it = 'Ciclismo', description_it = 'Per iniziare, siediti sulla bici e regola l''altezza della sella.' 
WHERE name = 'Bicycling';

UPDATE public.exercise_library 
SET name_it = 'Ciclismo, Cyclette', description_it = 'Per iniziare, siediti sulla cyclette e regola l''altezza della sella. Seleziona l''opzione desiderata dal menu. Potrebbe essere necessario iniziare a pedalare per accenderla. Puoi utilizzare l''impostazione manuale o selezionare un programma. Generalmente, puoi inserire età e peso per stimare le calorie bruciate durante l''esercizio. Il livello di resistenza può essere modificato durante l''allenamento. Le maniglie possono essere utilizzate per monitorare la frequenza cardiaca e aiutarti a mantenere un''intensità adeguata.' 
WHERE name = 'Bicycling, Stationary';

UPDATE public.exercise_library 
SET name_it = 'Board Press', description_it = 'Inizia sdraiato sulla panca, portando la testa oltre il bilanciere se possibile. Da uno a cinque listelli di legno (2x6 pollici) possono essere fissati insieme e tenuti in posizione da un compagno, con elastici o infilati sotto la maglietta. Posiziona i piedi sotto di te e inarca la schiena. Usando il bilanciere per supportare il peso, stacca le spalle dalla panca e retraile, strizzando le scapole. Usa i piedi per spingere i trapezi contro la panca. Mantieni questa posizione compatta per tutto il movimento. Puoi usare una presa standard o a larghezza spalle per focalizzarti sui tricipiti. Stacca il bilanciere dal rack senza protrarre le spalle. Bilanciere, polsi e gomiti devono rimanere allineati. Concentrati sullo stringere il bilanciere cercando di ''spezzarlo''. Abbassa il bilanciere sui listelli, quindi spingilo verso l''alto con la massima forza possibile. I gomiti devono rimanere stretti fino alla chiusura del movimento.' 
WHERE name = 'Board Press';

UPDATE public.exercise_library 
SET name_it = 'Rematore con bilanciere a presa inversa', description_it = 'Assumi una posizione eretta impugnando un bilanciere con una presa supinata (palmi rivolti verso l''alto). Fletti leggermente le ginocchia e porta il busto in avanti flettendo la vita, mantenendo la schiena dritta finché non è quasi parallela al pavimento. Consiglio: mantieni la testa alta. Il bilanciere dovrebbe penzolare davanti a te, con le braccia perpendicolari al pavimento e al busto. Questa è la posizione di partenza. Mantenendo il busto fermo, solleva il bilanciere espirando, tenendo i gomiti vicini al corpo ed evitando di usare la forza degli avambracci oltre a quella necessaria per reggere il peso. Nella posizione di massima contrazione, contrai i muscoli della schiena e mantieni per un secondo. Abbassa lentamente il peso nella posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Reverse Grip Bent-Over Rows';

UPDATE public.exercise_library 
SET name_it = 'Reverse Hyperextension', description_it = 'Posiziona i piedi tra i cuscinetti dopo aver caricato il peso appropriato. Sdraiati sul cuscinetto superiore, lasciando che le anche sporgano oltre il bordo, afferrando le maniglie per mantenere la posizione. Per iniziare il movimento, fletti le anche tirando le gambe in avanti. Inverti il movimento estendendo le anche e spingendo le gambe all''indietro. È fondamentale non iperestendere l''anca in questo movimento, fermandosi prima di raggiungere il massimo range di movimento. Ritorna flettendo nuovamente l''anca e tirando il carrello in avanti il più possibile. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Reverse Hyperextension';

UPDATE public.exercise_library 
SET name_it = 'Reverse Machine Flyes', description_it = 'Regola le maniglie in modo che siano completamente arretrate. Seleziona il peso appropriato e regola l''altezza del sedile in modo che le maniglie siano all''altezza delle spalle. Afferra le maniglie con i palmi rivolti verso l''interno. Questa sarà la posizione di partenza. Con un movimento semicircolare, tira le maniglie verso l''esterno e all''indietro, contraendo i deltoidi posteriori. Mantieni le braccia leggermente flesse durante tutto il movimento, facendo sì che l''intero movimento avvenga solo a livello dell''articolazione della spalla. Fermati al culmine del movimento e riporta lentamente il peso alla posizione iniziale.' 
WHERE name = 'Reverse Machine Flyes';

UPDATE public.exercise_library 
SET name_it = 'Reverse Plate Curls', description_it = 'Inizia stando in piedi, tenendo un disco con entrambe le mani e le braccia completamente distese. Usa una presa prona (palmi rivolti verso il basso) assicurandoti che le dita facciano presa sul lato ruvido del disco mentre il pollice afferra il lato liscio. Nota: per risultati ottimali, afferra il disco nelle posizioni corrispondenti alle ore 11:00 e 1:00 di un orologio. I piedi devono essere alla larghezza delle spalle e il disco deve trovarsi vicino all''inguine. Questa è la posizione di partenza. Solleva lentamente il disco espirando, mantenendo i gomiti vicini al corpo e la parte superiore delle braccia immobile, finché bicipiti e avambracci non si toccano. A questo punto il disco deve essere allineato con il busto. Senti la contrazione per un secondo e inizia ad abbassare il peso nella posizione di partenza inspirando. Ripeti per il numero di ripetizioni consigliato.' 
WHERE name = 'Reverse Plate Curls';

UPDATE public.exercise_library 
SET name_it = 'Reverse Triceps Bench Press', description_it = 'Sdraiati su una panca piana. Usando una presa stretta e supinata (circa alla larghezza delle spalle), solleva il bilanciere dal rack e tienilo dritto sopra di te con le braccia bloccate in estensione, perpendicolari al pavimento. Questa sarà la posizione di partenza. Inspirando, scendi lentamente finché non senti il bilanciere a metà petto. Consiglio: assicurati di mantenere i gomiti vicini al busto per massimizzare il coinvolgimento dei tricipiti, diversamente dalla panca piana tradizionale. Dopo una pausa di un secondo, riporta il bilanciere alla posizione di partenza espirando e spingendo usando i muscoli dei tricipiti. Blocca le braccia nella posizione contratta, mantieni per un secondo e poi ricomincia a scendere lentamente. Consiglio: la fase di discesa dovrebbe durare almeno il doppio della fase di risalita. Ripeti per il numero di ripetizioni prescritto. Al termine, riponi il bilanciere sul rack.' 
WHERE name = 'Reverse Triceps Bench Press';

UPDATE public.exercise_library 
SET name_it = 'SMR per i romboidi', description_it = 'Sdraiati con la schiena a terra. Posiziona un foam roller sotto la parte superiore della schiena e incrocia le braccia davanti a te, protraendo le spalle. Questa sarà la posizione di partenza. Solleva i fianchi da terra, scaricando il peso sul foam roller. Sposta il peso su un lato alla volta, facendolo scorrere sulla parte centrale e superiore della schiena. Fermati sui punti di tensione per 10-30 secondi.' 
WHERE name = 'Rhomboids-SMR';

UPDATE public.exercise_library 
SET name_it = 'Rickshaw Carry', description_it = 'Posiziona il telaio nel punto di partenza e caricalo con il peso appropriato. In piedi al centro del telaio, inizia afferrando le maniglie e spingendo sui talloni per sollevare il carico. Assicurati che petto e testa siano alti e la schiena dritta. Inizia subito a camminare velocemente con passi rapidi e controllati. Mantieni il petto alto, lo sguardo in avanti e continua a respirare. Appoggia il telaio a terra dopo aver raggiunto il punto di arrivo.' 
WHERE name = 'Rickshaw Carry';

UPDATE public.exercise_library 
SET name_it = 'Rickshaw Deadlift', description_it = 'Carica il telaio con il peso desiderato. Centrati tra le maniglie. I piedi dovrebbero essere alla larghezza dei fianchi. Fletti le anche per afferrare le maniglie, lasciando che le scapole vadano in protrazione. Con i piedi e la presa ben saldi, fai un respiro profondo, abbassa le anche e fletti le ginocchia. Guarda avanti, tieni il petto alto, la schiena inarcata e inizia a spingere sui talloni per sollevare il peso. Mentre il peso sale, unisci le scapole e spingi le anche in avanti. Abbassa il peso flettendo le anche e guidandolo verso il terreno.' 
WHERE name = 'Rickshaw Deadlift';

UPDATE public.exercise_library 
SET name_it = 'Dip agli anelli', description_it = 'Afferra un anello con ogni mano, quindi dai un piccolo slancio per portarti nella posizione di partenza con le braccia bloccate in estensione. Inizia flettendo i gomiti, abbassando il corpo finché le braccia non superano i 90 gradi. Evita di oscillare e mantieni una buona postura durante tutta la discesa. Inverti il movimento estendendo i gomiti e spingendoti verso l''alto fino alla posizione di partenza. Ripeti per il numero di ripetizioni desiderato.' 
WHERE name = 'Ring Dips';

